static uint32_t ds4_gpu_flash_attn_vec_nsg(uint32_t n_keys, uint32_t nwg, uint32_t ncpsg) {
 uint32_t nsg = 1;
 while (2u * nwg * nsg * ncpsg < n_keys && nsg < 4u) {
 nsg *= 2u;
 }
 return nsg;
}

