 uint32_t n_rot) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!kv || !raw_cache || raw_cap == 0 || row >= raw_cap || head_dim == 0 ||
 n_rot > head_dim || raw_cap > INT32_MAX) {
