 raw_kv,
 n_tokens,
 window,
 n_head,
 head_dim)) {
 return 0;
 }

 if (!ds4_gpu_finish_command_buffer(cb, owned, "graph prefill raw attention heads")) return 0;
 }

 return 1;
}

