 if (!heads || !model_map || !q || !raw_kv || !comp_kv || !topk ||
 n_tokens == 0 || n_raw == 0 || raw_cap < n_raw || raw_start >= raw_cap ||
 n_comp == 0 || top_k == 0 || top_k > n_comp || (top_k & (top_k - 1u)) != 0 ||
 ratio == 0 || n_head == 0 || head_dim != 512) {
