static NSUInteger ds4_gpu_bin_threads(uint32_t width, id<MTLComputePipelineState> pipeline) {
 NSUInteger nth_max = pipeline.maxTotalThreadsPerThreadgroup;
 if (nth_max > 256u) nth_max = 256u;
 NSUInteger nth = 1u;
 while (2u * nth < (NSUInteger)width && nth < nth_max) nth *= 2u;
 return nth ? nth : 1u;
}

/* #558 ICB Phase 4 helper for kernel_dsv4_softplus_sqrt_f32_4. The fixed
 * dispatch shape (width=256, rows=1, c4=1, min=0, max=0) means args + grid
 * are constant across both call sites; only src/dst buffers vary. Returns 1
 * if ICB executed, 0 if fell through. Opt-in via DS4_ICB_SOFTPLUS=1. */
static int ds4_softplus_sqrt_dispatch_icb(id<MTLCommandBuffer> cb,
                                           uint32_t slot_idx,
                                           id<MTLComputePipelineState> pipeline,
                                           id<MTLBuffer> src, NSUInteger src_off,
                                           id<MTLBuffer> dst, NSUInteger dst_off) {
    static int s_env_checked = 0;
    static int s_env_active = 0;
    if (!s_env_checked) {
        s_env_active = getenv("DS4_ICB_SOFTPLUS") != NULL ? 1 : 0;
        s_env_checked = 1;
        if (s_env_active) {
            fprintf(stderr, "ds4: DS4_ICB_SOFTPLUS=1 — softplus_sqrt ICB engaged (opt-in; measurement pending)\n");
        }
    }
    if (!s_env_active) return 0;
    if (slot_idx >= DS4_SOFTPLUS_SQRT_ICB_SLOTS) return 0;
    if (!pipeline) return 0;

    if (!g_softplus_sqrt_icb) {
        MTLIndirectCommandBufferDescriptor *desc = [MTLIndirectCommandBufferDescriptor new];
        desc.commandTypes = MTLIndirectCommandTypeConcurrentDispatch;
        desc.inheritBuffers = NO;
        desc.inheritPipelineState = NO;
        desc.maxKernelBufferBindCount = 3;
        g_softplus_sqrt_icb =
            [g_device newIndirectCommandBufferWithDescriptor:desc
                                              maxCommandCount:(NSUInteger)DS4_SOFTPLUS_SQRT_ICB_SLOTS
                                                      options:MTLResourceStorageModeShared];
        if (!g_softplus_sqrt_icb) return 0;
    }
    if (!g_softplus_sqrt_icb_args_buffer) {
        ds4_gpu_unary_args args = ds4_gpu_make_unary_rows_args(256u, 1u, 1, 0.0f, 0.0f);
        args.min = 0.0f;
        args.max = 0.0f;
        g_softplus_sqrt_icb_args_buffer =
            [g_device newBufferWithBytes:&args length:sizeof(args)
                                 options:MTLResourceStorageModeShared];
        if (!g_softplus_sqrt_icb_args_buffer) return 0;
    }

    ds4_softplus_sqrt_icb_slot *slot = &g_softplus_sqrt_icb_slots[slot_idx];
    const int sig_match = slot->recorded &&
        slot->src_ptr == (__bridge void *)src && slot->src_off == (uint64_t)src_off &&
        slot->dst_ptr == (__bridge void *)dst && slot->dst_off == (uint64_t)dst_off;

    if (!sig_match) {
        /* width=256, c4=1 → ne00=64; nth=64 (≤ pipeline max); nk0=1; grid (1,1,1). */
        id<MTLIndirectComputeCommand> cmd =
            [g_softplus_sqrt_icb indirectComputeCommandAtIndex:slot_idx];
        [cmd setComputePipelineState:pipeline];
        [cmd setKernelBuffer:g_softplus_sqrt_icb_args_buffer offset:0 atIndex:0];
        [cmd setKernelBuffer:src offset:src_off atIndex:1];
        [cmd setKernelBuffer:dst offset:dst_off atIndex:2];
        [cmd concurrentDispatchThreadgroups:MTLSizeMake(1, 1, 1)
                      threadsPerThreadgroup:MTLSizeMake(64, 1, 1)];
        slot->src_ptr = (__bridge void *)src; slot->src_off = (uint64_t)src_off;
        slot->dst_ptr = (__bridge void *)dst; slot->dst_off = (uint64_t)dst_off;
        slot->recorded = 1;
    }

    id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
    [enc useResource:g_softplus_sqrt_icb_args_buffer usage:MTLResourceUsageRead];
    [enc useResource:src usage:MTLResourceUsageRead];
    [enc useResource:dst usage:MTLResourceUsageRead | MTLResourceUsageWrite];
    [enc executeCommandsInBuffer:g_softplus_sqrt_icb
                       withRange:NSMakeRange(slot_idx, 1)];
    ds4_gpu_end_compute_encoder(cb, enc);
    return 1;
}

static int ds4_gpu_encode_unary_f32_rows(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> pipeline,
 id<MTLBuffer> src,
 NSUInteger src_off,
 id<MTLBuffer> dst,
 NSUInteger dst_off,
 uint32_t width,
 uint32_t rows,
 int c4,
 float min,
 float max) {
 if (!cb || !pipeline || !src || !dst || width == 0 || rows == 0) return 0;
 if (c4 && (width & 3u) != 0) return 0;

 ds4_gpu_unary_args args = ds4_gpu_make_unary_rows_args(width, rows, c4, 0.0f, 0.0f);
 args.min = min;
 args.max = max;

 NSUInteger nth_max = pipeline.maxTotalThreadsPerThreadgroup;
 if (nth_max > 256u) nth_max = 256u;
 NSUInteger nth = (NSUInteger)args.ne00;
 if (nth > nth_max) nth = nth_max;
 if (nth == 0) nth = 1u;
 const NSUInteger nk0 = ((NSUInteger)args.ne00 + nth - 1u) / nth;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:src offset:src_off atIndex:1];
 [enc setBuffer:dst offset:dst_off atIndex:2];
 [enc dispatchThreadgroups:MTLSizeMake(nk0 * (NSUInteger)args.ne01,
 (NSUInteger)args.ne02,
 (NSUInteger)args.ne03)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_bin_f32_rows(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> pipeline,
 const ds4_gpu_bin_args *args,
 id<MTLBuffer> a,
 NSUInteger a_off,
 id<MTLBuffer> b,
 NSUInteger b_off,
 id<MTLBuffer> out,
 NSUInteger out_off) {
 if (!cb || !pipeline || !args || !a || !b || !out || args->ne0 <= 0 || args->ne1 <= 0) {
 return 0;
 }

 const NSUInteger nth = ds4_gpu_bin_threads((uint32_t)args->ne0, pipeline);
 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:pipeline];
 [enc setBytes:args length:sizeof(*args) atIndex:0];
 [enc setBuffer:a offset:a_off atIndex:1];
 [enc setBuffer:b offset:b_off atIndex:2];
 [enc setBuffer:out offset:out_off atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)args->ne1,
 (NSUInteger)args->ne2,
 (NSUInteger)args->ne3)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static ds4_gpu_bin_args ds4_gpu_make_bin_rowwise_scalar_args(uint32_t width, uint32_t rows) {
 const uint64_t lhs_row_bytes = (uint64_t)width * sizeof(float);
 const uint64_t rhs_row_bytes = sizeof(float);
 return (ds4_gpu_bin_args) {
 .ne00 = (int32_t)width,
 .ne01 = (int32_t)rows,
 .ne02 = 1,
 .ne03 = 1,
 .nb00 = sizeof(float),
 .nb01 = lhs_row_bytes,
 .nb02 = (uint64_t)rows * lhs_row_bytes,
 .nb03 = (uint64_t)rows * lhs_row_bytes,
 .ne10 = 1,
 .ne11 = (int32_t)rows,
 .ne12 = 1,
 .ne13 = 1,
 .nb10 = sizeof(float),
 .nb11 = rhs_row_bytes,
 .nb12 = (uint64_t)rows * rhs_row_bytes,
 .nb13 = (uint64_t)rows * rhs_row_bytes,
 .ne0 = (int32_t)width,
 .ne1 = (int32_t)rows,
 .ne2 = 1,
 .ne3 = 1,
 .nb0 = sizeof(float),
 .nb1 = lhs_row_bytes,
 .nb2 = (uint64_t)rows * lhs_row_bytes,
 .nb3 = (uint64_t)rows * lhs_row_bytes,
 .offs = 0,
 .o1 = { 0 },
 };
}

static ds4_gpu_mul_mv_id_args ds4_gpu_make_mul_mv_id_args(
 uint32_t src0_cols,
 uint32_t src0_rows,
 uint32_t src0_experts,
 uint64_t src0_row_bytes,
 uint64_t src0_expert_bytes,
 uint32_t src1_expert_rows,
 uint32_t selected_experts,
 uint32_t n_tokens,
 uint32_t nr0) {
 const uint64_t src1_row_bytes = (uint64_t)src0_cols * sizeof(float);
 const uint64_t src0_blocks = src0_cols / 256u;
 const uint64_t src0_block_bytes = src0_blocks ? src0_row_bytes / src0_blocks : 1u;
 return (ds4_gpu_mul_mv_id_args) {
 .nei0 = (int32_t)selected_experts,
 .nei1 = (int32_t)n_tokens,
 .nbi1 = (uint64_t)selected_experts * sizeof(int32_t),
 .ne00 = (int32_t)src0_cols,
 .ne01 = (int32_t)src0_rows,
 .ne02 = (int32_t)src0_experts,
 .nb00 = src0_block_bytes,
 .nb01 = src0_row_bytes,
 .nb02 = src0_expert_bytes,
 .ne10 = (int32_t)src0_cols,
 .ne11 = (int32_t)src1_expert_rows,
 .ne12 = (int32_t)n_tokens,
 .ne13 = 1,
 .nb10 = sizeof(float),
 .nb11 = src1_row_bytes,
 .nb12 = (uint64_t)src1_expert_rows * src1_row_bytes,
 .ne0 = (int32_t)src0_rows,
 .ne1 = (int32_t)selected_experts,
 .nb1 = (uint64_t)src0_rows * sizeof(float),
 .nr0 = (int32_t)nr0,
 };
}

