static ds4_gpu_mul_mm_id_args ds4_gpu_make_mul_mm_id_args_src1_size(
 uint32_t src0_cols,
 uint32_t src0_rows,
 uint32_t src0_experts,
 uint64_t src0_row_bytes,
 uint64_t src0_expert_bytes,
 uint32_t src1_expert_rows,
