 switch (type) {
 case DS4_METAL_TENSOR_IQ2_XXS: return "iq2_xxs";
 case DS4_METAL_TENSOR_Q2_K: return "q2_k";
 case DS4_METAL_TENSOR_Q4_K: return "q4_k";
