/* silv 2026-05-27 — simdgroup mat-mat encoder for FP16 routed-FFN.
 *
 * Dispatches kernel_mul_mm_id_fp16_pair_swiglu_f32 with grid
 * (n_ffn_tiles, n_token_tiles, pairs). Each threadgroup computes one
 * 8x8 output tile via simdgroup_multiply_accumulate.
 *
 * Buffer contract:
 *   - src0_hot: the hot-store FP16 heap (bound via newBufferWithBytesNoCopy)
 *   - gate_base_off / up_base_off: byte offset into hot-store where each
 *     expert's gate/up tile starts (for expert 0 of the active layer)
 *   - args.nb02: stride between consecutive experts within hot-store
 *     (= bytes_per_gate_tile + bytes_per_up_tile + bytes_per_down_tile,
 *     since pin function writes [g0,u0,d0,g1,u1,d1,...] consecutively)
 *   - args.ne00 = expert_in_dim (K dim, the embed_dim)
 *   - args.ne0  = expert_mid_dim (output FFN dim)
 *   - args.ne11 = n_tokens (batch size)
 *   - args.nei0 × args.nei1 = pairs (the same as the matvec encoder)
 *
 * Threadgroup memory: 3×64 halves (A + Bg + Bu tiles) + 2×64 floats
 * (Cg + Cu tiles staged for SwiGLU). Max = 512 bytes; use 1024 for
 * safety alignment.
 */
static int ds4_gpu_encode_mul_mm_id_fp16_pair_swiglu(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> pipeline,
 const ds4_gpu_mul_mv_id_args *args,
 const ds4_gpu_dsv4_moe_swiglu_weight_args *act,
 id<MTLBuffer> src0_hot,
 NSUInteger gate_base_off,
 NSUInteger up_base_off,
 id<MTLBuffer> src1,
 NSUInteger src1_off,
 id<MTLBuffer> dst_mid,
 NSUInteger dst_mid_off,
 id<MTLBuffer> ids,
 NSUInteger ids_off,
 id<MTLBuffer> weights,
 NSUInteger weights_off) {
 if (!cb || !pipeline || !args || !act ||
     !src0_hot || !src1 || !dst_mid || !ids || !weights ||
     args->ne00 <= 0 || args->ne0 <= 0 || args->ne11 <= 0 ||
     args->nei0 <= 0 || args->nei1 <= 0) {
  return 0;
 }

 const NSUInteger n_ffn_tiles = ((NSUInteger)args->ne0 + 7u) / 8u;
 const NSUInteger n_token_tiles = ((NSUInteger)args->ne11 + 7u) / 8u;
 const NSUInteger pairs = (NSUInteger)args->nei0 * (NSUInteger)args->nei1;
 const NSUInteger tg_bytes = 1024;  /* threadgroup mem: 3×64 halves + 2×64 floats + slack */

 /* silv 2026-05-27 — ICB Phase 7 attempt. Opt-in via DS4_MOE_ICB=1.
  * Records the dispatch once into a classic-MTL ICB; per-call replay
  * skips encoder rebuild (~45µs/call). Per-token at 6 experts × 43
  * layers = 258 calls, target ~12ms/token savings. Falls through to
  * direct encoding when env not set or signature changes. */
 {
  static id<MTLBuffer> s_icb_args_buf = nil;
  static id<MTLBuffer> s_icb_act_buf = nil;
  static int s_icb_env_checked = 0;
  static int s_icb_env_active = 0;
  if (!s_icb_env_checked) {
   s_icb_env_active = getenv("DS4_MOE_ICB") != NULL ? 1 : 0;
   s_icb_env_checked = 1;
  }
  if (s_icb_env_active) {
   if (!s_icb_args_buf) {
    s_icb_args_buf = [g_device newBufferWithLength:sizeof(*args)
                                           options:MTLResourceStorageModeShared];
    s_icb_act_buf = [g_device newBufferWithLength:sizeof(*act)
                                          options:MTLResourceStorageModeShared];
   }
   if (s_icb_args_buf && s_icb_act_buf) {
    memcpy([s_icb_args_buf contents], args, sizeof(*args));
    memcpy([s_icb_act_buf contents], act, sizeof(*act));
    if (ds4_gpu_moe_matmul_icb_dispatch(cb, pipeline,
                                         s_icb_args_buf, 0,
                                         s_icb_act_buf, 0,
                                         src0_hot, gate_base_off,
                                         src0_hot, up_base_off,
                                         src1, src1_off,
                                         dst_mid, dst_mid_off,
                                         ids, ids_off,
                                         weights, weights_off,
                                         n_ffn_tiles, n_token_tiles, pairs)) {
     return 1;
    }
   }
  }
 }

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:pipeline];
 [enc setBytes:args length:sizeof(*args) atIndex:0];
 [enc setBytes:act length:sizeof(*act) atIndex:1];
 /* Both gate and up read from the same hot-store buffer; different base offsets. */
 [enc setBuffer:src0_hot offset:gate_base_off atIndex:2];
 [enc setBuffer:src0_hot offset:up_base_off   atIndex:3];
 [enc setBuffer:src1     offset:src1_off      atIndex:4];
 [enc setBuffer:dst_mid  offset:dst_mid_off   atIndex:5];
 [enc setBuffer:ids      offset:ids_off       atIndex:6];
 [enc setBuffer:weights  offset:weights_off   atIndex:7];
 [enc setThreadgroupMemoryLength:tg_bytes atIndex:0];

 [enc dispatchThreadgroups:MTLSizeMake(n_ffn_tiles, n_token_tiles, pairs)
       threadsPerThreadgroup:MTLSizeMake(64, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

/* silv 2026-05-27 — high-level dispatch wire for FP16 simdgroup mat-mat path.
 *
 * Conditions checked (returns 0 = "didn't dispatch, fall back to IQ2 path"):
 *   (a) DS4_HOT_FP16_KERNEL env set (caller already filtered, but rechecked)
 *   (b) g_moe_mul_mm_id_fp16_pair_swiglu_pipeline registered
 *   (c) hot-store active AND `layer` fully pinned (all 256 experts gate+up+down)
 *   (d) hot-store MTLBuffer wrapped (ds4_metal_vqb2_fp16_get_hot_buffer != NULL)
 *   (e) n_tokens >= 8 (mat-mat tile width)
 *
 * Replaces gate+up+SwiGLU+weight in one fused encoder dispatch. The kernel
 * writes directly to `dst_mid` with token-major pair-row layout that matches
 * what the down-projection mm_id reads. Returns 1 on successful dispatch. */
static int ds4_gpu_dispatch_fp16_simdgroup_pair_swiglu(
 id<MTLCommandBuffer> cb,
 uint32_t layer_index,
 uint32_t expert_in_dim,
 uint32_t expert_mid_dim,
 uint32_t n_tokens,
 uint32_t n_expert,
 float clamp_value,
 id<MTLBuffer> xbuf, NSUInteger x_off,
 id<MTLBuffer> midbuf, NSUInteger mid_off,
 id<MTLBuffer> selectedbuf, NSUInteger sel_off,
 id<MTLBuffer> weightsbuf, NSUInteger weights_off) {
 if (!cb || !xbuf || !midbuf || !selectedbuf || !weightsbuf) return 0;
 if (n_tokens < 8u) return 0;
 extern id<MTLComputePipelineState> g_moe_mul_mm_id_fp16_pair_swiglu_pipeline;
 if (!g_moe_mul_mm_id_fp16_pair_swiglu_pipeline) return 0;
 if (getenv("DS4_HOT_FP16_KERNEL") == NULL) return 0;

 ds4_hot_expert_store *hot = ds4_hot_store_get_active();
 if (!hot) return 0;
 if (!ds4_hot_layer_fully_pinned(hot, layer_index)) return 0;

 extern void *ds4_metal_vqb2_fp16_get_hot_buffer(void);
 void *hot_buf_void = ds4_metal_vqb2_fp16_get_hot_buffer();
 if (!hot_buf_void) return 0;
 id<MTLBuffer> hot_buf = (__bridge id<MTLBuffer>)hot_buf_void;

 /* Per-expert byte stride within the hot-store heap. The pin function lays
  * out experts as [g0,u0,d0, g1,u1,d1, ...] consecutively per layer, so the
  * stride is gate_offset[layer*N+1] - gate_offset[layer*N+0]. */
 const uint64_t base0 = (uint64_t)layer_index * DS4_N_EXPERT;
 const int64_t  gate_off_e0 = hot->gate_offset[base0];
 const int64_t  up_off_e0   = hot->up_offset  [base0];
 if (gate_off_e0 < 0 || up_off_e0 < 0) return 0;
 int64_t per_expert_stride = -1;
 if (n_expert > 1) {
  const int64_t gate_off_e1 = hot->gate_offset[base0 + 1];
  if (gate_off_e1 < 0) return 0;
  per_expert_stride = gate_off_e1 - gate_off_e0;
  if (per_expert_stride <= 0) return 0;
 } else {
  /* Single expert per token isn't the DS4 case (n_expert == 6 typically),
   * but guard the math: stride is the per-expert gate+up+down bundle size,
   * which equals the FP16 byte count for one expert's three tiles. We
   * cannot infer that without the next expert; reject. */
  return 0;
 }

 /* Build the mat-mat args. nei0 = experts-per-token (here `n_expert`),
  * nei1 = n_tokens (the kernel uses pairs = nei0*nei1 dispatch). */
 ds4_gpu_mul_mv_id_args args = ds4_gpu_make_mul_mv_id_args(
  (int)expert_in_dim, (int)expert_mid_dim, 256,
  /* row_bytes (placeholder, unused by mat-mat kernel) */
  (int64_t)expert_in_dim * sizeof(uint16_t),
  /* per-expert bytes — used by kernel as nb02 to stride across experts */
  per_expert_stride,
  1, (int)n_expert, (int)n_tokens, 1);

 /* The activation rows + mid rows layout: the kernel reads src1 as
  * `tok * n_in` floats (contiguous token-major activation) and writes mid
  * at `pair_row * mid_row_stride`. */
 ds4_gpu_dsv4_moe_swiglu_weight_args act_args = {
  .width = expert_mid_dim,
  .rows = (uint32_t)(n_tokens * n_expert),
  .gate_row_stride = (uint64_t)expert_mid_dim * sizeof(float),
  .up_row_stride   = (uint64_t)expert_mid_dim * sizeof(float),
  .mid_row_stride  = (uint64_t)expert_mid_dim * sizeof(float),
  .weight_stride   = sizeof(float),
  .write_clamped   = 0,
  .clamp_value     = clamp_value,
 };

 const int rc = ds4_gpu_encode_mul_mm_id_fp16_pair_swiglu(
  cb,
  g_moe_mul_mm_id_fp16_pair_swiglu_pipeline,
  &args, &act_args,
  hot_buf,
  (NSUInteger)gate_off_e0,
  (NSUInteger)up_off_e0,
  xbuf, x_off,
  midbuf, mid_off,
  selectedbuf, sel_off,
  weightsbuf, weights_off);

 static int dispatched_once_logged = 0;
 if (rc && !dispatched_once_logged) {
  fprintf(stderr,
          "ds4: FP16 simdgroup mat-mat DISPATCHED at layer=%u "
          "n_tokens=%u n_expert=%u per_expert_stride=%lld bytes (first call)\n",
          layer_index, n_tokens, n_expert, (long long)per_expert_stride);
  dispatched_once_logged = 1;
 }
 return rc;
}

/* silv 2026-05-27 task #643 — Hadamard-16 batched FP16 encoder.
 *
 * Dispatches kernel_hadamard16_fp16_batched on a buffer of FP16 activations.
 * Each threadgroup applies a 16-point Walsh-Hadamard (orthogonal-normalized)
 * to one 16-element block in threadgroup memory. Grid = (n_rows,
 * blocks_per_row, 1). Threadgroup = (16, 1, 1). Threadgroup memory = 32 B
 * (16 halves of scratch).
 *
 * Caller is responsible for n_rows × blocks_per_row × 16 halves of
 * device-accessible FP16 storage starting at (buf + buf_off) with stride
 * row_stride_bytes between consecutive rows. */
static int ds4_gpu_encode_hadamard16_fp16_batched(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> buf,
 NSUInteger buf_off,
 const ds4_gpu_hadamard16_batched_args *args) {
 if (!cb || !buf || !args) return 0;
 if (args->n_rows == 0u || args->blocks_per_row == 0u) return 0;
 if (!g_hadamard16_fp16_batched_pipeline) return 0;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_hadamard16_fp16_batched_pipeline];
 [enc setBytes:args length:sizeof(*args) atIndex:0];
 [enc setBuffer:buf offset:buf_off atIndex:1];
 /* 16 halves of scratch per threadgroup. */
 [enc setThreadgroupMemoryLength:(NSUInteger)(16 * sizeof(uint16_t)) atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake(args->n_rows, args->blocks_per_row, 1)
       threadsPerThreadgroup:MTLSizeMake(16, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

/* silv 2026-05-27 task #643 — public API for Hadamard-16 transform.
 *
 * Single-dispatch convenience wrapper. Opens a command buffer if no batch
 * is active; otherwise hooks into the active batch. Returns 1 on success,
 * 0 if pipeline absent or args invalid. */
int ds4_gpu_hadamard16_fp16_batched_tensor(ds4_gpu_tensor *tensor,
                                            uint32_t n_rows,
                                            uint32_t blocks_per_row,
                                            uint64_t row_stride_bytes) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!tensor || n_rows == 0u || blocks_per_row == 0u) return 0;
 if (!g_hadamard16_fp16_batched_pipeline) return 0;

 const uint64_t need_bytes =
  (uint64_t)(n_rows - 1u) * row_stride_bytes +
  (uint64_t)blocks_per_row * 16u * sizeof(uint16_t);
 if (ds4_gpu_tensor_bytes(tensor) < need_bytes) {
  fprintf(stderr,
          "ds4: hadamard16 batched: tensor too small (have=%llu, need=%llu)\n",
          (unsigned long long)ds4_gpu_tensor_bytes(tensor),
          (unsigned long long)need_bytes);
  return 0;
 }

 @autoreleasepool {
  id<MTLBuffer> buf = ds4_gpu_tensor_buffer(tensor);
  if (!buf) return 0;

  const bool had_batch = g_batch_cb != nil;
  if (!had_batch && ds4_gpu_begin_commands() == 0) return 0;
  int owned = 0;
  id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
  if (!cb) {
   if (!had_batch) ds4_gpu_end_commands();
   return 0;
  }

  const ds4_gpu_hadamard16_batched_args args = {
   .n_rows = n_rows,
   .blocks_per_row = blocks_per_row,
   .row_stride_bytes = row_stride_bytes,
  };
  const int rc = ds4_gpu_encode_hadamard16_fp16_batched(
   cb, buf, ds4_gpu_tensor_offset(tensor), &args);
  if (!rc) {
   if (!had_batch) ds4_gpu_end_commands();
   return 0;
  }
  if (!ds4_gpu_finish_command_buffer(cb, owned, "hadamard16 batched")) {
   if (!had_batch) ds4_gpu_end_commands();
   return 0;
  }
  if (!had_batch && ds4_gpu_end_commands() == 0) return 0;
 }
 return 1;
}

static int ds4_gpu_encode_mul_mv_id_sum6(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> pipeline,
 const ds4_gpu_mul_mv_id_args *args,
 id<MTLBuffer> src0,
 NSUInteger src0_off,
 id<MTLBuffer> src1,
 NSUInteger src1_off,
 id<MTLBuffer> dst,
 NSUInteger dst_off,
 id<MTLBuffer> ids,
 NSUInteger ids_off,
 NSUInteger threadgroup_bytes,
 NSUInteger nsg) {
 if (!cb || !pipeline || !args || !src0 || !src1 || !dst || !ids ||
 args->ne00 <= 0 || args->ne01 <= 0 || args->nei0 != 6 || args->nei1 <= 0) {
 return 0;
 }

 const NSUInteger rows_per_group = (NSUInteger)args->nr0 * nsg;
 const NSUInteger row_groups = ((NSUInteger)args->ne01 + rows_per_group - 1u) / rows_per_group;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:pipeline];
 [enc setBytes:args length:sizeof(*args) atIndex:0];
 [enc setBuffer:src0 offset:src0_off atIndex:1];
 [enc setBuffer:src1 offset:src1_off atIndex:2];
 [enc setBuffer:dst offset:dst_off atIndex:3];
 [enc setBuffer:ids offset:ids_off atIndex:4];
 if (threadgroup_bytes != 0) {
 [enc setThreadgroupMemoryLength:threadgroup_bytes atIndex:0];
 }
 [enc dispatchThreadgroups:MTLSizeMake(row_groups, (NSUInteger)args->nei1, 1)
 threadsPerThreadgroup:MTLSizeMake(32, nsg, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_mul_mm_id(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> map_pipeline,
 id<MTLComputePipelineState> mm_pipeline,
 const ds4_gpu_mul_mm_id_map_args *map_args,
 const ds4_gpu_mul_mm_id_args *mm_args,
 id<MTLBuffer> src0,
 NSUInteger src0_off,
 id<MTLBuffer> src1,
 NSUInteger src1_off,
 id<MTLBuffer> dst,
 NSUInteger dst_off,
 id<MTLBuffer> ids,
 NSUInteger ids_off) {
 if (!cb || !map_pipeline || !mm_pipeline || !map_args || !mm_args ||
 !src0 || !src1 || !dst || !ids ||
 mm_args->ne00 <= 0 || mm_args->ne0 <= 0 ||
 mm_args->ne20 <= 0 || mm_args->ne21 <= 0 || mm_args->ne02 <= 0) {
 return 0;
 }

 return ds4_gpu_encode_mul_mm_id_map(cb,
 map_pipeline,
 map_args,
 mm_args,
 ids,
 ids_off) &&
 ds4_gpu_encode_mul_mm_id_mapped(cb,
 mm_pipeline,
 mm_args,
 src0,
 src0_off,
 src1,
 src1_off,
 dst,
 dst_off);
}

static int ds4_gpu_encode_mul_mm_id_map(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> map_pipeline,
 const ds4_gpu_mul_mm_id_map_args *map_args,
 const ds4_gpu_mul_mm_id_args *mm_args,
 id<MTLBuffer> ids,
 NSUInteger ids_off) {
 if (!cb || !map_pipeline || !map_args || !mm_args || !ids ||
 mm_args->ne20 <= 0 || mm_args->ne21 <= 0 || mm_args->ne02 <= 0) {
 return 0;
 }

 const NSUInteger tpe_bytes = (NSUInteger)mm_args->ne02 * sizeof(int32_t);
 const NSUInteger hids_bytes = (NSUInteger)mm_args->ne02 * (NSUInteger)mm_args->ne21 * sizeof(int32_t);
 if (tpe_bytes > NSUIntegerMax - hids_bytes) return 0;
 if (!ds4_gpu_ensure_scratch_buffer(&g_moe_id_map_buffer,
 &g_moe_id_map_bytes,
 tpe_bytes + hids_bytes,
 "ds4_moe_id_map")) {
 return 0;
 }

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:map_pipeline];
 [enc setBytes:map_args length:sizeof(*map_args) atIndex:0];
 [enc setBuffer:ids offset:ids_off atIndex:1];
 [enc setBuffer:g_moe_id_map_buffer offset:0 atIndex:2];
 [enc setBuffer:g_moe_id_map_buffer offset:tpe_bytes atIndex:3];
 [enc setThreadgroupMemoryLength:(NSUInteger)mm_args->ne02 * (NSUInteger)mm_args->ne20 * sizeof(uint16_t) atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
 threadsPerThreadgroup:MTLSizeMake((NSUInteger)mm_args->ne02, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_mul_mm_id_mapped_tile(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> mm_pipeline,
 const ds4_gpu_mul_mm_id_args *mm_args,
 id<MTLBuffer> src0,
 NSUInteger src0_off,
 id<MTLBuffer> src1,
 NSUInteger src1_off,
 id<MTLBuffer> dst,
 NSUInteger dst_off) {
 if (!cb || !mm_pipeline || !mm_args || !src0 || !src1 || !dst ||
 !g_moe_id_map_buffer ||
 mm_args->ne00 <= 0 || mm_args->ne0 <= 0 ||
 mm_args->ne20 <= 0 || mm_args->ne21 <= 0 || mm_args->ne02 <= 0) {
 return 0;
 }
 /*
 * The routed MoE grouped matmul uses the legacy 32-token expert-major tile.
 * The removed TensorOps variant was not semantically stable on evals, so keep
 * this encoder tied to the tested simdgroup kernel shape.
 */
 const NSUInteger tile_n = 32u;

 const NSUInteger tpe_bytes = (NSUInteger)mm_args->ne02 * sizeof(int32_t);
 const NSUInteger hids_bytes = (NSUInteger)mm_args->ne02 * (NSUInteger)mm_args->ne21 * sizeof(int32_t);
 if (tpe_bytes > NSUIntegerMax - hids_bytes ||
 g_moe_id_map_bytes < tpe_bytes + hids_bytes) {
 return 0;
 }

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:mm_pipeline];
 [enc setBytes:mm_args length:sizeof(*mm_args) atIndex:0];
 [enc setBuffer:src0 offset:src0_off atIndex:1];
 [enc setBuffer:src1 offset:src1_off atIndex:2];
 [enc setBuffer:g_moe_id_map_buffer offset:0 atIndex:3];
 [enc setBuffer:g_moe_id_map_buffer offset:tpe_bytes atIndex:4];
 [enc setBuffer:dst offset:dst_off atIndex:5];
 [enc setThreadgroupMemoryLength:8192u atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake(((NSUInteger)mm_args->ne21 + tile_n - 1u) / tile_n,
 ((NSUInteger)mm_args->ne0 + 63u) / 64u,
 (NSUInteger)mm_args->ne02)
 threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_mul_mm_id_mapped(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> mm_pipeline,
 const ds4_gpu_mul_mm_id_args *mm_args,
 id<MTLBuffer> src0,
 NSUInteger src0_off,
 id<MTLBuffer> src1,
 NSUInteger src1_off,
 id<MTLBuffer> dst,
 NSUInteger dst_off) {
 return ds4_gpu_encode_mul_mm_id_mapped_tile(cb,
 mm_pipeline,
 mm_args,
 src0,
 src0_off,
 src1,
 src1_off,
 dst,
 dst_off);
}

static int ds4_gpu_encode_attn_out_low_q8_mpp(
 id<MTLCommandBuffer> cb,
 id<MTLComputePipelineState> pipeline,
 const ds4_gpu_mul_mm_id_args *mm_args,
 id<MTLBuffer> src0,
 NSUInteger src0_off,
 id<MTLBuffer> src1,
 NSUInteger src1_off,
 id<MTLBuffer> dst,
 NSUInteger dst_off) {
 if (!cb || !pipeline || !mm_args || !src0 || !src1 || !dst ||
 mm_args->ne00 <= 0 || mm_args->ne0 <= 0 ||
 mm_args->ne02 <= 0 || mm_args->ne1 <= 0 || mm_args->ne21 <= 0) {
 return 0;
 }

 const uint32_t tile_n = DS4_METAL_ATTN_OUT_MPP_TILE_N;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:pipeline];
 [enc setBytes:mm_args length:sizeof(*mm_args) atIndex:0];
 [enc setBuffer:src0 offset:src0_off atIndex:1];
 [enc setBuffer:src1 offset:src1_off atIndex:2];
 [enc setBuffer:dst offset:dst_off atIndex:3];
 [enc setThreadgroupMemoryLength:4096u atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake(((NSUInteger)mm_args->ne21 + (NSUInteger)tile_n - 1u) / (NSUInteger)tile_n,
 ((NSUInteger)mm_args->ne0 + 63u) / 64u,
 (NSUInteger)mm_args->ne02)
 threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_swiglu_flat(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> gate,
 NSUInteger gate_off,
 id<MTLBuffer> up,
 NSUInteger up_off,
 id<MTLBuffer> out,
 NSUInteger out_off,
 uint32_t n) {
 if (!cb || !gate || !up || !out || n == 0) return 0;

 ds4_gpu_glu_args args = {
 .ne00 = (int32_t)n,
 .nb01 = (uint64_t)n * sizeof(float),
 .ne10 = (int32_t)n,
 .nb11 = (uint64_t)n * sizeof(float),
 .ne0 = (int32_t)n,
 .nb1 = (uint64_t)n * sizeof(float),
 .i00 = 0,
 .i10 = 0,
 .alpha = 1.0f,
 .limit = 0.0f,
 };
 NSUInteger nth = g_swiglu_pipeline.maxTotalThreadsPerThreadgroup;
 const NSUInteger ds4_nth = n > 1 ? (NSUInteger)n / 2u : 1u;
 if (nth > ds4_nth) nth = ds4_nth;
 if (nth == 0) nth = 1u;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_swiglu_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:gate offset:gate_off atIndex:1];
 [enc setBuffer:up offset:up_off atIndex:2];
 [enc setBuffer:out offset:out_off atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_moe_swiglu_weight(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> gate,
 NSUInteger gate_off,
 id<MTLBuffer> up,
 NSUInteger up_off,
 id<MTLBuffer> mid,
 NSUInteger mid_off,
 id<MTLBuffer> weights,
 NSUInteger weights_off,
 uint32_t width,
 uint32_t rows,
 float clamp_value,
 bool mid_f16) {
 if (!cb || !gate || !up || !mid || !weights || width == 0 || rows == 0) return 0;

 id<MTLComputePipelineState> pipeline =
 ds4_gpu_get_pipeline(mid_f16 ? "kernel_dsv4_moe_swiglu_weight_f16" :
 "kernel_dsv4_moe_swiglu_weight");
 if (!pipeline) return 0;

 ds4_gpu_dsv4_moe_swiglu_weight_args args = {
 .width = width,
 .rows = rows,
 .gate_row_stride = (uint64_t)width * sizeof(float),
 .up_row_stride = (uint64_t)width * sizeof(float),
 .mid_row_stride = (uint64_t)width * (mid_f16 ? sizeof(uint16_t) : sizeof(float)),
 .weight_stride = sizeof(float),
 .write_clamped = getenv("DS4_METAL_MOE_WRITE_CLAMPED_ACT") != NULL ? 1u : 0u,
 .clamp_value = clamp_value,
 };

 NSUInteger nth = pipeline.maxTotalThreadsPerThreadgroup;
 if (nth > 256u) nth = 256u;
 if (nth > width) nth = width;
 if (nth == 0) nth = 1u;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:gate offset:gate_off atIndex:1];
 [enc setBuffer:up offset:up_off atIndex:2];
 [enc setBuffer:mid offset:mid_off atIndex:3];
 [enc setBuffer:weights offset:weights_off atIndex:4];
 [enc dispatchThreadgroups:MTLSizeMake(rows, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_moe_sum6(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> experts,
 NSUInteger experts_off,
 id<MTLBuffer> out,
 NSUInteger out_off,
 uint32_t out_dim,
 uint32_t n_tokens) {
 if (!cb || !experts || !out || out_dim == 0 || n_tokens == 0) return 0;

 if (!g_moe_sum6_pipeline) return 0;

 const uint64_t out_row_bytes = (uint64_t)out_dim * sizeof(float);
 ds4_gpu_dsv4_moe_sum6_args args = {
 .width = out_dim,
 .tokens = n_tokens,
 .src_token_stride = 6u * out_row_bytes,
 .dst_token_stride = out_row_bytes,
 };

 NSUInteger nth = g_moe_sum6_pipeline.maxTotalThreadsPerThreadgroup;
 if (nth > 256u) nth = 256u;
 if (nth > out_dim) nth = out_dim;
 if (nth == 0) nth = 1u;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_moe_sum6_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:experts offset:experts_off atIndex:1];
 [enc setBuffer:out offset:out_off atIndex:2];
 [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_tokens, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static ds4_gpu_bin_args ds4_gpu_make_moe_add_args(
 uint32_t out_dim,
 uint32_t n_tokens,
 uint64_t src0_token_stride,
 uint64_t src1_token_stride,
 uint64_t dst_token_stride) {
 return (ds4_gpu_bin_args) {
 .ne00 = (int32_t)out_dim,
 .ne01 = (int32_t)n_tokens,
 .ne02 = 1,
 .ne03 = 1,
 .nb00 = sizeof(float),
 .nb01 = src0_token_stride,
 .nb02 = (uint64_t)n_tokens * src0_token_stride,
 .nb03 = (uint64_t)n_tokens * src0_token_stride,
 .ne10 = (int32_t)out_dim,
 .ne11 = (int32_t)n_tokens,
 .ne12 = 1,
 .ne13 = 1,
 .nb10 = sizeof(float),
 .nb11 = src1_token_stride,
 .nb12 = (uint64_t)n_tokens * src1_token_stride,
 .nb13 = (uint64_t)n_tokens * src1_token_stride,
 .ne0 = (int32_t)out_dim,
 .ne1 = (int32_t)n_tokens,
 .ne2 = 1,
 .ne3 = 1,
 .nb0 = sizeof(float),
 .nb1 = dst_token_stride,
 .nb2 = (uint64_t)n_tokens * dst_token_stride,
 .nb3 = (uint64_t)n_tokens * dst_token_stride,
 .offs = 0,
 .o1 = { 0 },
 };
}

static int ds4_gpu_encode_moe_sum_experts(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> experts,
 NSUInteger experts_off,
 id<MTLBuffer> out,
 NSUInteger out_off,
 uint32_t out_dim,
 uint32_t n_expert,
 uint32_t n_tokens) {
 if (!cb || !experts || !out || out_dim == 0 || n_expert < 2 || n_tokens == 0) return 0;

 const uint64_t out_row_bytes = (uint64_t)out_dim * sizeof(float);
 const uint64_t expert_token_stride = (uint64_t)n_expert * out_row_bytes;

 if (n_expert == 6 &&
 ds4_gpu_encode_moe_sum6(cb,
 experts,
 experts_off,
 out,
 out_off,
 out_dim,
 n_tokens)) {
 return 1;
 }

 ds4_gpu_bin_args first =
 ds4_gpu_make_moe_add_args(out_dim, n_tokens, expert_token_stride, expert_token_stride, out_row_bytes);
 if (!ds4_gpu_encode_bin_f32_rows(cb,
 g_add_pipeline,
 &first,
 experts,
 experts_off,
 experts,
 experts_off + (NSUInteger)out_row_bytes,
 out,
 out_off)) {
 return 0;
 }

 ds4_gpu_bin_args accum =
 ds4_gpu_make_moe_add_args(out_dim, n_tokens, out_row_bytes, expert_token_stride, out_row_bytes);
 for (uint32_t slot = 2; slot < n_expert; slot++) {
 if (!ds4_gpu_encode_bin_f32_rows(cb,
 g_add_pipeline,
 &accum,
 out,
 out_off,
 experts,
 experts_off + (NSUInteger)((uint64_t)slot * out_row_bytes),
 out,
 out_off)) {
 return 0;
 }
 }
 return 1;
}

static int ds4_gpu_encode_get_rows_i32_token_rows(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> table,
 NSUInteger table_off,
 id<MTLBuffer> tokens,
 NSUInteger tokens_off,
 const int32_t *token_inline,
 id<MTLBuffer> selected,
 NSUInteger selected_off,
 uint32_t hash_rows,
 uint32_t n_tokens) {
 if (!cb || !table || !selected || hash_rows == 0 || n_tokens == 0) return 0;
 if (!tokens && !token_inline) return 0;

 const uint64_t table_row_bytes = 6u * sizeof(int32_t);
 const uint64_t token_bytes = (uint64_t)n_tokens * sizeof(int32_t);
 ds4_gpu_get_rows_args args = {
 .ne00t = 6,
 .ne00 = 6,
 .nb01 = table_row_bytes,
 .nb02 = (uint64_t)hash_rows * table_row_bytes,
 .nb03 = (uint64_t)hash_rows * table_row_bytes,
 .ne10 = (int32_t)n_tokens,
 .nb10 = sizeof(int32_t),
 .nb11 = token_bytes,
 .nb12 = token_bytes,
 .nb1 = table_row_bytes,
 .nb2 = (uint64_t)n_tokens * table_row_bytes,
 .nb3 = (uint64_t)n_tokens * table_row_bytes,
 };

 NSUInteger nth = 6u;
 const NSUInteger max_threads = g_get_rows_i32_pipeline.maxTotalThreadsPerThreadgroup;
 if (nth > max_threads) nth = max_threads;
 if (nth == 0) nth = 1u;
 const NSUInteger nw0 = (6u + nth - 1u) / nth;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_get_rows_i32_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:table offset:table_off atIndex:1];
 if (tokens) {
 [enc setBuffer:tokens offset:tokens_off atIndex:2];
 } else {
 [enc setBytes:token_inline length:sizeof(*token_inline) atIndex:2];
 }
 [enc setBuffer:selected offset:selected_off atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake(nw0 * n_tokens, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_get_rows_f32_router_weights(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> probs,
 NSUInteger probs_off,
 id<MTLBuffer> selected,
 NSUInteger selected_off,
 id<MTLBuffer> weights,
 NSUInteger weights_off,
 uint32_t n_tokens) {
 if (!cb || !probs || !selected || !weights || n_tokens == 0) return 0;

 const uint64_t probs_token_bytes = 256u * sizeof(float);
 const uint64_t selected_row_bytes = 6u * sizeof(int32_t);
 const uint64_t weights_row_bytes = 6u * sizeof(float);
 ds4_gpu_get_rows_args args = {
 .ne00t = 1,
 .ne00 = 1,
 .nb01 = sizeof(float),
 .nb02 = probs_token_bytes,
 .nb03 = (uint64_t)n_tokens * probs_token_bytes,
 .ne10 = 6,
 .nb10 = sizeof(int32_t),
 .nb11 = selected_row_bytes,
 .nb12 = (uint64_t)n_tokens * selected_row_bytes,
 .nb1 = sizeof(float),
 .nb2 = weights_row_bytes,
 .nb3 = (uint64_t)n_tokens * weights_row_bytes,
 };

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_get_rows_f32_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:probs offset:probs_off atIndex:1];
 [enc setBuffer:selected offset:selected_off atIndex:2];
 [enc setBuffer:weights offset:weights_off atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake(6u, n_tokens, 1)
 threadsPerThreadgroup:MTLSizeMake(1, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_sum_rows_f32(
 id<MTLCommandBuffer> cb,
 id<MTLBuffer> src,
 NSUInteger src_off,
 id<MTLBuffer> dst,
 NSUInteger dst_off,
 uint32_t width,
 uint32_t rows) {
 if (!cb || !src || !dst || width == 0 || rows == 0) return 0;

 const uint64_t src_row_bytes = (uint64_t)width * sizeof(float);
 ds4_gpu_kargs_sum_rows args = {
 .ne00 = (int64_t)width,
 .ne01 = (int64_t)rows,
 .ne02 = 1,
 .ne03 = 1,
 .nb00 = sizeof(float),
 .nb01 = src_row_bytes,
 .nb02 = (uint64_t)rows * src_row_bytes,
 .nb03 = (uint64_t)rows * src_row_bytes,
 .ne0 = 1,
 .ne1 = (int64_t)rows,
 .ne2 = 1,
 .ne3 = 1,
 .nb0 = sizeof(float),
 .nb1 = sizeof(float),
 .nb2 = (uint64_t)rows * sizeof(float),
 .nb3 = (uint64_t)rows * sizeof(float),
 };

 NSUInteger nth = 32u;
 const NSUInteger max_threads = g_sum_rows_f32_f32_pipeline.maxTotalThreadsPerThreadgroup;
 while (nth < (NSUInteger)args.ne00 && nth < max_threads) nth *= 2u;
 if (nth > max_threads) nth = max_threads;
 if (nth > (NSUInteger)args.ne00) nth = (NSUInteger)args.ne00;
 if (nth == 0) nth = 1u;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_sum_rows_f32_f32_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:src offset:src_off atIndex:1];
 [enc setBuffer:dst offset:dst_off atIndex:2];
 [enc setThreadgroupMemoryLength:32u * sizeof(float) atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake(rows, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 return 1;
}

static int ds4_gpu_encode_router_select(
 id<MTLCommandBuffer> cb,
 ds4_gpu_tensor *selected,
 ds4_gpu_tensor *weights,
 ds4_gpu_tensor *probs,
 id<MTLBuffer> logitsbuf,
 NSUInteger logits_off,
 id<MTLBuffer> biasbuf,
 NSUInteger bias_off,
 id<MTLBuffer> hashbuf,
 NSUInteger hash_off,
 id<MTLBuffer> tokensbuf,
 NSUInteger tokens_off,
 const int32_t *single_token,
 uint32_t hash_rows,
 uint32_t n_tokens,
 bool has_bias,
 bool hash_mode) {
 id<MTLBuffer> selectedbuf = ds4_gpu_tensor_buffer(selected);
 id<MTLBuffer> weightsbuf = ds4_gpu_tensor_buffer(weights);
 id<MTLBuffer> probsbuf = ds4_gpu_tensor_buffer(probs);
 const NSUInteger selected_off = ds4_gpu_tensor_offset(selected);
 const NSUInteger weights_off = ds4_gpu_tensor_offset(weights);
 const NSUInteger probs_off = ds4_gpu_tensor_offset(probs);

 if (!cb || !selectedbuf || !weightsbuf || !probsbuf || !logitsbuf || n_tokens == 0) return 0;

 const NSUInteger probs_bytes = (NSUInteger)n_tokens * 256u * sizeof(float);

 int ok = 0;
 if (!g_quality_mode && n_tokens == 1 &&
 getenv("DS4_METAL_DISABLE_ROUTER_SELECT_FUSION") == NULL) {
 id<MTLComputePipelineState> softplus_sqrt_pipeline =
 ds4_gpu_hot_pipeline(g_dsv4_softplus_sqrt_pipeline,
 "kernel_dsv4_softplus_sqrt_f32_4");
 id<MTLComputePipelineState> router_finalize_pipeline =
 ds4_gpu_hot_pipeline(g_dsv4_router_finalize_one_pipeline,
 "kernel_dsv4_router_finalize_one");
 id<MTLComputePipelineState> router_weights_pipeline =
 ds4_gpu_hot_pipeline(g_dsv4_router_weights_one_pipeline,
 "kernel_dsv4_router_weights_one");
 if (!softplus_sqrt_pipeline || !router_finalize_pipeline || !router_weights_pipeline) return 0;

 /* #558 ICB Phase 4 attempt; slot 0 = this site (~13767). Falls through on opt-out. */
 if (!ds4_softplus_sqrt_dispatch_icb(cb, 0, softplus_sqrt_pipeline,
                                     logitsbuf, logits_off, probsbuf, probs_off)) {
 ok = ds4_gpu_encode_unary_f32_rows(cb,
 softplus_sqrt_pipeline,
 logitsbuf,
 logits_off,
 probsbuf,
 probs_off,
 256,
 1,
 1,
 0.0f,
 0.0f);
 if (!ok) return 0;
 }

 const bool use_token_buffer = single_token == NULL;
 ds4_gpu_dsv4_router_select_one_args args = {
 .has_bias = has_bias ? 1u : 0u,
 .hash_mode = hash_mode ? 1u : 0u,
 .use_token_buffer = use_token_buffer ? 1u : 0u,
 .token = single_token ? (uint32_t)*single_token : 0u,
 .hash_rows = hash_rows,
 };

 const float zero_f32 = 0.0f;
 const int32_t zero_i32 = 0;
 if ((has_bias && !biasbuf) ||
 (hash_mode && !hashbuf) ||
 (use_token_buffer && !tokensbuf)) {
 return 0;
 }

 /* #559 ICB Phase 5 + #566 multi-command finalize-sequence ICB —
  * BOTH closed (no code) with shared structural blocker. Two reasons
  * router_finalize_one cannot be ICB-recorded on its current shape:
  *
  *   1. setThreadgroupMemoryLength (line below, 2 KB workspace) has NO
  *      equivalent in MTLIndirectComputeCommand. ICB exposes
  *      setKernelBuffer + setKernelBytes + concurrentDispatchThreadgroups
  *      but threadgroup memory size is set per-encoder, not per-command.
  *      Workaround would require kernel refactor to declare workspace
  *      as fixed-size threadgroup arrays in MSL — outside this commit's scope.
  *
  *   2. Conditional bindings (has_bias × hash_mode × use_token_buffer
  *      = 8 combinations) would need 8 distinct ICB slots, each with
  *      a different mix of setKernelBuffer / setKernelBytes calls. ICB
  *      record-time encoding can't conditionally choose between buffer
  *      and inline-bytes at the same arg index.
  *
  * Closing #559 with the doctrine block here so future-claude (or
  * a future codex agent) doesn't re-attempt without first restructuring
  * the kernel + caller. The direct encoding below remains the only
  * viable path on the current shape.
  *
  * #566 (multi-command finalize-sequence ICB: route_finalize +
  * weights_one in one ICB dispatch) inherits this blocker. The
  * weights_one half is already ICB-able (#560, ds4_route_weights_one_dispatch
  * below this block) BUT chaining it with route_finalize in a single
  * ICB requires route_finalize be ICB-able first. Same kernel refactor
  * (move setThreadgroupMemoryLength → fixed-size MSL declarations) is
  * the gate for both. */
 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:router_finalize_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:probsbuf offset:probs_off atIndex:1];
 if (has_bias) {
 [enc setBuffer:biasbuf offset:bias_off atIndex:2];
 } else {
 [enc setBytes:&zero_f32 length:sizeof(zero_f32) atIndex:2];
 }
 if (hash_mode) {
 [enc setBuffer:hashbuf offset:hash_off atIndex:3];
 } else {
 [enc setBytes:&zero_i32 length:sizeof(zero_i32) atIndex:3];
 }
 if (use_token_buffer) {
 [enc setBuffer:tokensbuf offset:tokens_off atIndex:4];
 } else {
 [enc setBytes:&zero_i32 length:sizeof(zero_i32) atIndex:4];
 }
 [enc setBuffer:selectedbuf offset:selected_off atIndex:5];
 [enc setThreadgroupMemoryLength:256u * sizeof(float) + 256u * sizeof(int32_t) atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);

 /* ICB record→replay path (slot 0 — decode-select-one), task #560.
  * Falls through to direct encoding when DS4_ICB_ACTIVE is off. */
 if (!ds4_route_weights_one_dispatch(cb, router_weights_pipeline, 0,
                                      probsbuf, probs_off,
                                      selectedbuf, selected_off,
                                      weightsbuf, weights_off)) {
     enc = ds4_gpu_compute_encoder(cb);
     [enc setComputePipelineState:router_weights_pipeline];
     [enc setBuffer:probsbuf    offset:probs_off    atIndex:0];
     [enc setBuffer:selectedbuf offset:selected_off atIndex:1];
     [enc setBuffer:weightsbuf  offset:weights_off  atIndex:2];
     [enc dispatchThreads:MTLSizeMake(6, 1, 1)
            threadsPerThreadgroup:MTLSizeMake(6, 1, 1)];
     ds4_gpu_end_compute_encoder(cb, enc);
 }
 return 1;
 }

 const NSUInteger sum_bytes = (NSUInteger)n_tokens * sizeof(float);
 if (!ds4_gpu_ensure_scratch_buffer(&g_router_weight_sum_buffer,
 &g_router_weight_sum_bytes,
 sum_bytes,
 "ds4_router_weight_sum")) {
 return 0;
 }

 if (!g_quality_mode && n_tokens == 1) {
 id<MTLComputePipelineState> softplus_sqrt_pipeline =
 ds4_gpu_hot_pipeline(g_dsv4_softplus_sqrt_pipeline,
 "kernel_dsv4_softplus_sqrt_f32_4");
 /* #558 ICB Phase 4 attempt; slot 1 = this site (~13857). */
 if (softplus_sqrt_pipeline && ds4_softplus_sqrt_dispatch_icb(cb, 1, softplus_sqrt_pipeline,
                                                              logitsbuf, logits_off, probsbuf, probs_off)) {
 ok = 1;
 } else {
 ok = softplus_sqrt_pipeline &&
 ds4_gpu_encode_unary_f32_rows(cb,
 softplus_sqrt_pipeline,
 logitsbuf,
 logits_off,
 probsbuf,
 probs_off,
 256,
 1,
 1,
 0.0f,
 0.0f);
 }
 } else {
 ok = ds4_gpu_encode_unary_f32_rows(cb,
 g_unary_softplus_pipeline,
 logitsbuf,
 logits_off,
 probsbuf,
 probs_off,
 256,
 n_tokens,
 1,
 0.0f,
 0.0f) &&
 ds4_gpu_encode_unary_f32_rows(cb,
 g_unary_sqrt_pipeline,
 probsbuf,
 probs_off,
 probsbuf,
 probs_off,
 256,
 n_tokens,
 1,
 0.0f,
 0.0f);
 }
 if (!ok) return 0;

 if (hash_mode) {
 ok = ds4_gpu_encode_get_rows_i32_token_rows(cb,
 hashbuf,
 hash_off,
 tokensbuf,
 tokens_off,
 single_token,
 selectedbuf,
 selected_off,
 hash_rows,
 n_tokens);
 } else {
 ds4_gpu_tensor *score_tensor = probs;
 DS4MetalTensor *selection_view = nil;

 if (has_bias) {
 if (!biasbuf ||
 !ds4_gpu_ensure_scratch_buffer(&g_router_selection_buffer,
 &g_router_selection_bytes,
 probs_bytes,
 "ds4_router_selection")) {
 return 0;
 }

 ds4_gpu_bin_args add_args = ds4_gpu_make_bin_rows_args(256, n_tokens, 256);
 ok = ds4_gpu_encode_bin_f32_rows(cb,
 g_add_pipeline,
 &add_args,
 probsbuf,
 probs_off,
 biasbuf,
 bias_off,
 g_router_selection_buffer,
 0);
 if (!ok) return 0;

 selection_view = [DS4MetalTensor new];
 selection_view.buffer = g_router_selection_buffer;
 selection_view.offset = 0;
 selection_view.bytes = probs_bytes;
 selection_view.owner = 0;
 score_tensor = (__bridge ds4_gpu_tensor *)selection_view;
 }

 ok = ds4_gpu_indexer_topk_tensor(selected, score_tensor, 256, n_tokens, 6) != 0;
 }
 if (!ok) return 0;

 if (!g_quality_mode && n_tokens == 1) {
 id<MTLComputePipelineState> router_weights_pipeline =
 ds4_gpu_hot_pipeline(g_dsv4_router_weights_one_pipeline,
 "kernel_dsv4_router_weights_one");
 if (!router_weights_pipeline) return 0;
 /* ICB record→replay path (slot 1 — generic-n_tokens-1 path), task #560. */
 if (!ds4_route_weights_one_dispatch(cb, router_weights_pipeline, 1,
                                      probsbuf, probs_off,
                                      selectedbuf, selected_off,
                                      weightsbuf, weights_off)) {
     id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
     [enc setComputePipelineState:router_weights_pipeline];
     [enc setBuffer:probsbuf    offset:probs_off    atIndex:0];
     [enc setBuffer:selectedbuf offset:selected_off atIndex:1];
     [enc setBuffer:weightsbuf  offset:weights_off  atIndex:2];
     [enc dispatchThreads:MTLSizeMake(6, 1, 1)
            threadsPerThreadgroup:MTLSizeMake(6, 1, 1)];
     ds4_gpu_end_compute_encoder(cb, enc);
 }
 return 1;
 }

 ok = ds4_gpu_encode_get_rows_f32_router_weights(cb,
 probsbuf,
 probs_off,
 selectedbuf,
 selected_off,
 weightsbuf,
 weights_off,
 n_tokens) &&
 ds4_gpu_encode_sum_rows_f32(cb,
 weightsbuf,
 weights_off,
 g_router_weight_sum_buffer,
 0,
 6,
 n_tokens) &&
 ds4_gpu_encode_unary_f32_rows(cb,
 g_unary_clamp_pipeline,
 g_router_weight_sum_buffer,
 0,
 g_router_weight_sum_buffer,
 0,
 1,
 n_tokens,
 0,
 6.103515625e-5f,
 ds4_gpu_positive_infinity());
 if (!ok) return 0;

 ds4_gpu_bin_args div_args = ds4_gpu_make_bin_rowwise_scalar_args(6, n_tokens);
 const float scale = 1.5f;
 ds4_gpu_bin_args scale_args = ds4_gpu_make_bin_rows_args(6, n_tokens, 1);

 ok = ds4_gpu_encode_bin_f32_rows(cb,
 g_bin_div_row_pipeline,
 &div_args,
 weightsbuf,
 weights_off,
 g_router_weight_sum_buffer,
 0,
 weightsbuf,
 weights_off);
 if (!ok) return 0;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_bin_mul_scalar_pipeline];
 [enc setBytes:&scale_args length:sizeof(scale_args) atIndex:0];
 [enc setBuffer:weightsbuf offset:weights_off atIndex:1];
 [enc setBytes:&scale length:sizeof(scale) atIndex:2];
 [enc setBuffer:weightsbuf offset:weights_off atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)scale_args.ne1,
 (NSUInteger)scale_args.ne2,
 (NSUInteger)scale_args.ne3)
 threadsPerThreadgroup:MTLSizeMake(ds4_gpu_bin_threads(6, g_bin_mul_scalar_pipeline), 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);

 return 1;
}

int ds4_gpu_router_select_tensor(
 ds4_gpu_tensor *selected,
 ds4_gpu_tensor *weights,
 ds4_gpu_tensor *probs,
 const void *model_map,
 uint64_t model_size,
 uint64_t bias_offset,
 uint64_t hash_offset,
 uint32_t hash_rows,
 uint32_t token,
 uint32_t n_expert,
 uint32_t n_expert_used,
 float expert_weight_scale,
 uint32_t n_expert_groups,
 uint32_t n_group_used,
 bool has_bias,
 bool hash_mode,
 const ds4_gpu_tensor *logits) {
 (void)n_expert; (void)n_expert_used; (void)expert_weight_scale; /* PRO params; silv non-PRO path hardcodes DS4_N_EXPERT/USED/SCALE */
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!selected || !weights || !probs || !logits || !model_map) return 0;
 if (hash_mode && token >= hash_rows) return 0;
 if (n_expert_groups > 1u || n_group_used > 0u) {
 fprintf(stderr, "ds4: Metal router group gating is not part of this DeepSeek V4 Flash path\n");
 return 0;
 }

 @autoreleasepool {
 id<MTLBuffer> logitsbuf = ds4_gpu_tensor_buffer(logits);
 id<MTLBuffer> selectedbuf = ds4_gpu_tensor_buffer(selected);
 id<MTLBuffer> weightsbuf = ds4_gpu_tensor_buffer(weights);
 id<MTLBuffer> probsbuf = ds4_gpu_tensor_buffer(probs);
 if (!logitsbuf || !selectedbuf || !weightsbuf || !probsbuf ||
 ds4_gpu_tensor_bytes(logits) < 256u * sizeof(float) ||
 ds4_gpu_tensor_bytes(selected) < 6u * sizeof(int) ||
 ds4_gpu_tensor_bytes(weights) < 6u * sizeof(float) ||
 ds4_gpu_tensor_bytes(probs) < 256u * sizeof(float)) {
 fprintf(stderr, "ds4: Metal router select received undersized buffers\n");
 return 0;
 }

 uint64_t bias_inner = 0;
 uint64_t hash_inner = 0;
 id<MTLBuffer> biasbuf = nil;
 id<MTLBuffer> hashbuf = nil;
 NSUInteger bias_set_offset = 0;
 NSUInteger hash_set_offset = 0;
 if (has_bias && !hash_mode) {
 const uint64_t bias_bytes = 256u * sizeof(float);
 biasbuf = ds4_gpu_wrap_model_range(model_map, model_size, bias_offset, bias_bytes, &bias_inner);
 if (!biasbuf) return 0;
 bias_set_offset = (NSUInteger)bias_inner;
 }
 if (hash_mode) {
 const uint64_t hash_bytes = (uint64_t)hash_rows * 6u * sizeof(int32_t);
 hashbuf = ds4_gpu_wrap_model_range(model_map, model_size, hash_offset, hash_bytes, &hash_inner);
 if (!hashbuf) return 0;
 hash_set_offset = (NSUInteger)hash_inner;
 }

 const bool had_batch = g_batch_cb != nil;
 if (!had_batch && ds4_gpu_begin_commands() == 0) return 0;
 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 const int32_t token_i32 = (int32_t)token;
 int ok = cb &&
 ds4_gpu_encode_router_select(cb,
 selected,
 weights,
 probs,
 logitsbuf,
 ds4_gpu_tensor_offset(logits),
 biasbuf,
 bias_set_offset,
 hashbuf,
 hash_set_offset,
 nil,
 0,
 &token_i32,
 hash_rows,
 1,
 has_bias && !hash_mode,
 hash_mode);
 if (!had_batch) {
 ok = ds4_gpu_end_commands() != 0 && ok;
 }
 if (!ok) return 0;
 }

 return 1;
}

