int ds4_gpu_routed_moe_one_tensor(
 ds4_gpu_tensor *out,
 ds4_gpu_tensor *gate,
 ds4_gpu_tensor *up,
 ds4_gpu_tensor *mid,
 ds4_gpu_tensor *experts,
 const void *model_map,
 uint64_t model_size,
 uint64_t gate_offset,
 uint64_t up_offset,
 uint64_t down_offset,
 uint32_t gate_type,
 uint32_t down_type,
 uint64_t gate_expert_bytes,
 uint64_t gate_row_bytes,
 uint64_t down_expert_bytes,
 uint64_t down_row_bytes,
 uint32_t expert_in_dim,
 uint32_t expert_mid_dim,
 uint32_t out_dim,
 const ds4_gpu_tensor *selected,
 const ds4_gpu_tensor *weights,
 uint32_t n_total_expert,
 uint32_t n_expert,
 float clamp,
 const ds4_gpu_tensor *x) {
 (void)n_total_expert; /* PRO param; silv non-PRO body uses fixed DS4_N_EXPERT */
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!out || !gate || !up || !mid || !x || !model_map || !selected || !weights ||
 n_expert == 0 || n_expert > 6) {
 return 0;
 }
 if ((expert_in_dim % 256u) != 0 || (expert_mid_dim % 256u) != 0) return 0;

 @autoreleasepool {
 id<MTLBuffer> xbuf = ds4_gpu_tensor_buffer(x);
 id<MTLBuffer> gatebuf = ds4_gpu_tensor_buffer(gate);
 id<MTLBuffer> upbuf = ds4_gpu_tensor_buffer(up);
 id<MTLBuffer> midbuf = ds4_gpu_tensor_buffer(mid);
 id<MTLBuffer> outbuf = ds4_gpu_tensor_buffer(out);
 id<MTLBuffer> expertsbuf = ds4_gpu_tensor_buffer(experts);
 id<MTLBuffer> selectedbuf = ds4_gpu_tensor_buffer(selected);
 id<MTLBuffer> weightsbuf = ds4_gpu_tensor_buffer(weights);
 const uint64_t x_bytes = (uint64_t)expert_in_dim * sizeof(float);
 const uint64_t mid_bytes = (uint64_t)n_expert * expert_mid_dim * sizeof(float);
 const uint64_t out_bytes = (uint64_t)out_dim * sizeof(float);
 if (!xbuf || !gatebuf || !upbuf || !midbuf || !outbuf || !selectedbuf || !weightsbuf ||
 ds4_gpu_tensor_bytes(x) < x_bytes ||
 ds4_gpu_tensor_bytes(gate) < mid_bytes ||
 ds4_gpu_tensor_bytes(up) < mid_bytes ||
 ds4_gpu_tensor_bytes(mid) < mid_bytes ||
 ds4_gpu_tensor_bytes(out) < out_bytes ||
 ds4_gpu_tensor_bytes(selected) < (uint64_t)n_expert * sizeof(int) ||
 ds4_gpu_tensor_bytes(weights) < (uint64_t)n_expert * sizeof(float)) {
 fprintf(stderr, "ds4: Metal routed tensor MoE received undersized activation buffers\n");
 return 0;
 }
 if (n_expert > 1 &&
 (!expertsbuf ||
 ds4_gpu_tensor_bytes(experts) < (uint64_t)n_expert * out_dim * sizeof(float))) {
 fprintf(stderr, "ds4: Metal routed tensor MoE received undersized expert output buffer\n");
 return 0;
 }

 const uint64_t gate_tensor_bytes = 256ull * gate_expert_bytes;
 const uint64_t down_tensor_bytes = 256ull * down_expert_bytes;
 uint64_t gate_inner = 0;
 uint64_t up_inner = 0;
 uint64_t down_inner = 0;
 id<MTLBuffer> gate_buf = ds4_gpu_wrap_model_range(model_map, model_size, gate_offset, gate_tensor_bytes, &gate_inner);
 id<MTLBuffer> up_buf = ds4_gpu_wrap_model_range(model_map, model_size, up_offset, gate_tensor_bytes, &up_inner);
 id<MTLBuffer> down_buf = ds4_gpu_wrap_model_range(model_map, model_size, down_offset, down_tensor_bytes, &down_inner);
 if (!gate_buf || !up_buf || !down_buf) return 0;

 const uint32_t n_tokens = 1;
 const uint32_t pair_rows = n_tokens * n_expert;
 const uint64_t down_scratch_bytes = (uint64_t)pair_rows * out_dim * sizeof(float);
 if ((n_expert > 1 && !expertsbuf &&
 !ds4_gpu_ensure_scratch_buffer(&g_moe_down_scratch_buffer,
 &g_moe_down_scratch_bytes,
 (NSUInteger)down_scratch_bytes,
 "ds4_moe_down_scratch"))) {
 return 0;
 }

 const uint32_t gate_nr0 = ds4_gpu_routed_mv_nr0(gate_type);
 const uint32_t down_nr0 = ds4_gpu_routed_mv_nr0(down_type);
 id<MTLComputePipelineState> gate_mv_pipeline = ds4_gpu_routed_mv_pipeline(gate_type);
 id<MTLComputePipelineState> down_mv_pipeline = ds4_gpu_routed_mv_pipeline(down_type);
 if (gate_nr0 == 0 || down_nr0 == 0 || !gate_mv_pipeline || !down_mv_pipeline) {
 fprintf(stderr, "ds4: unsupported Metal routed MoE quant types gate=%u down=%u\n",
 gate_type, down_type);
 return 0;
 }

 ds4_gpu_mul_mv_id_args gate_args =
 ds4_gpu_make_mul_mv_id_args(expert_in_dim, expert_mid_dim, 256,
 gate_row_bytes, gate_expert_bytes,
 1, n_expert, n_tokens, gate_nr0);
 ds4_gpu_mul_mv_id_args down_args =
 ds4_gpu_make_mul_mv_id_args(expert_mid_dim, out_dim, 256,
 down_row_bytes, down_expert_bytes,
 n_expert, n_expert, n_tokens, down_nr0);

 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;

 const NSUInteger gate_smem = ds4_gpu_routed_mv_smem(gate_type);
 const NSUInteger down_smem = ds4_gpu_routed_mv_smem(down_type);
 int ok = 1;
 const bool write_clamped_moe =
 getenv("DS4_METAL_MOE_WRITE_CLAMPED_ACT") != NULL;

 /* silv 2026-05-26: Metal-MoE predequant FP16 hot-store hook lives at the
  * caller in ds4.c (where layer index `il` is in scope), not here. See
  * ds4.c near ds4_gpu_routed_moe_one_tensor call, gated by DS4_HOT_METAL_MOE. */

 /* silv 2026-05-27 — codec-aligned FP16 dispatch: when DS4_HOT_FP16_KERNEL=1
  * AND the hot-store has the selected experts fully pinned for this layer,
  * use the FP16 pair_swiglu pipeline (reads FP16 row-major from hot-store
  * heap) instead of the IQ2_XXS pipeline (reads quantized weights from
  * model_map). Falls back to IQ2_XXS path when env unset OR hot-store not
  * ready OR layer/experts not pinned.
  *
  * NOTE: full deployment requires hot-store FULL row-block coverage of all
  * 16 row-blocks per expert × 256 experts × 43 layers × 3 kinds, AND the
  * gate_buf/up_buf arguments passed to ds4_gpu_encode_mul_mv_id_pair_swiglu
  * must point at the hot-store buffer with the right per-expert offsets.
  * This commit wires the BRANCH; full data plumbing is follow-up work. */
 static int hot_fp16_kernel_env_checked = 0;
 static int hot_fp16_kernel_active = 0;
 if (!hot_fp16_kernel_env_checked) {
 hot_fp16_kernel_active = (getenv("DS4_HOT_FP16_KERNEL") != NULL) ? 1 : 0;
 hot_fp16_kernel_env_checked = 1;
 if (hot_fp16_kernel_active && g_moe_mul_mv_id_fp16_pair_swiglu_pipeline) {
 fprintf(stderr,
   "ds4: DS4_HOT_FP16_KERNEL=1 — FP16 pair_swiglu kernel ready "
   "(activates only when hot-store fully pinned for selected experts)\n");
 } else if (hot_fp16_kernel_active) {
 fprintf(stderr,
   "ds4: DS4_HOT_FP16_KERNEL=1 set but FP16 kernel pipeline absent; "
   "IQ2_XXS path stays active\n");
 hot_fp16_kernel_active = 0;
 }
 }

 id<MTLComputePipelineState> pair_swiglu_pipeline = nil;
 if (gate_type == DS4_METAL_TENSOR_IQ2_XXS) {
 pair_swiglu_pipeline = g_moe_mul_mv_id_iq2_xxs_pair_swiglu_pipeline;
 } else if (gate_type == DS4_METAL_TENSOR_Q4_K) {
 pair_swiglu_pipeline = g_moe_mul_mv_id_q4_k_pair_swiglu_pipeline;
 }

 /* silv 2026-05-27 — mat-mat detection at prefill batch ≥ 8. The
  * kernel_mul_mm_id_fp16_pair_swiglu_f32 simdgroup path requires:
  *   (a) DS4_HOT_FP16_KERNEL=1
  *   (b) hot-store fully pinned for the active expert set
  *   (c) pair_rows >= 8 (mat-mat tile size)
  *
  * When all 3 hold, the mat-mat pipeline is selected. The encoder
  * function ds4_gpu_encode_mul_mm_id_pair_swiglu (TBD) builds the grid
  * (n_ffn/8, 1, n_groups) with per-group expert-id sorting and dispatches
  * with the hot-store FP16 heap + per-(layer,expert) offsets.
  *
  * Until the encoder lands, the matvec path stays selected; this block
  * just logs the readiness on first eligible call. */
 static int matmul_ready_logged = 0;
 if (hot_fp16_kernel_active &&
     g_moe_mul_mm_id_fp16_pair_swiglu_pipeline != nil &&
     pair_rows >= 8) {
  ds4_hot_expert_store *active_store = ds4_hot_store_get_active();
  if (active_store && !matmul_ready_logged) {
   fprintf(stderr,
           "ds4: simdgroup mat-mat pipeline READY (pair_rows=%llu, "
           "hot_pinned=%u experts). Encoder TBD — falling through to matvec.\n",
           (unsigned long long)pair_rows, active_store->n_pinned);
   matmul_ready_logged = 1;
  }
 }
 const bool fuse_pair_swiglu =
 !g_quality_mode &&
 !write_clamped_moe &&
 getenv("DS4_METAL_DISABLE_ROUTED_PAIR_SWIGLU_FUSION") == NULL &&
 pair_swiglu_pipeline != nil;
 if (fuse_pair_swiglu) {
 ds4_gpu_dsv4_moe_swiglu_weight_args act_args = {
 .width = expert_mid_dim,
 .rows = pair_rows,
 .gate_row_stride = (uint64_t)expert_mid_dim * sizeof(float),
 .up_row_stride = (uint64_t)expert_mid_dim * sizeof(float),
 .mid_row_stride = (uint64_t)expert_mid_dim * sizeof(float),
 .weight_stride = sizeof(float),
 .write_clamped = 0,
 .clamp_value = clamp,
 };
 ok = ds4_gpu_encode_mul_mv_id_pair_swiglu(cb,
 pair_swiglu_pipeline,
 &gate_args,
 &act_args,
 gate_buf,
 (NSUInteger)gate_inner,
 up_buf,
 (NSUInteger)up_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 upbuf,
 ds4_gpu_tensor_offset(up),
 midbuf,
 ds4_gpu_tensor_offset(mid),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 weightsbuf,
 ds4_gpu_tensor_offset(weights),
 gate_smem,
 2,
 false);
 } else if (!g_quality_mode &&
 gate_type == DS4_METAL_TENSOR_IQ2_XXS &&
 g_moe_mul_mv_id_iq2_xxs_pair_pipeline) {
 ok = ds4_gpu_encode_mul_mv_id_pair(cb,
 g_moe_mul_mv_id_iq2_xxs_pair_pipeline,
 &gate_args,
 gate_buf,
 (NSUInteger)gate_inner,
 up_buf,
 (NSUInteger)up_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 upbuf,
 ds4_gpu_tensor_offset(up),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 gate_smem,
 2,
 false);
 } else if (!g_quality_mode &&
 gate_type == DS4_METAL_TENSOR_Q4_K &&
 g_moe_mul_mv_id_q4_k_pair_pipeline) {
 ok = ds4_gpu_encode_mul_mv_id_pair(cb,
 g_moe_mul_mv_id_q4_k_pair_pipeline,
 &gate_args,
 gate_buf,
 (NSUInteger)gate_inner,
 up_buf,
 (NSUInteger)up_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 upbuf,
 ds4_gpu_tensor_offset(up),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 gate_smem,
 2,
 false);
 } else {
 ok = ds4_gpu_encode_mul_mv_id(cb,
 gate_mv_pipeline,
 &gate_args,
 gate_buf,
 (NSUInteger)gate_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 gate_smem,
 2,
 false) &&
 ds4_gpu_encode_mul_mv_id(cb,
 gate_mv_pipeline,
 &gate_args,
 up_buf,
 (NSUInteger)up_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 upbuf,
 ds4_gpu_tensor_offset(up),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 gate_smem,
 2,
 false);
 }
 if (ok && !fuse_pair_swiglu) {
 ok = ds4_gpu_encode_moe_swiglu_weight(cb,
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 upbuf,
 ds4_gpu_tensor_offset(up),
 midbuf,
 ds4_gpu_tensor_offset(mid),
 weightsbuf,
 ds4_gpu_tensor_offset(weights),
 expert_mid_dim,
 pair_rows,
 clamp,
 false);
 }

 id<MTLBuffer> down_dst = n_expert == 1 ? outbuf : (expertsbuf ? expertsbuf : g_moe_down_scratch_buffer);
 NSUInteger down_dst_off = n_expert == 1 ? ds4_gpu_tensor_offset(out) :
 (expertsbuf ? ds4_gpu_tensor_offset(experts) : 0);
 id<MTLComputePipelineState> down_sum6_pipeline = nil;
 if (down_type == DS4_METAL_TENSOR_Q2_K) {
 down_sum6_pipeline = g_moe_mul_mv_id_q2_k_sum6_pipeline;
 } else if (down_type == DS4_METAL_TENSOR_Q4_K) {
 down_sum6_pipeline = g_moe_mul_mv_id_q4_k_sum6_pipeline;
 }
 const bool direct_down_sum =
 !g_quality_mode &&
 n_expert == 6 &&
 n_tokens == 1 &&
 down_sum6_pipeline != nil;
 if (ok && direct_down_sum) {
 ok = ds4_gpu_encode_mul_mv_id_sum6(cb,
 down_sum6_pipeline,
 &down_args,
 down_buf,
 (NSUInteger)down_inner,
 midbuf,
 ds4_gpu_tensor_offset(mid),
 outbuf,
 ds4_gpu_tensor_offset(out),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 down_smem,
 2);
 } else if (ok) {
 ok = ds4_gpu_encode_mul_mv_id(cb,
 down_mv_pipeline,
 &down_args,
 down_buf,
 (NSUInteger)down_inner,
 midbuf,
 ds4_gpu_tensor_offset(mid),
 down_dst,
 down_dst_off,
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 down_smem,
 2,
 false);
 }
 if (ok && n_expert > 1 && !direct_down_sum) {
 ok = ds4_gpu_encode_moe_sum_experts(cb,
 down_dst,
 down_dst_off,
 outbuf,
 ds4_gpu_tensor_offset(out),
 out_dim,
 n_expert,
 n_tokens);
 }
 if (!ok) return 0;

 if (!ds4_gpu_finish_command_buffer(cb, owned, "routed tensor MoE")) return 0;
 }

 return 1;
}

/* Inference plumbing port for trim50 (parallel to pending integration.
 * Rewrites router-emitted selected_ids[k] in-place from logical_id to
 * file_position via the per-layer inverse remap table. Zeros weights for
 * trimmed entries. Optionally renormalizes the surviving weights to preserve
 * per-token total contribution.
 *
 * NO-OP when:
 * - DS4_EXPERT_REMAP_ACTIVE env not set, OR
 * - inverse remap table not uploaded (no trim metadata).
 *
 * Returns 1 on success / no-op-success, 0 on failure. */
/* ICB record→replay for kernel_dsv4_router_weights_one (task #560).
 * Called at most once per token from the n_tokens==1 decode path. Two
 * dispatch sites with identical structure (probs/selected/weights buffers,
 * dispatchThreads(6,1,1) → 1 threadgroup × 6 threads in ICB form).
 * The 2-slot signature cache lets both call sites share the recording.
 * Returns 1 if executed via ICB (or fell through), 0 only on hard error.
 *
 * Per-token cost saved per ICB hit: ~10-30 μs encoder setup. Marginal
 * compared to route_weights_with_remap (per-layer × 43), but extends the
 * H1716 graph-capture pattern to one more kernel in the route chain. */
static int ds4_route_weights_one_dispatch(id<MTLCommandBuffer> cb,
                                           id<MTLComputePipelineState> pipeline,
                                           uint32_t slot_idx,
                                           id<MTLBuffer> probsbuf, NSUInteger probs_off,
                                           id<MTLBuffer> selectedbuf, NSUInteger selected_off,
                                           id<MTLBuffer> weightsbuf, NSUInteger weights_off) {
    /* Measured 2026-05-25: 5-run A/B on trim50 full-Metal decode shows ICB-on
     * gen regresses to ~17.1 t/s mean (vs ICB-off ~19.1 t/s) with high
     * variance (15-19 range). The useResource×3 + executeCommandsInBuffer
     * overhead per call exceeds the encoder-setup savings on a 6-thread
     * kernel called once per token. Gate behind a SEPARATE env var so
     * DS4_ICB_ACTIVE keeps the winning route_remap ICB (43 layers × per-token
     * × 256-thread kernel) without dragging this losing one in by default.
     * Set DS4_ICB_WEIGHTS_ONE=1 to opt in (e.g. for batched/prefill paths). */
    static int s_env_checked = 0;
    static int s_env_active = 0;
    if (!s_env_checked) {
        s_env_active = getenv("DS4_ICB_WEIGHTS_ONE") != NULL ? 1 : 0;
        s_env_checked = 1;
        if (s_env_active) {
            fprintf(stderr, "ds4: DS4_ICB_WEIGHTS_ONE=1 — route_weights_one ICB engaged (opt-in: caller pays useResource cost)\n");
        }
    }
    if (!s_env_active) return 0; /* caller does direct encoding */
    if (slot_idx >= 2) return 0;

    if (!g_route_weights_one_icb) {
        MTLIndirectCommandBufferDescriptor *desc = [MTLIndirectCommandBufferDescriptor new];
        desc.commandTypes = MTLIndirectCommandTypeConcurrentDispatch;
        desc.inheritBuffers = NO;
        desc.inheritPipelineState = NO;
        desc.maxKernelBufferBindCount = 3;
        g_route_weights_one_icb =
            [g_device newIndirectCommandBufferWithDescriptor:desc
                                              maxCommandCount:2
                                                      options:MTLResourceStorageModeShared];
        if (!g_route_weights_one_icb) return 0;
    }

    ds4_route_weights_one_icb_slot *slot = &g_route_weights_one_icb_slots[slot_idx];
    const int sig_match = slot->recorded &&
        slot->probs_ptr    == (__bridge void *)probsbuf    && slot->probs_off    == (uint64_t)probs_off &&
        slot->selected_ptr == (__bridge void *)selectedbuf && slot->selected_off == (uint64_t)selected_off &&
        slot->weights_ptr  == (__bridge void *)weightsbuf  && slot->weights_off  == (uint64_t)weights_off;

    if (!sig_match) {
        id<MTLIndirectComputeCommand> cmd = [g_route_weights_one_icb indirectComputeCommandAtIndex:slot_idx];
        [cmd setComputePipelineState:pipeline];
        [cmd setKernelBuffer:probsbuf    offset:probs_off    atIndex:0];
        [cmd setKernelBuffer:selectedbuf offset:selected_off atIndex:1];
        [cmd setKernelBuffer:weightsbuf  offset:weights_off  atIndex:2];
        /* dispatchThreads(6,1,1) threadsPerThreadgroup(6,1,1) ≡ 1 group × 6 threads */
        [cmd concurrentDispatchThreadgroups:MTLSizeMake(1, 1, 1)
                      threadsPerThreadgroup:MTLSizeMake(6, 1, 1)];
        slot->probs_ptr    = (__bridge void *)probsbuf;    slot->probs_off    = (uint64_t)probs_off;
        slot->selected_ptr = (__bridge void *)selectedbuf; slot->selected_off = (uint64_t)selected_off;
        slot->weights_ptr  = (__bridge void *)weightsbuf;  slot->weights_off  = (uint64_t)weights_off;
        slot->recorded = 1;
    }

    id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
    [enc useResource:probsbuf    usage:MTLResourceUsageRead];
    [enc useResource:selectedbuf usage:MTLResourceUsageRead];
    [enc useResource:weightsbuf  usage:MTLResourceUsageRead | MTLResourceUsageWrite];
    [enc executeCommandsInBuffer:g_route_weights_one_icb
                       withRange:NSMakeRange(slot_idx, 1)];
    ds4_gpu_end_compute_encoder(cb, enc);
    return 1;
}

int ds4_gpu_remap_routed_for_trim(
 ds4_gpu_tensor *selected,
 ds4_gpu_tensor *weights,
 uint32_t layer_index,
 uint32_t n_expert,
 uint32_t n_tokens,
 bool renormalize) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!selected || !weights || n_expert == 0 || n_tokens == 0) return 0;

 /* Gate: env flag + buffer present. Both must hold for the remap to run. */
 static int s_env_checked = 0;
 static int s_env_active = 0;
 if (!s_env_checked) {
 s_env_active = getenv("DS4_EXPERT_REMAP_ACTIVE") != NULL ? 1 : 0;
 s_env_checked = 1;
 if (s_env_active) {
 fprintf(stderr, "ds4: DS4_EXPERT_REMAP_ACTIVE=1 — trim50 inference plumbing engaged\n");
 /* Append-only journal: log the transition. Per append-only discipline,
 * substrate state-changes get an event row. (declarations forward-
 * declared as extern at file scope above; this branch only
 * references them.) */
 ds4_journal *jrnl = (ds4_journal *)ds4_get_journal();
 if (jrnl) {
 ds4_journal_emit_event(jrnl, ds4_get_journal_session(),
 "plumbing_port_engaged",
 "{\"trim50\":true,\"fused_kernel\":true}");
 }
 }
 }
 if (!s_env_active) return 1; /* no-op success */
 if (!g_dsv4_expert_inverse_table_buffer) return 1; /* no trim metadata */

 @autoreleasepool {
 id<MTLBuffer> selectedbuf = ds4_gpu_tensor_buffer(selected);
 id<MTLBuffer> weightsbuf = ds4_gpu_tensor_buffer(weights);
 const NSUInteger selected_off = ds4_gpu_tensor_offset(selected);
 const NSUInteger weights_off = ds4_gpu_tensor_offset(weights);

 if (!selectedbuf || !weightsbuf) return 0;
 if (ds4_gpu_tensor_bytes(selected) < (uint64_t)n_tokens * n_expert * sizeof(int32_t)) return 0;
 if (ds4_gpu_tensor_bytes(weights) < (uint64_t)n_tokens * n_expert * sizeof(float)) return 0;

 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;

 /* fused single-kernel path: remap + renormalize in one
 * dispatch via threadgroup memory. Saves 1 dispatch per layer. */
 id<MTLComputePipelineState> fused_pipeline =
 ds4_gpu_hot_pipeline(g_dsv4_router_weights_with_remap_pipeline,
 "kernel_dsv4_router_weights_with_remap");
 if (!fused_pipeline) return 0;

 /* Ensure per-layer args slots are populated for the current n_tokens. The
  * args buffer is 43 contiguous (layer_index, n_expert, n_tokens) tuples.
  * Refill triggers only when n_tokens changes (free between decode steps,
  * one refill per prefill chunk-size change). 516 bytes total. */
 if (!g_dsv4_route_remap_args_buf) {
 g_dsv4_route_remap_args_buf =
 [g_device newBufferWithLength:(43u * 3u * sizeof(uint32_t))
 options:MTLResourceStorageModeShared];
 g_dsv4_route_remap_args_n_tokens = 0;
 }
 if (g_dsv4_route_remap_args_n_tokens != n_tokens) {
 uint32_t *slots = (uint32_t *)g_dsv4_route_remap_args_buf.contents;
 for (uint32_t L = 0; L < 43u; L++) {
 slots[L * 3u + 0u] = L;
 slots[L * 3u + 1u] = n_expert;
 slots[L * 3u + 2u] = n_tokens;
 }
 g_dsv4_route_remap_args_n_tokens = n_tokens;
 }

 /* ICB record→replay path: gated by DS4_ICB_ACTIVE. Each layer slot caches
  * the recorded command with (selectedbuf, weightsbuf, n_tokens) signature.
  * Signature match → just execute. Mismatch → re-record at that slot. The
  * args buffer offset is part of the recorded command (per-layer), so layer
  * id is implicit. Per H1716 codex tinygrad: this slice is ~1/4 of the
  * route chain. Expected gain: 5-15% of route encoding cost reclaimed. */
 if (!g_route_remap_icb_env_checked) {
 g_route_remap_icb_env_active = getenv("DS4_ICB_ACTIVE") != NULL ? 1 : 0;
 g_route_remap_icb_env_checked = 1;
 if (g_route_remap_icb_env_active) {
 fprintf(stderr, "ds4: DS4_ICB_ACTIVE=1 — route_remap ICB record→replay engaged\n");
 }
 }

 if (g_route_remap_icb_env_active && layer_index < 43u) {
 if (!g_route_remap_icb) {
 MTLIndirectCommandBufferDescriptor *desc = [MTLIndirectCommandBufferDescriptor new];
 desc.commandTypes = MTLIndirectCommandTypeConcurrentDispatch;
 desc.inheritBuffers = NO;
 desc.inheritPipelineState = NO;
 desc.maxKernelBufferBindCount = 4;
 g_route_remap_icb =
 [g_device newIndirectCommandBufferWithDescriptor:desc
 maxCommandCount:43
 options:MTLResourceStorageModeShared];
 if (!g_route_remap_icb) {
 fprintf(stderr, "ds4: ICB allocation failed — falling back to direct encoding\n");
 g_route_remap_icb_env_active = 0;
 }
 }
 }

 if (g_route_remap_icb_env_active && g_route_remap_icb) {
 ds4_route_remap_icb_slot *slot = &g_route_remap_icb_slots[layer_index];
 const int sig_match = slot->recorded &&
 slot->selected_ptr == (__bridge void *)selectedbuf &&
 slot->selected_off == (uint64_t)selected_off &&
 slot->weights_ptr == (__bridge void *)weightsbuf &&
 slot->weights_off == (uint64_t)weights_off &&
 slot->n_tokens == n_tokens;
 if (!sig_match) {
 id<MTLIndirectComputeCommand> cmd =
 [g_route_remap_icb indirectComputeCommandAtIndex:layer_index];
 [cmd setComputePipelineState:fused_pipeline];
 [cmd setKernelBuffer:g_dsv4_expert_inverse_table_buffer offset:0 atIndex:0];
 [cmd setKernelBuffer:selectedbuf offset:selected_off atIndex:1];
 [cmd setKernelBuffer:weightsbuf offset:weights_off atIndex:2];
 [cmd setKernelBuffer:g_dsv4_route_remap_args_buf
 offset:(NSUInteger)(layer_index * 3u * sizeof(uint32_t))
 atIndex:3];
 [cmd setThreadgroupMemoryLength:(NSUInteger)n_expert * sizeof(float) atIndex:0];
 [cmd concurrentDispatchThreadgroups:MTLSizeMake(n_tokens, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(n_expert, 1, 1)];
 slot->selected_ptr = (__bridge void *)selectedbuf;
 slot->selected_off = (uint64_t)selected_off;
 slot->weights_ptr = (__bridge void *)weightsbuf;
 slot->weights_off = (uint64_t)weights_off;
 slot->n_tokens = n_tokens;
 slot->recorded = 1;
 }
 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc useResource:g_dsv4_expert_inverse_table_buffer usage:MTLResourceUsageRead];
 [enc useResource:selectedbuf usage:MTLResourceUsageRead | MTLResourceUsageWrite];
 [enc useResource:weightsbuf usage:MTLResourceUsageRead | MTLResourceUsageWrite];
 [enc useResource:g_dsv4_route_remap_args_buf usage:MTLResourceUsageRead];
 [enc executeCommandsInBuffer:g_route_remap_icb
 withRange:NSMakeRange(layer_index, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 } else {
 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:fused_pipeline];
 [enc setBuffer:g_dsv4_expert_inverse_table_buffer offset:0 atIndex:0];
 [enc setBuffer:selectedbuf offset:selected_off atIndex:1];
 [enc setBuffer:weightsbuf offset:weights_off atIndex:2];
 /* Args at buffer(3) with per-layer offset. ICB-compatible (no setBytes). */
 [enc setBuffer:g_dsv4_route_remap_args_buf
 offset:(NSUInteger)(layer_index * 3u * sizeof(uint32_t))
 atIndex:3];
 [enc setThreadgroupMemoryLength:(NSUInteger)n_expert * sizeof(float) atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake(n_tokens, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(n_expert, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);
 }
 (void)renormalize; /* always renormalized inside the fused kernel */

 if (!ds4_gpu_finish_command_buffer(cb, owned, "trim remap")) return 0;
 }

 /* Per-layer routing emit when journal active. Overhead measured in noise. */
 ds4_journal *jrnl = (ds4_journal *)ds4_get_journal();
 if (jrnl) {
 int32_t sel_buf[6] = {0};
 float w_buf[6] = {0};
 const uint32_t k_log = n_expert < 6u ? n_expert : 6u;
 if (ds4_gpu_tensor_read(selected, 0, sel_buf, k_log * sizeof(int32_t)) != 0 &&
 ds4_gpu_tensor_read(weights, 0, w_buf, k_log * sizeof(float)) != 0) {
 uint16_t sel_u16[6] = {0};
 for (uint32_t k = 0; k < k_log; k++) sel_u16[k] = (uint16_t)sel_buf[k];
 ds4_journal_emit_routing(jrnl, ds4_get_journal_session(), 0,
 (int32_t)layer_index, sel_u16, w_buf,
 (int)k_log, 0.0f/0.0f);
 }
 }

 return 1;
}

int ds4_gpu_routed_moe_batch_tensor(
 ds4_gpu_tensor *out,
 ds4_gpu_tensor *gate,
 ds4_gpu_tensor *up,
 ds4_gpu_tensor *mid,
 ds4_gpu_tensor *experts,
 const void *model_map,
 uint64_t model_size,
 uint64_t gate_offset,
 uint64_t up_offset,
 uint64_t down_offset,
 uint32_t gate_type,
 uint32_t down_type,
 uint64_t gate_expert_bytes,
 uint64_t gate_row_bytes,
 uint64_t down_expert_bytes,
 uint64_t down_row_bytes,
 uint32_t expert_in_dim,
 uint32_t expert_mid_dim,
 uint32_t out_dim,
 const ds4_gpu_tensor *selected,
 const ds4_gpu_tensor *weights,
 uint32_t n_total_expert,
 uint32_t n_expert,
 float clamp,
 const ds4_gpu_tensor *x,
 uint32_t layer_index,
 uint32_t n_tokens,
 bool *mid_is_f16) {
 (void)n_total_expert;
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!out || !gate || !up || !mid || !x || !model_map || !selected || !weights ||
 n_tokens == 0 || n_expert == 0 || n_expert > 6) {
 return 0;
 }
 if ((expert_in_dim % 256u) != 0 || (expert_mid_dim % 256u) != 0) return 0;

 @autoreleasepool {
 id<MTLBuffer> xbuf = ds4_gpu_tensor_buffer(x);
 id<MTLBuffer> gatebuf = ds4_gpu_tensor_buffer(gate);
 id<MTLBuffer> upbuf = ds4_gpu_tensor_buffer(up);
 id<MTLBuffer> midbuf = ds4_gpu_tensor_buffer(mid);
 id<MTLBuffer> outbuf = ds4_gpu_tensor_buffer(out);
 id<MTLBuffer> expertsbuf = ds4_gpu_tensor_buffer(experts);
 id<MTLBuffer> selectedbuf = ds4_gpu_tensor_buffer(selected);
 id<MTLBuffer> weightsbuf = ds4_gpu_tensor_buffer(weights);
 const uint64_t x_bytes = (uint64_t)n_tokens * expert_in_dim * sizeof(float);
 const uint64_t mid_bytes = (uint64_t)n_tokens * n_expert * expert_mid_dim * sizeof(float);
 const uint64_t out_bytes = (uint64_t)n_tokens * out_dim * sizeof(float);
 const uint64_t selected_bytes = (uint64_t)n_tokens * n_expert * sizeof(int);
 const uint64_t weights_bytes = (uint64_t)n_tokens * n_expert * sizeof(float);
 if (!xbuf || !gatebuf || !upbuf || !midbuf || !outbuf || !selectedbuf || !weightsbuf ||
 ds4_gpu_tensor_bytes(x) < x_bytes ||
 ds4_gpu_tensor_bytes(gate) < mid_bytes ||
 ds4_gpu_tensor_bytes(up) < mid_bytes ||
 ds4_gpu_tensor_bytes(mid) < mid_bytes ||
 ds4_gpu_tensor_bytes(out) < out_bytes ||
 ds4_gpu_tensor_bytes(selected) < selected_bytes ||
 ds4_gpu_tensor_bytes(weights) < weights_bytes) {
 fprintf(stderr, "ds4: Metal routed batch MoE received undersized activation buffers\n");
 return 0;
 }
 if (n_expert > 1 &&
 (!expertsbuf ||
 ds4_gpu_tensor_bytes(experts) < (uint64_t)n_tokens * n_expert * out_dim * sizeof(float))) {
 fprintf(stderr, "ds4: Metal routed batch MoE received undersized expert output buffer\n");
 return 0;
 }

 const uint64_t gate_tensor_bytes = 256ull * gate_expert_bytes;
 const uint64_t down_tensor_bytes = 256ull * down_expert_bytes;
 uint64_t gate_inner = 0;
 uint64_t up_inner = 0;
 uint64_t down_inner = 0;
 id<MTLBuffer> gate_buf = ds4_gpu_wrap_model_range(model_map, model_size, gate_offset, gate_tensor_bytes, &gate_inner);
 id<MTLBuffer> up_buf = ds4_gpu_wrap_model_range(model_map, model_size, up_offset, gate_tensor_bytes, &up_inner);
 id<MTLBuffer> down_buf = ds4_gpu_wrap_model_range(model_map, model_size, down_offset, down_tensor_bytes, &down_inner);
 if (!gate_buf || !up_buf || !down_buf) return 0;

 const uint32_t pair_rows = n_tokens * n_expert;
 const uint64_t down_scratch_bytes = (uint64_t)pair_rows * out_dim * sizeof(float);
 if ((n_expert > 1 && !expertsbuf &&
 !ds4_gpu_ensure_scratch_buffer(&g_moe_down_scratch_buffer,
 &g_moe_down_scratch_bytes,
 (NSUInteger)down_scratch_bytes,
 "ds4_moe_down_scratch"))) {
 return 0;
 }

 const uint32_t gate_nr0 = ds4_gpu_routed_mv_nr0(gate_type);
 const uint32_t down_nr0 = ds4_gpu_routed_mv_nr0(down_type);
 id<MTLComputePipelineState> gate_mv_pipeline = ds4_gpu_routed_mv_pipeline(gate_type);
 id<MTLComputePipelineState> down_mv_pipeline = ds4_gpu_routed_mv_pipeline(down_type);
 id<MTLComputePipelineState> gate_mm_pipeline = nil;
 id<MTLComputePipelineState> up_mm_pipeline = nil;
 id<MTLComputePipelineState> down_mm_pipeline = nil;
 if (gate_nr0 == 0 || down_nr0 == 0 || !gate_mv_pipeline || !down_mv_pipeline) {
 fprintf(stderr, "ds4: unsupported Metal routed batch MoE quant types gate=%u down=%u\n",
 gate_type, down_type);
 return 0;
 }

 ds4_gpu_mul_mv_id_args gate_args =
 ds4_gpu_make_mul_mv_id_args(expert_in_dim, expert_mid_dim, 256,
 gate_row_bytes, gate_expert_bytes,
 1, n_expert, n_tokens, gate_nr0);
 ds4_gpu_mul_mv_id_args down_args =
 ds4_gpu_make_mul_mv_id_args(expert_mid_dim, out_dim, 256,
 down_row_bytes, down_expert_bytes,
 n_expert, n_expert, n_tokens, down_nr0);
 const bool use_mm_id = n_tokens >= 32u && ds4_gpu_mul_mm_id_map0_name(n_expert) != NULL;

 /* silv 2026-05-27 — prefill mat-mat FP16 dispatch precondition. Sets
  * `try_fp16_simdgroup` only when env + pipeline + shape + codec line up;
  * the actual dispatch + hot-store fully-pinned check fires after the
  * command buffer is acquired below. Conditions:
  *   (a) DS4_HOT_FP16_KERNEL=1
  *   (b) g_moe_mul_mm_id_fp16_pair_swiglu_pipeline registered
  *   (c) n_tokens >= 8 (mat-mat tile size)
  *   (d) gate_type is IQ2_XXS (only codec hot-store currently dequants) */
 extern id<MTLComputePipelineState> g_moe_mul_mm_id_fp16_pair_swiglu_pipeline;
 const bool try_fp16_simdgroup =
  getenv("DS4_HOT_FP16_KERNEL") != NULL &&
  g_moe_mul_mm_id_fp16_pair_swiglu_pipeline != nil &&
  n_tokens >= 8u &&
  gate_type == DS4_METAL_TENSOR_IQ2_XXS;

 /*
 * MTP verification is neither normal decode nor large prefill: the
 * target model must verify a tiny suffix (usually 2 tokens) in one
 * layer-major pass. For that shape the prefill expert-major GEMM path
 * is too large, but the decode pair kernels are exactly the right
 * primitive: they read the same activation once and compute routed
 * gate/up together for every selected expert row. Keep this limited to
 * tiny batches so ordinary prefill keeps using the higher-throughput
 * grouped matmul path.
 */
 const bool use_tiny_pair_mv =
 !g_quality_mode &&
 n_tokens <= 4u &&
 !use_mm_id &&
 ((gate_type == DS4_METAL_TENSOR_IQ2_XXS && g_moe_mul_mv_id_iq2_xxs_pair_pipeline) ||
 (gate_type == DS4_METAL_TENSOR_Q4_K && g_moe_mul_mv_id_q4_k_pair_pipeline));
 ds4_gpu_mul_mm_id_map_args gate_map_args = { 0 };
 ds4_gpu_mul_mm_id_args gate_mm_args = { 0 };
 ds4_gpu_mul_mm_id_args down_mm_args = { 0 };
 id<MTLComputePipelineState> map_pipeline = nil;
 /*
 * The grouped routed-MoE matmul loads activation tiles as half before
 * using SIMD-group MMA. Store the SwiGLU/route-weight intermediate in
 * that same precision so the down projection avoids a large F32 mid
 * write/read. --quality keeps the older F32 intermediate.
 */
 const bool request_mid_f16 = !g_quality_mode;
 if (use_mm_id) {
 gate_map_args =
 ds4_gpu_make_mul_mm_id_map_args(expert_in_dim, 256, 1, n_expert, n_tokens);
 gate_mm_args =
 ds4_gpu_make_mul_mm_id_args(expert_in_dim, expert_mid_dim, 256,
 gate_row_bytes, gate_expert_bytes,
 1, n_expert, n_tokens);
 down_mm_args =
 ds4_gpu_make_mul_mm_id_args_src1_size(expert_mid_dim, out_dim, 256,
 down_row_bytes, down_expert_bytes,
 n_expert, n_expert, n_tokens,
 request_mid_f16 ? sizeof(uint16_t) : sizeof(float));

 map_pipeline = ds4_gpu_get_pipeline(ds4_gpu_mul_mm_id_map0_name(n_expert));
 gate_mm_pipeline = ds4_gpu_routed_mm_pipeline(gate_type);
 up_mm_pipeline = ds4_gpu_routed_mm_pipeline(gate_type);
 down_mm_pipeline = request_mid_f16 ?
 ds4_gpu_routed_mm_f16_rhs_pipeline(down_type) :
 ds4_gpu_routed_mm_pipeline(down_type);
 if (!map_pipeline || !gate_mm_pipeline || !up_mm_pipeline || !down_mm_pipeline) {
 return 0;
 }
 }

 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;
 const bool moe_stage_profile =
 getenv("DS4_METAL_MOE_STAGE_PROFILE") != NULL && g_batch_cb != nil;
 const char *moe_stage_filter = getenv("DS4_METAL_MOE_STAGE_PROFILE_FILTER");
 const char *moe_path =
 use_mm_id ? "mm_id" :
 (use_tiny_pair_mv ? "tiny_pair_mv" : "mv");
 double moe_stage_t0 = moe_stage_profile ? ds4_gpu_now_ms() : 0.0;
 if (moe_stage_profile) {
 if (ds4_gpu_end_commands() == 0 || ds4_gpu_begin_commands() == 0) {
 return 0;
 }
 cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;
 moe_stage_t0 = ds4_gpu_now_ms();
 }
#define DS4_METAL_PROFILE_MOE_STAGE(name) do { \
 if (ok && moe_stage_profile) { \
 if (ds4_gpu_end_commands() == 0) { \
 ok = 0; \
 } else { \
 const char *stage_name = (name); \
 const double now_ms = ds4_gpu_now_ms(); \
 const int print_stage = \
 !moe_stage_filter || !moe_stage_filter[0] || \
 strstr(stage_name, moe_stage_filter) != NULL; \
 if (print_stage) { \
 fprintf(stderr, \
 "ds4: Metal routed MoE stage layer=%u tokens=%u pairs=%u experts=%u " \
 "gate=%s down=%s path=%s mid=%s %s=%.3f ms\n", \
 layer_index, n_tokens, pair_rows, n_expert, \
 ds4_gpu_metal_tensor_type_name(gate_type), \
 ds4_gpu_metal_tensor_type_name(down_type), \
 moe_path, \
 request_mid_f16 ? "f16" : "f32", \
 stage_name, now_ms - moe_stage_t0); \
 } \
 moe_stage_t0 = now_ms; \
 if (ds4_gpu_begin_commands() == 0) { \
 ok = 0; \
 } else { \
 cb = ds4_gpu_command_buffer(&owned); \
 if (!cb) ok = 0; \
 } \
 } \
 } \
 } while (0)

 const NSUInteger gate_smem = ds4_gpu_routed_mv_smem(gate_type);
 const NSUInteger down_smem = ds4_gpu_routed_mv_smem(down_type);
 id<MTLComputePipelineState> down_sum6_pipeline = nil;
 if (down_type == DS4_METAL_TENSOR_Q2_K) {
 down_sum6_pipeline = g_moe_mul_mv_id_q2_k_sum6_pipeline;
 } else if (down_type == DS4_METAL_TENSOR_Q4_K) {
 down_sum6_pipeline = g_moe_mul_mv_id_q4_k_sum6_pipeline;
 }
 const bool direct_down_sum =
 !g_quality_mode &&
 !use_mm_id &&
 n_expert == 6 &&
 n_tokens <= 4u &&
 down_sum6_pipeline != nil;
 int ok = 0;
 int fp16_simdgroup_used = 0;
 /* silv 2026-05-27 — FP16 simdgroup mat-mat fused gate+up+SwiGLU dispatch.
  * Replaces the gate matmul + up matmul + SwiGLU+weight steps with a single
  * fused kernel reading FP16 weights from the hot-store. The down projection
  * runs unchanged from `midbuf`. Returns 1 on successful dispatch; on 0 the
  * IQ2_XXS path below runs as fallback. Hot-store fully-pinned check happens
  * inside the helper (cheap layer-level check, no GPU sync needed). */
 if (try_fp16_simdgroup) {
 fp16_simdgroup_used = ds4_gpu_dispatch_fp16_simdgroup_pair_swiglu(
  cb, layer_index, expert_in_dim, expert_mid_dim, n_tokens, n_expert,
  clamp,
  xbuf, ds4_gpu_tensor_offset(x),
  midbuf, ds4_gpu_tensor_offset(mid),
  selectedbuf, ds4_gpu_tensor_offset(selected),
  weightsbuf, ds4_gpu_tensor_offset(weights));
 if (fp16_simdgroup_used) {
  ok = 1;
  DS4_METAL_PROFILE_MOE_STAGE("fp16_simdgroup_fused");
 }
 }
 if (!fp16_simdgroup_used && use_mm_id) {
 /*
 * The routed pair ids are the same for gate, up, and down. Build
 * the expert-major work map once, then reuse it for all three
 * batched expert matmuls.
 */
 ok = ds4_gpu_encode_mul_mm_id_map(cb,
 map_pipeline,
 &gate_map_args,
 &gate_mm_args,
 selectedbuf,
 ds4_gpu_tensor_offset(selected));
 DS4_METAL_PROFILE_MOE_STAGE("map");
 if (ok) {
 ok = ds4_gpu_encode_mul_mm_id_mapped_tile(cb,
 gate_mm_pipeline,
 &gate_mm_args,
 gate_buf,
 (NSUInteger)gate_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 gatebuf,
 ds4_gpu_tensor_offset(gate));
 DS4_METAL_PROFILE_MOE_STAGE("gate");
 }
 if (ok) {
 ok = ds4_gpu_encode_mul_mm_id_mapped_tile(cb,
 up_mm_pipeline,
 &gate_mm_args,
 up_buf,
 (NSUInteger)up_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 upbuf,
 ds4_gpu_tensor_offset(up));
 DS4_METAL_PROFILE_MOE_STAGE("up");
 }
 } else if (!fp16_simdgroup_used && use_tiny_pair_mv) {
 id<MTLComputePipelineState> pair_pipeline =
 gate_type == DS4_METAL_TENSOR_IQ2_XXS ?
 g_moe_mul_mv_id_iq2_xxs_pair_pipeline :
 g_moe_mul_mv_id_q4_k_pair_pipeline;
 ok = ds4_gpu_encode_mul_mv_id_pair(cb,
 pair_pipeline,
 &gate_args,
 gate_buf,
 (NSUInteger)gate_inner,
 up_buf,
 (NSUInteger)up_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 upbuf,
 ds4_gpu_tensor_offset(up),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 gate_smem,
 2,
 false);
 } else if (!fp16_simdgroup_used) {
 ok = ds4_gpu_encode_mul_mv_id(cb,
 gate_mv_pipeline,
 &gate_args,
 gate_buf,
 (NSUInteger)gate_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 gate_smem,
 2,
 false) &&
 ds4_gpu_encode_mul_mv_id(cb,
 gate_mv_pipeline,
 &gate_args,
 up_buf,
 (NSUInteger)up_inner,
 xbuf,
 ds4_gpu_tensor_offset(x),
 upbuf,
 ds4_gpu_tensor_offset(up),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 gate_smem,
 2,
 false);
 }
 if (!fp16_simdgroup_used) DS4_METAL_PROFILE_MOE_STAGE("gate_up");
 const bool use_fused_activation = !g_quality_mode;
 const bool use_mid_f16 =
 !fp16_simdgroup_used &&
 use_mm_id &&
 use_fused_activation &&
 request_mid_f16;
 if (mid_is_f16) *mid_is_f16 = use_mid_f16;
 if (ok && !fp16_simdgroup_used && use_fused_activation) {
 ok = ds4_gpu_encode_moe_swiglu_weight(cb,
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 upbuf,
 ds4_gpu_tensor_offset(up),
 midbuf,
 ds4_gpu_tensor_offset(mid),
 weightsbuf,
 ds4_gpu_tensor_offset(weights),
 expert_mid_dim,
 pair_rows,
 clamp,
 use_mid_f16);
 } else if (ok && !fp16_simdgroup_used && clamp > 1.0e-6f) {
 ok = ds4_gpu_encode_unary_f32_rows(cb,
 g_unary_clamp_pipeline,
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 expert_mid_dim,
 pair_rows,
 0,
 -FLT_MAX,
 clamp);
 if (ok) {
 ok = ds4_gpu_encode_unary_f32_rows(cb,
 g_unary_silu_pipeline,
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 midbuf,
 ds4_gpu_tensor_offset(mid),
 expert_mid_dim,
 pair_rows,
 1,
 0.0f,
 0.0f);
 }
 if (ok) {
 ok = ds4_gpu_encode_unary_f32_rows(cb,
 g_unary_clamp_pipeline,
 upbuf,
 ds4_gpu_tensor_offset(up),
 upbuf,
 ds4_gpu_tensor_offset(up),
 expert_mid_dim,
 pair_rows,
 0,
 -clamp,
 clamp);
 }
 if (ok) {
 ds4_gpu_bin_args mul_args =
 ds4_gpu_make_bin_same_rows_args(expert_mid_dim, pair_rows);
 ok = ds4_gpu_encode_bin_f32_rows(cb,
 g_mul_pipeline,
 &mul_args,
 midbuf,
 ds4_gpu_tensor_offset(mid),
 upbuf,
 ds4_gpu_tensor_offset(up),
 midbuf,
 ds4_gpu_tensor_offset(mid));
 }
 } else if (ok && !fp16_simdgroup_used) {
 ok = ds4_gpu_encode_swiglu_flat(cb,
 gatebuf,
 ds4_gpu_tensor_offset(gate),
 upbuf,
 ds4_gpu_tensor_offset(up),
 midbuf,
 ds4_gpu_tensor_offset(mid),
 (uint32_t)((uint64_t)pair_rows * expert_mid_dim));
 }
 if (ok && !fp16_simdgroup_used && !use_fused_activation) {
 ds4_gpu_bin_args weight_args =
 ds4_gpu_make_bin_rowwise_scalar_args(expert_mid_dim, pair_rows);
 ok = ds4_gpu_encode_bin_f32_rows(cb,
 g_bin_mul_scalar_pipeline,
 &weight_args,
 midbuf,
 ds4_gpu_tensor_offset(mid),
 weightsbuf,
 ds4_gpu_tensor_offset(weights),
 midbuf,
 ds4_gpu_tensor_offset(mid));
 }
 if (!fp16_simdgroup_used) DS4_METAL_PROFILE_MOE_STAGE("activation_weight");

 id<MTLBuffer> down_dst = n_expert == 1 ? outbuf : (expertsbuf ? expertsbuf : g_moe_down_scratch_buffer);
 NSUInteger down_dst_off = n_expert == 1 ? ds4_gpu_tensor_offset(out) :
 (expertsbuf ? ds4_gpu_tensor_offset(experts) : 0);
 if (ok) {
 if (direct_down_sum) {
 ok = ds4_gpu_encode_mul_mv_id_sum6(cb,
 down_sum6_pipeline,
 &down_args,
 down_buf,
 (NSUInteger)down_inner,
 midbuf,
 ds4_gpu_tensor_offset(mid),
 outbuf,
 ds4_gpu_tensor_offset(out),
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 down_smem,
 2);
 } else if (use_mm_id) {
 ok = ds4_gpu_encode_mul_mm_id_mapped_tile(cb,
 down_mm_pipeline,
 &down_mm_args,
 down_buf,
 (NSUInteger)down_inner,
 midbuf,
 ds4_gpu_tensor_offset(mid),
 down_dst,
 down_dst_off);
 } else {
 ok = ds4_gpu_encode_mul_mv_id(cb,
 down_mv_pipeline,
 &down_args,
 down_buf,
 (NSUInteger)down_inner,
 midbuf,
 ds4_gpu_tensor_offset(mid),
 down_dst,
 down_dst_off,
 selectedbuf,
 ds4_gpu_tensor_offset(selected),
 down_smem,
 2,
 false);
 }
 }
 DS4_METAL_PROFILE_MOE_STAGE("down");
 if (ok && n_expert > 1 && !direct_down_sum) {
 ok = ds4_gpu_encode_moe_sum_experts(cb,
 down_dst,
 down_dst_off,
 outbuf,
 ds4_gpu_tensor_offset(out),
 out_dim,
 n_expert,
 n_tokens);
 }
 DS4_METAL_PROFILE_MOE_STAGE("sum");
 if (!ok) return 0;

 if (!ds4_gpu_finish_command_buffer(cb, owned, "routed batch MoE")) return 0;
#undef DS4_METAL_PROFILE_MOE_STAGE
 }

 return 1;
}

/* MTL4 ML packaged-organ scaffold. Current target: routed-MoE (DYNAMIC,
 * wrong per research partition). Correct target: FROZEN dense subgraphs —
 * shared-expert MLP (per-token unchanging structure), output head matmul,
 * attention output projection, HC split/expand. The 2-3 OOM speed frontier
 * is boundary deletion + graph capture (ICB) FIRST; THEN package frozen
 * organs that no longer need surgery. Scaffold kept for reference + retarget
 * to a frozen organ once ICB integration lands. Env-gated DS4_MTL4_MOE_ENABLE;
 * current preflight: n_tokens ≤ 16, n_expert == 6, package + queue allocated. */

/* ============================================================ */
/* Polar p8_m2 MTL4 dot kernel (port of codex H1725)            */
/* ============================================================ */
/* H1722 lifecycle: newCommandAllocator → newCommandBuffer from device →
 * beginCommandBufferWithAllocator → useResidencySet → encoder →
 * endCommandBuffer → MTL4 queue commit.
 *
 * H1724 critical: MTL4ArgumentTable buffers silently read as zero unless
 * their allocations are committed/requested through MTLResidencySet and
 * attached to the command buffer/queue. The bind goes via .gpuAddress.
 *
 * H1725 measured: 7776 packets @ 0.605 ms via 256-thread threadgroup per
 * packet (13.54× speedup over the H1724 serial-thread version).
 *
 * Self-test path: ds4_gpu_mtl4_polar_dot_canary(packets, pairs) — exposed
 * for diagnostic dispatch. Real DS4 integration (consuming polar-encoded
 * routed expert weights for actual inference) is task #563.
 *
 * Codex artifact source: research/llm_fallacy_deconstruction/
 *   framework_deconstruction/h1725_mtl4_polar_dot_parallel_kernel_20260525.m
 */

static id<MTL4Compiler> g_polar_compiler;
static id<MTLComputePipelineState> g_polar_pipeline;
static id<MTL4CommandAllocator> g_polar_allocator;
static id<MTL4CommandQueue> g_polar_queue;
static int g_polar_init_attempted;
static int g_polar_init_ok;

static int ds4_polar_pipeline_init(void) {
    if (g_polar_init_attempted) return g_polar_init_ok;
    g_polar_init_attempted = 1;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "kernel void polar_dot(device const uchar* mag [[buffer(0)]],\n"
         "                      device const uchar* phase [[buffer(1)]],\n"
         "                      device const float* levels [[buffer(2)]],\n"
         "                      device const float* hidden [[buffer(3)]],\n"
         "                      device const float* cos_lut [[buffer(4)]],\n"
         "                      device const float* sin_lut [[buffer(5)]],\n"
         "                      device float* out [[buffer(6)]],\n"
         "                      device const uint* pairs_ptr [[buffer(7)]],\n"
         "                      uint3 tg [[threadgroup_position_in_grid]],\n"
         "                      uint tid [[thread_index_in_threadgroup]]) {\n"
         "  constexpr uint THREADS = 256;\n"
         "  threadgroup float partial[THREADS];\n"
         "  uint packet = tg.x;\n"
         "  uint pairs = pairs_ptr[0];\n"
         "  uint base = packet * pairs;\n"
         "  uint hbase = packet * pairs * 2;\n"
         "  float acc = 0.0f;\n"
         "  for (uint j = tid; j < pairs; j += THREADS) {\n"
         "    uint idx = base + j;\n"
         "    uchar mcode = mag[idx];\n"
         "    float qmag = levels[packet * 4 + uint(mcode)];\n"
         "    uint lut = uint(phase[idx]);\n"
         "    float x0 = qmag * cos_lut[lut];\n"
         "    float x1 = qmag * sin_lut[lut];\n"
         "    acc += x0 * hidden[hbase + 2*j] + x1 * hidden[hbase + 2*j + 1];\n"
         "  }\n"
         "  partial[tid] = acc;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  for (uint stride = THREADS >> 1; stride > 0; stride >>= 1) {\n"
         "    if (tid < stride) partial[tid] += partial[tid + stride];\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  if (tid == 0) out[packet] = partial[0];\n"
         "}\n";

    MTL4CompilerDescriptor *compDesc = [MTL4CompilerDescriptor new];
    g_polar_compiler = [g_device newCompilerWithDescriptor:compDesc error:&err];
    if (!g_polar_compiler) {
        fprintf(stderr, "ds4: polar MTL4 compiler init failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_polar_dot";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: polar MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"polar_dot";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_polar_pipeline = [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                                           compilerTaskOptions:nil
                                                                         error:&err];
    if (!g_polar_pipeline) {
        fprintf(stderr, "ds4: polar MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    g_polar_allocator = [g_device newCommandAllocatorWithDescriptor:[MTL4CommandAllocatorDescriptor new] error:&err];
    if (!g_polar_allocator) {
        fprintf(stderr, "ds4: polar MTL4 allocator failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    g_polar_queue = [g_device newMTL4CommandQueueWithDescriptor:[MTL4CommandQueueDescriptor new] error:&err];
    if (!g_polar_queue) {
        fprintf(stderr, "ds4: polar MTL4 queue failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: polar MTL4 pipeline initialized "
                    "(threadExecutionWidth=%lu maxThreadsPerTg=%lu)\n",
            (unsigned long)g_polar_pipeline.threadExecutionWidth,
            (unsigned long)g_polar_pipeline.maxTotalThreadsPerThreadgroup);
    g_polar_init_ok = 1;
    return 1;
}

/* Polar canary: dispatch the polar_dot kernel on deterministic synthetic inputs
 * (all-ones hidden, level[0]=1.0, mag code 0, phase code 0 → angle 0 in 9-entry
 * LUT). Expected output per packet = pairs × 1.0. Reports GPU elapsed via
 * MTL4CommitFeedback. Returns 1 on success, 0 on failure. */
int ds4_gpu_mtl4_polar_dot_canary(uint32_t packets, uint32_t pairs) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_polar_pipeline_init()) return 0;
    if (packets == 0 || pairs == 0) return 0;

    @autoreleasepool {
        NSError *err = nil;
        const NSUInteger pairCount = (NSUInteger)packets * pairs;
        const NSUInteger scalarCount = pairCount * 2;

        id<MTLBuffer> mag       = [g_device newBufferWithLength:pairCount options:MTLResourceStorageModeShared];
        id<MTLBuffer> phase     = [g_device newBufferWithLength:pairCount options:MTLResourceStorageModeShared];
        id<MTLBuffer> levels    = [g_device newBufferWithLength:packets * 4 * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> hidden    = [g_device newBufferWithLength:scalarCount * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> cosLut    = [g_device newBufferWithLength:9 * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> sinLut    = [g_device newBufferWithLength:9 * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> out       = [g_device newBufferWithLength:packets * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> pairsBuf  = [g_device newBufferWithLength:sizeof(uint32_t) options:MTLResourceStorageModeShared];
        if (!mag || !phase || !levels || !hidden || !cosLut || !sinLut || !out || !pairsBuf) return 0;

        memset(mag.contents, 0, pairCount);
        memset(phase.contents, 4, pairCount); /* phase code 4 → angle 0 in 9-entry LUT */
        float *lvl = (float *)levels.contents;
        for (uint32_t p = 0; p < packets; p++) {
            lvl[p * 4 + 0] = 1.0f;
            lvl[p * 4 + 1] = 0.5f;
            lvl[p * 4 + 2] = 0.25f;
            lvl[p * 4 + 3] = 0.125f;
        }
        float *hid = (float *)hidden.contents;
        for (NSUInteger i = 0; i < scalarCount; i++) hid[i] = 1.0f;
        float *cosP = (float *)cosLut.contents;
        float *sinP = (float *)sinLut.contents;
        for (int code = -4; code <= 4; code++) {
            float angle = (float)code * 0.78539816339744830962f;
            cosP[code + 4] = cosf(angle);
            sinP[code + 4] = sinf(angle);
        }
        *((uint32_t *)pairsBuf.contents) = (uint32_t)pairs;

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) {
            fprintf(stderr, "ds4: polar residency set: %s\n",
                    err ? err.localizedDescription.UTF8String : "(no error)");
            return 0;
        }
        id<MTLAllocation> allocs[8] = {
            (id<MTLAllocation>)mag, (id<MTLAllocation>)phase,
            (id<MTLAllocation>)levels, (id<MTLAllocation>)hidden,
            (id<MTLAllocation>)cosLut, (id<MTLAllocation>)sinLut,
            (id<MTLAllocation>)out, (id<MTLAllocation>)pairsBuf,
        };
        [residency addAllocations:allocs count:8];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 8;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) {
            fprintf(stderr, "ds4: polar argument table: %s\n",
                    err ? err.localizedDescription.UTF8String : "(no error)");
            return 0;
        }
        [argTable setAddress:mag.gpuAddress atIndex:0];
        [argTable setAddress:phase.gpuAddress atIndex:1];
        [argTable setAddress:levels.gpuAddress atIndex:2];
        [argTable setAddress:hidden.gpuAddress atIndex:3];
        [argTable setAddress:cosLut.gpuAddress atIndex:4];
        [argTable setAddress:sinLut.gpuAddress atIndex:5];
        [argTable setAddress:out.gpuAddress atIndex:6];
        [argTable setAddress:pairsBuf.gpuAddress atIndex:7];

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) return 0;
        [enc setComputePipelineState:g_polar_pipeline];
        [enc setArgumentTable:argTable];
        [enc dispatchThreadgroups:MTLSizeMake(packets, 1, 1)
            threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0;
        __block CFTimeInterval gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime;
            gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 10LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) { fprintf(stderr, "ds4: polar canary timeout\n"); return 0; }
        if (fbErr) { fprintf(stderr, "ds4: polar canary feedback err: %s\n", fbErr.localizedDescription.UTF8String); return 0; }

        float *outPtr = (float *)out.contents;
        float expected = (float)pairs * 1.0f;
        float maxAbsErr = 0.0f;
        for (uint32_t p = 0; p < packets; p++) {
            float diff = fabsf(outPtr[p] - expected);
            if (diff > maxAbsErr) maxAbsErr = diff;
        }
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        fprintf(stderr,
                "ds4: polar MTL4 canary packets=%u pairs=%u expected=%.3f "
                "out[0]=%.3f max_abs_err=%.3e gpu_elapsed=%.6f ms (%.0f ns/packet)\n",
                packets, pairs, (double)expected, (double)outPtr[0],
                (double)maxAbsErr, gpuMs, gpuMs * 1e6 / (double)packets);
        return maxAbsErr < 1e-3f ? 1 : 0;
    }
}

/* ============================================================ */
/* MTL4 Hadamard-16 widened kernel — task #653                  */
/* ============================================================ */
/* silv 2026-05-27 "crash velocity ship": MTL4 dispatch + widened
 * kernel (16 blocks per threadgroup, 256 threads) for the Hadamard-16
 * codec primitive. Reuses polar's compiler/queue/allocator.
 *
 * Speedup geometry:
 *   - MTL4 dispatch overhead < MTL dispatch overhead per CB
 *   - Widened kernel: 256 threads × 16-block parallelism in scratch =
 *     16× fewer threadgroups per tensor
 *
 * Self-inverse falsifier: applying H twice to a buffer should recover
 * the original within FP16 precision. Synthetic canary fills with
 * deterministic random FP16, dispatches twice, checks max|err| < FP16
 * floor.
 *
 * Note: the MTL4 widened kernel source is inlined here (a copy of
 * kernel_hadamard16_fp16_batched_wide from metal/hadamard.metal). This
 * keeps the MTL4 path self-contained against the polar-style
 * MTL4Compiler/Library. The regular MTL path keeps using the source
 * concatenated into ds4_gpu_full_source.
 */

static id<MTLComputePipelineState> g_hadamard_mtl4_pipeline;
static int g_hadamard_mtl4_init_attempted;
static int g_hadamard_mtl4_init_ok;

static int ds4_hadamard_mtl4_pipeline_init(void) {
    if (g_hadamard_mtl4_init_attempted) return g_hadamard_mtl4_init_ok;
    g_hadamard_mtl4_init_attempted = 1;

    if (!ds4_polar_pipeline_init()) return 0; /* reuse compiler/queue/allocator */

    /* MTL4 ArgumentTable binds via gpuAddress + setAddress, which requires
     * `device const` storage on the kernel side. Using `constant &` (like the
     * regular MTL path's setBytes-bound args) reads zero/garbage through the
     * MTL4 binding — first crash this session, caught by mtl4_canary at
     * rel_L2=1.57 on a 1×16 minimum-scale test. */
    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct ds4_metal_args_hadamard16_batched {\n"
         "  uint32_t n_rows;\n"
         "  uint32_t blocks_per_row;\n"
         "  uint64_t row_stride_bytes;\n"
         "};\n"
         "kernel void hadamard16_wide(\n"
         "    device const ds4_metal_args_hadamard16_batched * args_ptr [[buffer(0)]],\n"
         "    device half * x [[buffer(1)]],\n"
         "    threadgroup half * scratch [[threadgroup(0)]],\n"
         "    uint2 tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort tid [[thread_index_in_threadgroup]]) {\n"
         "  const uint n_rows = args_ptr[0].n_rows;\n"
         "  const uint blocks_per_row = args_ptr[0].blocks_per_row;\n"
         "  const uint64_t row_stride_bytes = args_ptr[0].row_stride_bytes;\n"
         "  const uint row = tgpig.x;\n"
         "  const uint tg_block = tgpig.y;\n"
         "  const ushort block_in_tg = tid / 16;\n"
         "  const ushort elem = tid % 16;\n"
         "  const uint global_block = tg_block * 16u + (uint)block_in_tg;\n"
         "  if (row >= n_rows) return;\n"
         "  const bool active = (global_block < blocks_per_row);\n"
         "  device half * row_ptr = (device half *)((device char *)x + (uint64_t)row * row_stride_bytes);\n"
         "  device half * block_ptr = row_ptr + (uint64_t)global_block * 16u;\n"
         "  threadgroup half * sub = scratch + (uint)block_in_tg * 16u;\n"
         "  if (active) sub[elem] = block_ptr[elem];\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  for (uint stride = 1u; stride < 16u; stride <<= 1u) {\n"
         "    if (active && ((elem & stride) == 0u)) {\n"
         "      const ushort base = (elem & ~(2u * stride - 1u)) + (elem & (stride - 1u));\n"
         "      const float a = (float)sub[base];\n"
         "      const float b = (float)sub[base + stride];\n"
         "      sub[base] = (half)(a + b);\n"
         "      sub[base + stride] = (half)(a - b);\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  if (active) block_ptr[elem] = (half)((float)sub[elem] * 0.25f);\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_hadamard16_wide";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: hadamard MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"hadamard16_wide";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_hadamard_mtl4_pipeline = [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                                                   compilerTaskOptions:nil
                                                                                 error:&err];
    if (!g_hadamard_mtl4_pipeline) {
        fprintf(stderr, "ds4: hadamard MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: hadamard MTL4 pipeline initialized "
                    "(threadExecutionWidth=%lu maxThreadsPerTg=%lu)\n",
            (unsigned long)g_hadamard_mtl4_pipeline.threadExecutionWidth,
            (unsigned long)g_hadamard_mtl4_pipeline.maxTotalThreadsPerThreadgroup);
    g_hadamard_mtl4_init_ok = 1;
    return 1;
}

/* silv 2026-05-27 task #654 next-level: reusable MTL4 Hadamard apply.
 *
 * Encode `n_apply` consecutive forward H passes on a caller-owned MTLBuffer.
 * `tensor` must hold n_rows × n_in halves at offset 0. n_in must be % 16.
 *
 * The widened kernel processes 16 blocks per threadgroup (256 threads).
 * Each application: dispatch (n_rows, ceil(blocks_per_row/16), 1) threadgroups.
 * Between applications: barrierAfterEncoderStages(Dispatch) so the second
 * H reads what the first wrote (R1 fix proven on the canary, rel_L2=6.22e-4
 * for the round-trip H×H=I).
 *
 * `tensor` and `argsBuf` MUST be in the residency set passed in (caller
 * owns residency lifecycle so multiple apply()s in one pass share it).
 * The argsBuf contents (n_rows, blocks_per_row, row_stride_bytes) must
 * be written by the caller before this is called.
 *
 * Returns 1 on success, 0 on failure (pipeline not initialized).
 *
 * The canary wraps this with synthetic data + round-trip verification;
 * runtime callers (basis-aware sidecar dispatch, encode-time validators)
 * use this directly. */
static int ds4_gpu_mtl4_hadamard16_apply_encoder(
        id<MTL4ComputeCommandEncoder> enc,
        id<MTLBuffer> tensor,
        id<MTLBuffer> argsBuf,
        id<MTL4ArgumentTable> argTable,
        uint32_t n_rows,
        uint32_t blocks_per_row,
        uint32_t n_apply) {
    if (!enc || !tensor || !argsBuf || !argTable) return 0;
    if (!g_hadamard_mtl4_pipeline) return 0;
    if (n_rows == 0u || blocks_per_row == 0u || n_apply == 0u) return 0;

    [argTable setAddress:argsBuf.gpuAddress atIndex:0];
    [argTable setAddress:tensor.gpuAddress atIndex:1];

    const uint32_t tg_y = (blocks_per_row + 15u) / 16u;
    const MTLSize grid = MTLSizeMake(n_rows, tg_y, 1);
    const MTLSize tg   = MTLSizeMake(256, 1, 1);
    /* 16 blocks × 16 halves × 2 bytes = 512 B threadgroup scratch. */
    [enc setComputePipelineState:g_hadamard_mtl4_pipeline];
    [enc setArgumentTable:argTable];
    [enc setThreadgroupMemoryLength:(NSUInteger)(16 * 16 * sizeof(uint16_t)) atIndex:0];

    for (uint32_t i = 0; i < n_apply; i++) {
        [enc dispatchThreadgroups:grid threadsPerThreadgroup:tg];
        if (i + 1 < n_apply) {
            /* Same-encoder sequential dispatches need explicit barrier per R1. */
            [enc barrierAfterEncoderStages:MTLStageDispatch
                       beforeEncoderStages:MTLStageDispatch
                         visibilityOptions:MTL4VisibilityOptionDevice];
        }
    }
    return 1;
}

/* Public-facing API: apply H once to an n_rows × n_in FP16 buffer.
 * Standalone — allocates residency / args / encoder / queue internally.
 * For multi-apply sequences (encode pipeline composing multiple
 * transforms) callers should drive the encoder directly via the
 * static helper above + the residency set they manage.
 *
 * Returns 1 on success, 0 on failure (e.g. pipeline init failed or n_in
 * not divisible by 16). */
int ds4_gpu_mtl4_hadamard16_apply(_Float16 *host_buf, uint32_t n_rows, uint32_t n_in) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_hadamard_mtl4_pipeline_init()) return 0;
    if (!host_buf || n_rows == 0u || n_in == 0u || (n_in % 16u) != 0u) return 0;
    const uint32_t blocks_per_row = n_in / 16u;
    const NSUInteger n_halves = (NSUInteger)n_rows * (NSUInteger)n_in;
    const NSUInteger byte_count = n_halves * sizeof(uint16_t);

    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> tensor = [g_device newBufferWithLength:byte_count
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:sizeof(ds4_gpu_hadamard16_batched_args)
                                                     options:MTLResourceStorageModeShared];
        if (!tensor || !argsBuf) return 0;

        memcpy(tensor.contents, host_buf, byte_count);
        ds4_gpu_hadamard16_batched_args *args = (ds4_gpu_hadamard16_batched_args *)argsBuf.contents;
        args->n_rows = n_rows;
        args->blocks_per_row = blocks_per_row;
        args->row_stride_bytes = (uint64_t)n_in * sizeof(uint16_t);

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) return 0;
        id<MTLAllocation> allocs[2] = { (id<MTLAllocation>)tensor, (id<MTLAllocation>)argsBuf };
        [residency addAllocations:allocs count:2];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 2;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) return 0;

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) return 0;
        if (!ds4_gpu_mtl4_hadamard16_apply_encoder(enc, tensor, argsBuf, argTable,
                                                    n_rows, blocks_per_row, 1u)) {
            return 0;
        }
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0 || fbErr) return 0;

        memcpy(host_buf, tensor.contents, byte_count);
        return 1;
    }
}

/* MTL4 Hadamard canary: fill an n_rows×n_in FP16 buffer with deterministic
 * random values, dispatch H twice (H*H=I), check max|err| against FP16
 * precision floor. n_in must be divisible by 16. Reports per-tensor GPU
 * elapsed via MTL4CommitFeedback. Returns 1 on success, 0 on failure. */
int ds4_gpu_mtl4_hadamard16_canary(uint32_t n_rows, uint32_t n_in) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_hadamard_mtl4_pipeline_init()) return 0;
    if (n_rows == 0u || n_in == 0u || (n_in % 16u) != 0u) {
        fprintf(stderr, "ds4: hadamard MTL4 canary: n_in=%u must be n_rows>0 and n_in%%16==0\n", n_in);
        return 0;
    }
    const uint32_t blocks_per_row = n_in / 16u;
    const NSUInteger n_halves = (NSUInteger)n_rows * (NSUInteger)n_in;
    const NSUInteger byte_count = n_halves * sizeof(uint16_t);

    @autoreleasepool {
        NSError *err = nil;

        id<MTLBuffer> tensor = [g_device newBufferWithLength:byte_count
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:sizeof(ds4_gpu_hadamard16_batched_args)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> orig = [g_device newBufferWithLength:byte_count
                                                  options:MTLResourceStorageModeShared];
        if (!tensor || !argsBuf || !orig) return 0;

        /* Fill with deterministic FP16 in [-0.5, 0.5]. _Float16 cast via uint16
         * bit pattern would be opaque; use float conversion for clarity. */
        _Float16 *src = (_Float16 *)tensor.contents;
        _Float16 *ref = (_Float16 *)orig.contents;
        uint32_t s = 0xC0FFEE0Du;
        for (NSUInteger i = 0; i < n_halves; i++) {
            s ^= s << 13; s ^= s >> 17; s ^= s << 5;
            const float v = ((float)(int32_t)s / (float)0x80000000u) * 0.5f;
            src[i] = (_Float16)v;
            ref[i] = (_Float16)v;
        }

        ds4_gpu_hadamard16_batched_args *args = (ds4_gpu_hadamard16_batched_args *)argsBuf.contents;
        args->n_rows = n_rows;
        args->blocks_per_row = blocks_per_row;
        args->row_stride_bytes = (uint64_t)n_in * sizeof(uint16_t);

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) {
            fprintf(stderr, "ds4: hadamard residency: %s\n",
                    err ? err.localizedDescription.UTF8String : "(no error)");
            return 0;
        }
        id<MTLAllocation> allocs[2] = { (id<MTLAllocation>)tensor, (id<MTLAllocation>)argsBuf };
        [residency addAllocations:allocs count:2];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 2;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) {
            fprintf(stderr, "ds4: hadamard arg table: %s\n",
                    err ? err.localizedDescription.UTF8String : "(no error)");
            return 0;
        }
        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) return 0;

        /* Apply H twice via the reusable encoder helper. R1 barrier between
         * dispatches is handled inside (n_apply > 1). */
        if (!ds4_gpu_mtl4_hadamard16_apply_encoder(enc, tensor, argsBuf, argTable,
                                                    n_rows, blocks_per_row, 2u)) {
            [residency endResidency];
            return 0;
        }
        const uint32_t tg_y = (blocks_per_row + 15u) / 16u;

        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0;
        __block CFTimeInterval gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime;
            gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) { fprintf(stderr, "ds4: hadamard canary timeout\n"); return 0; }
        if (fbErr) {
            fprintf(stderr, "ds4: hadamard canary feedback err: %s\n",
                    fbErr.localizedDescription.UTF8String);
            return 0;
        }

        /* Compare H(H(x)) vs original. FP16 round-trip floor ~5e-3. */
        float maxAbsErr = 0.0f;
        double sum_sq_diff = 0.0;
        double sum_sq_ref  = 0.0;
        for (NSUInteger i = 0; i < n_halves; i++) {
            const float a = (float)src[i];
            const float b = (float)ref[i];
            const float d = fabsf(a - b);
            if (d > maxAbsErr) maxAbsErr = d;
            sum_sq_diff += (double)d * (double)d;
            sum_sq_ref  += (double)b * (double)b;
        }
        const double rel_l2 = sqrt(sum_sq_diff / (sum_sq_ref + 1e-12));
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        const double n_dispatches_naive = (double)n_rows * (double)blocks_per_row;
        const double n_dispatches_wide  = (double)n_rows * (double)tg_y;
        fprintf(stderr,
                "ds4: hadamard MTL4 canary n_rows=%u n_in=%u (blocks/row=%u, tg_y=%u): "
                "max_abs_err=%.4e rel_L2=%.4e gpu_elapsed=%.4f ms (2× H dispatches), "
                "naive_dispatches=%.0f wide_dispatches=%.0f reduction=%.1f×\n",
                n_rows, n_in, blocks_per_row, tg_y,
                (double)maxAbsErr, rel_l2, gpuMs,
                n_dispatches_naive, n_dispatches_wide,
                n_dispatches_naive / n_dispatches_wide);
        return rel_l2 < 1.0e-2 ? 1 : 0;
    }
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_softplus_sqrt_f32_4                   */
/* silv 2026-05-27 task #670 — first of the 74-kernel MTL4 sweep.
 *
 * Smallest blast radius port: 1 args struct + 2 buffers + simple math.
 * Classic-MTL version is at metal/unary.metal:290 (already ICB-captured
 * as Phase 4 #558). The MTL4 port duplicates the pipeline against the
 * MTL4 compiler so it can be MTL4-dispatched with ArgumentTable bindings.
 *
 * Storage-class migration (R1 lesson from Hadamard):
 *   classic: constant ds4_metal_args_unary & args
 *   MTL4:    device const ds4_metal_args_unary *args_ptr
 *
 * The classic kernel can't be reused because MTL4 ArgumentTable bindings
 * go via gpuAddress + setAddress, which require device storage class.
 *
 * Reduced struct: this kernel only reads ne00, ne01, ne0, nb01, nb1 —
 * we only declare the fields it actually uses. The classic version
 * shares the full ds4_metal_args_unary struct with other unary kernels;
 * for MTL4 we just need this kernel's subset.
 * ============================================================ */
static id<MTLComputePipelineState> g_softplus_sqrt_mtl4_pipeline;
static int g_softplus_sqrt_mtl4_init_attempted;
static int g_softplus_sqrt_mtl4_init_ok;

static int ds4_softplus_sqrt_mtl4_pipeline_init(void) {
    if (g_softplus_sqrt_mtl4_init_attempted) return g_softplus_sqrt_mtl4_init_ok;
    g_softplus_sqrt_mtl4_init_attempted = 1;

    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct ds4_softplus_sqrt_args {\n"
         "  int32_t  ne00;\n"
         "  int32_t  ne01;\n"
         "  int32_t  ne0;\n"
         "  uint64_t nb01;\n"
         "  uint64_t nb1;\n"
         "};\n"
         "kernel void softplus_sqrt_f32_4_mtl4(\n"
         "    device const ds4_softplus_sqrt_args *args_ptr [[buffer(0)]],\n"
         "    device const char *src [[buffer(1)]],\n"
         "    device char *dst [[buffer(2)]],\n"
         "    uint3 tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort3 tpitg [[thread_position_in_threadgroup]],\n"
         "    ushort3 ntg [[threads_per_threadgroup]]) {\n"
         "  const int ne01 = args_ptr->ne01;\n"
         "  const int ne0 = args_ptr->ne0;\n"
         "  const uint64_t nb01 = args_ptr->nb01;\n"
         "  const uint64_t nb1 = args_ptr->nb1;\n"
         "  const int k0 = (int)tgpig.x / ne01;\n"
         "  const int i01 = (int)tgpig.x - k0 * ne01;\n"
         "  const int i0 = k0 * (int)ntg.x + (int)tpitg.x;\n"
         "  if (i0 >= ne0) return;\n"
         "  device const float4 *s = (device const float4 *)(src + i01 * nb01);\n"
         "  device float4 *d = (device float4 *)(dst + i01 * nb1);\n"
         "  const float4 x = s[i0];\n"
         "  const float4 sp = select(log(1.0f + exp(x)), x, x > 20.0f);\n"
         "  d[i0] = sqrt(sp);\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_softplus_sqrt_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: softplus_sqrt MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"softplus_sqrt_f32_4_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_softplus_sqrt_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil
                                                         error:&err];
    if (!g_softplus_sqrt_mtl4_pipeline) {
        fprintf(stderr, "ds4: softplus_sqrt MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: softplus_sqrt MTL4 pipeline initialized "
                    "(threadExecutionWidth=%lu maxThreadsPerTg=%lu)\n",
            (unsigned long)g_softplus_sqrt_mtl4_pipeline.threadExecutionWidth,
            (unsigned long)g_softplus_sqrt_mtl4_pipeline.maxTotalThreadsPerThreadgroup);
    g_softplus_sqrt_mtl4_init_ok = 1;
    return 1;
}

/* Canary: feed deterministic input, verify softplus(x) followed by sqrt
 * matches CPU reference within FP32 precision. */
int ds4_gpu_mtl4_softplus_sqrt_canary(uint32_t n_rows, uint32_t n_cols) {
    if (n_cols % 4u != 0u) {
        fprintf(stderr, "ds4: softplus_sqrt canary requires n_cols %% 4 == 0 (got %u)\n", n_cols);
        return 0;
    }
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_softplus_sqrt_mtl4_pipeline_init()) return 0;

    const uint64_t n_elems = (uint64_t)n_rows * n_cols;
    float *host_in = (float *)calloc(n_elems, sizeof(float));
    float *host_out = (float *)calloc(n_elems, sizeof(float));
    float *host_ref = (float *)calloc(n_elems, sizeof(float));
    if (!host_in || !host_out || !host_ref) {
        free(host_in); free(host_out); free(host_ref); return 0;
    }
    /* Deterministic test pattern: spans softplus's domain — negative,
     * zero, small positive, the > 20 fast-path. */
    for (uint64_t i = 0; i < n_elems; i++) {
        host_in[i] = -3.0f + (float)(i % 256) * 0.1f;
    }
    /* CPU reference */
    for (uint64_t i = 0; i < n_elems; i++) {
        const float x = host_in[i];
        const float sp = (x > 20.0f) ? x : logf(1.0f + expf(x));
        host_ref[i] = sqrtf(sp);
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:32 options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithLength:n_elems * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:n_elems * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        memcpy(srcBuf.contents, host_in, n_elems * sizeof(float));

        struct {
            int32_t ne00, ne01, ne0;
            uint64_t nb01, nb1;
        } args = {
            .ne00 = (int32_t)n_cols,
            .ne01 = (int32_t)n_rows,
            .ne0  = (int32_t)(n_cols / 4),  /* float4 lane count */
            .nb01 = (uint64_t)n_cols * sizeof(float),
            .nb1  = (uint64_t)n_cols * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)srcBuf, (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_softplus_sqrt_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const MTLSize grid = MTLSizeMake(n_rows, 1, 1);
                const MTLSize tg = MTLSizeMake(n_cols / 4, 1, 1);
                [enc dispatchThreadgroups:grid threadsPerThreadgroup:tg];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
                    (void)feedback; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 10LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_out, dstBuf.contents, n_elems * sizeof(float));
                    rc = 1;
                } else {
                    fprintf(stderr, "ds4: softplus_sqrt canary timeout\n");
                }
            } else {
                fprintf(stderr, "ds4: softplus_sqrt argument table: %s\n",
                        err ? err.localizedDescription.UTF8String : "(no error)");
            }
        } else {
            fprintf(stderr, "ds4: softplus_sqrt residency set: %s\n",
                    err ? err.localizedDescription.UTF8String : "(no error)");
        }
    }
    if (!rc) { free(host_in); free(host_out); free(host_ref); return 0; }

    /* Compare host_out vs host_ref */
    double max_abs_diff = 0.0;
    double sum_sq = 0.0;
    for (uint64_t i = 0; i < n_elems; i++) {
        const double d = (double)(host_out[i] - host_ref[i]);
        if (fabs(d) > max_abs_diff) max_abs_diff = fabs(d);
        sum_sq += d * d;
    }
    const double rms = sqrt(sum_sq / (double)n_elems);
    fprintf(stderr,
        "ds4: softplus_sqrt MTL4 canary n_rows=%u n_cols=%u "
        "max_abs_diff=%.6e rms=%.6e\n",
        n_rows, n_cols, max_abs_diff, rms);
    const int ok = (max_abs_diff < 1.0e-4) ? 1 : 0;

    free(host_in); free(host_out); free(host_ref);
    return ok;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_router_weights_one (task #671)        */
/* Second of 74-kernel sweep. metal/dsv4_misc.metal:263.        */
/* 3 buffers (probs, selected, weights), NO args struct, body   */
/* normalizes 6 expert weights from top-K probs.                */
/* ============================================================ */
static id<MTLComputePipelineState> g_router_weights_one_mtl4_pipeline;
static int g_router_weights_one_mtl4_init_attempted;
static int g_router_weights_one_mtl4_init_ok;

static int ds4_router_weights_one_mtl4_pipeline_init(void) {
    if (g_router_weights_one_mtl4_init_attempted) return g_router_weights_one_mtl4_init_ok;
    g_router_weights_one_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "kernel void router_weights_one_mtl4(\n"
         "    device const float *probs [[buffer(0)]],\n"
         "    device const int *selected [[buffer(1)]],\n"
         "    device float *weights [[buffer(2)]],\n"
         "    uint tid [[thread_position_in_grid]]) {\n"
         "  if (tid >= 6) return;\n"
         "  float sum = 0.0f;\n"
         "  for (uint i = 0; i < 6; i++) sum += probs[selected[i]];\n"
         "  sum = max(sum, 6.103515625e-5f);\n"
         "  weights[tid] = probs[selected[tid]] / sum * 1.5f;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_router_weights_one_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: router_weights_one MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"router_weights_one_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 32;
    g_router_weights_one_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_router_weights_one_mtl4_pipeline) {
        fprintf(stderr, "ds4: router_weights_one MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: router_weights_one MTL4 pipeline initialized\n");
    g_router_weights_one_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_router_weights_one_canary(void) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_router_weights_one_mtl4_pipeline_init()) return 0;

    /* Synthetic: 256 probs (uniform), top-6 selected = {0, 50, 100, 150, 200, 250}.
     * Each selected entry has prob = 1/256, sum = 6/256, weight = (1/256) / (6/256) * 1.5
     * = 0.25 for each. */
    float host_probs[256];
    int host_selected[6] = {0, 50, 100, 150, 200, 250};
    float host_weights_gpu[6] = {0};
    float host_weights_ref[6] = {0};
    for (int i = 0; i < 256; i++) host_probs[i] = 1.0f / 256.0f;

    /* CPU reference */
    float sum = 0.0f;
    for (int i = 0; i < 6; i++) sum += host_probs[host_selected[i]];
    sum = sum > 6.103515625e-5f ? sum : 6.103515625e-5f;
    for (int i = 0; i < 6; i++) host_weights_ref[i] = host_probs[host_selected[i]] / sum * 1.5f;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> probsBuf = [g_device newBufferWithBytes:host_probs
                                                       length:sizeof(host_probs)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> selBuf = [g_device newBufferWithBytes:host_selected
                                                     length:sizeof(host_selected)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithLength:6 * sizeof(float)
                                                   options:MTLResourceStorageModeShared];

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)probsBuf, (id<MTLAllocation>)selBuf, (id<MTLAllocation>)wBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:probsBuf.gpuAddress atIndex:0];
                [argTable setAddress:selBuf.gpuAddress atIndex:1];
                [argTable setAddress:wBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_router_weights_one_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(8, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_weights_gpu, wBuf.contents, sizeof(host_weights_gpu));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) return 0;

    double max_abs = 0.0;
    for (int i = 0; i < 6; i++) {
        double d = fabs((double)(host_weights_gpu[i] - host_weights_ref[i]));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: router_weights_one MTL4 canary expected[0]=%.4f gpu[0]=%.4f max_abs=%.4e\n",
        (double)host_weights_ref[0], (double)host_weights_gpu[0], max_abs);
    return max_abs < 1.0e-5 ? 1 : 0;
}

/* Forward declarations of the pool API (defined later in the file). */
static id<MTL4ArgumentTable> ds4_mtl4_pool_acquire(NSUInteger n_bindings);
static void ds4_mtl4_pool_release(id<MTL4ArgumentTable> at, NSUInteger n_bindings);

/* silv 2026-05-27 task #679 — amortization demonstration.
 *
 * Runs router_weights_one back-to-back N times, using the ArgumentTable
 * pool. After warm-up, the pool's `alloc_count` should stay at 1 while
 * `acquire_count` scales with N. This proves the persistence path:
 * consecutive dispatches reuse the same table.
 *
 * Reports correctness (functional regression guard against the pool
 * breaking the kernel output) AND the alloc/acquire ratio. */
int ds4_gpu_mtl4_router_weights_one_amortized_canary(uint32_t n_iterations) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_router_weights_one_mtl4_pipeline_init()) return 0;
    if (n_iterations == 0) n_iterations = 100;

    float host_probs[256];
    int host_selected[6] = {0, 50, 100, 150, 200, 250};
    float host_weights_gpu[6] = {0};
    for (int i = 0; i < 256; i++) host_probs[i] = 1.0f / 256.0f;

    /* Pre-state */
    uint64_t acq_before = 0, alloc_before = 0, rel_before = 0;
    ds4_gpu_mtl4_pool_stats(&acq_before, &alloc_before, &rel_before);

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> probsBuf = [g_device newBufferWithBytes:host_probs
                                                       length:sizeof(host_probs)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> selBuf = [g_device newBufferWithBytes:host_selected
                                                     length:sizeof(host_selected)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithLength:6 * sizeof(float)
                                                   options:MTLResourceStorageModeShared];

        /* Persistent residency set across iterations — proper amortization. */
        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)probsBuf, (id<MTLAllocation>)selBuf, (id<MTLAllocation>)wBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];
            [g_polar_queue addResidencySet:residency];

            rc = 1;
            for (uint32_t iter = 0; iter < n_iterations && rc; iter++) {
                /* ACQUIRE pool table (allocates first-time, reuses thereafter) */
                id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(3);
                if (!argTable) { rc = 0; break; }
                [argTable setAddress:probsBuf.gpuAddress atIndex:0];
                [argTable setAddress:selBuf.gpuAddress atIndex:1];
                [argTable setAddress:wBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_router_weights_one_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(8, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                if (waitRes != 0) { rc = 0; }

                /* RELEASE back to pool (preserves binding state) */
                ds4_mtl4_pool_release(argTable, 3);
            }
            if (rc) {
                memcpy(host_weights_gpu, wBuf.contents, sizeof(host_weights_gpu));
            }
            [residency endResidency];
        }
    }
    if (!rc) return 0;

    /* Post-state */
    uint64_t acq_after = 0, alloc_after = 0, rel_after = 0;
    ds4_gpu_mtl4_pool_stats(&acq_after, &alloc_after, &rel_after);

    /* Verify correctness still holds */
    const float ref = (1.0f / 256.0f) / (6.0f / 256.0f) * 1.5f;  /* = 0.25 */
    double max_abs = 0.0;
    for (int i = 0; i < 6; i++) {
        double d = fabs((double)(host_weights_gpu[i] - ref));
        if (d > max_abs) max_abs = d;
    }
    const uint64_t acq_delta = acq_after - acq_before;
    const uint64_t alloc_delta = alloc_after - alloc_before;
    fprintf(stderr,
        "ds4: router_weights_one amortized canary n_iter=%u acquires=%llu "
        "allocs=%llu releases=%llu pool_hit_rate=%.1f%% "
        "gpu[0]=%.4f max_abs=%.4e\n",
        n_iterations,
        (unsigned long long)acq_delta,
        (unsigned long long)alloc_delta,
        (unsigned long long)(rel_after - rel_before),
        acq_delta > 0 ? 100.0 * (1.0 - (double)alloc_delta / (double)acq_delta) : 0.0,
        (double)host_weights_gpu[0], max_abs);
    /* Pass criteria: correctness + alloc count << acquire count after warm-up. */
    return (max_abs < 1.0e-5 && alloc_delta <= 1 && acq_delta >= n_iterations) ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_topk_mask (task #672)                  */
/* metal/dsv4_misc.metal:346. Fills mask with -inf;             */
/* topk_mask_scatter then enables selected rows in second pass. */
/* 1 args struct + 2 buffers + small body.                       */
/* ============================================================ */
static id<MTLComputePipelineState> g_topk_mask_mtl4_pipeline;
static int g_topk_mask_mtl4_init_attempted;
static int g_topk_mask_mtl4_init_ok;

static int ds4_topk_mask_mtl4_pipeline_init(void) {
    if (g_topk_mask_mtl4_init_attempted) return g_topk_mask_mtl4_init_ok;
    g_topk_mask_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct topk_mask_args {\n"
         "  int64_t ne00; int64_t ne01;\n"
         "  uint64_t nb00; uint64_t nb01;\n"
         "  int64_t ne0; int64_t ne1;\n"
         "  uint64_t nb0; uint64_t nb1;\n"
         "};\n"
         "kernel void topk_mask_mtl4(\n"
         "    device const topk_mask_args *args_ptr [[buffer(0)]],\n"
         "    device const char *topk [[buffer(1)]],\n"
         "    device char *dst [[buffer(2)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  const int64_t n = args_ptr->ne0 * args_ptr->ne1;\n"
         "  if ((int64_t)gid >= n) return;\n"
         "  const int64_t ic = (int64_t)gid % args_ptr->ne0;\n"
         "  const int64_t it = (int64_t)gid / args_ptr->ne0;\n"
         "  (void)topk;\n"
         "  *((device float *)(dst + ic * args_ptr->nb0 + it * args_ptr->nb1)) = -INFINITY;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_topk_mask_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: topk_mask MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"topk_mask_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_topk_mask_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_topk_mask_mtl4_pipeline) {
        fprintf(stderr, "ds4: topk_mask MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: topk_mask MTL4 pipeline initialized\n");
    g_topk_mask_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_topk_mask_canary(uint32_t ne0, uint32_t ne1) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_topk_mask_mtl4_pipeline_init()) return 0;

    const uint64_t n = (uint64_t)ne0 * ne1;
    float *host_dst = (float *)calloc(n, sizeof(float));
    if (!host_dst) return 0;
    /* Pre-fill with 1.0 to verify GPU writes -INFINITY over it */
    for (uint64_t i = 0; i < n; i++) host_dst[i] = 1.0f;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:64
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> topkBuf = [g_device newBufferWithLength:n * sizeof(int32_t)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithBytes:host_dst
                                                     length:n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];

        struct {
            int64_t ne00, ne01;
            uint64_t nb00, nb01;
            int64_t ne0_, ne1_;
            uint64_t nb0_, nb1_;
        } args = {
            .ne00 = 1, .ne01 = 1, .nb00 = 4, .nb01 = 4,
            .ne0_ = (int64_t)ne0, .ne1_ = (int64_t)ne1,
            .nb0_ = sizeof(float),
            .nb1_ = (uint64_t)ne0 * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)topkBuf, (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:topkBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_topk_mask_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const NSUInteger tg = 256;
                const NSUInteger n_tgs = (n + tg - 1) / tg;
                [enc dispatchThreadgroups:MTLSizeMake(n_tgs, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(tg, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, n * sizeof(float));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) { free(host_dst); return 0; }

    /* All cells should be -INFINITY (or close enough). Use isinf since
     * -ffast-math may treat -INFINITY as undefined. */
    uint64_t n_correct = 0;
    for (uint64_t i = 0; i < n; i++) {
        if (host_dst[i] < -1.0e30f) n_correct++;  /* -INFINITY → large neg */
    }
    fprintf(stderr,
        "ds4: topk_mask MTL4 canary ne0=%u ne1=%u n=%llu correct=%llu first=%g last=%g\n",
        ne0, ne1, (unsigned long long)n, (unsigned long long)n_correct,
        (double)host_dst[0], (double)host_dst[n - 1]);
    free(host_dst);
    return (n_correct == n) ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_topk_mask_scatter (task #673)         */
/* metal/dsv4_misc.metal:366. Companion to topk_mask: writes 0  */
/* at selected rows in the dense compressed-attention mask.      */
/* Same args struct + 2 buffers as topk_mask.                    */
/* ============================================================ */
static id<MTLComputePipelineState> g_topk_mask_scatter_mtl4_pipeline;
static int g_topk_mask_scatter_mtl4_init_attempted;
static int g_topk_mask_scatter_mtl4_init_ok;

static int ds4_topk_mask_scatter_mtl4_pipeline_init(void) {
    if (g_topk_mask_scatter_mtl4_init_attempted) return g_topk_mask_scatter_mtl4_init_ok;
    g_topk_mask_scatter_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct topk_mask_args {\n"
         "  int64_t ne00; int64_t ne01;\n"
         "  uint64_t nb00; uint64_t nb01;\n"
         "  int64_t ne0; int64_t ne1;\n"
         "  uint64_t nb0; uint64_t nb1;\n"
         "};\n"
         "kernel void topk_mask_scatter_mtl4(\n"
         "    device const topk_mask_args *args_ptr [[buffer(0)]],\n"
         "    device const char *topk [[buffer(1)]],\n"
         "    device char *dst [[buffer(2)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  const int64_t n = args_ptr->ne00 * args_ptr->ne01;\n"
         "  if ((int64_t)gid >= n) return;\n"
         "  const int64_t ik = (int64_t)gid % args_ptr->ne00;\n"
         "  const int64_t it = (int64_t)gid / args_ptr->ne00;\n"
         "  const int32_t idx = *((device const int32_t *)(topk + ik * args_ptr->nb00 + it * args_ptr->nb01));\n"
         "  if (idx >= 0 && (int64_t)idx < args_ptr->ne0) {\n"
         "    *((device float *)(dst + (int64_t)idx * args_ptr->nb0 + it * args_ptr->nb1)) = 0.0f;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_topk_mask_scatter_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: topk_mask_scatter MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"topk_mask_scatter_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_topk_mask_scatter_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_topk_mask_scatter_mtl4_pipeline) {
        fprintf(stderr, "ds4: topk_mask_scatter MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: topk_mask_scatter MTL4 pipeline initialized\n");
    g_topk_mask_scatter_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_topk_mask_scatter_canary(uint32_t n_topk, uint32_t n_tokens, uint32_t n_comp) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_topk_mask_scatter_mtl4_pipeline_init()) return 0;

    /* Synthetic: each token has top-k indices = {0, n_comp/2, n_comp-1, -1, -1, ...}.
     * After scatter, dst[idx, token] = 0 for the valid indices. */
    const uint64_t topk_n = (uint64_t)n_topk * n_tokens;
    const uint64_t dst_n = (uint64_t)n_comp * n_tokens;
    int32_t *host_topk = (int32_t *)calloc(topk_n, sizeof(int32_t));
    float *host_dst = (float *)calloc(dst_n, sizeof(float));
    if (!host_topk || !host_dst) { free(host_topk); free(host_dst); return 0; }
    /* Pre-fill dst with -INF marker (we'll zero selected positions). */
    for (uint64_t i = 0; i < dst_n; i++) host_dst[i] = -1.0e30f;
    /* Each token's top-k: first 3 are {0, n_comp/2, n_comp-1}, rest are -1 (skip). */
    for (uint32_t t = 0; t < n_tokens; t++) {
        for (uint32_t k = 0; k < n_topk; k++) {
            int32_t v;
            switch (k) {
                case 0: v = 0; break;
                case 1: v = (int32_t)(n_comp / 2); break;
                case 2: v = (int32_t)(n_comp - 1); break;
                default: v = -1; break;
            }
            host_topk[(uint64_t)t * n_topk + k] = v;
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:64
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> topkBuf = [g_device newBufferWithBytes:host_topk
                                                      length:topk_n * sizeof(int32_t)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithBytes:host_dst
                                                     length:dst_n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];

        struct {
            int64_t ne00, ne01;
            uint64_t nb00, nb01;
            int64_t ne0_, ne1_;
            uint64_t nb0_, nb1_;
        } args = {
            .ne00 = (int64_t)n_topk, .ne01 = (int64_t)n_tokens,
            .nb00 = sizeof(int32_t), .nb01 = (uint64_t)n_topk * sizeof(int32_t),
            .ne0_ = (int64_t)n_comp, .ne1_ = (int64_t)n_tokens,
            .nb0_ = sizeof(float), .nb1_ = (uint64_t)n_comp * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)topkBuf, (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:topkBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_topk_mask_scatter_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const NSUInteger tg = 256;
                const NSUInteger n_tgs = (topk_n + tg - 1) / tg;
                [enc dispatchThreadgroups:MTLSizeMake(n_tgs, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(tg, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, dst_n * sizeof(float));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) { free(host_topk); free(host_dst); return 0; }

    /* Verify: 3 cells per token should be 0; remainder should still be -1e30. */
    uint64_t n_zeroed = 0;
    uint64_t n_untouched = 0;
    for (uint64_t i = 0; i < dst_n; i++) {
        if (host_dst[i] == 0.0f) n_zeroed++;
        else if (host_dst[i] < -1.0e29f) n_untouched++;
    }
    fprintf(stderr,
        "ds4: topk_mask_scatter MTL4 canary n_topk=%u n_tokens=%u n_comp=%u "
        "zeroed=%llu (expected %llu) untouched=%llu\n",
        n_topk, n_tokens, n_comp,
        (unsigned long long)n_zeroed,
        (unsigned long long)(3ULL * n_tokens),
        (unsigned long long)n_untouched);
    free(host_topk); free(host_dst);
    /* Expected 3 zeroed per token (n_topk = 6 but only first 3 valid). */
    return (n_zeroed == 3ULL * n_tokens) ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_indexer_weighted_sum (task #674)      */
/* metal/dsv4_misc.metal:1340. Weighted sum over indexer head    */
/* scores with negative-clip + scale. 1 args + 3 buffers.        */
/* ============================================================ */
static id<MTLComputePipelineState> g_indexer_weighted_sum_mtl4_pipeline;
static int g_indexer_weighted_sum_mtl4_init_attempted;
static int g_indexer_weighted_sum_mtl4_init_ok;

static int ds4_indexer_weighted_sum_mtl4_pipeline_init(void) {
    if (g_indexer_weighted_sum_mtl4_init_attempted) return g_indexer_weighted_sum_mtl4_init_ok;
    g_indexer_weighted_sum_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct iws_args {\n"
         "  int64_t ne00; int64_t ne01; int64_t ne02;\n"
         "  uint64_t nb00; uint64_t nb01; uint64_t nb02;\n"
         "  int64_t ne10; int64_t ne11;\n"
         "  uint64_t nb10; uint64_t nb11;\n"
         "  int64_t ne0; int64_t ne1;\n"
         "  uint64_t nb0; uint64_t nb1;\n"
         "  float scale;\n"
         "};\n"
         "kernel void indexer_weighted_sum_mtl4(\n"
         "    device const iws_args *args_ptr [[buffer(0)]],\n"
         "    device const char *scores [[buffer(1)]],\n"
         "    device const char *weights [[buffer(2)]],\n"
         "    device char *dst [[buffer(3)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  const int64_t n = args_ptr->ne0 * args_ptr->ne1;\n"
         "  if ((int64_t)gid >= n) return;\n"
         "  const int64_t ic = (int64_t)gid % args_ptr->ne0;\n"
         "  const int64_t it = (int64_t)gid / args_ptr->ne0;\n"
         "  float acc = 0.0f;\n"
         "  for (int64_t ih = 0; ih < args_ptr->ne02; ++ih) {\n"
         "    const float s = *((device const float *)(scores + ic * args_ptr->nb00 + it * args_ptr->nb01 + ih * args_ptr->nb02));\n"
         "    const float w = *((device const float *)(weights + ih * args_ptr->nb10 + it * args_ptr->nb11));\n"
         "    acc += max(s, 0.0f) * (w * args_ptr->scale);\n"
         "  }\n"
         "  *((device float *)(dst + ic * args_ptr->nb0 + it * args_ptr->nb1)) = acc;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_indexer_weighted_sum_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: indexer_weighted_sum MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"indexer_weighted_sum_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_indexer_weighted_sum_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_indexer_weighted_sum_mtl4_pipeline) {
        fprintf(stderr, "ds4: indexer_weighted_sum MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: indexer_weighted_sum MTL4 pipeline initialized\n");
    g_indexer_weighted_sum_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_indexer_weighted_sum_canary(uint32_t ne0, uint32_t ne1, uint32_t n_heads) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_indexer_weighted_sum_mtl4_pipeline_init()) return 0;

    /* Synthetic: scores[ic, it, ih] = (ic + it + ih) - 5 (some negative for clip);
     * weights[ih, it] = 1.0; scale = 0.5.
     * Expected: dst[ic, it] = sum_ih max(score, 0) * (1.0 * 0.5). */
    const uint64_t scores_n = (uint64_t)ne0 * ne1 * n_heads;
    const uint64_t weights_n = (uint64_t)n_heads * ne1;
    const uint64_t dst_n = (uint64_t)ne0 * ne1;

    float *host_scores = (float *)calloc(scores_n, sizeof(float));
    float *host_weights = (float *)calloc(weights_n, sizeof(float));
    float *host_dst_gpu = (float *)calloc(dst_n, sizeof(float));
    float *host_dst_ref = (float *)calloc(dst_n, sizeof(float));
    if (!host_scores || !host_weights || !host_dst_gpu || !host_dst_ref) {
        free(host_scores); free(host_weights); free(host_dst_gpu); free(host_dst_ref);
        return 0;
    }
    const float scale = 0.5f;
    for (uint32_t it = 0; it < ne1; it++) {
        for (uint32_t ic = 0; ic < ne0; ic++) {
            for (uint32_t ih = 0; ih < n_heads; ih++) {
                const float s = (float)(int)((int)ic + (int)it + (int)ih - 5);
                host_scores[ic + it * ne0 + ih * ne0 * ne1] = s;
            }
        }
        for (uint32_t ih = 0; ih < n_heads; ih++) host_weights[ih + it * n_heads] = 1.0f;
    }
    /* CPU reference */
    for (uint32_t it = 0; it < ne1; it++) {
        for (uint32_t ic = 0; ic < ne0; ic++) {
            float acc = 0.0f;
            for (uint32_t ih = 0; ih < n_heads; ih++) {
                const float s = host_scores[ic + it * ne0 + ih * ne0 * ne1];
                const float w = host_weights[ih + it * n_heads];
                acc += fmaxf(s, 0.0f) * (w * scale);
            }
            host_dst_ref[ic + it * ne0] = acc;
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:128
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> scoresBuf = [g_device newBufferWithBytes:host_scores
                                                        length:scores_n * sizeof(float)
                                                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> weightsBuf = [g_device newBufferWithBytes:host_weights
                                                         length:weights_n * sizeof(float)
                                                        options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int64_t ne00, ne01, ne02;
            uint64_t nb00, nb01, nb02;
            int64_t ne10, ne11;
            uint64_t nb10, nb11;
            int64_t ne0_, ne1_;
            uint64_t nb0_, nb1_;
            float scale_;
            char pad[4];
        } args = {
            .ne00 = (int64_t)ne0, .ne01 = (int64_t)ne1, .ne02 = (int64_t)n_heads,
            .nb00 = sizeof(float), .nb01 = (uint64_t)ne0 * sizeof(float),
            .nb02 = (uint64_t)ne0 * ne1 * sizeof(float),
            .ne10 = (int64_t)n_heads, .ne11 = (int64_t)ne1,
            .nb10 = sizeof(float), .nb11 = (uint64_t)n_heads * sizeof(float),
            .ne0_ = (int64_t)ne0, .ne1_ = (int64_t)ne1,
            .nb0_ = sizeof(float), .nb1_ = (uint64_t)ne0 * sizeof(float),
            .scale_ = scale,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[4] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)scoresBuf,
                (id<MTLAllocation>)weightsBuf, (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:4];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:scoresBuf.gpuAddress atIndex:1];
                [argTable setAddress:weightsBuf.gpuAddress atIndex:2];
                [argTable setAddress:dstBuf.gpuAddress atIndex:3];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_indexer_weighted_sum_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const NSUInteger tg = 256;
                const NSUInteger n_tgs = (dst_n + tg - 1) / tg;
                [enc dispatchThreadgroups:MTLSizeMake(n_tgs, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(tg, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst_gpu, dstBuf.contents, dst_n * sizeof(float));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) {
        free(host_scores); free(host_weights); free(host_dst_gpu); free(host_dst_ref);
        return 0;
    }

    double max_abs = 0.0;
    for (uint64_t i = 0; i < dst_n; i++) {
        double d = fabs((double)(host_dst_gpu[i] - host_dst_ref[i]));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: indexer_weighted_sum MTL4 canary ne0=%u ne1=%u n_heads=%u "
        "expected[0]=%.4f gpu[0]=%.4f max_abs=%.4e\n",
        ne0, ne1, n_heads,
        (double)host_dst_ref[0], (double)host_dst_gpu[0], max_abs);
    free(host_scores); free(host_weights); free(host_dst_gpu); free(host_dst_ref);
    return max_abs < 1.0e-4 ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_directional_steering_project_f32 (#675)*/
/* metal/dsv4_misc.metal:106. Project x against a steering       */
/* direction; subtract scaled projection. Uses threadgroup       */
/* scratch for parallel reduction.                               */
/* ============================================================ */
static id<MTLComputePipelineState> g_dir_steering_mtl4_pipeline;
static int g_dir_steering_mtl4_init_attempted;
static int g_dir_steering_mtl4_init_ok;

static int ds4_dir_steering_mtl4_pipeline_init(void) {
    if (g_dir_steering_mtl4_init_attempted) return g_dir_steering_mtl4_init_ok;
    g_dir_steering_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct dir_steering_args {\n"
         "  uint32_t width;\n"
         "  uint32_t rows;\n"
         "  uint32_t layer;\n"
         "  uint32_t n_threads;\n"
         "  float scale;\n"
         "};\n"
         "kernel void dir_steering_project_mtl4(\n"
         "    device const dir_steering_args *args_ptr [[buffer(0)]],\n"
         "    device float *x [[buffer(1)]],\n"
         "    device const float *directions [[buffer(2)]],\n"
         "    threadgroup float *scratch [[threadgroup(0)]],\n"
         "    uint row [[threadgroup_position_in_grid]],\n"
         "    uint tid [[thread_position_in_threadgroup]]) {\n"
         "  if (row >= args_ptr->rows || args_ptr->width == 0) return;\n"
         "  device float *xr = x + (uint64_t)row * args_ptr->width;\n"
         "  device const float *dir = directions + (uint64_t)args_ptr->layer * args_ptr->width;\n"
         "  const uint nth = args_ptr->n_threads;\n"
         "  float sum = 0.0f;\n"
         "  for (uint i = tid; i < args_ptr->width; i += nth) sum += xr[i] * dir[i];\n"
         "  scratch[tid] = sum;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  for (uint step = nth >> 1; step > 0; step >>= 1) {\n"
         "    if (tid < step) scratch[tid] += scratch[tid + step];\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  const float coeff = args_ptr->scale * scratch[0];\n"
         "  for (uint i = tid; i < args_ptr->width; i += nth) xr[i] -= coeff * dir[i];\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_dir_steering_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: dir_steering MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"dir_steering_project_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_dir_steering_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_dir_steering_mtl4_pipeline) {
        fprintf(stderr, "ds4: dir_steering MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: dir_steering MTL4 pipeline initialized\n");
    g_dir_steering_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_dir_steering_canary(uint32_t width, uint32_t rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_dir_steering_mtl4_pipeline_init()) return 0;

    /* Synthetic: x[row, i] = sin(i*0.1)+row*0.01; direction = unit-along axis 0
     * (length 1.0 at i=0, 0 elsewhere); scale = 0.5.
     * Expected: dot = x[row, 0]; coeff = 0.5 * dot;
     *           x[row, 0] -= coeff * 1.0 = x[row, 0] - 0.5 * x[row, 0] = 0.5 * x[row, 0].
     *           x[row, i!=0] unchanged. */
    const uint32_t n_threads = 64;
    const uint32_t n_layers = 4;
    const uint32_t layer = 1;
    const float scale = 0.5f;

    const uint64_t x_n = (uint64_t)rows * width;
    const uint64_t dir_n = (uint64_t)n_layers * width;
    float *host_x = (float *)calloc(x_n, sizeof(float));
    float *host_x_ref = (float *)calloc(x_n, sizeof(float));
    float *host_dir = (float *)calloc(dir_n, sizeof(float));
    if (!host_x || !host_x_ref || !host_dir) {
        free(host_x); free(host_x_ref); free(host_dir);
        return 0;
    }
    for (uint64_t i = 0; i < x_n; i++) {
        const uint32_t row = (uint32_t)(i / width);
        const uint32_t col = (uint32_t)(i % width);
        host_x[i] = sinf((float)col * 0.1f) + (float)row * 0.01f;
        host_x_ref[i] = host_x[i];
    }
    /* layer=1 direction: 1.0 at index 0, 0 elsewhere */
    for (uint32_t i = 0; i < width; i++) {
        host_dir[(uint64_t)layer * width + i] = (i == 0) ? 1.0f : 0.0f;
    }
    /* CPU reference */
    for (uint32_t r = 0; r < rows; r++) {
        float dot = 0.0f;
        for (uint32_t i = 0; i < width; i++) {
            dot += host_x_ref[(uint64_t)r * width + i] *
                   host_dir[(uint64_t)layer * width + i];
        }
        const float coeff = scale * dot;
        for (uint32_t i = 0; i < width; i++) {
            host_x_ref[(uint64_t)r * width + i] -=
                coeff * host_dir[(uint64_t)layer * width + i];
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:32
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> xBuf = [g_device newBufferWithBytes:host_x
                                                   length:x_n * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> dirBuf = [g_device newBufferWithBytes:host_dir
                                                     length:dir_n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        struct {
            uint32_t width, rows, layer, n_threads;
            float scale;
        } args = {
            .width = width, .rows = rows, .layer = layer,
            .n_threads = n_threads, .scale = scale,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)xBuf, (id<MTLAllocation>)dirBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:xBuf.gpuAddress atIndex:1];
                [argTable setAddress:dirBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_dir_steering_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* scratch: n_threads * sizeof(float) bytes per threadgroup */
                [enc setThreadgroupMemoryLength:n_threads * sizeof(float) atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(n_threads, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_x, xBuf.contents, x_n * sizeof(float));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) {
        free(host_x); free(host_x_ref); free(host_dir);
        return 0;
    }

    double max_abs = 0.0;
    for (uint64_t i = 0; i < x_n; i++) {
        double d = fabs((double)(host_x[i] - host_x_ref[i]));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: dir_steering MTL4 canary width=%u rows=%u "
        "x[0]=%.4f gpu=%.4f ref=%.4f max_abs=%.4e\n",
        width, rows, (double)host_x[0], (double)host_x[0], (double)host_x_ref[0], max_abs);
    free(host_x); free(host_x_ref); free(host_dir);
    return max_abs < 1.0e-4 ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_sort_i32_rows_asc (task #676)         */
/* metal/dsv4_misc.metal:388. Bitonic-sort each row of top-K    */
/* int32 indices in ascending order. Reuses topk_mask args.     */
/* ============================================================ */
static id<MTLComputePipelineState> g_sort_i32_rows_mtl4_pipeline;
static int g_sort_i32_rows_mtl4_init_attempted;
static int g_sort_i32_rows_mtl4_init_ok;

static int ds4_sort_i32_rows_mtl4_pipeline_init(void) {
    if (g_sort_i32_rows_mtl4_init_attempted) return g_sort_i32_rows_mtl4_init_ok;
    g_sort_i32_rows_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct topk_mask_args {\n"
         "  int64_t ne00; int64_t ne01;\n"
         "  uint64_t nb00; uint64_t nb01;\n"
         "  int64_t ne0; int64_t ne1;\n"
         "  uint64_t nb0; uint64_t nb1;\n"
         "};\n"
         "kernel void sort_i32_rows_asc_mtl4(\n"
         "    device const topk_mask_args *args_ptr [[buffer(0)]],\n"
         "    device const char *src [[buffer(1)]],\n"
         "    device char *dst [[buffer(2)]],\n"
         "    threadgroup int32_t *row_tmp [[threadgroup(0)]],\n"
         "    uint row [[threadgroup_position_in_grid]],\n"
         "    uint tid [[thread_position_in_threadgroup]]) {\n"
         "  const uint top_k = (uint)args_ptr->ne00;\n"
         "  if (row >= (uint)args_ptr->ne01 || tid >= top_k) return;\n"
         "  row_tmp[tid] = *((device const int32_t *)(src + (uint64_t)tid * args_ptr->nb00 + (uint64_t)row * args_ptr->nb01));\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  for (uint k = 2; k <= top_k; k <<= 1) {\n"
         "    for (uint j = k >> 1; j > 0; j >>= 1) {\n"
         "      const uint other = tid ^ j;\n"
         "      if (other > tid && other < top_k) {\n"
         "        const int32_t a = row_tmp[tid];\n"
         "        const int32_t b = row_tmp[other];\n"
         "        const bool up = (tid & k) == 0;\n"
         "        if ((up && a > b) || (!up && a < b)) {\n"
         "          row_tmp[tid] = b;\n"
         "          row_tmp[other] = a;\n"
         "        }\n"
         "      }\n"
         "      threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    }\n"
         "  }\n"
         "  *((device int32_t *)(dst + (uint64_t)tid * args_ptr->nb00 + (uint64_t)row * args_ptr->nb01)) = row_tmp[tid];\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_sort_i32_rows_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: sort_i32_rows MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"sort_i32_rows_asc_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_sort_i32_rows_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_sort_i32_rows_mtl4_pipeline) {
        fprintf(stderr, "ds4: sort_i32_rows MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: sort_i32_rows MTL4 pipeline initialized\n");
    g_sort_i32_rows_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_sort_i32_rows_canary(uint32_t top_k, uint32_t n_rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_sort_i32_rows_mtl4_pipeline_init()) return 0;
    if (top_k == 0 || (top_k & (top_k - 1)) != 0) {
        fprintf(stderr, "ds4: sort_i32_rows canary requires top_k power-of-2 (got %u)\n", top_k);
        return 0;
    }
    if (top_k > 256) {
        fprintf(stderr, "ds4: sort_i32_rows canary requires top_k <= 256 (got %u)\n", top_k);
        return 0;
    }

    /* Synthetic: each row has indices reverse-sorted (top_k-1, top_k-2, ..., 0).
     * After kernel, expect ascending: 0, 1, ..., top_k-1. */
    const uint64_t n = (uint64_t)top_k * n_rows;
    int32_t *host_src = (int32_t *)calloc(n, sizeof(int32_t));
    int32_t *host_dst = (int32_t *)calloc(n, sizeof(int32_t));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    for (uint32_t r = 0; r < n_rows; r++) {
        for (uint32_t k = 0; k < top_k; k++) {
            host_src[(uint64_t)r * top_k + k] = (int32_t)(top_k - 1 - k + r);
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:64
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:n * sizeof(int32_t)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:n * sizeof(int32_t)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int64_t ne00, ne01;
            uint64_t nb00, nb01;
            int64_t ne0_, ne1_;
            uint64_t nb0_, nb1_;
        } args = {
            .ne00 = (int64_t)top_k, .ne01 = (int64_t)n_rows,
            .nb00 = sizeof(int32_t),
            .nb01 = (uint64_t)top_k * sizeof(int32_t),
            .ne0_ = 0, .ne1_ = 0, .nb0_ = 0, .nb1_ = 0,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)srcBuf, (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_sort_i32_rows_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc setThreadgroupMemoryLength:top_k * sizeof(int32_t) atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(n_rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(top_k, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, n * sizeof(int32_t));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    /* Verify each row is ascending */
    uint32_t n_correct_rows = 0;
    for (uint32_t r = 0; r < n_rows; r++) {
        int ok_row = 1;
        for (uint32_t k = 0; k + 1 < top_k; k++) {
            if (host_dst[(uint64_t)r * top_k + k] > host_dst[(uint64_t)r * top_k + k + 1]) {
                ok_row = 0; break;
            }
        }
        if (ok_row) n_correct_rows++;
    }
    fprintf(stderr,
        "ds4: sort_i32_rows MTL4 canary top_k=%u n_rows=%u correct_rows=%u/%u "
        "row0={%d,%d,%d,...}\n",
        top_k, n_rows, n_correct_rows, n_rows,
        (int)host_dst[0], top_k>1?(int)host_dst[1]:-1, top_k>2?(int)host_dst[2]:-1);
    free(host_src); free(host_dst);
    return (n_correct_rows == n_rows) ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_router_weights_with_remap (task #677) */
/* metal/dsv4_misc.metal:210. Companion to router_weights_one    */
/* but with expert inverse-remap indirection. Already ICB-       */
/* captured Phase 2 (#555). Completes 4/4 router-cycle MTL4.    */
/*                                                               */
/* Args is a `constant uint *args` array (3 uints), not a struct.*/
/* MTL4 path keeps the array shape via `device const uint *`.    */
/* selected_ids + weights are both READ-WRITE (in/out).          */
/* ============================================================ */
static id<MTLComputePipelineState> g_router_remap_mtl4_pipeline;
static int g_router_remap_mtl4_init_attempted;
static int g_router_remap_mtl4_init_ok;

static int ds4_router_remap_mtl4_pipeline_init(void) {
    if (g_router_remap_mtl4_init_attempted) return g_router_remap_mtl4_init_ok;
    g_router_remap_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "kernel void router_weights_with_remap_mtl4(\n"
         "    device const int *inverse_remap_table [[buffer(0)]],\n"
         "    device int *selected_ids [[buffer(1)]],\n"
         "    device float *weights [[buffer(2)]],\n"
         "    device const uint *args [[buffer(3)]],\n"
         "    threadgroup float *scratch [[threadgroup(0)]],\n"
         "    uint2 tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort tid [[thread_index_in_threadgroup]]) {\n"
         "  const uint layer_index = args[0];\n"
         "  const uint n_expert = args[1];\n"
         "  const uint n_tokens = args[2];\n"
         "  const uint token = tgpig.x;\n"
         "  if (token >= n_tokens) return;\n"
         "  if (tid >= n_expert) return;\n"
         "  const uint slot = token * n_expert + tid;\n"
         "  const int logical = selected_ids[slot];\n"
         "  int file_pos = -1;\n"
         "  if (logical >= 0 && logical < 256) {\n"
         "    file_pos = inverse_remap_table[layer_index * 256u + (uint)logical];\n"
         "  }\n"
         "  float w = weights[slot];\n"
         "  if (file_pos < 0) { w = 0.0f; file_pos = 0; }\n"
         "  scratch[tid] = w;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  float sum = 0.0f;\n"
         "  for (uint k = 0; k < n_expert; k++) sum += scratch[k];\n"
         "  if (sum > 6.103515625e-5f) w *= (1.5f / sum);\n"
         "  selected_ids[slot] = file_pos;\n"
         "  weights[slot] = w;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_router_remap_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: router_remap MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"router_weights_with_remap_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 32;
    g_router_remap_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_router_remap_mtl4_pipeline) {
        fprintf(stderr, "ds4: router_remap MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: router_remap MTL4 pipeline initialized\n");
    g_router_remap_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_router_remap_canary(uint32_t n_tokens) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_router_remap_mtl4_pipeline_init()) return 0;

    /* Synthetic: identity remap (file_pos = logical for all kept experts).
     * Selected_ids per token = {0, 50, 100, 150, 200, 250}.
     * Weights uniform 0.5 → sum = 3.0 → renormalize to 0.5 * (1.5 / 3.0) = 0.25 each. */
    const uint32_t n_expert = 6;
    const uint32_t layer = 9;
    const uint64_t selected_n = (uint64_t)n_tokens * n_expert;
    const uint64_t remap_n = 43 * 256;

    int32_t *host_remap = (int32_t *)calloc(remap_n, sizeof(int32_t));
    int32_t *host_selected = (int32_t *)calloc(selected_n, sizeof(int32_t));
    int32_t *host_selected_ref = (int32_t *)calloc(selected_n, sizeof(int32_t));
    float *host_weights = (float *)calloc(selected_n, sizeof(float));
    float *host_weights_ref = (float *)calloc(selected_n, sizeof(float));
    if (!host_remap || !host_selected || !host_selected_ref || !host_weights || !host_weights_ref) {
        free(host_remap); free(host_selected); free(host_selected_ref);
        free(host_weights); free(host_weights_ref);
        return 0;
    }
    /* Identity remap */
    for (uint64_t i = 0; i < remap_n; i++) host_remap[i] = (int32_t)(i % 256);
    /* Each token has top-6 = {0, 50, 100, 150, 200, 250}, weights 0.5 each */
    const int32_t seed_ids[6] = {0, 50, 100, 150, 200, 250};
    for (uint32_t t = 0; t < n_tokens; t++) {
        for (uint32_t k = 0; k < n_expert; k++) {
            host_selected[t * n_expert + k] = seed_ids[k];
            host_selected_ref[t * n_expert + k] = seed_ids[k];  /* identity remap keeps it */
            host_weights[t * n_expert + k] = 0.5f;
            host_weights_ref[t * n_expert + k] = 0.5f * (1.5f / 3.0f);  /* = 0.25 */
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> remapBuf = [g_device newBufferWithBytes:host_remap
                                                       length:remap_n * sizeof(int32_t)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> selBuf = [g_device newBufferWithBytes:host_selected
                                                     length:selected_n * sizeof(int32_t)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithBytes:host_weights
                                                   length:selected_n * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        const uint32_t args_u32[3] = { layer, n_expert, n_tokens };
        memcpy(argsBuf.contents, args_u32, sizeof(args_u32));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[4] = {
                (id<MTLAllocation>)remapBuf, (id<MTLAllocation>)selBuf,
                (id<MTLAllocation>)wBuf, (id<MTLAllocation>)argsBuf,
            };
            [residency addAllocations:allocs count:4];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:remapBuf.gpuAddress atIndex:0];
                [argTable setAddress:selBuf.gpuAddress atIndex:1];
                [argTable setAddress:wBuf.gpuAddress atIndex:2];
                [argTable setAddress:argsBuf.gpuAddress atIndex:3];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_router_remap_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc setThreadgroupMemoryLength:n_expert * sizeof(float) atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(n_tokens, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(8, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_selected, selBuf.contents, selected_n * sizeof(int32_t));
                    memcpy(host_weights, wBuf.contents, selected_n * sizeof(float));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) {
        free(host_remap); free(host_selected); free(host_selected_ref);
        free(host_weights); free(host_weights_ref);
        return 0;
    }

    /* Verify selected_ids unchanged (identity remap), weights renormalized to 0.25 */
    double max_abs_w = 0.0;
    uint64_t n_id_correct = 0;
    for (uint64_t i = 0; i < selected_n; i++) {
        double d = fabs((double)(host_weights[i] - host_weights_ref[i]));
        if (d > max_abs_w) max_abs_w = d;
        if (host_selected[i] == host_selected_ref[i]) n_id_correct++;
    }
    fprintf(stderr,
        "ds4: router_remap MTL4 canary n_tokens=%u n_expert=%u "
        "weights[0]_gpu=%.4f weights[0]_ref=%.4f max_abs_w=%.4e ids_correct=%llu/%llu\n",
        n_tokens, n_expert,
        (double)host_weights[0], (double)host_weights_ref[0], max_abs_w,
        (unsigned long long)n_id_correct, (unsigned long long)selected_n);
    free(host_remap); free(host_selected); free(host_selected_ref);
    free(host_weights); free(host_weights_ref);
    return (max_abs_w < 1.0e-5 && n_id_correct == selected_n) ? 1 : 0;
}

/* ============================================================ */
/* MTL4 ArgumentTable amortization pool (task #679)             */
/* silv 2026-05-27: "implement ArgumentTable amortization and    */
/* relevant icb optimizations".                                  */
/*                                                               */
/* Per-canary allocation creates a fresh MTL4ArgumentTable on    */
/* every call. Allocation cost is dominated by the descriptor +  */
/* newArgumentTableWithDescriptor call (~10-50µs each). On the   */
/* per-token decode hot path with 774 MoE dispatches + 4 router  */
/* dispatches + ~50 misc kernels, this becomes a measurable      */
/* encoding overhead.                                            */
/*                                                               */
/* This pool maintains a free-list of argument tables keyed by   */
/* max_buffer_bind_count. acquire() returns a cached table or    */
/* allocates fresh; release() returns to free list. Bindings are */
/* re-set per-dispatch via setAddress (which is cheap and        */
/* designed for this).                                           */
/*                                                               */
/* Thread safety: single-threaded GPU dispatch path; no lock     */
/* needed. If multi-threaded use is added later, wrap with       */
/* os_unfair_lock around the per-bucket free list.               */
/*                                                               */
/* Memory: O(n_pipelines × peak_concurrent_dispatches). For DS4  */
/* that's bounded by ~80 pipelines × 1 concurrent = ~80 tables   */
/* in worst case ≈ ~80 × few-KB-each = trivial.                  */
/* ============================================================ */

/* Buckets sized for the bind-count distribution: 3, 4, 6, 8.
 * Most ported kernels fit 3 or 4; MoE matmul uses 8. */
#define DS4_MTL4_POOL_BUCKETS 5
#define DS4_MTL4_POOL_MAX_PER_BUCKET 8

typedef struct {
    NSUInteger max_bindings;
    NSUInteger n_free;
    /* The actual __strong references — stored as id<MTL4ArgumentTable>.
     * Use NSMutableArray since we need ARC retain semantics. */
    NSMutableArray *free_tables;
} ds4_mtl4_pool_bucket;

static ds4_mtl4_pool_bucket g_mtl4_pool[DS4_MTL4_POOL_BUCKETS];
static int g_mtl4_pool_initialized = 0;
static uint64_t g_mtl4_pool_acquire_count = 0;
static uint64_t g_mtl4_pool_alloc_count = 0;
static uint64_t g_mtl4_pool_release_count = 0;

static void ds4_mtl4_pool_init(void) {
    if (g_mtl4_pool_initialized) return;
    /* Bucket sizes covering the ported kernels: 3, 4, 6, 8, 16. */
    const NSUInteger sizes[DS4_MTL4_POOL_BUCKETS] = {3, 4, 6, 8, 16};
    for (int i = 0; i < DS4_MTL4_POOL_BUCKETS; i++) {
        g_mtl4_pool[i].max_bindings = sizes[i];
        g_mtl4_pool[i].n_free = 0;
        g_mtl4_pool[i].free_tables = [NSMutableArray arrayWithCapacity:DS4_MTL4_POOL_MAX_PER_BUCKET];
    }
    g_mtl4_pool_initialized = 1;
}

/* Returns the bucket index that fits >= n_bindings, or -1 if too large.
 * Caller falls back to direct allocation in that case. */
static int ds4_mtl4_pool_bucket_for(NSUInteger n_bindings) {
    for (int i = 0; i < DS4_MTL4_POOL_BUCKETS; i++) {
        if (g_mtl4_pool[i].max_bindings >= n_bindings) return i;
    }
    return -1;
}

/* Acquire an ArgumentTable that supports at least n_bindings. Returns a
 * cached table (with all bindings unchanged from prior use — caller MUST
 * re-bind all needed slots before dispatch) or allocates fresh.
 * Returns nil on allocation failure. */
static id<MTL4ArgumentTable> ds4_mtl4_pool_acquire(NSUInteger n_bindings) {
    ds4_mtl4_pool_init();
    g_mtl4_pool_acquire_count++;
    const int bi = ds4_mtl4_pool_bucket_for(n_bindings);
    if (bi < 0) {
        /* Too large for pool; allocate direct. */
        NSError *err = nil;
        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = n_bindings;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> at = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        g_mtl4_pool_alloc_count++;
        return at;
    }
    ds4_mtl4_pool_bucket *b = &g_mtl4_pool[bi];
    if (b->n_free > 0) {
        id<MTL4ArgumentTable> at = [b->free_tables lastObject];
        [b->free_tables removeLastObject];
        b->n_free--;
        return at;
    }
    /* Fresh allocation at bucket size. */
    NSError *err = nil;
    MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
    atDesc.maxBufferBindCount = b->max_bindings;
    atDesc.initializeBindings = YES;
    id<MTL4ArgumentTable> at = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
    if (!at) return nil;
    g_mtl4_pool_alloc_count++;
    return at;
}

/* Return an ArgumentTable to the free list for the bucket that owns its
 * max_bindings. Bindings persist across acquire/release pairs — this is
 * the AMORTIZATION: caller need not rebind unchanged buffers. */
static void ds4_mtl4_pool_release(id<MTL4ArgumentTable> at, NSUInteger n_bindings) {
    if (!at) return;
    g_mtl4_pool_release_count++;
    const int bi = ds4_mtl4_pool_bucket_for(n_bindings);
    if (bi < 0) return;  /* Was direct-allocated; let ARC reclaim. */
    ds4_mtl4_pool_bucket *b = &g_mtl4_pool[bi];
    if (b->n_free >= DS4_MTL4_POOL_MAX_PER_BUCKET) {
        /* Bucket full — let ARC reclaim. */
        return;
    }
    [b->free_tables addObject:at];
    b->n_free++;
}

/* Public stats query (for diagnostic logging + tests). */
void ds4_gpu_mtl4_pool_stats(uint64_t *out_acquire,
                              uint64_t *out_alloc,
                              uint64_t *out_release) {
    if (out_acquire) *out_acquire = g_mtl4_pool_acquire_count;
    if (out_alloc) *out_alloc = g_mtl4_pool_alloc_count;
    if (out_release) *out_release = g_mtl4_pool_release_count;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_ratio4_shift_f32 (task #678)          */
/* metal/dsv4_kv.metal:271. Tiny KV ratio-4 state shift —        */
/* state[gid] = state[n + gid] for both kv and score.            */
/* 1 args (width only) + 2 r/w buffers. ~12-line body.           */
/* ============================================================ */
static id<MTLComputePipelineState> g_ratio4_shift_mtl4_pipeline;
static int g_ratio4_shift_mtl4_init_attempted;
static int g_ratio4_shift_mtl4_init_ok;

static int ds4_ratio4_shift_mtl4_pipeline_init(void) {
    if (g_ratio4_shift_mtl4_init_attempted) return g_ratio4_shift_mtl4_init_ok;
    g_ratio4_shift_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct ratio4_shift_args { uint32_t width; };\n"
         "kernel void ratio4_shift_f32_mtl4(\n"
         "    device const ratio4_shift_args *args_ptr [[buffer(0)]],\n"
         "    device float *state_kv [[buffer(1)]],\n"
         "    device float *state_score [[buffer(2)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  const uint n = 4u * args_ptr->width;\n"
         "  if (gid >= n) return;\n"
         "  state_kv[gid] = state_kv[n + gid];\n"
         "  state_score[gid] = state_score[n + gid];\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_ratio4_shift_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: ratio4_shift MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"ratio4_shift_f32_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_ratio4_shift_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_ratio4_shift_mtl4_pipeline) {
        fprintf(stderr, "ds4: ratio4_shift MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: ratio4_shift MTL4 pipeline initialized\n");
    g_ratio4_shift_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_ratio4_shift_canary(uint32_t width) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_ratio4_shift_mtl4_pipeline_init()) return 0;

    /* Synthetic: state_kv[gid] = -1.0 (placeholder), state_kv[n + gid] = (float)gid.
     * Same for state_score. After kernel: state_kv[gid] = (float)gid for gid < n. */
    const uint32_t n = 4u * width;
    const uint64_t total = (uint64_t)n * 2;  /* old + new halves */
    float *host_kv = (float *)calloc(total, sizeof(float));
    float *host_score = (float *)calloc(total, sizeof(float));
    if (!host_kv || !host_score) { free(host_kv); free(host_score); return 0; }
    for (uint32_t i = 0; i < n; i++) {
        host_kv[i] = -1.0f;
        host_score[i] = -2.0f;
        host_kv[n + i] = (float)i;
        host_score[n + i] = (float)i * 0.5f;
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> kvBuf = [g_device newBufferWithBytes:host_kv
                                                    length:total * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> scoreBuf = [g_device newBufferWithBytes:host_score
                                                       length:total * sizeof(float)
                                                      options:MTLResourceStorageModeShared];
        *((uint32_t *)argsBuf.contents) = width;

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)kvBuf, (id<MTLAllocation>)scoreBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
            atDesc.maxBufferBindCount = 4;
            atDesc.initializeBindings = YES;
            id<MTL4ArgumentTable> argTable =
                [g_device newArgumentTableWithDescriptor:atDesc error:&err];
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:kvBuf.gpuAddress atIndex:1];
                [argTable setAddress:scoreBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_ratio4_shift_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const NSUInteger tg = 256;
                const NSUInteger n_tgs = (n + tg - 1) / tg;
                [enc dispatchThreadgroups:MTLSizeMake(n_tgs, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(tg, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_kv, kvBuf.contents, total * sizeof(float));
                    memcpy(host_score, scoreBuf.contents, total * sizeof(float));
                    rc = 1;
                }
            }
        }
    }
    if (!rc) { free(host_kv); free(host_score); return 0; }

    /* Verify shifted: state_kv[i] should now equal i for i < n */
    uint64_t n_correct_kv = 0;
    uint64_t n_correct_score = 0;
    for (uint32_t i = 0; i < n; i++) {
        if (host_kv[i] == (float)i) n_correct_kv++;
        if (host_score[i] == (float)i * 0.5f) n_correct_score++;
    }
    fprintf(stderr,
        "ds4: ratio4_shift MTL4 canary width=%u n=%u "
        "kv_correct=%llu/%u score_correct=%llu/%u\n",
        width, n,
        (unsigned long long)n_correct_kv, n,
        (unsigned long long)n_correct_score, n);
    free(host_kv); free(host_score);
    return (n_correct_kv == n && n_correct_score == n) ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_compressor_store_one (task #680)      */
/* metal/dsv4_kv.metal:288. One-token compressor frontier        */
/* update: append projected KV+score+APE into recurrent state.   */
/* 1 args + 5 buffers (kv, score, ape, state_kv, state_score).   */
/* ============================================================ */
static id<MTLComputePipelineState> g_compressor_store_one_mtl4_pipeline;
static int g_compressor_store_one_mtl4_init_attempted;
static int g_compressor_store_one_mtl4_init_ok;

static int ds4_compressor_store_one_mtl4_pipeline_init(void) {
    if (g_compressor_store_one_mtl4_init_attempted) return g_compressor_store_one_mtl4_init_ok;
    g_compressor_store_one_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct csa { uint32_t width; uint32_t ratio; uint32_t pos; uint32_t ape_type; };\n"
         "kernel void compressor_store_one_mtl4(\n"
         "    device const csa *args_ptr [[buffer(0)]],\n"
         "    device const float *kv [[buffer(1)]],\n"
         "    device const float *score [[buffer(2)]],\n"
         "    device const char *ape [[buffer(3)]],\n"
         "    device float *state_kv [[buffer(4)]],\n"
         "    device float *state_score [[buffer(5)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  if (gid >= args_ptr->width || args_ptr->width == 0 || args_ptr->ratio == 0) return;\n"
         "  const uint pos_mod = args_ptr->pos % args_ptr->ratio;\n"
         "  const uint dst_row = args_ptr->ratio == 4u ? args_ptr->ratio + pos_mod : pos_mod;\n"
         "  const uint dst = dst_row * args_ptr->width + gid;\n"
         "  const uint ape_i = pos_mod * args_ptr->width + gid;\n"
         "  float ape_v;\n"
         "  if (args_ptr->ape_type == 1u) {\n"
         "    ape_v = (float)(((device const half *)ape)[ape_i]);\n"
         "  } else {\n"
         "    ape_v = ((device const float *)ape)[ape_i];\n"
         "  }\n"
         "  state_kv[dst] = kv[gid];\n"
         "  state_score[dst] = score[gid] + ape_v;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_compressor_store_one_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: compressor_store_one MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"compressor_store_one_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_compressor_store_one_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_compressor_store_one_mtl4_pipeline) {
        fprintf(stderr, "ds4: compressor_store_one MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: compressor_store_one MTL4 pipeline initialized\n");
    g_compressor_store_one_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_compressor_store_one_canary(uint32_t width) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_compressor_store_one_mtl4_pipeline_init()) return 0;

    const uint32_t ratio = 4;
    const uint32_t pos = 5;
    const uint32_t pos_mod = pos % ratio;
    const uint32_t dst_row = ratio + pos_mod;  /* = 4 + 1 = 5 */
    const uint32_t state_n = 2 * ratio * width;  /* old + new halves */

    float *host_kv = (float *)calloc(width, sizeof(float));
    float *host_score = (float *)calloc(width, sizeof(float));
    float *host_ape = (float *)calloc(ratio * width, sizeof(float));  /* ape_type=0 → float */
    float *host_state_kv = (float *)calloc(state_n, sizeof(float));
    float *host_state_score = (float *)calloc(state_n, sizeof(float));
    if (!host_kv || !host_score || !host_ape || !host_state_kv || !host_state_score) {
        free(host_kv); free(host_score); free(host_ape);
        free(host_state_kv); free(host_state_score);
        return 0;
    }
    for (uint32_t i = 0; i < width; i++) {
        host_kv[i] = (float)i * 0.1f;
        host_score[i] = (float)i * 0.01f;
    }
    /* APE at pos_mod=1 row: per-element offset 0.5 */
    for (uint32_t i = 0; i < width; i++) {
        host_ape[pos_mod * width + i] = 0.5f;
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> kvBuf = [g_device newBufferWithBytes:host_kv
                                                    length:width * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> scoreBuf = [g_device newBufferWithBytes:host_score
                                                       length:width * sizeof(float)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> apeBuf = [g_device newBufferWithBytes:host_ape
                                                     length:ratio * width * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> stateKvBuf = [g_device newBufferWithLength:state_n * sizeof(float)
                                                         options:MTLResourceStorageModeShared];
        id<MTLBuffer> stateScoreBuf = [g_device newBufferWithLength:state_n * sizeof(float)
                                                            options:MTLResourceStorageModeShared];

        struct { uint32_t width, ratio, pos, ape_type; } args = {
            .width = width, .ratio = ratio, .pos = pos, .ape_type = 0,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[6] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)kvBuf, (id<MTLAllocation>)scoreBuf,
                (id<MTLAllocation>)apeBuf, (id<MTLAllocation>)stateKvBuf, (id<MTLAllocation>)stateScoreBuf,
            };
            [residency addAllocations:allocs count:6];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(6);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:kvBuf.gpuAddress atIndex:1];
                [argTable setAddress:scoreBuf.gpuAddress atIndex:2];
                [argTable setAddress:apeBuf.gpuAddress atIndex:3];
                [argTable setAddress:stateKvBuf.gpuAddress atIndex:4];
                [argTable setAddress:stateScoreBuf.gpuAddress atIndex:5];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_compressor_store_one_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const NSUInteger tg = 256;
                const NSUInteger n_tgs = (width + tg - 1) / tg;
                [enc dispatchThreadgroups:MTLSizeMake(n_tgs, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(tg, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_state_kv, stateKvBuf.contents, state_n * sizeof(float));
                    memcpy(host_state_score, stateScoreBuf.contents, state_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 6);
            }
        }
    }
    if (!rc) {
        free(host_kv); free(host_score); free(host_ape);
        free(host_state_kv); free(host_state_score);
        return 0;
    }

    /* Verify: state_kv[dst_row * width + i] = host_kv[i] = i*0.1 */
    /*         state_score[dst_row * width + i] = host_score[i] + 0.5 = i*0.01 + 0.5 */
    uint32_t n_correct_kv = 0;
    uint32_t n_correct_score = 0;
    for (uint32_t i = 0; i < width; i++) {
        const uint32_t idx = dst_row * width + i;
        const float exp_kv = (float)i * 0.1f;
        const float exp_score = (float)i * 0.01f + 0.5f;
        if (fabsf(host_state_kv[idx] - exp_kv) < 1.0e-4f) n_correct_kv++;
        if (fabsf(host_state_score[idx] - exp_score) < 1.0e-4f) n_correct_score++;
    }
    fprintf(stderr,
        "ds4: compressor_store_one MTL4 canary width=%u pos=%u dst_row=%u "
        "kv_correct=%u/%u score_correct=%u/%u\n",
        width, pos, dst_row, n_correct_kv, width, n_correct_score, width);
    free(host_kv); free(host_score); free(host_ape);
    free(host_state_kv); free(host_state_score);
    return (n_correct_kv == width && n_correct_score == width) ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_softmax_pool (task #681)              */
/* metal/dsv4_misc.metal:1367. Fused softmax-weighted KV pool   */
/* — exp-sum-mul-divide in one kernel. 1 args + 3 buffers.       */
/* ============================================================ */
static id<MTLComputePipelineState> g_softmax_pool_mtl4_pipeline;
static int g_softmax_pool_mtl4_init_attempted;
static int g_softmax_pool_mtl4_init_ok;

static int ds4_softmax_pool_mtl4_pipeline_init(void) {
    if (g_softmax_pool_mtl4_init_attempted) return g_softmax_pool_mtl4_init_ok;
    g_softmax_pool_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct smp_args {\n"
         "  int64_t ne00; int64_t ne01; int64_t ne02;\n"
         "  uint64_t nb00; uint64_t nb01; uint64_t nb02;\n"
         "  uint64_t nb10; uint64_t nb11; uint64_t nb12;\n"
         "  int64_t ne0; int64_t ne1;\n"
         "  uint64_t nb0; uint64_t nb1;\n"
         "};\n"
         "kernel void softmax_pool_mtl4(\n"
         "    device const smp_args *args_ptr [[buffer(0)]],\n"
         "    device const char *kv [[buffer(1)]],\n"
         "    device const char *score [[buffer(2)]],\n"
         "    device char *dst [[buffer(3)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  const int64_t n = args_ptr->ne0 * args_ptr->ne1;\n"
         "  if ((int64_t)gid >= n) return;\n"
         "  const int64_t id_ = (int64_t)gid % args_ptr->ne0;\n"
         "  const int64_t ic = (int64_t)gid / args_ptr->ne0;\n"
         "  float max_s = -INFINITY;\n"
         "  for (int64_t ir = 0; ir < args_ptr->ne00; ++ir) {\n"
         "    const float s = *((device const float *)(score + ir * args_ptr->nb10 + id_ * args_ptr->nb11 + ic * args_ptr->nb12));\n"
         "    max_s = max(max_s, s);\n"
         "  }\n"
         "  float sum = 0.0f;\n"
         "  float acc = 0.0f;\n"
         "  for (int64_t ir = 0; ir < args_ptr->ne00; ++ir) {\n"
         "    const float s = *((device const float *)(score + ir * args_ptr->nb10 + id_ * args_ptr->nb11 + ic * args_ptr->nb12));\n"
         "    const float w = exp(s - max_s);\n"
         "    const float v = *((device const float *)(kv + ir * args_ptr->nb00 + id_ * args_ptr->nb01 + ic * args_ptr->nb02));\n"
         "    sum += w;\n"
         "    acc += v * w;\n"
         "  }\n"
         "  *((device float *)(dst + id_ * args_ptr->nb0 + ic * args_ptr->nb1)) = acc / sum;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_softmax_pool_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: softmax_pool MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"softmax_pool_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_softmax_pool_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_softmax_pool_mtl4_pipeline) {
        fprintf(stderr, "ds4: softmax_pool MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: softmax_pool MTL4 pipeline initialized\n");
    g_softmax_pool_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_softmax_pool_canary(uint32_t ne0, uint32_t ne1, uint32_t n_rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_softmax_pool_mtl4_pipeline_init()) return 0;

    /* Synthetic: kv[ir, id, ic] = ic*ne0+id (constant per row), scores[ir, id, ic] = ir
     * (rising along row axis). Softmax-pool with max-shift gives weighted average
     * dominated by max score row. For our pattern: scores rise linearly, so the
     * highest-ir row dominates; pooled output ≈ kv at row=ne00-1 = ic*ne0+id. */
    const uint64_t kv_n = (uint64_t)n_rows * ne0 * ne1;
    const uint64_t dst_n = (uint64_t)ne0 * ne1;
    float *host_kv = (float *)calloc(kv_n, sizeof(float));
    float *host_score = (float *)calloc(kv_n, sizeof(float));
    float *host_dst_gpu = (float *)calloc(dst_n, sizeof(float));
    float *host_dst_ref = (float *)calloc(dst_n, sizeof(float));
    if (!host_kv || !host_score || !host_dst_gpu || !host_dst_ref) {
        free(host_kv); free(host_score); free(host_dst_gpu); free(host_dst_ref);
        return 0;
    }
    for (uint32_t ic = 0; ic < ne1; ic++) {
        for (uint32_t id = 0; id < ne0; id++) {
            for (uint32_t ir = 0; ir < n_rows; ir++) {
                /* layout: stride along ir (nb*0), then id (nb*1), then ic (nb*2) */
                const uint64_t idx = ir + (uint64_t)id * n_rows + (uint64_t)ic * n_rows * ne0;
                host_kv[idx] = (float)(ic * ne0 + id);  /* constant per (id, ic) */
                host_score[idx] = (float)ir;  /* rising along ir */
            }
        }
    }
    /* CPU reference */
    for (uint32_t ic = 0; ic < ne1; ic++) {
        for (uint32_t id = 0; id < ne0; id++) {
            float max_s = -INFINITY;
            for (uint32_t ir = 0; ir < n_rows; ir++) {
                const uint64_t idx = ir + (uint64_t)id * n_rows + (uint64_t)ic * n_rows * ne0;
                if (host_score[idx] > max_s) max_s = host_score[idx];
            }
            float sum = 0.0f, acc = 0.0f;
            for (uint32_t ir = 0; ir < n_rows; ir++) {
                const uint64_t idx = ir + (uint64_t)id * n_rows + (uint64_t)ic * n_rows * ne0;
                const float w = expf(host_score[idx] - max_s);
                sum += w;
                acc += host_kv[idx] * w;
            }
            host_dst_ref[id + (uint64_t)ic * ne0] = acc / sum;
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:128
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> kvBuf = [g_device newBufferWithBytes:host_kv
                                                    length:kv_n * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> scoreBuf = [g_device newBufferWithBytes:host_score
                                                       length:kv_n * sizeof(float)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int64_t ne00, ne01, ne02;
            uint64_t nb00, nb01, nb02;
            uint64_t nb10, nb11, nb12;
            int64_t ne0_, ne1_;
            uint64_t nb0_, nb1_;
        } args = {
            .ne00 = (int64_t)n_rows, .ne01 = (int64_t)ne0, .ne02 = (int64_t)ne1,
            .nb00 = sizeof(float),
            .nb01 = (uint64_t)n_rows * sizeof(float),
            .nb02 = (uint64_t)n_rows * ne0 * sizeof(float),
            .nb10 = sizeof(float),
            .nb11 = (uint64_t)n_rows * sizeof(float),
            .nb12 = (uint64_t)n_rows * ne0 * sizeof(float),
            .ne0_ = (int64_t)ne0, .ne1_ = (int64_t)ne1,
            .nb0_ = sizeof(float),
            .nb1_ = (uint64_t)ne0 * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[4] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)kvBuf,
                (id<MTLAllocation>)scoreBuf, (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:4];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:kvBuf.gpuAddress atIndex:1];
                [argTable setAddress:scoreBuf.gpuAddress atIndex:2];
                [argTable setAddress:dstBuf.gpuAddress atIndex:3];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_softmax_pool_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const NSUInteger tg = 256;
                const NSUInteger n_tgs = (dst_n + tg - 1) / tg;
                [enc dispatchThreadgroups:MTLSizeMake(n_tgs, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(tg, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst_gpu, dstBuf.contents, dst_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) {
        free(host_kv); free(host_score); free(host_dst_gpu); free(host_dst_ref);
        return 0;
    }

    double max_abs = 0.0;
    for (uint64_t i = 0; i < dst_n; i++) {
        double d = fabs((double)(host_dst_gpu[i] - host_dst_ref[i]));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: softmax_pool MTL4 canary ne0=%u ne1=%u n_rows=%u "
        "expected[0]=%.4f gpu[0]=%.4f max_abs=%.4e\n",
        ne0, ne1, n_rows,
        (double)host_dst_ref[0], (double)host_dst_gpu[0], max_abs);
    free(host_kv); free(host_score); free(host_dst_gpu); free(host_dst_ref);
    return max_abs < 1.0e-3 ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_mul_mm_id_fp16_pair_swiglu_f32 (task #682) */
/* metal/moe.metal:1282. THE per-token decode bottleneck —      */
/* 774 dispatches/token. 8 buffer bindings + 2 args structs +    */
/* 1024-byte threadgroup. FP16 simdgroup matmul (8×8 tile) +     */
/* SwiGLU + route-weight fusion in one kernel.                   */
/*                                                               */
/* PIPELINE SHIPS THIS TURN — canary deferred (synthetic data    */
/* synthesis for a 130-line kernel with 8 bindings needs careful */
/* setup; multi-turn item per silv's directive). The pipeline    */
/* init validates the kernel source compiles under MTL4 and is   */
/* dispatchable. Hot-path integration into ds4.c is a separate   */
/* 1-2 turn effort.                                              */
/* ============================================================ */
static id<MTLComputePipelineState> g_moe_matmul_mtl4_pipeline;
static int g_moe_matmul_mtl4_init_attempted;
static int g_moe_matmul_mtl4_init_ok;

static int ds4_moe_matmul_mtl4_pipeline_init(void) {
    if (g_moe_matmul_mtl4_init_attempted) return g_moe_matmul_mtl4_init_ok;
    g_moe_matmul_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct mmid_args {\n"
         "  int32_t nei0; int32_t nei1; uint64_t nbi1;\n"
         "  int32_t ne00; int32_t ne01; int32_t ne02;\n"
         "  uint64_t nb00; uint64_t nb01; uint64_t nb02;\n"
         "  int32_t ne10; int32_t ne11; int32_t ne12; int32_t ne13;\n"
         "  uint64_t nb10; uint64_t nb11; uint64_t nb12;\n"
         "  int32_t ne0; int32_t ne1; uint64_t nb1; int32_t nr0;\n"
         "};\n"
         "struct moe_swiglu_args {\n"
         "  uint32_t width; uint32_t rows;\n"
         "  uint64_t gate_row_stride; uint64_t up_row_stride;\n"
         "  uint64_t mid_row_stride; uint64_t weight_stride;\n"
         "  uint32_t write_clamped; float clamp_value;\n"
         "};\n"
         "kernel void mul_mm_id_fp16_pair_swiglu_mtl4(\n"
         "    device const mmid_args *args_ptr [[buffer(0)]],\n"
         "    device const moe_swiglu_args *act_ptr [[buffer(1)]],\n"
         "    device const char *src0_gate [[buffer(2)]],\n"
         "    device const char *src0_up [[buffer(3)]],\n"
         "    device const char *src1 [[buffer(4)]],\n"
         "    device char *dst_mid [[buffer(5)]],\n"
         "    device const char *ids [[buffer(6)]],\n"
         "    device const char *weights [[buffer(7)]],\n"
         "    threadgroup char *shmem [[threadgroup(0)]],\n"
         "    uint3 tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort tiitg [[thread_index_in_threadgroup]],\n"
         "    ushort tiisg [[thread_index_in_simdgroup]],\n"
         "    ushort sgitg [[simdgroup_index_in_threadgroup]]) {\n"
         "  (void)tiisg; (void)sgitg;\n"
         "  const uint out_col_tile = tgpig.x;\n"
         "  const uint token_tile = tgpig.y;\n"
         "  const int iid1 = (int)(tgpig.z / args_ptr->nei0);\n"
         "  const int idx = (int)(tgpig.z % args_ptr->nei0);\n"
         "  {\n"
         "    device const float *rw_check =\n"
         "      (device const float *)(weights + (uint64_t)idx * act_ptr->weight_stride);\n"
         "    if (rw_check[0] == 0.0f) return;\n"
         "  }\n"
         "  const int32_t i02 = ((device const int32_t *)(ids + iid1 * args_ptr->nbi1))[idx];\n"
         "  const int n_in = args_ptr->ne00;\n"
         "  const int n_out = args_ptr->ne0;\n"
         "  const uint out_col_start = out_col_tile * 8;\n"
         "  const uint token_start = token_tile * 8;\n"
         "  if ((int)out_col_start >= n_out) return;\n"
         "  device const half *Wg = (device const half *)(src0_gate + (uint64_t)i02 * args_ptr->nb02);\n"
         "  device const half *Wu = (device const half *)(src0_up + (uint64_t)i02 * args_ptr->nb02);\n"
         "  device const float *Y = (device const float *)src1;\n"
         "  simdgroup_float8x8 acc_gate = make_filled_simdgroup_matrix<float, 8>(0.0f);\n"
         "  simdgroup_float8x8 acc_up = make_filled_simdgroup_matrix<float, 8>(0.0f);\n"
         "  threadgroup half *ts_A = (threadgroup half *)shmem;\n"
         "  threadgroup half *ts_B = ts_A + 64;\n"
         "  threadgroup half *ts_Bu = ts_B + 64;\n"
         "  for (int k = 0; k < n_in; k += 8) {\n"
         "    if (tiitg < 64) {\n"
         "      const uint trow = tiitg / 8;\n"
         "      const uint tcol = tiitg % 8;\n"
         "      const uint tok = token_start + trow;\n"
         "      const int kk = k + (int)tcol;\n"
         "      float v = 0.0f;\n"
         "      if ((int)tok < args_ptr->ne11 && kk < n_in) {\n"
         "        v = Y[(uint64_t)tok * (uint64_t)n_in + (uint64_t)kk];\n"
         "      }\n"
         "      ts_A[trow * 8 + tcol] = (half)v;\n"
         "    }\n"
         "    if (tiitg < 64) {\n"
         "      const uint trow = tiitg / 8;\n"
         "      const uint tcol = tiitg % 8;\n"
         "      const uint out_col = out_col_start + tcol;\n"
         "      const int kk = k + (int)trow;\n"
         "      half vg = 0.h, vu = 0.h;\n"
         "      if ((int)out_col < n_out && kk < n_in) {\n"
         "        const uint64_t off = (uint64_t)out_col * (uint64_t)n_in + (uint64_t)kk;\n"
         "        vg = Wg[off]; vu = Wu[off];\n"
         "      }\n"
         "      ts_B[trow * 8 + tcol] = vg;\n"
         "      ts_Bu[trow * 8 + tcol] = vu;\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    simdgroup_half8x8 mA, mBg, mBu;\n"
         "    simdgroup_load(mA, ts_A, 8, 0, false);\n"
         "    simdgroup_load(mBg, ts_B, 8, 0, false);\n"
         "    simdgroup_load(mBu, ts_Bu, 8, 0, false);\n"
         "    simdgroup_multiply_accumulate(acc_gate, mA, mBg, acc_gate);\n"
         "    simdgroup_multiply_accumulate(acc_up, mA, mBu, acc_up);\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  threadgroup float *ts_Cg = (threadgroup float *)shmem;\n"
         "  threadgroup float *ts_Cu = ts_Cg + 64;\n"
         "  simdgroup_store(acc_gate, ts_Cg, 8, 0, false);\n"
         "  simdgroup_store(acc_up, ts_Cu, 8, 0, false);\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  if (tiitg < 64) {\n"
         "    const uint trow = tiitg / 8;\n"
         "    const uint tcol = tiitg % 8;\n"
         "    const uint tok = token_start + trow;\n"
         "    const uint out_col = out_col_start + tcol;\n"
         "    if ((int)tok < args_ptr->ne11 && (int)out_col < n_out) {\n"
         "      float g = ts_Cg[trow * 8 + tcol];\n"
         "      float u = ts_Cu[trow * 8 + tcol];\n"
         "      const float c = act_ptr->clamp_value;\n"
         "      if (c > 1.0e-6f) { g = min(g, c); u = clamp(u, -c, c); }\n"
         "      const float silu = g / (1.0f + exp(-g));\n"
         "      device const float *route_w =\n"
         "        (device const float *)(weights + (uint64_t)idx * act_ptr->weight_stride);\n"
         "      const uint64_t pair_row = (uint64_t)tok * (uint64_t)args_ptr->nei0 + (uint64_t)idx;\n"
         "      device float *dst_mid_f32 =\n"
         "        (device float *)(dst_mid + pair_row * act_ptr->mid_row_stride);\n"
         "      dst_mid_f32[(uint64_t)out_col] = silu * u * route_w[0];\n"
         "    }\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_moe_matmul_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: moe_matmul MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"mul_mm_id_fp16_pair_swiglu_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 64;
    g_moe_matmul_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_moe_matmul_mtl4_pipeline) {
        fprintf(stderr, "ds4: moe_matmul MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: moe_matmul MTL4 pipeline initialized (threadExecutionWidth=%lu)\n",
            (unsigned long)g_moe_matmul_mtl4_pipeline.threadExecutionWidth);
    g_moe_matmul_mtl4_init_ok = 1;
    return 1;
}

/* Smoke test: confirms the pipeline compiles + initializes. Full output
 * canary follows below. */
int ds4_gpu_mtl4_moe_matmul_init_canary(void) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_moe_matmul_mtl4_pipeline_init()) return 0;
    fprintf(stderr, "ds4: moe_matmul MTL4 pipeline canary — init OK\n");
    return 1;
}

/* FP32 → FP16 conversion via bit manipulation (no _Float16 dependency).
 * Handles normal range; denormals + Inf clamp gracefully for canary use. */
static inline uint16_t ds4_fp32_to_fp16(float f) {
    uint32_t u;
    memcpy(&u, &f, sizeof(u));
    const uint32_t sign = (u >> 16) & 0x8000u;
    int32_t exp = ((u >> 23) & 0xff) - 127 + 15;
    uint32_t mant = (u >> 13) & 0x3ff;
    if (exp <= 0) return (uint16_t)sign;
    if (exp >= 31) return (uint16_t)(sign | (31u << 10));
    return (uint16_t)(sign | ((uint32_t)exp << 10) | mant);
}

/* silv 2026-05-27 task #682 — FULL output canary for MoE matmul MTL4.
 *
 * Test setup:
 *   n_in       = 16 (K dim)
 *   n_out      = 8  (one output column tile)
 *   n_tokens   = 8  (one token tile)
 *   n_expert   = 1  (single expert in this test)
 *   nei0       = 1  (experts-per-token = 1)
 *   nei1       = n_tokens
 *   ids[t]     = 0 (all tokens select expert 0)
 *   route_w[t] = 1.0 (no scaling)
 *   clamp      = 0.0 (no clamp branch)
 *   weights    = identity-padded: W[i,k] = 1.0 if i==k (i < 8), else 0
 *
 * Expected mid[pair_row, oc] = silu(x[t, oc]) * x[t, oc] * 1.0
 * where pair_row = t * nei0 + idx = t * 1 + 0 = t.
 *
 * Validates: MTL4 pipeline produces correct FP16-simdgroup-matmul +
 * SwiGLU + route-weight in one fused dispatch, matching CPU reference. */
int ds4_gpu_mtl4_moe_matmul_full_canary(void) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_moe_matmul_mtl4_pipeline_init()) return 0;

    const int n_in = 16;
    const int n_out = 8;
    const int n_tokens = 8;
    const int n_expert = 1;  /* only one in weight buffer */
    const int nei0 = 1;
    const int nei1 = n_tokens;

    /* Weights (FP16): n_expert × n_out × n_in, row-major within each expert.
     * Identity-padded: gate[0][i][k] = up[0][i][k] = (i == k) ? 1.0 : 0.0. */
    const size_t w_elems = (size_t)n_expert * n_out * n_in;
    uint16_t *host_gate = (uint16_t *)calloc(w_elems, sizeof(uint16_t));
    uint16_t *host_up = (uint16_t *)calloc(w_elems, sizeof(uint16_t));
    if (!host_gate || !host_up) { free(host_gate); free(host_up); return 0; }
    const uint16_t one_fp16 = ds4_fp32_to_fp16(1.0f);
    for (int e = 0; e < n_expert; e++) {
        for (int i = 0; i < n_out; i++) {
            for (int k = 0; k < n_in; k++) {
                if (i == k) {
                    host_gate[e * n_out * n_in + i * n_in + k] = one_fp16;
                    host_up[e * n_out * n_in + i * n_in + k] = one_fp16;
                }
            }
        }
    }

    /* Activation (FP32): n_tokens × n_in, x[t, k] = (t + k) * 0.05 */
    const size_t x_elems = (size_t)n_tokens * n_in;
    float *host_x = (float *)calloc(x_elems, sizeof(float));
    if (!host_x) { free(host_gate); free(host_up); return 0; }
    for (int t = 0; t < n_tokens; t++) {
        for (int k = 0; k < n_in; k++) {
            host_x[t * n_in + k] = ((float)(t + k)) * 0.05f;
        }
    }

    /* ids: n_tokens entries, each = 0 */
    int32_t *host_ids = (int32_t *)calloc(n_tokens * nei0, sizeof(int32_t));
    if (!host_ids) { free(host_gate); free(host_up); free(host_x); return 0; }
    /* default 0 — selected expert is 0 */

    /* Route weights: nei0 × nei1 = n_tokens entries, each = 1.0 */
    float *host_weights = (float *)calloc(n_tokens, sizeof(float));
    if (!host_weights) {
        free(host_gate); free(host_up); free(host_x); free(host_ids);
        return 0;
    }
    for (int t = 0; t < n_tokens; t++) host_weights[t] = 1.0f;

    /* Output: n_tokens × n_out = n_tokens pair-rows × n_out floats each.
     * pair_row = tok * nei0 + idx = tok * 1 + 0 = tok. */
    const size_t mid_elems = (size_t)n_tokens * n_out;
    float *host_mid_gpu = (float *)calloc(mid_elems, sizeof(float));
    float *host_mid_ref = (float *)calloc(mid_elems, sizeof(float));
    if (!host_mid_gpu || !host_mid_ref) {
        free(host_gate); free(host_up); free(host_x); free(host_ids);
        free(host_weights); free(host_mid_gpu); free(host_mid_ref);
        return 0;
    }
    /* CPU reference: identity-weights make gate = up = x; SwiGLU + route. */
    for (int t = 0; t < n_tokens; t++) {
        for (int oc = 0; oc < n_out; oc++) {
            const float g = host_x[t * n_in + oc];
            const float u = host_x[t * n_in + oc];
            const float silu = g / (1.0f + expf(-g));
            host_mid_ref[t * n_out + oc] = silu * u * 1.0f;
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:128
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> actBuf = [g_device newBufferWithLength:64
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> gateBuf = [g_device newBufferWithBytes:host_gate
                                                      length:w_elems * sizeof(uint16_t)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> upBuf = [g_device newBufferWithBytes:host_up
                                                    length:w_elems * sizeof(uint16_t)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> xBuf = [g_device newBufferWithBytes:host_x
                                                   length:x_elems * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> midBuf = [g_device newBufferWithLength:mid_elems * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> idsBuf = [g_device newBufferWithBytes:host_ids
                                                     length:n_tokens * nei0 * sizeof(int32_t)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithBytes:host_weights
                                                   length:n_tokens * sizeof(float)
                                                  options:MTLResourceStorageModeShared];

        /* mmid_args struct mirrors what the kernel reads. nb02 = per-expert
         * weight stride. nbi1 = stride to next token's ids (1 idx × sizeof int). */
        struct mmid_args {
            int32_t nei0_, nei1_; uint64_t nbi1_;
            int32_t ne00, ne01, ne02;
            uint64_t nb00, nb01, nb02;
            int32_t ne10, ne11, ne12, ne13;
            uint64_t nb10, nb11, nb12;
            int32_t ne0_, ne1_; uint64_t nb1_; int32_t nr0_;
        } args = {
            .nei0_ = nei0, .nei1_ = nei1, .nbi1_ = (uint64_t)nei0 * sizeof(int32_t),
            .ne00 = n_in, .ne01 = n_out, .ne02 = n_expert,
            .nb00 = sizeof(uint16_t),
            .nb01 = (uint64_t)n_in * sizeof(uint16_t),
            .nb02 = (uint64_t)n_in * n_out * sizeof(uint16_t),
            .ne10 = n_in, .ne11 = n_tokens, .ne12 = 1, .ne13 = 1,
            .nb10 = sizeof(float),
            .nb11 = (uint64_t)n_in * sizeof(float),
            .nb12 = 0, .ne0_ = n_out, .ne1_ = 0,
            .nb1_ = 0, .nr0_ = 1,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        /* moe_swiglu_args: per-row strides + clamp config */
        struct {
            uint32_t width, rows;
            uint64_t gate_row_stride, up_row_stride, mid_row_stride, weight_stride;
            uint32_t write_clamped; float clamp_value;
        } act = {
            .width = (uint32_t)n_out,
            .rows = (uint32_t)(n_tokens * nei0),
            .gate_row_stride = 0,  /* unused in MTL4 port — no gate buffer write */
            .up_row_stride = 0,
            .mid_row_stride = (uint64_t)n_out * sizeof(float),
            .weight_stride = sizeof(float),
            .write_clamped = 0,
            .clamp_value = 0.0f,
        };
        memcpy(actBuf.contents, &act, sizeof(act));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 16;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[8] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)actBuf,
                (id<MTLAllocation>)gateBuf, (id<MTLAllocation>)upBuf,
                (id<MTLAllocation>)xBuf, (id<MTLAllocation>)midBuf,
                (id<MTLAllocation>)idsBuf, (id<MTLAllocation>)wBuf,
            };
            [residency addAllocations:allocs count:8];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(8);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:actBuf.gpuAddress atIndex:1];
                [argTable setAddress:gateBuf.gpuAddress atIndex:2];
                [argTable setAddress:upBuf.gpuAddress atIndex:3];
                [argTable setAddress:xBuf.gpuAddress atIndex:4];
                [argTable setAddress:midBuf.gpuAddress atIndex:5];
                [argTable setAddress:idsBuf.gpuAddress atIndex:6];
                [argTable setAddress:wBuf.gpuAddress atIndex:7];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_moe_matmul_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc setThreadgroupMemoryLength:1024 atIndex:0];

                /* Dispatch: (out_col_tiles, token_tiles, batch_id) where
                 * out_col_tiles = ceil(n_out / 8) = 1
                 * token_tiles = ceil(n_tokens / 8) = 1
                 * batch_id = nei0 × nei1 = n_tokens (one batch per (idx, token)) */
                const NSUInteger n_out_tiles = (n_out + 7) / 8;
                const NSUInteger n_tok_tiles = (n_tokens + 7) / 8;
                const NSUInteger n_batch = nei0 * nei1;
                [enc dispatchThreadgroups:MTLSizeMake(n_out_tiles, n_tok_tiles, n_batch)
                    threadsPerThreadgroup:MTLSizeMake(64, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_mid_gpu, midBuf.contents, mid_elems * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 8);
            }
        }
    }
    if (!rc) {
        free(host_gate); free(host_up); free(host_x); free(host_ids);
        free(host_weights); free(host_mid_gpu); free(host_mid_ref);
        return 0;
    }

    double max_abs = 0.0;
    double sum_sq = 0.0;
    for (size_t i = 0; i < mid_elems; i++) {
        double d = (double)(host_mid_gpu[i] - host_mid_ref[i]);
        if (fabs(d) > max_abs) max_abs = fabs(d);
        sum_sq += d * d;
    }
    const double rms = sqrt(sum_sq / (double)mid_elems);
    fprintf(stderr,
        "ds4: moe_matmul MTL4 full canary n_tokens=%d n_out=%d n_in=%d\n"
        "  mid_ref[0]=%.4f gpu[0]=%.4f mid_ref[7]=%.4f gpu[7]=%.4f\n"
        "  max_abs=%.4e rms=%.4e (threshold 5e-3 for FP16 simdgroup matmul)\n",
        n_tokens, n_out, n_in,
        (double)host_mid_ref[0], (double)host_mid_gpu[0],
        (double)host_mid_ref[7], (double)host_mid_gpu[7],
        max_abs, rms);

    free(host_gate); free(host_up); free(host_x); free(host_ids);
    free(host_weights); free(host_mid_gpu); free(host_mid_ref);
    /* FP16 simdgroup matmul has limited precision; 5e-3 is empirically loose
     * but safe for identity-weight case with small magnitudes. */
    return max_abs < 5.0e-3 ? 1 : 0;
}

/* ============================================================ */
/* ICB Phase 7: MoE matmul dispatch capture (task #664)         */
/* silv 2026-05-27: "full canary for moe matmul then icb phase 7"*/
/*                                                              */
/* The per-token decode hot path fires 6 expert dispatches per   */
/* layer × 43 layers = 258 MoE matmul calls per token. Each      */
/* dispatch costs ~50µs in encoder overhead (setPipelineState +  */
/* 8× setBuffer + setThreadgroupMemoryLength + dispatchTGs).     */
/*                                                               */
/* ICB Phase 7 records ONE 6-slot dispatch into a classic        */
/* MTLIndirectCommandBuffer at first call. Per-layer per-token   */
/* replay via executeCommandsInBuffer with range[0..6].          */
/*                                                               */
/* Per-token target savings: 258 × ~45µs ≈ 12ms/token encoding   */
/* overhead removed. At baseline ~53ms/token, that's ~22%        */
/* speedup at Level 1 of the speedup ladder.                     */
/*                                                               */
/* Same args buffer shape as the classic MoE dispatch:           */
/*   [0] mmid_args (constant)                                    */
/*   [1] moe_swiglu_args (constant)                              */
/*   [2] src0_gate                                               */
/*   [3] src0_up                                                 */
/*   [4] src1 (activation)                                       */
/*   [5] dst_mid (output)                                        */
/*   [6] ids                                                     */
/*   [7] weights                                                 */
/* Threadgroup memory: 1024 bytes                                */
/* Dispatch shape: (n_out_tiles, n_tok_tiles, n_experts)         */
/* ============================================================ */
#define DS4_MOE_ICB_SLOTS 6   /* K-top experts per token */

static id<MTLIndirectCommandBuffer> g_moe_matmul_icb;
typedef struct {
    int recorded;
    void *gate_ptr;  uint64_t gate_off;
    void *up_ptr;    uint64_t up_off;
    void *x_ptr;     uint64_t x_off;
    void *mid_ptr;   uint64_t mid_off;
    void *ids_ptr;   uint64_t ids_off;
    void *w_ptr;     uint64_t w_off;
    void *args_ptr;
    void *act_ptr;
    NSUInteger n_out_tiles;
    NSUInteger n_tok_tiles;
} ds4_moe_icb_slot;
static ds4_moe_icb_slot g_moe_matmul_icb_slot;

/* Record/replay a MoE matmul dispatch via ICB.
 *
 * Returns 1 if executed via ICB (or no-op fallthrough on opt-out),
 * 0 only on hard error. Caller MUST verify `pipeline` is the
 * classic-MTL g_moe_mul_mm_id_fp16_pair_swiglu_pipeline (not the
 * MTL4 variant — classic ICB only encodes classic pipelines).
 *
 * Gated by env var DS4_MOE_ICB=1 (opt-in initially per the
 * router_weights_one ICB lesson — verify wins per workload). */
int ds4_gpu_moe_matmul_icb_dispatch(
        id<MTLCommandBuffer> cb,
        id<MTLComputePipelineState> pipeline,
        id<MTLBuffer> argsbuf, NSUInteger args_off,
        id<MTLBuffer> actbuf, NSUInteger act_off,
        id<MTLBuffer> gatebuf, NSUInteger gate_off,
        id<MTLBuffer> upbuf, NSUInteger up_off,
        id<MTLBuffer> xbuf, NSUInteger x_off,
        id<MTLBuffer> midbuf, NSUInteger mid_off,
        id<MTLBuffer> idsbuf, NSUInteger ids_off,
        id<MTLBuffer> weightsbuf, NSUInteger weights_off,
        NSUInteger n_out_tiles,
        NSUInteger n_tok_tiles,
        NSUInteger n_experts) {
    static int s_env_checked = 0;
    static int s_env_active = 0;
    if (!s_env_checked) {
        s_env_active = getenv("DS4_MOE_ICB") != NULL ? 1 : 0;
        s_env_checked = 1;
        if (s_env_active) {
            fprintf(stderr, "ds4: DS4_MOE_ICB=1 — MoE matmul ICB engaged "
                            "(records 6-slot dispatch, replays per layer/token)\n");
        }
    }
    if (!s_env_active) return 0;
    if (!cb || !pipeline || n_experts == 0 || n_experts > DS4_MOE_ICB_SLOTS) return 0;

    if (!g_moe_matmul_icb) {
        MTLIndirectCommandBufferDescriptor *desc = [MTLIndirectCommandBufferDescriptor new];
        desc.commandTypes = MTLIndirectCommandTypeConcurrentDispatch;
        desc.inheritBuffers = NO;
        desc.inheritPipelineState = NO;
        desc.maxKernelBufferBindCount = 8;
        g_moe_matmul_icb =
            [g_device newIndirectCommandBufferWithDescriptor:desc
                                              maxCommandCount:DS4_MOE_ICB_SLOTS
                                                      options:MTLResourceStorageModeShared];
        if (!g_moe_matmul_icb) {
            fprintf(stderr, "ds4: MoE matmul ICB alloc failed\n");
            return 0;
        }
    }

    ds4_moe_icb_slot *slot = &g_moe_matmul_icb_slot;
    const int sig_match = slot->recorded &&
        slot->gate_ptr == (__bridge void *)gatebuf && slot->gate_off == (uint64_t)gate_off &&
        slot->up_ptr   == (__bridge void *)upbuf   && slot->up_off   == (uint64_t)up_off &&
        slot->x_ptr    == (__bridge void *)xbuf    && slot->x_off    == (uint64_t)x_off &&
        slot->mid_ptr  == (__bridge void *)midbuf  && slot->mid_off  == (uint64_t)mid_off &&
        slot->ids_ptr  == (__bridge void *)idsbuf  && slot->ids_off  == (uint64_t)ids_off &&
        slot->w_ptr    == (__bridge void *)weightsbuf && slot->w_off == (uint64_t)weights_off &&
        slot->args_ptr == (__bridge void *)argsbuf &&
        slot->act_ptr  == (__bridge void *)actbuf &&
        slot->n_out_tiles == n_out_tiles && slot->n_tok_tiles == n_tok_tiles;

    if (!sig_match) {
        /* CORRECTION: original 6-slot design was wrong. Each command's
         * tgpig.z extent is 1 → all commands would see idx=0 in
         *   const int idx = (int)(tgpig.z % args.nei0);
         * Fix: record ONE command with full dispatch shape (n_out_tiles,
         * n_tok_tiles, n_experts). The kernel sees tgpig.z=0..n_experts-1
         * naturally via dispatchThreadgroups extent.
         *
         * ICB amortization comes from skipping setComputePipelineState +
         * 8× setBuffer + setThreadgroupMemoryLength + dispatchThreadgroups
         * encoding (~45µs/call). Same target savings as the 6-slot design;
         * cleaner implementation. */
        id<MTLIndirectComputeCommand> cmd =
            [g_moe_matmul_icb indirectComputeCommandAtIndex:0];
        [cmd setComputePipelineState:pipeline];
        [cmd setKernelBuffer:argsbuf  offset:args_off    atIndex:0];
        [cmd setKernelBuffer:actbuf   offset:act_off     atIndex:1];
        [cmd setKernelBuffer:gatebuf  offset:gate_off    atIndex:2];
        [cmd setKernelBuffer:upbuf    offset:up_off      atIndex:3];
        [cmd setKernelBuffer:xbuf     offset:x_off       atIndex:4];
        [cmd setKernelBuffer:midbuf   offset:mid_off     atIndex:5];
        [cmd setKernelBuffer:idsbuf   offset:ids_off     atIndex:6];
        [cmd setKernelBuffer:weightsbuf offset:weights_off atIndex:7];
        [cmd setThreadgroupMemoryLength:1024 atIndex:0];
        [cmd concurrentDispatchThreadgroups:MTLSizeMake(n_out_tiles, n_tok_tiles, n_experts)
                      threadsPerThreadgroup:MTLSizeMake(64, 1, 1)];
        slot->gate_ptr = (__bridge void *)gatebuf; slot->gate_off = (uint64_t)gate_off;
        slot->up_ptr   = (__bridge void *)upbuf;   slot->up_off   = (uint64_t)up_off;
        slot->x_ptr    = (__bridge void *)xbuf;    slot->x_off    = (uint64_t)x_off;
        slot->mid_ptr  = (__bridge void *)midbuf;  slot->mid_off  = (uint64_t)mid_off;
        slot->ids_ptr  = (__bridge void *)idsbuf;  slot->ids_off  = (uint64_t)ids_off;
        slot->w_ptr    = (__bridge void *)weightsbuf; slot->w_off = (uint64_t)weights_off;
        slot->args_ptr = (__bridge void *)argsbuf;
        slot->act_ptr  = (__bridge void *)actbuf;
        slot->n_out_tiles = n_out_tiles;
        slot->n_tok_tiles = n_tok_tiles;
        slot->recorded = 1;
    }

    id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
    [enc useResource:argsbuf    usage:MTLResourceUsageRead];
    [enc useResource:actbuf     usage:MTLResourceUsageRead];
    [enc useResource:gatebuf    usage:MTLResourceUsageRead];
    [enc useResource:upbuf      usage:MTLResourceUsageRead];
    [enc useResource:xbuf       usage:MTLResourceUsageRead];
    [enc useResource:midbuf     usage:MTLResourceUsageRead | MTLResourceUsageWrite];
    [enc useResource:idsbuf     usage:MTLResourceUsageRead];
    [enc useResource:weightsbuf usage:MTLResourceUsageRead];
    /* Single command at index 0; n_experts is encoded in the dispatch
     * extent recorded into the command, not in the replay range. */
    (void)n_experts;
    [enc executeCommandsInBuffer:g_moe_matmul_icb
                       withRange:NSMakeRange(0, 1)];
    ds4_gpu_end_compute_encoder(cb, enc);
    return 1;
}

/* Diagnostic: report ICB record state. */
int ds4_gpu_moe_matmul_icb_status(uint32_t *out_recorded, uint32_t *out_slots) {
    if (out_recorded) *out_recorded = g_moe_matmul_icb_slot.recorded ? 1 : 0;
    if (out_slots) *out_slots = DS4_MOE_ICB_SLOTS;
    return g_moe_matmul_icb ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_hc_weighted_sum (task #683)           */
/* metal/dsv4_hc.metal:863. HC weighted sum: dst[d,t] = sum_h    */
/* x[d,h,t] * weights[h,t]. 1 args + 3 buffers. First port from  */
/* dsv4_hc.metal (head-compress family).                         */
/* ============================================================ */
static id<MTLComputePipelineState> g_hc_weighted_sum_mtl4_pipeline;
static int g_hc_weighted_sum_mtl4_init_attempted;
static int g_hc_weighted_sum_mtl4_init_ok;

static int ds4_hc_weighted_sum_mtl4_pipeline_init(void) {
    if (g_hc_weighted_sum_mtl4_init_attempted) return g_hc_weighted_sum_mtl4_init_ok;
    g_hc_weighted_sum_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct hcws_args {\n"
         "  int64_t n_embd; int64_t n_hc; int64_t n_tokens;\n"
         "  uint64_t nb_x0; uint64_t nb_x1; uint64_t nb_x2;\n"
         "  uint64_t nb_w0; uint64_t nb_w1;\n"
         "  uint64_t nb0; uint64_t nb1;\n"
         "};\n"
         "kernel void hc_weighted_sum_mtl4(\n"
         "    device const hcws_args *args_ptr [[buffer(0)]],\n"
         "    device const char *x [[buffer(1)]],\n"
         "    device const char *weights [[buffer(2)]],\n"
         "    device char *dst [[buffer(3)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  const int64_t n_elem = args_ptr->n_embd * args_ptr->n_tokens;\n"
         "  if ((int64_t)gid >= n_elem) return;\n"
         "  const int64_t d = (int64_t)gid % args_ptr->n_embd;\n"
         "  const int64_t t = (int64_t)gid / args_ptr->n_embd;\n"
         "  float acc = 0.0f;\n"
         "  for (int64_t h = 0; h < args_ptr->n_hc; ++h) {\n"
         "    const float xv = *((device const float *)(x + d * args_ptr->nb_x0 + h * args_ptr->nb_x1 + t * args_ptr->nb_x2));\n"
         "    const float wv = *((device const float *)(weights + h * args_ptr->nb_w0 + t * args_ptr->nb_w1));\n"
         "    acc += xv * wv;\n"
         "  }\n"
         "  *((device float *)(dst + d * args_ptr->nb0 + t * args_ptr->nb1)) = acc;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_hc_weighted_sum_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: hc_weighted_sum MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"hc_weighted_sum_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_hc_weighted_sum_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_hc_weighted_sum_mtl4_pipeline) {
        fprintf(stderr, "ds4: hc_weighted_sum MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: hc_weighted_sum MTL4 pipeline initialized\n");
    g_hc_weighted_sum_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_hc_weighted_sum_canary(uint32_t n_embd, uint32_t n_hc, uint32_t n_tokens) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_hc_weighted_sum_mtl4_pipeline_init()) return 0;

    /* Synthetic: x[d, h, t] = (h+1) * (d+1) * 0.001, weights[h, t] = (h+1)*0.1.
     * Expected dst[d, t] = sum_h ((h+1)*(d+1)*0.001) * ((h+1)*0.1)
     *                    = (d+1) * 0.0001 * sum_h (h+1)^2 */
    const uint64_t x_n = (uint64_t)n_embd * n_hc * n_tokens;
    const uint64_t w_n = (uint64_t)n_hc * n_tokens;
    const uint64_t dst_n = (uint64_t)n_embd * n_tokens;

    float *host_x = (float *)calloc(x_n, sizeof(float));
    float *host_w = (float *)calloc(w_n, sizeof(float));
    float *host_dst_gpu = (float *)calloc(dst_n, sizeof(float));
    float *host_dst_ref = (float *)calloc(dst_n, sizeof(float));
    if (!host_x || !host_w || !host_dst_gpu || !host_dst_ref) {
        free(host_x); free(host_w); free(host_dst_gpu); free(host_dst_ref); return 0;
    }
    /* Layout: nb_x0=sizeof(float), nb_x1=n_embd*float, nb_x2=n_embd*n_hc*float */
    for (uint32_t t = 0; t < n_tokens; t++) {
        for (uint32_t h = 0; h < n_hc; h++) {
            host_w[h + t * n_hc] = (float)(h + 1) * 0.1f;
            for (uint32_t d = 0; d < n_embd; d++) {
                host_x[d + h * n_embd + (uint64_t)t * n_embd * n_hc] =
                    (float)(h + 1) * (float)(d + 1) * 0.001f;
            }
        }
    }
    /* CPU reference */
    for (uint32_t t = 0; t < n_tokens; t++) {
        for (uint32_t d = 0; d < n_embd; d++) {
            float acc = 0.0f;
            for (uint32_t h = 0; h < n_hc; h++) {
                const float xv = host_x[d + h * n_embd + (uint64_t)t * n_embd * n_hc];
                const float wv = host_w[h + t * n_hc];
                acc += xv * wv;
            }
            host_dst_ref[d + t * n_embd] = acc;
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:96
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> xBuf = [g_device newBufferWithBytes:host_x
                                                   length:x_n * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithBytes:host_w
                                                   length:w_n * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int64_t n_embd, n_hc, n_tokens;
            uint64_t nb_x0, nb_x1, nb_x2;
            uint64_t nb_w0, nb_w1;
            uint64_t nb0, nb1;
        } args = {
            .n_embd = (int64_t)n_embd, .n_hc = (int64_t)n_hc, .n_tokens = (int64_t)n_tokens,
            .nb_x0 = sizeof(float),
            .nb_x1 = (uint64_t)n_embd * sizeof(float),
            .nb_x2 = (uint64_t)n_embd * n_hc * sizeof(float),
            .nb_w0 = sizeof(float),
            .nb_w1 = (uint64_t)n_hc * sizeof(float),
            .nb0 = sizeof(float),
            .nb1 = (uint64_t)n_embd * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[4] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)xBuf,
                (id<MTLAllocation>)wBuf, (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:4];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:xBuf.gpuAddress atIndex:1];
                [argTable setAddress:wBuf.gpuAddress atIndex:2];
                [argTable setAddress:dstBuf.gpuAddress atIndex:3];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_hc_weighted_sum_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                const NSUInteger tg = 256;
                const NSUInteger n_tgs = (dst_n + tg - 1) / tg;
                [enc dispatchThreadgroups:MTLSizeMake(n_tgs, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(tg, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst_gpu, dstBuf.contents, dst_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) {
        free(host_x); free(host_w); free(host_dst_gpu); free(host_dst_ref);
        return 0;
    }

    double max_abs = 0.0;
    for (uint64_t i = 0; i < dst_n; i++) {
        double d = fabs((double)(host_dst_gpu[i] - host_dst_ref[i]));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: hc_weighted_sum MTL4 canary n_embd=%u n_hc=%u n_tokens=%u "
        "expected[0]=%.4f gpu[0]=%.4f max_abs=%.4e\n",
        n_embd, n_hc, n_tokens,
        (double)host_dst_ref[0], (double)host_dst_gpu[0], max_abs);
    free(host_x); free(host_w); free(host_dst_gpu); free(host_dst_ref);
    return max_abs < 1.0e-4 ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_router_finalize_one (task #684)       */
/* metal/dsv4_misc.metal:288. Top-K expert selection: bitonic    */
/* sort of 256 probs with optional bias, hash-mode bypass, plus  */
/* writes top-6 expert indices.                                  */
/*                                                               */
/* COMPLETES THE ROUTER CYCLE MTL4 SET (5/5):                    */
/*   topk_mask + topk_mask_scatter +                             */
/*   router_weights_one + router_weights_with_remap +            */
/*   router_finalize_one (this).                                 */
/* ============================================================ */
static id<MTLComputePipelineState> g_router_finalize_one_mtl4_pipeline;
static int g_router_finalize_one_mtl4_init_attempted;
static int g_router_finalize_one_mtl4_init_ok;

static int ds4_router_finalize_one_mtl4_pipeline_init(void) {
    if (g_router_finalize_one_mtl4_init_attempted) return g_router_finalize_one_mtl4_init_ok;
    g_router_finalize_one_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct rs_args {\n"
         "  uint32_t has_bias; uint32_t hash_mode;\n"
         "  uint32_t use_token_buffer; uint32_t token;\n"
         "  uint32_t hash_rows;\n"
         "};\n"
         "kernel void router_finalize_one_mtl4(\n"
         "    device const rs_args *args_ptr [[buffer(0)]],\n"
         "    device const float *probs [[buffer(1)]],\n"
         "    device const float *bias [[buffer(2)]],\n"
         "    device const int32_t *hash [[buffer(3)]],\n"
         "    device const int32_t *tokens [[buffer(4)]],\n"
         "    device int32_t *selected [[buffer(5)]],\n"
         "    threadgroup float *scratch [[threadgroup(0)]],\n"
         "    uint tid [[thread_position_in_threadgroup]]) {\n"
         "  if (tid >= 256) return;\n"
         "  threadgroup float *sel_scores = scratch;\n"
         "  threadgroup int32_t *idx = (threadgroup int32_t *)(scratch + 256);\n"
         "  const float p = probs[tid];\n"
         "  sel_scores[tid] = args_ptr->has_bias ? p + bias[tid] : p;\n"
         "  idx[tid] = (int32_t)tid;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  if (args_ptr->hash_mode) {\n"
         "    if (tid == 0) {\n"
         "      const uint token = args_ptr->use_token_buffer ? (uint)tokens[0] : args_ptr->token;\n"
         "      const uint row = min(token, args_ptr->hash_rows - 1u);\n"
         "      device const int32_t *src = hash + row * 6u;\n"
         "      for (uint i = 0; i < 6; i++) selected[i] = src[i];\n"
         "    }\n"
         "  } else {\n"
         "    for (uint k = 2; k <= 256; k <<= 1) {\n"
         "      for (uint j = k >> 1; j > 0; j >>= 1) {\n"
         "        const uint other = tid ^ j;\n"
         "        if (other > tid) {\n"
         "          if ((tid & k) == 0) {\n"
         "            if (sel_scores[(uint)idx[tid]] < sel_scores[(uint)idx[other]]) {\n"
         "              const int32_t tmp = idx[tid]; idx[tid] = idx[other]; idx[other] = tmp;\n"
         "            }\n"
         "          } else {\n"
         "            if (sel_scores[(uint)idx[tid]] > sel_scores[(uint)idx[other]]) {\n"
         "              const int32_t tmp = idx[tid]; idx[tid] = idx[other]; idx[other] = tmp;\n"
         "            }\n"
         "          }\n"
         "        }\n"
         "        threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "      }\n"
         "    }\n"
         "    if (tid < 6) selected[tid] = idx[tid];\n"
         "  }\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_router_finalize_one_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: router_finalize_one MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"router_finalize_one_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_router_finalize_one_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_router_finalize_one_mtl4_pipeline) {
        fprintf(stderr, "ds4: router_finalize_one MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: router_finalize_one MTL4 pipeline initialized "
                    "(threadExecutionWidth=%lu)\n",
            (unsigned long)g_router_finalize_one_mtl4_pipeline.threadExecutionWidth);
    g_router_finalize_one_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_router_finalize_one_canary(int has_bias_flag) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_router_finalize_one_mtl4_pipeline_init()) return 0;

    /* Synthetic: probs[i] = (i == 0..5) ? 1.0 - i*0.01 : 0.001 (top-6 are i=0..5)
     * with descending scores. Expected selected = {0, 1, 2, 3, 4, 5}.
     * Optional bias: bias[i] = 0 (no-op when has_bias=1). */
    float host_probs[256];
    float host_bias[256] = {0};
    int32_t host_hash[6] = {99, 98, 97, 96, 95, 94};  /* unused unless hash_mode=1 */
    int32_t host_tokens[1] = {0};
    int32_t host_selected[6] = {-1, -1, -1, -1, -1, -1};
    int32_t host_selected_ref[6] = {0, 1, 2, 3, 4, 5};

    for (int i = 0; i < 256; i++) {
        host_probs[i] = (i < 6) ? (1.0f - (float)i * 0.01f) : 0.001f;
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:32
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> probsBuf = [g_device newBufferWithBytes:host_probs
                                                       length:sizeof(host_probs)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> biasBuf = [g_device newBufferWithBytes:host_bias
                                                      length:sizeof(host_bias)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> hashBuf = [g_device newBufferWithBytes:host_hash
                                                      length:sizeof(host_hash)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> tokensBuf = [g_device newBufferWithBytes:host_tokens
                                                        length:sizeof(host_tokens)
                                                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> selBuf = [g_device newBufferWithLength:6 * sizeof(int32_t)
                                                     options:MTLResourceStorageModeShared];

        struct { uint32_t has_bias, hash_mode, use_token_buffer, token, hash_rows; } args = {
            .has_bias = (uint32_t)(has_bias_flag ? 1 : 0),
            .hash_mode = 0, .use_token_buffer = 0, .token = 0, .hash_rows = 1,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[6] = {
                (id<MTLAllocation>)argsBuf, (id<MTLAllocation>)probsBuf,
                (id<MTLAllocation>)biasBuf, (id<MTLAllocation>)hashBuf,
                (id<MTLAllocation>)tokensBuf, (id<MTLAllocation>)selBuf,
            };
            [residency addAllocations:allocs count:6];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(6);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:probsBuf.gpuAddress atIndex:1];
                [argTable setAddress:biasBuf.gpuAddress atIndex:2];
                [argTable setAddress:hashBuf.gpuAddress atIndex:3];
                [argTable setAddress:tokensBuf.gpuAddress atIndex:4];
                [argTable setAddress:selBuf.gpuAddress atIndex:5];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_router_finalize_one_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* scratch: 256 float scores + 256 int32 indices = 1024 + 1024 bytes */
                [enc setThreadgroupMemoryLength:2048 atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_selected, selBuf.contents, sizeof(host_selected));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 6);
            }
        }
    }
    if (!rc) return 0;

    /* Bitonic sort on a small N with distinct scores should yield top-K
     * as 0..5 in any permutation; verify SET membership rather than order. */
    int found[6] = {0};
    for (int i = 0; i < 6; i++) {
        const int v = host_selected[i];
        if (v >= 0 && v < 6) found[v] = 1;
    }
    int n_found = 0;
    for (int i = 0; i < 6; i++) n_found += found[i];
    fprintf(stderr,
        "ds4: router_finalize_one MTL4 canary has_bias=%d selected={%d,%d,%d,%d,%d,%d} "
        "set_found=%d/6 (expected all 6 of {0..5})\n",
        has_bias_flag,
        host_selected[0], host_selected[1], host_selected[2],
        host_selected[3], host_selected[4], host_selected[5], n_found);
    (void)host_selected_ref;
    return n_found == 6 ? 1 : 0;
}

/* ============================================================ */
/* MTL4 port: kernel_dsv4_qkv_rms_norm_f32_4 (task #685)        */
/* metal/norm.metal:102. Fused Q+KV RMSNorm — fires 43× per     */
/* token (once per layer). 1 args + 6 buffers + simd reductions.*/
/* High call-density target.                                     */
/* ============================================================ */
static id<MTLComputePipelineState> g_qkv_rms_norm_mtl4_pipeline;
static int g_qkv_rms_norm_mtl4_init_attempted;
static int g_qkv_rms_norm_mtl4_init_ok;

static int ds4_qkv_rms_norm_mtl4_pipeline_init(void) {
    if (g_qkv_rms_norm_mtl4_init_attempted) return g_qkv_rms_norm_mtl4_init_ok;
    g_qkv_rms_norm_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct qkv_args {\n"
         "  int32_t q_n; int32_t q_n4; int32_t kv_n; int32_t kv_n4;\n"
         "  uint64_t q_row_stride; uint64_t kv_row_stride; float eps;\n"
         "};\n"
         "kernel void qkv_rms_norm_mtl4(\n"
         "    device const qkv_args *args_ptr [[buffer(0)]],\n"
         "    device const float4 *q_src [[buffer(1)]],\n"
         "    device const float4 *q_weight [[buffer(2)]],\n"
         "    device float4 *q_dst [[buffer(3)]],\n"
         "    device const float4 *kv_src [[buffer(4)]],\n"
         "    device const float4 *kv_weight [[buffer(5)]],\n"
         "    device float4 *kv_dst [[buffer(6)]],\n"
         "    threadgroup float *shmem_f32 [[threadgroup(0)]],\n"
         "    uint3 tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort3 tpitg [[thread_position_in_threadgroup]],\n"
         "    ushort sgitg [[simdgroup_index_in_threadgroup]],\n"
         "    ushort tiisg [[thread_index_in_simdgroup]],\n"
         "    ushort3 ntg [[threads_per_threadgroup]]) {\n"
         "  if (sgitg == 0) shmem_f32[tiisg] = 0.0f;\n"
         "  const uint row = tgpig.x;\n"
         "  const bool kv_task = tgpig.y != 0;\n"
         "  const int n = kv_task ? args_ptr->kv_n : args_ptr->q_n;\n"
         "  const int n4 = kv_task ? args_ptr->kv_n4 : args_ptr->q_n4;\n"
         "  const uint64_t row_stride4 = (kv_task ? args_ptr->kv_row_stride : args_ptr->q_row_stride) / sizeof(float4);\n"
         "  device const float4 *x = kv_task ? kv_src + row * row_stride4 : q_src + row * row_stride4;\n"
         "  device const float4 *w = kv_task ? kv_weight : q_weight;\n"
         "  device float4 *y = kv_task ? kv_dst + row * row_stride4 : q_dst + row * row_stride4;\n"
         "  float sumf = 0.0f;\n"
         "  for (int i = tpitg.x; i < n4; i += ntg.x) {\n"
         "    const float4 v = x[i]; sumf += dot(v, v);\n"
         "  }\n"
         "  sumf = simd_sum(sumf);\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  if (tiisg == 0) shmem_f32[sgitg] = sumf;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  sumf = shmem_f32[tiisg];\n"
         "  sumf = simd_sum(sumf);\n"
         "  const float scale = rsqrt(sumf / float(n) + args_ptr->eps);\n"
         "  for (int i = tpitg.x; i < n4; i += ntg.x) {\n"
         "    y[i] = (x[i] * scale) * w[i];\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_qkv_rms_norm_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: qkv_rms_norm MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"qkv_rms_norm_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_qkv_rms_norm_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_qkv_rms_norm_mtl4_pipeline) {
        fprintf(stderr, "ds4: qkv_rms_norm MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: qkv_rms_norm MTL4 pipeline initialized\n");
    g_qkv_rms_norm_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_qkv_rms_norm_canary(uint32_t q_n, uint32_t kv_n) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_qkv_rms_norm_mtl4_pipeline_init()) return 0;
    if (q_n % 4 != 0 || kv_n % 4 != 0) {
        fprintf(stderr, "ds4: qkv_rms_norm canary requires q_n, kv_n %% 4 == 0\n");
        return 0;
    }

    /* Single row each for Q + KV. Q dim: q_n; KV dim: kv_n.
     * Synthesize: q_src = constant 1.0, q_weight = constant 0.5 →
     *   sum_sq = q_n; rms = sqrt(q_n/q_n + eps) ≈ 1; scale ≈ 1; y = 1*1*0.5 = 0.5.
     * Same for KV. */
    const float eps = 1.0e-6f;
    const uint32_t q_n4 = q_n / 4;
    const uint32_t kv_n4 = kv_n / 4;

    float *host_q_src = (float *)calloc(q_n, sizeof(float));
    float *host_q_weight = (float *)calloc(q_n, sizeof(float));
    float *host_q_dst = (float *)calloc(q_n, sizeof(float));
    float *host_kv_src = (float *)calloc(kv_n, sizeof(float));
    float *host_kv_weight = (float *)calloc(kv_n, sizeof(float));
    float *host_kv_dst = (float *)calloc(kv_n, sizeof(float));
    if (!host_q_src || !host_q_weight || !host_q_dst ||
        !host_kv_src || !host_kv_weight || !host_kv_dst) {
        free(host_q_src); free(host_q_weight); free(host_q_dst);
        free(host_kv_src); free(host_kv_weight); free(host_kv_dst);
        return 0;
    }
    for (uint32_t i = 0; i < q_n; i++) { host_q_src[i] = 1.0f; host_q_weight[i] = 0.5f; }
    for (uint32_t i = 0; i < kv_n; i++) { host_kv_src[i] = 1.0f; host_kv_weight[i] = 0.25f; }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:48
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> qSrcBuf = [g_device newBufferWithBytes:host_q_src length:q_n * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> qWBuf = [g_device newBufferWithBytes:host_q_weight length:q_n * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> qDstBuf = [g_device newBufferWithLength:q_n * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> kvSrcBuf = [g_device newBufferWithBytes:host_kv_src length:kv_n * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> kvWBuf = [g_device newBufferWithBytes:host_kv_weight length:kv_n * sizeof(float) options:MTLResourceStorageModeShared];
        id<MTLBuffer> kvDstBuf = [g_device newBufferWithLength:kv_n * sizeof(float) options:MTLResourceStorageModeShared];

        struct {
            int32_t q_n_, q_n4_, kv_n_, kv_n4_;
            uint64_t q_row_stride, kv_row_stride;
            float eps;
            uint32_t pad;
        } args = {
            .q_n_ = (int32_t)q_n, .q_n4_ = (int32_t)q_n4,
            .kv_n_ = (int32_t)kv_n, .kv_n4_ = (int32_t)kv_n4,
            .q_row_stride = (uint64_t)q_n * sizeof(float),
            .kv_row_stride = (uint64_t)kv_n * sizeof(float),
            .eps = eps,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[7] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)qSrcBuf, (id<MTLAllocation>)qWBuf, (id<MTLAllocation>)qDstBuf,
                (id<MTLAllocation>)kvSrcBuf, (id<MTLAllocation>)kvWBuf, (id<MTLAllocation>)kvDstBuf,
            };
            [residency addAllocations:allocs count:7];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(8);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:qSrcBuf.gpuAddress atIndex:1];
                [argTable setAddress:qWBuf.gpuAddress atIndex:2];
                [argTable setAddress:qDstBuf.gpuAddress atIndex:3];
                [argTable setAddress:kvSrcBuf.gpuAddress atIndex:4];
                [argTable setAddress:kvWBuf.gpuAddress atIndex:5];
                [argTable setAddress:kvDstBuf.gpuAddress atIndex:6];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_qkv_rms_norm_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* shmem: 32 simdgroups × 4 bytes = 128 bytes scratch */
                [enc setThreadgroupMemoryLength:128 atIndex:0];
                /* Dispatch: 1 row × 2 tasks (q, kv) */
                [enc dispatchThreadgroups:MTLSizeMake(1, 2, 1)
                    threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_q_dst, qDstBuf.contents, q_n * sizeof(float));
                    memcpy(host_kv_dst, kvDstBuf.contents, kv_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 8);
            }
        }
    }
    if (!rc) {
        free(host_q_src); free(host_q_weight); free(host_q_dst);
        free(host_kv_src); free(host_kv_weight); free(host_kv_dst);
        return 0;
    }

    /* Reference: sum_sq = q_n × 1.0; rms = sqrt(q_n / q_n + eps) ≈ 1; scale ≈ rsqrt(1+eps) ≈ 1.
     * y_q = 1.0 * 1.0 * 0.5 = 0.5; y_kv = 1.0 * 1.0 * 0.25 = 0.25. */
    const float q_scale = 1.0f / sqrtf(1.0f + eps);
    const float kv_scale = 1.0f / sqrtf(1.0f + eps);
    const float q_ref = 1.0f * q_scale * 0.5f;
    const float kv_ref = 1.0f * kv_scale * 0.25f;

    double max_abs_q = 0.0, max_abs_kv = 0.0;
    for (uint32_t i = 0; i < q_n; i++) {
        double d = fabs((double)(host_q_dst[i] - q_ref));
        if (d > max_abs_q) max_abs_q = d;
    }
    for (uint32_t i = 0; i < kv_n; i++) {
        double d = fabs((double)(host_kv_dst[i] - kv_ref));
        if (d > max_abs_kv) max_abs_kv = d;
    }
    fprintf(stderr,
        "ds4: qkv_rms_norm MTL4 canary q_n=%u kv_n=%u "
        "q[0]=%.4f (ref=%.4f) kv[0]=%.4f (ref=%.4f) "
        "max_abs_q=%.4e max_abs_kv=%.4e\n",
        q_n, kv_n,
        (double)host_q_dst[0], (double)q_ref,
        (double)host_kv_dst[0], (double)kv_ref,
        max_abs_q, max_abs_kv);
    free(host_q_src); free(host_q_weight); free(host_q_dst);
    free(host_kv_src); free(host_kv_weight); free(host_kv_dst);
    return (max_abs_q < 1.0e-5 && max_abs_kv < 1.0e-5) ? 1 : 0;
}

/* ============================================================ */
/* soft_max_f32_4 MTL4 port (silv 2026-05-27 task #678)         */
/* ============================================================ */
/* MTL4-side port of kernel_soft_max_4<float4> from metal/softmax.metal.
 * Row softmax with optional mask + sink + ALiBi slope (canary uses the
 * simplified path: scale=1, no mask, no sink, no ALiBi — that exercises
 * the load-reduce-renormalize pattern over a float4 row).
 *
 * Dispatch shape: (rows, planes, 1) threadgroups × (nth, 1, 1) threads.
 * Threadgroup scratch: 32 floats (one per simdgroup, max 8 simdgroups @
 * 256 threads on M1).
 *
 * The full production-path version would inline mask + sink + ALiBi;
 * this port validates the core compute kernel + MTL4 argument-table
 * binding shape. Production wire deferred until A/B path is open per
 * the deep-ops design memo. */

static id<MTLComputePipelineState> g_soft_max_4_mtl4_pipeline;
static int g_soft_max_4_mtl4_init_attempted;
static int g_soft_max_4_mtl4_init_ok;

static int ds4_soft_max_4_mtl4_pipeline_init(void) {
    if (g_soft_max_4_mtl4_init_attempted) return g_soft_max_4_mtl4_init_ok;
    g_soft_max_4_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct sm_args {\n"
         "  int32_t n;       /* row length in float elements */\n"
         "  int32_t n4;      /* row length / 4 */\n"
         "  float   scale;\n"
         "};\n"
         "kernel void soft_max_4_mtl4(\n"
         "    device const sm_args *args [[buffer(0)]],\n"
         "    device const float4  *src [[buffer(1)]],\n"
         "    device       float4  *dst [[buffer(2)]],\n"
         "    threadgroup  float   *shmem [[threadgroup(0)]],\n"
         "    uint3  tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort3 tpitg [[thread_position_in_threadgroup]],\n"
         "    ushort  sgitg [[simdgroup_index_in_threadgroup]],\n"
         "    ushort  tiisg [[thread_index_in_simdgroup]],\n"
         "    ushort3 ntg [[threads_per_threadgroup]]) {\n"
         "  const uint row = tgpig.x;\n"
         "  const int  n4  = args->n4;\n"
         "  const float scale = args->scale;\n"
         "  device const float4 *psrc = src + row * (uint)n4;\n"
         "  device       float4 *pdst = dst + row * (uint)n4;\n"
         "  /* pass 1: max */\n"
         "  float4 lmax4 = (float4)(-INFINITY);\n"
         "  for (int i = tpitg.x; i < n4; i += ntg.x) {\n"
         "    lmax4 = fmax(lmax4, psrc[i] * scale);\n"
         "  }\n"
         "  float lmax = fmax(fmax(lmax4.x, lmax4.y), fmax(lmax4.z, lmax4.w));\n"
         "  lmax = simd_max(lmax);\n"
         "  if (ntg.x > 32) {\n"
         "    if (sgitg == 0) shmem[tiisg] = -INFINITY;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    if (tiisg == 0)  shmem[sgitg] = lmax;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    lmax = shmem[tiisg];\n"
         "    lmax = simd_max(lmax);\n"
         "  }\n"
         "  /* pass 2: exp + sum + write */\n"
         "  float4 lsum4 = (float4)(0.0f);\n"
         "  for (int i = tpitg.x; i < n4; i += ntg.x) {\n"
         "    const float4 e = exp(psrc[i] * scale - lmax);\n"
         "    lsum4 += e;\n"
         "    pdst[i] = e;\n"
         "  }\n"
         "  float lsum = lsum4.x + lsum4.y + lsum4.z + lsum4.w;\n"
         "  threadgroup_barrier(mem_flags::mem_none);\n"
         "  lsum = simd_sum(lsum);\n"
         "  if (ntg.x > 32) {\n"
         "    if (sgitg == 0) shmem[tiisg] = 0.0f;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    if (tiisg == 0)  shmem[sgitg] = lsum;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    lsum = shmem[tiisg];\n"
         "    lsum = simd_sum(lsum);\n"
         "  }\n"
         "  const float inv_sum = 1.0f / lsum;\n"
         "  /* pass 3: normalize */\n"
         "  for (int i = tpitg.x; i < n4; i += ntg.x) {\n"
         "    pdst[i] *= inv_sum;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_soft_max_4_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: soft_max_4 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"soft_max_4_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_soft_max_4_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_soft_max_4_mtl4_pipeline) {
        fprintf(stderr, "ds4: soft_max_4 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: soft_max_4 MTL4 pipeline initialized\n");
    g_soft_max_4_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_soft_max_4_canary(uint32_t n) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_soft_max_4_mtl4_pipeline_init()) return 0;
    if (n == 0 || (n % 4) != 0) {
        fprintf(stderr, "ds4: soft_max_4 canary requires n>0 and n %% 4 == 0\n");
        return 0;
    }

    /* Reference setup: all-zero input → softmax → uniform 1/n.
     * Also test a non-trivial pattern: src[i] = (i==0)?1:0 with scale=1.
     * Expected: exp(1)/(exp(1) + (n-1)*exp(0)) at index 0; exp(0)/Z elsewhere. */
    const uint32_t n4 = n / 4;
    float *host_src = (float *)calloc(n, sizeof(float));
    float *host_dst = (float *)calloc(n, sizeof(float));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    /* Use the spike pattern for stronger validation than uniform-0. */
    host_src[0] = 1.0f;

    /* Reference. */
    const float scale = 1.0f;
    const float max_v = 1.0f;
    double Z = expf(1.0f - max_v) + (double)(n - 1) * expf(0.0f - max_v);
    const float ref0 = (float)(expf(1.0f - max_v) / Z);
    const float ref_else = (float)(expf(0.0f - max_v) / Z);

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct { int32_t n_, n4_; float scale_; uint32_t pad; } args = {
            .n_ = (int32_t)n, .n4_ = (int32_t)n4, .scale_ = scale,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)srcBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                /* Pick a thread count: clamp to 256 (M1 max), ≤ n4 */
                NSUInteger nth = 32u;
                while (nth < n4 && nth < 256u) nth *= 2u;
                if (nth > g_soft_max_4_mtl4_pipeline.maxTotalThreadsPerThreadgroup)
                    nth = g_soft_max_4_mtl4_pipeline.maxTotalThreadsPerThreadgroup;

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_soft_max_4_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* 32 simdgroups × 4 bytes = 128 bytes scratch (one slot per
                 * simdgroup, indexed by sgitg ∈ [0, ntg.x/32)) */
                [enc setThreadgroupMemoryLength:128 atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    /* Validate */
    double max_abs = 0.0;
    double sum = 0.0;
    double d0 = fabs((double)(host_dst[0] - ref0));
    if (d0 > max_abs) max_abs = d0;
    sum += (double)host_dst[0];
    for (uint32_t i = 1; i < n; i++) {
        double d = fabs((double)(host_dst[i] - ref_else));
        if (d > max_abs) max_abs = d;
        sum += (double)host_dst[i];
    }
    fprintf(stderr,
        "ds4: soft_max_4 MTL4 canary n=%u dst[0]=%.6f (ref=%.6f) "
        "dst[1]=%.6f (ref=%.6f) sum=%.6f max_abs=%.4e\n",
        n,
        (double)host_dst[0], (double)ref0,
        (double)host_dst[1], (double)ref_else,
        sum, max_abs);
    free(host_src); free(host_dst);
    /* Looser tol: float exp accumulation across N=512+ has ~1e-6 drift */
    return (max_abs < 5.0e-6 && fabs(sum - 1.0) < 5.0e-5) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_hc_expand4 MTL4 port (silv 2026-05-27 task #679)         */
/* ============================================================ */
/* MTL4-side port of kernel_dsv4_hc_expand4 from metal/dsv4_hc.metal:579.
 * HC=4 specialization: one thread = one (d, t) tuple → 4 outputs.
 *
 * Production kernel: 5 input buffers (block_out, residual, post, comb,
 * block_add) + dst. Per-thread reads block_v, 4 residual values, 4 post
 * values, 16 comb values → produces 4 dst values.
 *
 * Canary path keeps the same compute shape but uses contiguous row-major
 * buffers without the production kernel's arbitrary striding. The MTL4
 * production wire would re-add full nb* striding via the args buffer.
 *
 * Per-layer dispatch density: 43× per token in the attention/FFN block
 * expansion path. */

static id<MTLComputePipelineState> g_hc_expand4_mtl4_pipeline;
static int g_hc_expand4_mtl4_init_attempted;
static int g_hc_expand4_mtl4_init_ok;

static int ds4_hc_expand4_mtl4_pipeline_init(void) {
    if (g_hc_expand4_mtl4_init_attempted) return g_hc_expand4_mtl4_init_ok;
    g_hc_expand4_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct hc_args {\n"
         "  int32_t n_embd;\n"
         "  int32_t n_hc;     /* fixed at 4 for this kernel */\n"
         "  int32_t n_tokens;\n"
         "  int32_t has_add;\n"
         "};\n"
         "/* Contiguous-row-major layout:\n"
         "   block_out : float[n_embd, n_tokens]              — index d + t*n_embd\n"
         "   residual  : float[n_embd, 4, n_tokens]           — d + src_hc*n_embd + t*4*n_embd\n"
         "   post      : float[4, n_tokens]                   — dst_hc + t*4\n"
         "   comb      : float[4, 4, n_tokens]                — dst_hc + src_hc*4 + t*16\n"
         "   block_add : same as block_out (aliased when !has_add)\n"
         "   dst       : float[n_embd, 4, n_tokens]           — d + dst_hc*n_embd + t*4*n_embd */\n"
         "kernel void hc_expand4_mtl4(\n"
         "    device const hc_args  *args [[buffer(0)]],\n"
         "    device const float    *block_out [[buffer(1)]],\n"
         "    device const float    *residual  [[buffer(2)]],\n"
         "    device const float    *post      [[buffer(3)]],\n"
         "    device const float    *comb      [[buffer(4)]],\n"
         "    device const float    *block_add [[buffer(5)]],\n"
         "    device       float    *dst       [[buffer(6)]],\n"
         "    uint gid [[thread_position_in_grid]]) {\n"
         "  const int32_t n_embd = args->n_embd;\n"
         "  const int32_t n_tokens = args->n_tokens;\n"
         "  const int64_t n_elem = (int64_t)n_embd * (int64_t)n_tokens;\n"
         "  if ((int64_t)gid >= n_elem) return;\n"
         "  const int64_t d = (int64_t)gid % n_embd;\n"
         "  const int64_t t = (int64_t)gid / n_embd;\n"
         "  float block_v = block_out[d + t * n_embd];\n"
         "  if (args->has_add) {\n"
         "    block_v += block_add[d + t * n_embd];\n"
         "  }\n"
         "  /* Pre-load the 4 residual values for this (d, t) */\n"
         "  const int64_t res_base = d + t * 4 * n_embd;\n"
         "  const float r0 = residual[res_base + 0 * n_embd];\n"
         "  const float r1 = residual[res_base + 1 * n_embd];\n"
         "  const float r2 = residual[res_base + 2 * n_embd];\n"
         "  const float r3 = residual[res_base + 3 * n_embd];\n"
         "  const int64_t post_base = t * 4;\n"
         "  const int64_t comb_base = t * 16;\n"
         "  for (int dst_hc = 0; dst_hc < 4; ++dst_hc) {\n"
         "    float acc = block_v * post[post_base + dst_hc];\n"
         "    acc += comb[comb_base + dst_hc + 0 * 4] * r0;\n"
         "    acc += comb[comb_base + dst_hc + 1 * 4] * r1;\n"
         "    acc += comb[comb_base + dst_hc + 2 * 4] * r2;\n"
         "    acc += comb[comb_base + dst_hc + 3 * 4] * r3;\n"
         "    dst[d + dst_hc * n_embd + t * 4 * n_embd] = acc;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_hc_expand4_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: hc_expand4 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"hc_expand4_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_hc_expand4_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_hc_expand4_mtl4_pipeline) {
        fprintf(stderr, "ds4: hc_expand4 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: hc_expand4 MTL4 pipeline initialized\n");
    g_hc_expand4_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_hc_expand4_canary(uint32_t n_embd, uint32_t n_tokens) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_hc_expand4_mtl4_pipeline_init()) return 0;
    if (n_embd == 0 || n_tokens == 0) {
        fprintf(stderr, "ds4: hc_expand4 canary requires n_embd>0 and n_tokens>0\n");
        return 0;
    }

    /* Canary setup:
     *   block_out[d, t]            = 1.0
     *   residual[d, src_hc, t]     = (src_hc + 1) * 0.5  (small)
     *   post[dst_hc, t]            = 1.0
     *   comb[dst_hc, src_hc, t]    = (dst_hc == src_hc) ? 2.0 : 0.0  (identity × 2)
     *   has_add                    = 0
     *
     * Expected per element:
     *   acc = 1.0 * 1.0 + 2.0 * (dst_hc+1) * 0.5 = 1.0 + (dst_hc + 1)
     *   dst[d, dst_hc, t] = dst_hc + 2  (independent of d, t)
     *
     * So dst[*, 0, *] = 2, dst[*, 1, *] = 3, dst[*, 2, *] = 4, dst[*, 3, *] = 5. */
    const uint32_t n_hc = 4;
    const uint64_t block_n = (uint64_t)n_embd * n_tokens;
    const uint64_t res_n = (uint64_t)n_embd * n_hc * n_tokens;
    const uint64_t post_n = (uint64_t)n_hc * n_tokens;
    const uint64_t comb_n = (uint64_t)n_hc * n_hc * n_tokens;
    const uint64_t dst_n = (uint64_t)n_embd * n_hc * n_tokens;

    float *host_block = (float *)calloc(block_n, sizeof(float));
    float *host_res = (float *)calloc(res_n, sizeof(float));
    float *host_post = (float *)calloc(post_n, sizeof(float));
    float *host_comb = (float *)calloc(comb_n, sizeof(float));
    float *host_dst = (float *)calloc(dst_n, sizeof(float));
    if (!host_block || !host_res || !host_post || !host_comb || !host_dst) {
        free(host_block); free(host_res); free(host_post); free(host_comb); free(host_dst);
        return 0;
    }

    /* Fill inputs */
    for (uint64_t i = 0; i < block_n; i++) host_block[i] = 1.0f;
    for (uint32_t t = 0; t < n_tokens; t++) {
        for (uint32_t src_hc = 0; src_hc < n_hc; src_hc++) {
            const float r = (float)(src_hc + 1) * 0.5f;
            for (uint32_t d = 0; d < n_embd; d++) {
                host_res[(uint64_t)d + src_hc * n_embd + (uint64_t)t * n_hc * n_embd] = r;
            }
        }
        for (uint32_t dst_hc = 0; dst_hc < n_hc; dst_hc++) {
            host_post[(uint64_t)dst_hc + (uint64_t)t * n_hc] = 1.0f;
        }
        for (uint32_t src_hc = 0; src_hc < n_hc; src_hc++) {
            for (uint32_t dst_hc = 0; dst_hc < n_hc; dst_hc++) {
                host_comb[(uint64_t)dst_hc + src_hc * n_hc + (uint64_t)t * n_hc * n_hc] =
                    (dst_hc == src_hc) ? 2.0f : 0.0f;
            }
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> blockBuf = [g_device newBufferWithBytes:host_block
                                                       length:block_n * sizeof(float)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> resBuf = [g_device newBufferWithBytes:host_res
                                                     length:res_n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> postBuf = [g_device newBufferWithBytes:host_post
                                                      length:post_n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> combBuf = [g_device newBufferWithBytes:host_comb
                                                      length:comb_n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];

        struct { int32_t n_embd_, n_hc_, n_tokens_, has_add_; } args = {
            .n_embd_ = (int32_t)n_embd,
            .n_hc_ = (int32_t)n_hc,
            .n_tokens_ = (int32_t)n_tokens,
            .has_add_ = 0,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[7] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)blockBuf,
                (id<MTLAllocation>)resBuf,
                (id<MTLAllocation>)postBuf,
                (id<MTLAllocation>)combBuf,
                (id<MTLAllocation>)blockBuf,   /* block_add alias when !has_add */
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:7];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(8);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:blockBuf.gpuAddress atIndex:1];
                [argTable setAddress:resBuf.gpuAddress atIndex:2];
                [argTable setAddress:postBuf.gpuAddress atIndex:3];
                [argTable setAddress:combBuf.gpuAddress atIndex:4];
                [argTable setAddress:blockBuf.gpuAddress atIndex:5]; /* block_add */
                [argTable setAddress:dstBuf.gpuAddress atIndex:6];

                const uint64_t n_elem = (uint64_t)n_embd * n_tokens;
                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)n_elem));
                NSUInteger n_tg = ((NSUInteger)n_elem + nth - 1u) / nth;

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_hc_expand4_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(n_tg, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, dst_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 8);
            }
        }
    }
    if (!rc) {
        free(host_block); free(host_res); free(host_post); free(host_comb); free(host_dst);
        return 0;
    }

    /* Validate */
    double max_abs = 0.0;
    int n_checked = 0;
    for (uint32_t t = 0; t < n_tokens; t++) {
        for (uint32_t dst_hc = 0; dst_hc < n_hc; dst_hc++) {
            const float ref = (float)(dst_hc + 2);
            for (uint32_t d = 0; d < n_embd; d++) {
                const float v = host_dst[(uint64_t)d + dst_hc * n_embd + (uint64_t)t * n_hc * n_embd];
                const double diff = fabs((double)(v - ref));
                if (diff > max_abs) max_abs = diff;
                n_checked++;
            }
        }
    }
    fprintf(stderr,
        "ds4: hc_expand4 MTL4 canary n_embd=%u n_tokens=%u n_checked=%d "
        "dst[0,0,0]=%.4f (ref=2.0) dst[0,1,0]=%.4f (ref=3.0) "
        "dst[0,2,0]=%.4f (ref=4.0) dst[0,3,0]=%.4f (ref=5.0) max_abs=%.4e\n",
        n_embd, n_tokens, n_checked,
        (double)host_dst[0],
        (double)host_dst[n_embd],
        (double)host_dst[2 * n_embd],
        (double)host_dst[3 * n_embd],
        max_abs);
    free(host_block); free(host_res); free(host_post); free(host_comb); free(host_dst);
    return (max_abs < 1.0e-5) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_indexer_score_one_direct MTL4 port (silv 2026-05-27 task #680) */
/* ============================================================ */
/* MTL4-side port of kernel_dsv4_indexer_score_one_direct from
 * metal/dsv4_misc.metal:142.
 *
 * Decode-only DS4 ratio-4 indexer score builder. Hardcoded for
 * n_head=64, head_dim=128, threadgroup=128 threads = 4 simdgroups × 32
 * lanes. Per row (one compressed K vector), produces a single score
 * value via: ReLU(dot(q_head, k_row)) × weight[head], summed over 64
 * heads.
 *
 * The kernel structure exercises:
 *   - 128-thread threadgroup that stages 128-wide k vector once
 *   - 4-simdgroup parallelism over head groups (4 heads per iter × 16)
 *   - simd_sum cross-lane reduction
 *   - 2-stage tg-shared accumulation across 4 simdgroups
 *   - Two threadgroup_barriers per iteration
 *
 * Per-attention dispatch density (fires once per decode call). */

static id<MTLComputePipelineState> g_indexer_score_one_direct_mtl4_pipeline;
static int g_indexer_score_one_direct_mtl4_init_attempted;
static int g_indexer_score_one_direct_mtl4_init_ok;

static int ds4_indexer_score_one_direct_mtl4_pipeline_init(void) {
    if (g_indexer_score_one_direct_mtl4_init_attempted) return g_indexer_score_one_direct_mtl4_init_ok;
    g_indexer_score_one_direct_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct idx_args {\n"
         "  uint32_t n_comp;        /* number of compressed rows = dispatch.x */\n"
         "  uint32_t n_head;        /* must be 64 */\n"
         "  uint32_t head_dim;      /* must be 128 */\n"
         "  uint32_t pad;\n"
         "  uint64_t q_head_stride;     /* bytes between heads in q   */\n"
         "  uint64_t index_row_stride;  /* bytes between rows in k    */\n"
         "  float    scale;\n"
         "};\n"
         "kernel void indexer_score_one_direct_mtl4(\n"
         "    device const idx_args *args [[buffer(0)]],\n"
         "    device const char     *q [[buffer(1)]],\n"
         "    device const float    *weights [[buffer(2)]],\n"
         "    device const char     *index_comp [[buffer(3)]],\n"
         "    device       float    *scores [[buffer(4)]],\n"
         "    threadgroup  float    *shared [[threadgroup(0)]],\n"
         "    uint   row  [[threadgroup_position_in_grid]],\n"
         "    ushort tid  [[thread_index_in_threadgroup]],\n"
         "    ushort lane [[thread_index_in_simdgroup]],\n"
         "    ushort sg   [[simdgroup_index_in_threadgroup]]) {\n"
         "  if (row >= args->n_comp || args->n_head != 64u || args->head_dim != 128u) return;\n"
         "  threadgroup float *ktg = shared;        // [128]\n"
         "  threadgroup float *psum = ktg + 128u;   // [4]\n"
         "  /* Stage k row in shared mem */\n"
         "  if (tid < 128u) {\n"
         "    device const float *krow = (device const float *)(index_comp +\n"
         "                                  (uint64_t)row * args->index_row_stride);\n"
         "    ktg[tid] = krow[tid];\n"
         "  }\n"
         "  float acc = 0.0f;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  for (uint head0 = 0u; head0 < 64u; head0 += 4u) {\n"
         "    const uint head = head0 + (uint)sg;\n"
         "    device const float4 *q4 = (device const float4 *)(q +\n"
         "                                (uint64_t)head * args->q_head_stride);\n"
         "    threadgroup const float4 *k4 = (threadgroup const float4 *)ktg;\n"
         "    float s = dot(q4[lane], k4[lane]);\n"
         "    s = simd_sum(s);\n"
         "    if (lane == 0) {\n"
         "      psum[sg] = max(s, 0.0f) * (weights[head] * args->scale);\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    if (tid == 0) {\n"
         "      acc += psum[0]; acc += psum[1]; acc += psum[2]; acc += psum[3];\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  if (tid == 0) scores[row] = acc;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_indexer_score_one_direct_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: indexer_score_one_direct MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"indexer_score_one_direct_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 128;
    g_indexer_score_one_direct_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_indexer_score_one_direct_mtl4_pipeline) {
        fprintf(stderr, "ds4: indexer_score_one_direct MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: indexer_score_one_direct MTL4 pipeline initialized\n");
    g_indexer_score_one_direct_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_indexer_score_one_direct_canary(uint32_t n_comp) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_indexer_score_one_direct_mtl4_pipeline_init()) return 0;
    if (n_comp == 0) {
        fprintf(stderr, "ds4: indexer_score_one_direct canary requires n_comp > 0\n");
        return 0;
    }

    /* Canary setup (all-ones pattern across q + k + weights, scale=1):
     *   per-lane dot = sum over 4 contiguous dim-products = 4 (since q,k=1)
     *   simd_sum across 32 lanes = 4 × 32 = 128
     *   ReLU(128) = 128
     *   psum[sg] = 128 × (1 × 1) = 128
     *   per outer iter: acc += 4 × 128 = 512
     *   16 outer iters: acc = 512 × 16 = 8192
     *   scores[row] = 8192 for every row */
    const uint32_t n_head = 64;
    const uint32_t head_dim = 128;
    const uint64_t q_n = (uint64_t)n_head * head_dim;
    const uint64_t k_n = (uint64_t)n_comp * head_dim;
    const uint64_t w_n = n_head;
    const uint64_t s_n = n_comp;
    const float ref = 8192.0f;

    float *host_q = (float *)calloc(q_n, sizeof(float));
    float *host_k = (float *)calloc(k_n, sizeof(float));
    float *host_w = (float *)calloc(w_n, sizeof(float));
    float *host_s = (float *)calloc(s_n, sizeof(float));
    if (!host_q || !host_k || !host_w || !host_s) {
        free(host_q); free(host_k); free(host_w); free(host_s);
        return 0;
    }
    for (uint64_t i = 0; i < q_n; i++) host_q[i] = 1.0f;
    for (uint64_t i = 0; i < k_n; i++) host_k[i] = 1.0f;
    for (uint64_t i = 0; i < w_n; i++) host_w[i] = 1.0f;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:32
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> qBuf = [g_device newBufferWithBytes:host_q
                                                   length:q_n * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithBytes:host_w
                                                   length:w_n * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> kBuf = [g_device newBufferWithBytes:host_k
                                                   length:k_n * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> sBuf = [g_device newBufferWithLength:s_n * sizeof(float)
                                                   options:MTLResourceStorageModeShared];

        struct {
            uint32_t n_comp_, n_head_, head_dim_, pad_;
            uint64_t q_head_stride, index_row_stride;
            float scale_; uint32_t pad2;
        } args = {
            .n_comp_ = n_comp,
            .n_head_ = n_head,
            .head_dim_ = head_dim,
            .q_head_stride = (uint64_t)head_dim * sizeof(float),
            .index_row_stride = (uint64_t)head_dim * sizeof(float),
            .scale_ = 1.0f,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 6;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[5] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)qBuf,
                (id<MTLAllocation>)wBuf,
                (id<MTLAllocation>)kBuf,
                (id<MTLAllocation>)sBuf,
            };
            [residency addAllocations:allocs count:5];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(6);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:qBuf.gpuAddress atIndex:1];
                [argTable setAddress:wBuf.gpuAddress atIndex:2];
                [argTable setAddress:kBuf.gpuAddress atIndex:3];
                [argTable setAddress:sBuf.gpuAddress atIndex:4];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_indexer_score_one_direct_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* shmem: ktg[128] + psum[4] = 132 floats = 528 bytes */
                [enc setThreadgroupMemoryLength:132 * sizeof(float) atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(n_comp, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_s, sBuf.contents, s_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 6);
            }
        }
    }
    if (!rc) {
        free(host_q); free(host_k); free(host_w); free(host_s);
        return 0;
    }

    /* Validate: each row should equal 8192.0 exactly (integer arithmetic) */
    double max_abs = 0.0;
    for (uint32_t r = 0; r < n_comp; r++) {
        const double diff = fabs((double)(host_s[r] - ref));
        if (diff > max_abs) max_abs = diff;
    }
    fprintf(stderr,
        "ds4: indexer_score_one_direct MTL4 canary n_comp=%u "
        "scores[0]=%.2f (ref=%.2f) scores[n-1]=%.2f max_abs=%.4e\n",
        n_comp,
        (double)host_s[0], (double)ref,
        (double)host_s[n_comp - 1],
        max_abs);
    free(host_q); free(host_k); free(host_w); free(host_s);
    return (max_abs < 1.0e-3) ? 1 : 0;
}

/* ============================================================ */
/* soft_max_f32 MTL4 port (silv 2026-05-27 task #683)            */
/* ============================================================ */
/* MTL4 port of kernel_soft_max<float> from metal/softmax.metal.
 * Non-vectorized softmax — handles arbitrary row widths (no n%4==0
 * requirement that soft_max_f32_4 has). Same simd_max + simd_sum
 * reduction pattern. Used by the compressor pool path when width%4 != 0
 * (line 7791 dispatch). */

static id<MTLComputePipelineState> g_soft_max_mtl4_pipeline;
static int g_soft_max_mtl4_init_attempted;
static int g_soft_max_mtl4_init_ok;

static int ds4_soft_max_mtl4_pipeline_init(void) {
    if (g_soft_max_mtl4_init_attempted) return g_soft_max_mtl4_init_ok;
    g_soft_max_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct sm_args { int32_t n; float scale; };\n"
         "kernel void soft_max_mtl4(\n"
         "    device const sm_args *args [[buffer(0)]],\n"
         "    device const float   *src [[buffer(1)]],\n"
         "    device       float   *dst [[buffer(2)]],\n"
         "    threadgroup  float   *shmem [[threadgroup(0)]],\n"
         "    uint3  tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort3 tpitg [[thread_position_in_threadgroup]],\n"
         "    ushort  sgitg [[simdgroup_index_in_threadgroup]],\n"
         "    ushort  tiisg [[thread_index_in_simdgroup]],\n"
         "    ushort3 ntg [[threads_per_threadgroup]]) {\n"
         "  const uint row = tgpig.x;\n"
         "  const int  n   = args->n;\n"
         "  const float s  = args->scale;\n"
         "  device const float *p = src + row * (uint)n;\n"
         "  device       float *q = dst + row * (uint)n;\n"
         "  /* pass 1: max */\n"
         "  float lmax = -INFINITY;\n"
         "  for (int i = tpitg.x; i < n; i += ntg.x) {\n"
         "    lmax = fmax(lmax, p[i] * s);\n"
         "  }\n"
         "  lmax = simd_max(lmax);\n"
         "  if (ntg.x > 32) {\n"
         "    if (sgitg == 0) shmem[tiisg] = -INFINITY;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    if (tiisg == 0)  shmem[sgitg] = lmax;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    lmax = shmem[tiisg]; lmax = simd_max(lmax);\n"
         "  }\n"
         "  /* pass 2: exp + sum + write */\n"
         "  float lsum = 0.0f;\n"
         "  for (int i = tpitg.x; i < n; i += ntg.x) {\n"
         "    const float e = exp(p[i] * s - lmax);\n"
         "    lsum += e; q[i] = e;\n"
         "  }\n"
         "  threadgroup_barrier(mem_flags::mem_none);\n"
         "  lsum = simd_sum(lsum);\n"
         "  if (ntg.x > 32) {\n"
         "    if (sgitg == 0) shmem[tiisg] = 0.0f;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    if (tiisg == 0)  shmem[sgitg] = lsum;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    lsum = shmem[tiisg]; lsum = simd_sum(lsum);\n"
         "  }\n"
         "  const float inv = 1.0f / lsum;\n"
         "  for (int i = tpitg.x; i < n; i += ntg.x) q[i] *= inv;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_soft_max_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: soft_max MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"soft_max_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_soft_max_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_soft_max_mtl4_pipeline) {
        fprintf(stderr, "ds4: soft_max MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: soft_max MTL4 pipeline initialized\n");
    g_soft_max_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_soft_max_canary(uint32_t n) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_soft_max_mtl4_pipeline_init()) return 0;
    if (n == 0) {
        fprintf(stderr, "ds4: soft_max canary requires n > 0\n");
        return 0;
    }

    /* Same spike pattern as soft_max_4: src[0]=1, rest=0, scale=1. */
    float *host_src = (float *)calloc(n, sizeof(float));
    float *host_dst = (float *)calloc(n, sizeof(float));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    host_src[0] = 1.0f;

    double Z = exp(1.0 - 1.0) + (double)(n - 1) * exp(0.0 - 1.0);
    const float ref0 = (float)(exp(1.0 - 1.0) / Z);
    const float ref_else = (float)(exp(0.0 - 1.0) / Z);

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        struct { int32_t n_; float s_; uint64_t pad; } args = {
            .n_ = (int32_t)n, .s_ = 1.0f,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)srcBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                NSUInteger nth = 32u;
                while (nth < n && nth < 256u) nth *= 2u;
                if (nth > g_soft_max_mtl4_pipeline.maxTotalThreadsPerThreadgroup)
                    nth = g_soft_max_mtl4_pipeline.maxTotalThreadsPerThreadgroup;

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_soft_max_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc setThreadgroupMemoryLength:128 atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    double max_abs = 0.0;
    double sum = 0.0;
    double d0 = fabs((double)(host_dst[0] - ref0));
    if (d0 > max_abs) max_abs = d0;
    sum += (double)host_dst[0];
    for (uint32_t i = 1; i < n; i++) {
        double d = fabs((double)(host_dst[i] - ref_else));
        if (d > max_abs) max_abs = d;
        sum += (double)host_dst[i];
    }
    fprintf(stderr,
        "ds4: soft_max MTL4 canary n=%u dst[0]=%.6f (ref=%.6f) "
        "dst[1]=%.6f (ref=%.6f) sum=%.6f max_abs=%.4e\n",
        n,
        (double)host_dst[0], (double)ref0,
        (double)host_dst[1], (double)ref_else,
        sum, max_abs);
    free(host_src); free(host_dst);
    return (max_abs < 5.0e-6 && fabs(sum - 1.0) < 5.0e-5) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_fp8_kv_quantize_f32 MTL4 port (silv 2026-05-27 task #684) */
/* ============================================================ */
/* MTL4-side port of kernel_dsv4_fp8_kv_quantize_f32 from metal/dsv4_kv.metal.
 * Per-row: walk the non-RoPE region (ne00 - n_rot elements) in blocks
 * of 64. For each block: find amax via threadgroup reduction → scale =
 * exp2(ceil(log2(amax/448))) → write back E4M3FN-quantized values
 * scaled by `scale`. Then copy the RoPE tail (n_rot elements) unchanged.
 *
 * Exercises new patterns:
 *   - LUT-driven E4M3FN value generation (16 exponent scales)
 *   - Binary-search dequant function inline in kernel source
 *   - Threadgroup-wide max-reduction (64-thread groups) via halving
 *   - Per-block scale + dequant + scale-back round-trip
 *
 * Per-decode dispatch (fires per KV-cache update step).
 *
 * Canary uses synthetic per-row input where all values are equal so the
 * round-trip is deterministic (amax = abs_value, scale = power-of-2 of
 * abs_value / 448, E4M3FN dequant lands on the nearest LUT value). */

static id<MTLComputePipelineState> g_fp8_kv_quantize_mtl4_pipeline;
static int g_fp8_kv_quantize_mtl4_init_attempted;
static int g_fp8_kv_quantize_mtl4_init_ok;

static int ds4_fp8_kv_quantize_mtl4_pipeline_init(void) {
    if (g_fp8_kv_quantize_mtl4_init_attempted) return g_fp8_kv_quantize_mtl4_init_ok;
    g_fp8_kv_quantize_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "constant float dsv4_e4m3fn_exp_scale[16] = {\n"
         "  0.0f, 0.015625f, 0.03125f, 0.0625f,\n"
         "  0.125f, 0.25f, 0.5f, 1.0f,\n"
         "  2.0f, 4.0f, 8.0f, 16.0f,\n"
         "  32.0f, 64.0f, 128.0f, 256.0f,\n"
         "};\n"
         "static inline float dsv4_e4m3fn_value(int i) {\n"
         "  const int exp  = (i >> 3) & 0x0f;\n"
         "  const int mant = i & 0x07;\n"
         "  return exp == 0\n"
         "    ? float(mant) * 0.001953125f\n"
         "    : (1.0f + float(mant) * 0.125f) * dsv4_e4m3fn_exp_scale[exp];\n"
         "}\n"
         "static inline float dsv4_e4m3fn_dequant(float x) {\n"
         "  const float sign = x < 0.0f ? -1.0f : 1.0f;\n"
         "  const float ax = min(abs(x), 448.0f);\n"
         "  int lo = 0;\n"
         "  int hi = 126;\n"
         "  while (lo < hi) {\n"
         "    const int mid = (lo + hi + 1) >> 1;\n"
         "    if (dsv4_e4m3fn_value(mid) <= ax) lo = mid; else hi = mid - 1;\n"
         "  }\n"
         "  int best = lo;\n"
         "  if (best < 126) {\n"
         "    const float bd = abs(ax - dsv4_e4m3fn_value(best));\n"
         "    const float nd = abs(ax - dsv4_e4m3fn_value(best + 1));\n"
         "    if (nd < bd || (nd == bd && ((best + 1) & 1) == 0 && (best & 1) != 0))\n"
         "      best = best + 1;\n"
         "  }\n"
         "  return sign * dsv4_e4m3fn_value(best);\n"
         "}\n"
         "struct fp8_args { int32_t n_full; int32_t n_rot; };\n"
         "kernel void fp8_kv_quantize_mtl4(\n"
         "    device const fp8_args *args [[buffer(0)]],\n"
         "    device const float    *src  [[buffer(1)]],\n"
         "    device       float    *dst  [[buffer(2)]],\n"
         "    threadgroup  float    *scratch [[threadgroup(0)]],\n"
         "    uint   row [[threadgroup_position_in_grid]],\n"
         "    uint   tid [[thread_position_in_threadgroup]]) {\n"
         "  const int n_full = args->n_full;\n"
         "  const int n_rot  = args->n_rot;\n"
         "  const int n_nope = n_full - n_rot;\n"
         "  device const float *psrc = src + row * (uint)n_full;\n"
         "  device       float *pdst = dst + row * (uint)n_full;\n"
         "  /* FP8-quantize the non-RoPE region in 64-element blocks */\n"
         "  for (int off = 0; off < n_nope; off += 64) {\n"
         "    float v = 0.0f;\n"
         "    if (tid < 64u && off + (int)tid < n_nope) {\n"
         "      v = psrc[off + tid];\n"
         "      scratch[tid] = abs(v);\n"
         "    } else if (tid < 64u) {\n"
         "      scratch[tid] = 0.0f;\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    /* per-block amax via halving reduction over 64 lanes */\n"
         "    for (uint stride = 32u; stride > 0u; stride >>= 1) {\n"
         "      if (tid < stride) scratch[tid] = max(scratch[tid], scratch[tid + stride]);\n"
         "      threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    }\n"
         "    const float amax = max(scratch[0], 1.0e-4f);\n"
         "    const float scale = exp2(ceil(log2(amax / 448.0f)));\n"
         "    if (tid < 64u && off + (int)tid < n_nope) {\n"
         "      const float q = dsv4_e4m3fn_dequant(clamp(v / scale, -448.0f, 448.0f)) * scale;\n"
         "      pdst[off + tid] = q;\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  /* Copy the RoPE tail unchanged */\n"
         "  for (int i = n_nope + (int)tid; i < n_full; i += 64) {\n"
         "    pdst[i] = psrc[i];\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_fp8_kv_quantize_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: fp8_kv_quantize MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"fp8_kv_quantize_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 64;
    g_fp8_kv_quantize_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_fp8_kv_quantize_mtl4_pipeline) {
        fprintf(stderr, "ds4: fp8_kv_quantize MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: fp8_kv_quantize MTL4 pipeline initialized\n");
    g_fp8_kv_quantize_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_fp8_kv_quantize_canary(uint32_t n_rows, uint32_t n_full, uint32_t n_rot) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_fp8_kv_quantize_mtl4_pipeline_init()) return 0;
    if (n_rows == 0 || n_full == 0 || n_rot >= n_full) {
        fprintf(stderr, "ds4: fp8_kv_quantize canary requires n_rows>0, n_full>0, n_rot<n_full\n");
        return 0;
    }

    /* Canary: per-row src[i] = (i < n_nope) ? 1.0 : 7.5 (tail unchanged).
     * For the FP8 region: amax = 1.0, scale = exp2(ceil(log2(1/448))) = 2^-9 = 0.001953125
     *   v/scale = 1.0/0.001953125 = 512, clamped to 448
     *   dequant(448) ≈ nearest LUT value (256 with mantissa adjustments → exactly 448 if in LUT)
     *   result = 448 * 0.001953125 = 0.875 (closest E4M3FN approximation to 1.0)
     * For the RoPE tail: passes through as 7.5.
     *
     * We don't compute the exact E4M3FN nearest-value here; just verify:
     *   - FP8 region values are non-zero + close to 1.0 (within ~12.5% — E4M3FN granularity)
     *   - RoPE tail equals 7.5 exactly (byte copy) */
    const uint64_t total = (uint64_t)n_rows * n_full;
    const int32_t n_nope = (int32_t)(n_full - n_rot);

    float *host_src = (float *)calloc(total, sizeof(float));
    float *host_dst = (float *)calloc(total, sizeof(float));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    for (uint32_t r = 0; r < n_rows; r++) {
        for (uint32_t i = 0; i < n_full; i++) {
            host_src[(uint64_t)r * n_full + i] = (int32_t)i < n_nope ? 1.0f : 7.5f;
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:total * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        struct { int32_t n_full_, n_rot_; uint64_t pad; } args = {
            .n_full_ = (int32_t)n_full, .n_rot_ = (int32_t)n_rot,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)srcBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_fp8_kv_quantize_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* 64 lanes × 4 bytes = 256 bytes scratch for the per-block reduction */
                [enc setThreadgroupMemoryLength:256 atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(n_rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(64, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, total * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    /* Validate:
     *   FP8 region (i < n_nope): result close to 1.0 (within E4M3FN tolerance ~12.5%)
     *   RoPE tail (i >= n_nope): exact 7.5 (bit-identical copy) */
    double fp8_max_dev = 0.0;
    double tail_max_dev = 0.0;
    for (uint32_t r = 0; r < n_rows; r++) {
        for (uint32_t i = 0; i < n_full; i++) {
            const float v = host_dst[(uint64_t)r * n_full + i];
            if ((int32_t)i < n_nope) {
                double dev = fabs((double)v - 1.0);
                if (dev > fp8_max_dev) fp8_max_dev = dev;
            } else {
                double dev = fabs((double)v - 7.5);
                if (dev > tail_max_dev) tail_max_dev = dev;
            }
        }
    }
    fprintf(stderr,
        "ds4: fp8_kv_quantize MTL4 canary n_rows=%u n_full=%u n_rot=%u "
        "fp8_dst[0]=%.6f (ref≈1.0) tail_dst[%d]=%.6f (ref=7.5) "
        "fp8_max_dev=%.4e tail_max_dev=%.4e\n",
        n_rows, n_full, n_rot,
        (double)host_dst[0],
        n_nope, (double)host_dst[n_nope],
        fp8_max_dev, tail_max_dev);
    free(host_src); free(host_dst);
    /* E4M3FN nearest to 1.0 in [0.875, 1.125] range — accept ≤ 0.2 abs dev.
     * Tail must be bit-identical. */
    return (fp8_max_dev < 0.2 && tail_max_dev < 1.0e-6) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_indexer_hadamard_fp4_f32 MTL4 port (silv 2026-05-27 task #685b) */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_indexer_hadamard_fp4_f32 from
 * metal/dsv4_kv.metal. Decode-side indexer QAT: per row, apply a
 * 128-wide Walsh-Hadamard transform in-place, then FP4 E2M1FN
 * round-trip with per-32-block scaling.
 *
 * Exercises NEW patterns:
 *   - Walsh-Hadamard butterfly: 7 stride-doubling stages (1,2,4,...,64)
 *     with threadgroup_barrier between each. In-place pair sum/diff.
 *   - Hadamard normalization factor 1/sqrt(128) = 0.0883883...
 *   - Per-32-block amax reduction (different from prior 64-block fp8)
 *   - FP4 E2M1FN LUT (8 values: 0, 0.5, 1, 1.5, 2, 3, 4, 6) + linear-scan dequant
 *
 * Hardcoded head_dim=128. Per-row dispatch (128 threads/row). */

static id<MTLComputePipelineState> g_indexer_hadamard_fp4_mtl4_pipeline;
static int g_indexer_hadamard_fp4_mtl4_init_attempted;
static int g_indexer_hadamard_fp4_mtl4_init_ok;

static int ds4_indexer_hadamard_fp4_mtl4_pipeline_init(void) {
    if (g_indexer_hadamard_fp4_mtl4_init_attempted) return g_indexer_hadamard_fp4_mtl4_init_ok;
    g_indexer_hadamard_fp4_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "constant float dsv4_e2m1fn_values[8] = {\n"
         "  0.0f, 0.5f, 1.0f, 1.5f, 2.0f, 3.0f, 4.0f, 6.0f\n"
         "};\n"
         "static inline float dsv4_e2m1fn_dequant(float x) {\n"
         "  const float sign = x < 0.0f ? -1.0f : 1.0f;\n"
         "  const float ax = min(abs(x), 6.0f);\n"
         "  int best = 0;\n"
         "  float bd = abs(ax - dsv4_e2m1fn_values[0]);\n"
         "  for (int i = 1; i < 8; i++) {\n"
         "    const float d = abs(ax - dsv4_e2m1fn_values[i]);\n"
         "    if (d < bd || (d == bd && ((i & 1) == 0) && ((best & 1) != 0))) {\n"
         "      best = i; bd = d;\n"
         "    }\n"
         "  }\n"
         "  return sign * dsv4_e2m1fn_values[best];\n"
         "}\n"
         "struct had_args { uint32_t n_rows; uint32_t head_dim; uint64_t row_stride; };\n"
         "kernel void indexer_hadamard_fp4_mtl4(\n"
         "    device const had_args *args [[buffer(0)]],\n"
         "    device       char     *x [[buffer(1)]],\n"
         "    threadgroup  float    *scratch [[threadgroup(0)]],\n"
         "    uint   row [[threadgroup_position_in_grid]],\n"
         "    uint   tid [[thread_position_in_threadgroup]]) {\n"
         "  if (row >= args->n_rows || args->head_dim != 128u || tid >= 128u) return;\n"
         "  threadgroup float *vals  = scratch;\n"
         "  threadgroup float *absbuf = scratch + 128u;\n"
         "  device float *xr = (device float *)(x + (uint64_t)row * args->row_stride);\n"
         "  vals[tid] = xr[tid];\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  /* 7-stage Walsh-Hadamard butterfly (log2(128) = 7) */\n"
         "  for (uint stride = 1u; stride < 128u; stride <<= 1u) {\n"
         "    if ((tid & stride) == 0u) {\n"
         "      const uint base = (tid & ~(2u * stride - 1u)) + (tid & (stride - 1u));\n"
         "      const float a = vals[base];\n"
         "      const float b = vals[base + stride];\n"
         "      vals[base] = a + b;\n"
         "      vals[base + stride] = a - b;\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  /* Hadamard normalization × per-32-block amax */\n"
         "  float v = vals[tid] * 0.08838834764831845f;  /* 1/sqrt(128) */\n"
         "  const uint block = tid >> 5u;       /* 0..3, four 32-blocks */\n"
         "  const uint lane = tid & 31u;\n"
         "  const uint base = block * 32u;\n"
         "  absbuf[tid] = abs(v);\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  /* Per-block halving max-reduction (32 → 16 → 8 → 4 → 2 → 1) */\n"
         "  for (uint stride = 16u; stride > 0u; stride >>= 1u) {\n"
         "    if (lane < stride) {\n"
         "      absbuf[base + lane] = max(absbuf[base + lane], absbuf[base + lane + stride]);\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  const float amax = max(absbuf[base], 7.052966104933725e-38f);\n"
         "  const float scale = exp2(ceil(log2(amax / 6.0f)));\n"
         "  xr[tid] = dsv4_e2m1fn_dequant(clamp(v / scale, -6.0f, 6.0f)) * scale;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_indexer_hadamard_fp4_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: indexer_hadamard_fp4 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"indexer_hadamard_fp4_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 128;
    g_indexer_hadamard_fp4_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_indexer_hadamard_fp4_mtl4_pipeline) {
        fprintf(stderr, "ds4: indexer_hadamard_fp4 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: indexer_hadamard_fp4 MTL4 pipeline initialized\n");
    g_indexer_hadamard_fp4_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_indexer_hadamard_fp4_canary(uint32_t n_rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_indexer_hadamard_fp4_mtl4_pipeline_init()) return 0;
    if (n_rows == 0) {
        fprintf(stderr, "ds4: indexer_hadamard_fp4 canary requires n_rows > 0\n");
        return 0;
    }

    /* Canary: each row is a unit impulse — x[0]=1, rest=0.
     * After Walsh-Hadamard of unit impulse: all 128 outputs = +1
     *   (H_128 row-0 has all +1 coefficients in this normalization).
     * Then × 1/sqrt(128) ≈ 0.0884: all elements = 0.0884.
     * amax per block = 0.0884; scale = exp2(ceil(log2(0.0884/6))) = 2^-6 = 0.015625
     *   v/scale = 0.0884/0.015625 = 5.658; clamped/in-range.
     * E2M1FN dequant(5.658) → nearest of {0,0.5,1,1.5,2,3,4,6} = 6 (5.658→6 by tie-break) OR 4 (4 is closer to 5.658)
     *   abs(5.658-4) = 1.658; abs(5.658-6) = 0.342; 6 wins
     * Result = 6 × 0.015625 = 0.09375 per element.
     *
     * Verify: every output is 0.09375 ± tiny rounding. */
    const uint32_t head_dim = 128;
    const uint64_t total = (uint64_t)n_rows * head_dim;
    const float ref = 0.09375f; /* 6 × 0.015625 */
    float *host_x = (float *)calloc(total, sizeof(float));
    if (!host_x) return 0;
    for (uint32_t r = 0; r < n_rows; r++) {
        host_x[(uint64_t)r * head_dim + 0] = 1.0f; /* impulse */
        /* rest are 0 */
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:24
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> xBuf = [g_device newBufferWithBytes:host_x
                                                   length:total * sizeof(float)
                                                  options:MTLResourceStorageModeShared];

        struct { uint32_t n_rows_, head_dim_; uint64_t row_stride_; } args = {
            .n_rows_ = n_rows, .head_dim_ = head_dim,
            .row_stride_ = (uint64_t)head_dim * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[2] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)xBuf,
            };
            [residency addAllocations:allocs count:2];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:xBuf.gpuAddress atIndex:1];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_indexer_hadamard_fp4_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* shmem: vals[128] + absbuf[128] = 256 floats = 1024 bytes */
                [enc setThreadgroupMemoryLength:256 * sizeof(float) atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(n_rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(128, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_x, xBuf.contents, total * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_x); return 0; }

    /* Validate: every output ≈ 0.09375, scanning sign — since the
     * Walsh-Hadamard of (1,0,0,...,0) is all +1 (every H row has
     * +1 in column 0), all outputs share sign + magnitude. */
    double max_abs_dev = 0.0;
    for (uint32_t r = 0; r < n_rows; r++) {
        for (uint32_t i = 0; i < head_dim; i++) {
            const float v = host_x[(uint64_t)r * head_dim + i];
            const double dev = fabs((double)v - (double)ref);
            if (dev > max_abs_dev) max_abs_dev = dev;
        }
    }
    fprintf(stderr,
        "ds4: indexer_hadamard_fp4 MTL4 canary n_rows=%u "
        "x[0]=%.6f (ref=%.6f) x[127]=%.6f max_abs_dev=%.4e\n",
        n_rows,
        (double)host_x[0], (double)ref,
        (double)host_x[head_dim - 1],
        max_abs_dev);
    free(host_x);
    /* E2M1FN has coarse granularity; accept ≤ 0.001 absolute deviation
     * (rounding inside the dequant + fp arithmetic). */
    return (max_abs_dev < 1.0e-3) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_kv_fp8_store_f32 MTL4 port (silv 2026-05-27 task #686)   */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_kv_fp8_store_f32 from metal/dsv4_kv.metal.
 * Decode-side KV finalizer: identical FP8 round-trip as
 * fp8_kv_quantize (#684) on the non-RoPE region, but ALSO writes a
 * FP16-rounded mirror into raw_cache used by FlashAttention.
 *
 * The single-token finalizer is dispatched once per token at decode.
 * Pairs with fp8_kv_quantize_f32 (#684) which is the prefill batched
 * variant. */

static id<MTLComputePipelineState> g_kv_fp8_store_mtl4_pipeline;
static int g_kv_fp8_store_mtl4_init_attempted;
static int g_kv_fp8_store_mtl4_init_ok;

static int ds4_kv_fp8_store_mtl4_pipeline_init(void) {
    if (g_kv_fp8_store_mtl4_init_attempted) return g_kv_fp8_store_mtl4_init_ok;
    g_kv_fp8_store_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "constant float dsv4_e4m3fn_exp_scale[16] = {\n"
         "  0.0f, 0.015625f, 0.03125f, 0.0625f,\n"
         "  0.125f, 0.25f, 0.5f, 1.0f,\n"
         "  2.0f, 4.0f, 8.0f, 16.0f,\n"
         "  32.0f, 64.0f, 128.0f, 256.0f,\n"
         "};\n"
         "static inline float dsv4_e4m3fn_value(int i) {\n"
         "  const int exp_ = (i >> 3) & 0x0f;\n"
         "  const int mant = i & 0x07;\n"
         "  return exp_ == 0\n"
         "    ? float(mant) * 0.001953125f\n"
         "    : (1.0f + float(mant) * 0.125f) * dsv4_e4m3fn_exp_scale[exp_];\n"
         "}\n"
         "static inline float dsv4_e4m3fn_dequant(float x) {\n"
         "  const float sign = x < 0.0f ? -1.0f : 1.0f;\n"
         "  const float ax = min(abs(x), 448.0f);\n"
         "  int lo = 0;\n"
         "  int hi = 126;\n"
         "  while (lo < hi) {\n"
         "    const int mid = (lo + hi + 1) >> 1;\n"
         "    if (dsv4_e4m3fn_value(mid) <= ax) lo = mid; else hi = mid - 1;\n"
         "  }\n"
         "  int best = lo;\n"
         "  if (best < 126) {\n"
         "    const float bd = abs(ax - dsv4_e4m3fn_value(best));\n"
         "    const float nd = abs(ax - dsv4_e4m3fn_value(best + 1));\n"
         "    if (nd < bd || (nd == bd && ((best + 1) & 1) == 0 && (best & 1) != 0))\n"
         "      best = best + 1;\n"
         "  }\n"
         "  return sign * dsv4_e4m3fn_value(best);\n"
         "}\n"
         "struct kv_store_args { int32_t head_dim; int32_t n_rot; int32_t raw_row; };\n"
         "kernel void kv_fp8_store_mtl4(\n"
         "    device const kv_store_args *args [[buffer(0)]],\n"
         "    device       float         *kv   [[buffer(1)]],\n"
         "    device       float         *raw_cache [[buffer(2)]],\n"
         "    threadgroup  float         *scratch [[threadgroup(0)]],\n"
         "    uint tid [[thread_position_in_threadgroup]]) {\n"
         "  const int head_dim = args->head_dim;\n"
         "  const int n_rot = args->n_rot;\n"
         "  const int n_nope = head_dim - n_rot;\n"
         "  if (head_dim <= 0 || n_rot < 0 || n_nope < 0 || tid >= 64u) return;\n"
         "  device float *raw = raw_cache + (int64_t)args->raw_row * head_dim;\n"
         "  /* FP8 round-trip + FP16-mirror on the non-RoPE region in 64-blocks */\n"
         "  for (int off = 0; off < n_nope; off += 64) {\n"
         "    float v = 0.0f;\n"
         "    if (off + (int)tid < n_nope) {\n"
         "      v = kv[off + tid];\n"
         "      scratch[tid] = abs(v);\n"
         "    } else {\n"
         "      scratch[tid] = 0.0f;\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    for (uint stride = 32u; stride > 0u; stride >>= 1) {\n"
         "      if (tid < stride) scratch[tid] = max(scratch[tid], scratch[tid + stride]);\n"
         "      threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    }\n"
         "    const float amax = max(scratch[0], 1.0e-4f);\n"
         "    const float fp8_scale = exp2(ceil(log2(amax / 448.0f)));\n"
         "    if (off + (int)tid < n_nope) {\n"
         "      const float q = dsv4_e4m3fn_dequant(clamp(v / fp8_scale, -448.0f, 448.0f)) * fp8_scale;\n"
         "      kv[off + tid] = q;\n"
         "      raw[off + tid] = (float)((half)q);  /* FP16 round-trip mirror */\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  /* RoPE tail: copy-through with FP16 round-trip mirror to raw */\n"
         "  for (int i = n_nope + (int)tid; i < head_dim; i += 64) {\n"
         "    raw[i] = (float)((half)kv[i]);\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_kv_fp8_store_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: kv_fp8_store MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"kv_fp8_store_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 64;
    g_kv_fp8_store_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_kv_fp8_store_mtl4_pipeline) {
        fprintf(stderr, "ds4: kv_fp8_store MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: kv_fp8_store MTL4 pipeline initialized\n");
    g_kv_fp8_store_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_kv_fp8_store_canary(uint32_t head_dim, uint32_t n_rot) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_kv_fp8_store_mtl4_pipeline_init()) return 0;
    if (head_dim == 0 || n_rot >= head_dim) {
        fprintf(stderr, "ds4: kv_fp8_store canary requires head_dim > 0, n_rot < head_dim\n");
        return 0;
    }

    /* Canary: single-token KV row of head_dim floats.
     *   non-RoPE region (first head_dim - n_rot): all 1.0
     *   RoPE tail (last n_rot): all 7.5
     *   raw_row = 0 (single token)
     *
     * Expected (same as fp8_kv_quantize on the FP8 region):
     *   kv FP8 region: lands on exactly 1.0 (E4M3FN+scale identity at all-ones)
     *   kv RoPE tail: unchanged at 7.5
     *   raw FP8 region: FP16 round-trip of 1.0 = 1.0 (FP16 exact)
     *   raw RoPE tail: FP16 round-trip of 7.5 = 7.5 (FP16 exact for half-integers in [-65k, 65k]) */
    const int32_t n_nope = (int32_t)(head_dim - n_rot);
    const uint32_t raw_capacity = head_dim;  /* one row */
    float *host_kv = (float *)calloc(head_dim, sizeof(float));
    float *host_raw = (float *)calloc(raw_capacity, sizeof(float));
    if (!host_kv || !host_raw) { free(host_kv); free(host_raw); return 0; }
    for (uint32_t i = 0; i < head_dim; i++) {
        host_kv[i] = (int32_t)i < n_nope ? 1.0f : 7.5f;
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:16
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> kvBuf = [g_device newBufferWithBytes:host_kv
                                                    length:head_dim * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> rawBuf = [g_device newBufferWithLength:raw_capacity * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct { int32_t head_dim_, n_rot_, raw_row_, pad_; } args = {
            .head_dim_ = (int32_t)head_dim,
            .n_rot_ = (int32_t)n_rot,
            .raw_row_ = 0,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)kvBuf,
                (id<MTLAllocation>)rawBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:kvBuf.gpuAddress atIndex:1];
                [argTable setAddress:rawBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_kv_fp8_store_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc setThreadgroupMemoryLength:64 * sizeof(float) atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(64, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_kv, kvBuf.contents, head_dim * sizeof(float));
                    memcpy(host_raw, rawBuf.contents, raw_capacity * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_kv); free(host_raw); return 0; }

    /* Validate kv (FP8 region close to 1.0, tail bit-identical 7.5)
     * and raw (FP16-rounded mirror = same values since 1.0 + 7.5 exact in FP16) */
    double kv_fp8_dev = 0.0, kv_tail_dev = 0.0;
    double raw_fp8_dev = 0.0, raw_tail_dev = 0.0;
    for (uint32_t i = 0; i < head_dim; i++) {
        if ((int32_t)i < n_nope) {
            double k = fabs((double)host_kv[i] - 1.0);
            double r = fabs((double)host_raw[i] - 1.0);
            if (k > kv_fp8_dev) kv_fp8_dev = k;
            if (r > raw_fp8_dev) raw_fp8_dev = r;
        } else {
            double k = fabs((double)host_kv[i] - 7.5);
            double r = fabs((double)host_raw[i] - 7.5);
            if (k > kv_tail_dev) kv_tail_dev = k;
            if (r > raw_tail_dev) raw_tail_dev = r;
        }
    }
    fprintf(stderr,
        "ds4: kv_fp8_store MTL4 canary head_dim=%u n_rot=%u "
        "kv[0]=%.6f raw[0]=%.6f kv[%d]=%.6f raw[%d]=%.6f "
        "kv_fp8_dev=%.4e raw_fp8_dev=%.4e kv_tail_dev=%.4e raw_tail_dev=%.4e\n",
        head_dim, n_rot,
        (double)host_kv[0], (double)host_raw[0],
        n_nope, (double)host_kv[n_nope], n_nope, (double)host_raw[n_nope],
        kv_fp8_dev, raw_fp8_dev, kv_tail_dev, raw_tail_dev);
    free(host_kv); free(host_raw);
    return (kv_fp8_dev < 0.2 && raw_fp8_dev < 0.2 &&
            kv_tail_dev < 1.0e-6 && raw_tail_dev < 1.0e-6) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_moe_swiglu_weight MTL4 port (silv 2026-05-27 task #687)   */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_moe_swiglu_weight from metal/moe.metal.
 * Per-row routed-MoE activation: mid[i] = SiLU(g) × u × route_weight,
 * with optional clamp on g/u and optional write-back of clamped values.
 *
 * One row = one expert × one token slot. Per-layer dispatch with as
 * many rows as activated (expert, token) pairs.
 *
 * Exercises:
 *   - SiLU activation: g / (1 + exp(-g))
 *   - Per-row scalar reads (route_weight from packed weights table)
 *   - Conditional write-back path (clamp diagnostic mode) */

static id<MTLComputePipelineState> g_moe_swiglu_weight_mtl4_pipeline;
static int g_moe_swiglu_weight_mtl4_init_attempted;
static int g_moe_swiglu_weight_mtl4_init_ok;

static int ds4_moe_swiglu_weight_mtl4_pipeline_init(void) {
    if (g_moe_swiglu_weight_mtl4_init_attempted) return g_moe_swiglu_weight_mtl4_init_ok;
    g_moe_swiglu_weight_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct sw_args {\n"
         "  uint32_t width;\n"
         "  uint32_t rows;\n"
         "  uint64_t gate_row_stride;\n"
         "  uint64_t up_row_stride;\n"
         "  uint64_t mid_row_stride;\n"
         "  uint64_t weight_stride;\n"
         "  uint32_t write_clamped;\n"
         "  float    clamp_value;\n"
         "};\n"
         "kernel void moe_swiglu_weight_mtl4(\n"
         "    device const sw_args *args [[buffer(0)]],\n"
         "    device       char    *gate [[buffer(1)]],\n"
         "    device       char    *up   [[buffer(2)]],\n"
         "    device       char    *mid  [[buffer(3)]],\n"
         "    device const char    *weights [[buffer(4)]],\n"
         "    uint row [[threadgroup_position_in_grid]],\n"
         "    uint tid [[thread_position_in_threadgroup]],\n"
         "    uint ntg [[threads_per_threadgroup]]) {\n"
         "  if (row >= args->rows) return;\n"
         "  device float *gr = (device float *)(gate + (uint64_t)row * args->gate_row_stride);\n"
         "  device float *ur = (device float *)(up   + (uint64_t)row * args->up_row_stride);\n"
         "  device float *mr = (device float *)(mid  + (uint64_t)row * args->mid_row_stride);\n"
         "  device const float *w = (device const float *)(weights + (uint64_t)row * args->weight_stride);\n"
         "  const float route_weight = w[0];\n"
         "  const float c = args->clamp_value;\n"
         "  for (uint i = tid; i < args->width; i += ntg) {\n"
         "    float g = gr[i];\n"
         "    float u = ur[i];\n"
         "    if (c > 1.0e-6f) {\n"
         "      g = min(g, c);\n"
         "      u = clamp(u, -c, c);\n"
         "      if (args->write_clamped != 0) { gr[i] = g; ur[i] = u; }\n"
         "    }\n"
         "    const float silu = g / (1.0f + exp(-g));\n"
         "    mr[i] = silu * u * route_weight;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_moe_swiglu_weight_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: moe_swiglu_weight MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"moe_swiglu_weight_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_moe_swiglu_weight_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_moe_swiglu_weight_mtl4_pipeline) {
        fprintf(stderr, "ds4: moe_swiglu_weight MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: moe_swiglu_weight MTL4 pipeline initialized\n");
    g_moe_swiglu_weight_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_moe_swiglu_weight_canary(uint32_t rows, uint32_t width) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_moe_swiglu_weight_mtl4_pipeline_init()) return 0;
    if (rows == 0 || width == 0) {
        fprintf(stderr, "ds4: moe_swiglu_weight canary requires rows>0 and width>0\n");
        return 0;
    }

    /* Canary setup (no clamp, route_weight = 1.0):
     *   gate[r,i] = 1.0,  up[r,i] = 2.0,  weights[r] = 1.0
     *   SiLU(1.0) = 1.0 / (1 + e^-1) = 1.0 / (1 + 0.3678794) ≈ 0.7310586
     *   mid[r,i] = 0.7310586 × 2.0 × 1.0 = 1.4621172 */
    const uint64_t total = (uint64_t)rows * width;
    float *host_gate = (float *)calloc(total, sizeof(float));
    float *host_up = (float *)calloc(total, sizeof(float));
    float *host_mid = (float *)calloc(total, sizeof(float));
    float *host_w = (float *)calloc(rows, sizeof(float));
    if (!host_gate || !host_up || !host_mid || !host_w) {
        free(host_gate); free(host_up); free(host_mid); free(host_w);
        return 0;
    }
    for (uint64_t i = 0; i < total; i++) { host_gate[i] = 1.0f; host_up[i] = 2.0f; }
    for (uint32_t r = 0; r < rows; r++) host_w[r] = 1.0f;

    /* Reference value */
    const float silu_1 = 1.0f / (1.0f + expf(-1.0f));
    const float ref = silu_1 * 2.0f * 1.0f;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:48
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> gateBuf = [g_device newBufferWithBytes:host_gate
                                                      length:total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> upBuf = [g_device newBufferWithBytes:host_up
                                                    length:total * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> midBuf = [g_device newBufferWithLength:total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithBytes:host_w
                                                   length:rows * sizeof(float)
                                                  options:MTLResourceStorageModeShared];

        struct {
            uint32_t width_, rows_;
            uint64_t gs_, us_, ms_, ws_;
            uint32_t wc_;
            float c_;
        } args = {
            .width_ = width, .rows_ = rows,
            .gs_ = (uint64_t)width * sizeof(float),
            .us_ = (uint64_t)width * sizeof(float),
            .ms_ = (uint64_t)width * sizeof(float),
            .ws_ = sizeof(float),
            .wc_ = 0,
            .c_ = 0.0f,  /* clamp disabled */
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 6;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[5] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)gateBuf,
                (id<MTLAllocation>)upBuf,
                (id<MTLAllocation>)midBuf,
                (id<MTLAllocation>)wBuf,
            };
            [residency addAllocations:allocs count:5];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(6);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:gateBuf.gpuAddress atIndex:1];
                [argTable setAddress:upBuf.gpuAddress atIndex:2];
                [argTable setAddress:midBuf.gpuAddress atIndex:3];
                [argTable setAddress:wBuf.gpuAddress atIndex:4];

                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)width));

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_moe_swiglu_weight_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_mid, midBuf.contents, total * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 6);
            }
        }
    }
    if (!rc) {
        free(host_gate); free(host_up); free(host_mid); free(host_w);
        return 0;
    }

    double max_abs = 0.0;
    for (uint64_t i = 0; i < total; i++) {
        double d = fabs((double)(host_mid[i] - ref));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: moe_swiglu_weight MTL4 canary rows=%u width=%u "
        "mid[0]=%.6f (ref=%.6f) mid[end]=%.6f max_abs=%.4e\n",
        rows, width,
        (double)host_mid[0], (double)ref,
        (double)host_mid[total - 1],
        max_abs);
    free(host_gate); free(host_up); free(host_mid); free(host_w);
    return (max_abs < 1.0e-5) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_moe_sum6_f32 MTL4 port (silv 2026-05-27 task #688)        */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_moe_sum6_f32 from metal/moe.metal.
 * Per-token sum of 6 contiguous expert output buffers into one
 * destination. dst[c] = sum_{k=0..5} src[k*width + c].
 *
 * Used by the routed-MoE finalize path when num_active = 6 (top-6).
 * One token per threadgroup; threads parallelize over width. */

static id<MTLComputePipelineState> g_moe_sum6_mtl4_pipeline;
static int g_moe_sum6_mtl4_init_attempted;
static int g_moe_sum6_mtl4_init_ok;

static int ds4_moe_sum6_mtl4_pipeline_init(void) {
    if (g_moe_sum6_mtl4_init_attempted) return g_moe_sum6_mtl4_init_ok;
    g_moe_sum6_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct sum6_args {\n"
         "  uint32_t width;\n"
         "  uint32_t tokens;\n"
         "  uint64_t src_token_stride;\n"
         "  uint64_t dst_token_stride;\n"
         "};\n"
         "kernel void moe_sum6_mtl4(\n"
         "    device const sum6_args *args [[buffer(0)]],\n"
         "    device const char      *src [[buffer(1)]],\n"
         "    device       char      *dst [[buffer(2)]],\n"
         "    uint token [[threadgroup_position_in_grid]],\n"
         "    uint tid [[thread_position_in_threadgroup]],\n"
         "    uint ntg [[threads_per_threadgroup]]) {\n"
         "  if (token >= args->tokens) return;\n"
         "  device const float *s = (device const float *)(src + (uint64_t)token * args->src_token_stride);\n"
         "  device       float *d = (device       float *)(dst + (uint64_t)token * args->dst_token_stride);\n"
         "  const uint w = args->width;\n"
         "  for (uint col = tid; col < w; col += ntg) {\n"
         "    float v = s[col];\n"
         "    v += s[w + col];\n"
         "    v += s[2u * w + col];\n"
         "    v += s[3u * w + col];\n"
         "    v += s[4u * w + col];\n"
         "    v += s[5u * w + col];\n"
         "    d[col] = v;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_moe_sum6_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: moe_sum6 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"moe_sum6_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_moe_sum6_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_moe_sum6_mtl4_pipeline) {
        fprintf(stderr, "ds4: moe_sum6 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: moe_sum6 MTL4 pipeline initialized\n");
    g_moe_sum6_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_moe_sum6_canary(uint32_t tokens, uint32_t width) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_moe_sum6_mtl4_pipeline_init()) return 0;
    if (tokens == 0 || width == 0) {
        fprintf(stderr, "ds4: moe_sum6 canary requires tokens>0 and width>0\n");
        return 0;
    }

    /* Canary: src[k*width + col] = (k+1) for k in 0..5.
     * Expected: dst[col] = 1+2+3+4+5+6 = 21 every column. */
    const uint64_t src_per_token = (uint64_t)6 * width;
    const uint64_t src_total = (uint64_t)tokens * src_per_token;
    const uint64_t dst_total = (uint64_t)tokens * width;
    float *host_src = (float *)calloc(src_total, sizeof(float));
    float *host_dst = (float *)calloc(dst_total, sizeof(float));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    for (uint32_t t = 0; t < tokens; t++) {
        for (uint32_t k = 0; k < 6; k++) {
            for (uint32_t i = 0; i < width; i++) {
                host_src[(uint64_t)t * src_per_token + (uint64_t)k * width + i] = (float)(k + 1);
            }
        }
    }
    const float ref = 21.0f;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:32
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:src_total * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct { uint32_t width_, tokens_; uint64_t sts_, dts_; } args = {
            .width_ = width, .tokens_ = tokens,
            .sts_ = src_per_token * sizeof(float),
            .dts_ = (uint64_t)width * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)srcBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)width));

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_moe_sum6_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(tokens, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, dst_total * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    double max_abs = 0.0;
    for (uint64_t i = 0; i < dst_total; i++) {
        double d = fabs((double)(host_dst[i] - ref));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: moe_sum6 MTL4 canary tokens=%u width=%u "
        "dst[0]=%.4f (ref=%.4f) dst[end]=%.4f max_abs=%.4e\n",
        tokens, width,
        (double)host_dst[0], (double)ref,
        (double)host_dst[dst_total - 1],
        max_abs);
    free(host_src); free(host_dst);
    return (max_abs < 1.0e-5) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_moe_swiglu_weight_f16 MTL4 port (silv 2026-05-27 task #689) */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_moe_swiglu_weight_f16 — FP16 mid variant
 * of #687. Same activation (SiLU(g) × u × route_weight + optional
 * clamp) but writes mid as half precision to halve down-projection
 * read traffic. */

static id<MTLComputePipelineState> g_moe_swiglu_weight_f16_mtl4_pipeline;
static int g_moe_swiglu_weight_f16_mtl4_init_attempted;
static int g_moe_swiglu_weight_f16_mtl4_init_ok;

static int ds4_moe_swiglu_weight_f16_mtl4_pipeline_init(void) {
    if (g_moe_swiglu_weight_f16_mtl4_init_attempted) return g_moe_swiglu_weight_f16_mtl4_init_ok;
    g_moe_swiglu_weight_f16_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct sw_args {\n"
         "  uint32_t width;\n"
         "  uint32_t rows;\n"
         "  uint64_t gate_row_stride;\n"
         "  uint64_t up_row_stride;\n"
         "  uint64_t mid_row_stride;\n"
         "  uint64_t weight_stride;\n"
         "  uint32_t write_clamped;\n"
         "  float    clamp_value;\n"
         "};\n"
         "kernel void moe_swiglu_weight_f16_mtl4(\n"
         "    device const sw_args *args [[buffer(0)]],\n"
         "    device       char    *gate [[buffer(1)]],\n"
         "    device       char    *up   [[buffer(2)]],\n"
         "    device       char    *mid  [[buffer(3)]],\n"
         "    device const char    *weights [[buffer(4)]],\n"
         "    uint row [[threadgroup_position_in_grid]],\n"
         "    uint tid [[thread_position_in_threadgroup]],\n"
         "    uint ntg [[threads_per_threadgroup]]) {\n"
         "  if (row >= args->rows) return;\n"
         "  device float *gr = (device float *)(gate + (uint64_t)row * args->gate_row_stride);\n"
         "  device float *ur = (device float *)(up   + (uint64_t)row * args->up_row_stride);\n"
         "  device half  *mr = (device half  *)(mid  + (uint64_t)row * args->mid_row_stride);\n"
         "  device const float *w = (device const float *)(weights + (uint64_t)row * args->weight_stride);\n"
         "  const float route_weight = w[0];\n"
         "  const float c = args->clamp_value;\n"
         "  for (uint i = tid; i < args->width; i += ntg) {\n"
         "    float g = gr[i];\n"
         "    float u = ur[i];\n"
         "    if (c > 1.0e-6f) {\n"
         "      g = min(g, c);\n"
         "      u = clamp(u, -c, c);\n"
         "      if (args->write_clamped != 0) { gr[i] = g; ur[i] = u; }\n"
         "    }\n"
         "    const float silu = g / (1.0f + exp(-g));\n"
         "    mr[i] = (half)(silu * u * route_weight);\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_moe_swiglu_weight_f16_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: moe_swiglu_weight_f16 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"moe_swiglu_weight_f16_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_moe_swiglu_weight_f16_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_moe_swiglu_weight_f16_mtl4_pipeline) {
        fprintf(stderr, "ds4: moe_swiglu_weight_f16 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: moe_swiglu_weight_f16 MTL4 pipeline initialized\n");
    g_moe_swiglu_weight_f16_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_moe_swiglu_weight_f16_canary(uint32_t rows, uint32_t width) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_moe_swiglu_weight_f16_mtl4_pipeline_init()) return 0;
    if (rows == 0 || width == 0) {
        fprintf(stderr, "ds4: moe_swiglu_weight_f16 canary requires rows>0 and width>0\n");
        return 0;
    }

    /* Same canary as #687 but mid stored as half. Expected = SiLU(1.0)*2 = 1.462117,
     * stored as half (closest FP16 value to 1.462117 is 1.4619140625). */
    const uint64_t total = (uint64_t)rows * width;
    float *host_gate = (float *)calloc(total, sizeof(float));
    float *host_up = (float *)calloc(total, sizeof(float));
    uint16_t *host_mid = (uint16_t *)calloc(total, sizeof(uint16_t));  /* half = 16 bits */
    float *host_w = (float *)calloc(rows, sizeof(float));
    if (!host_gate || !host_up || !host_mid || !host_w) {
        free(host_gate); free(host_up); free(host_mid); free(host_w);
        return 0;
    }
    for (uint64_t i = 0; i < total; i++) { host_gate[i] = 1.0f; host_up[i] = 2.0f; }
    for (uint32_t r = 0; r < rows; r++) host_w[r] = 1.0f;
    const float ref = (1.0f / (1.0f + expf(-1.0f))) * 2.0f * 1.0f;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:48
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> gateBuf = [g_device newBufferWithBytes:host_gate
                                                      length:total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> upBuf = [g_device newBufferWithBytes:host_up
                                                    length:total * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> midBuf = [g_device newBufferWithLength:total * sizeof(uint16_t)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> wBuf = [g_device newBufferWithBytes:host_w
                                                   length:rows * sizeof(float)
                                                  options:MTLResourceStorageModeShared];

        struct {
            uint32_t width_, rows_;
            uint64_t gs_, us_, ms_, ws_;
            uint32_t wc_;
            float c_;
        } args = {
            .width_ = width, .rows_ = rows,
            .gs_ = (uint64_t)width * sizeof(float),
            .us_ = (uint64_t)width * sizeof(float),
            .ms_ = (uint64_t)width * sizeof(uint16_t),  /* half */
            .ws_ = sizeof(float),
            .wc_ = 0,
            .c_ = 0.0f,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 6;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[5] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)gateBuf,
                (id<MTLAllocation>)upBuf,
                (id<MTLAllocation>)midBuf,
                (id<MTLAllocation>)wBuf,
            };
            [residency addAllocations:allocs count:5];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(6);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:gateBuf.gpuAddress atIndex:1];
                [argTable setAddress:upBuf.gpuAddress atIndex:2];
                [argTable setAddress:midBuf.gpuAddress atIndex:3];
                [argTable setAddress:wBuf.gpuAddress atIndex:4];

                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)width));

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_moe_swiglu_weight_f16_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_mid, midBuf.contents, total * sizeof(uint16_t));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 6);
            }
        }
    }
    if (!rc) {
        free(host_gate); free(host_up); free(host_mid); free(host_w);
        return 0;
    }

    /* Convert half → float for verification via _Float16. */
    double max_abs = 0.0;
    float first = 0.0f, last = 0.0f;
    for (uint64_t i = 0; i < total; i++) {
        _Float16 h;
        memcpy(&h, &host_mid[i], sizeof(h));
        const float v = (float)h;
        if (i == 0) first = v;
        if (i == total - 1) last = v;
        double d = fabs((double)(v - ref));
        if (d > max_abs) max_abs = d;
    }
    fprintf(stderr,
        "ds4: moe_swiglu_weight_f16 MTL4 canary rows=%u width=%u "
        "mid[0]=%.6f (ref=%.6f) mid[end]=%.6f max_abs=%.4e\n",
        rows, width, (double)first, (double)ref, (double)last, max_abs);
    free(host_gate); free(host_up); free(host_mid); free(host_w);
    /* FP16 has ~0.5e-3 relative precision near 1.5; accept ≤ 1e-3 absolute. */
    return (max_abs < 1.0e-3) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_hc_split_sinkhorn MTL4 port (silv 2026-05-27 task #690)  */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_hc_split_sinkhorn (HC=4 specialization).
 * Splits one HC mixer row of 24 floats into:
 *   - positions 0..3: pre  (sigmoid + eps after pre_scale*mix + base)
 *   - positions 4..7: post (twice_sigmoid)
 *   - positions 8..23: 4×4 comb matrix (Sinkhorn-normalized rows+cols)
 *
 * The Sinkhorn portion: row-softmax once + (iters-1) alternating
 * col/row normalize steps to produce a doubly-stochastic 4×4 matrix.
 *
 * Per-row dispatch (one thread per row in 1D grid). HC=4 only. */

static id<MTLComputePipelineState> g_hc_split_sinkhorn_mtl4_pipeline;
static int g_hc_split_sinkhorn_mtl4_init_attempted;
static int g_hc_split_sinkhorn_mtl4_init_ok;

static int ds4_hc_split_sinkhorn_mtl4_pipeline_init(void) {
    if (g_hc_split_sinkhorn_mtl4_init_attempted) return g_hc_split_sinkhorn_mtl4_init_ok;
    g_hc_split_sinkhorn_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "static inline float  hc_sigmoid(float  z)        { return 1.0f / (1.0f + exp(-z)); }\n"
         "static inline float4 hc_sigmoid4(float4 z)       { return 1.0f / (1.0f + exp(-z)); }\n"
         "static inline float4 hc_twice_sigmoid4(float4 z) { return 2.0f / (1.0f + exp(-z)); }\n"
         "struct sk_args {\n"
         "  int32_t n_hc;\n"
         "  int32_t sinkhorn_iters;\n"
         "  int64_t n_rows;\n"
         "  int64_t mix_hc;\n"
         "  uint64_t nb01;\n"
         "  uint64_t nb1;\n"
         "  float eps;\n"
         "};\n"
         "kernel void hc_split_sinkhorn_mtl4(\n"
         "    device const sk_args *args [[buffer(0)]],\n"
         "    device const float   *mixes [[buffer(1)]],\n"
         "    device const float   *scale [[buffer(2)]],\n"
         "    device const float   *base  [[buffer(3)]],\n"
         "    device       float   *dst   [[buffer(4)]],\n"
         "    uint tid [[thread_position_in_grid]]) {\n"
         "  if ((int64_t)tid >= args->n_rows || args->n_hc != 4) return;\n"
         "  device const float *mix = mixes + ((int64_t)tid) * args->mix_hc;\n"
         "  device       float *out = dst   + ((int64_t)tid) * args->mix_hc;\n"
         "  const float epsv = args->eps;\n"
         "  const float pre_s = scale[0];\n"
         "  const float post_s = scale[1];\n"
         "  const float comb_s = scale[2];\n"
         "  /* pre + post */\n"
         "  const float4 pre_z  = *((device const float4 *)mix)       * pre_s  + *((device const float4 *)base);\n"
         "  *((device float4 *)out) = hc_sigmoid4(pre_z) + epsv;\n"
         "  const float4 post_z = *((device const float4 *)(mix + 4)) * post_s + *((device const float4 *)(base + 4));\n"
         "  *((device float4 *)(out + 4)) = hc_twice_sigmoid4(post_z);\n"
         "  /* Sinkhorn 4×4 with stable row-softmax */\n"
         "  float4 r0 = *((device const float4 *)(mix +  8)) * comb_s + *((device const float4 *)(base +  8));\n"
         "  float4 r1 = *((device const float4 *)(mix + 12)) * comb_s + *((device const float4 *)(base + 12));\n"
         "  float4 r2 = *((device const float4 *)(mix + 16)) * comb_s + *((device const float4 *)(base + 16));\n"
         "  float4 r3 = *((device const float4 *)(mix + 20)) * comb_s + *((device const float4 *)(base + 20));\n"
         "  const float m0 = max(max(r0.x, r0.y), max(r0.z, r0.w));\n"
         "  const float m1 = max(max(r1.x, r1.y), max(r1.z, r1.w));\n"
         "  const float m2 = max(max(r2.x, r2.y), max(r2.z, r2.w));\n"
         "  const float m3 = max(max(r3.x, r3.y), max(r3.z, r3.w));\n"
         "  r0 = exp(r0 - m0);\n"
         "  r1 = exp(r1 - m1);\n"
         "  r2 = exp(r2 - m2);\n"
         "  r3 = exp(r3 - m3);\n"
         "  r0 = r0 * (1.0f / (r0.x + r0.y + r0.z + r0.w)) + epsv;\n"
         "  r1 = r1 * (1.0f / (r1.x + r1.y + r1.z + r1.w)) + epsv;\n"
         "  r2 = r2 * (1.0f / (r2.x + r2.y + r2.z + r2.w)) + epsv;\n"
         "  r3 = r3 * (1.0f / (r3.x + r3.y + r3.z + r3.w)) + epsv;\n"
         "  float4 col_inv = 1.0f / (r0 + r1 + r2 + r3 + epsv);\n"
         "  r0 *= col_inv; r1 *= col_inv; r2 *= col_inv; r3 *= col_inv;\n"
         "  for (int iter = 1; iter < args->sinkhorn_iters; ++iter) {\n"
         "    r0 *= 1.0f / (r0.x + r0.y + r0.z + r0.w + epsv);\n"
         "    r1 *= 1.0f / (r1.x + r1.y + r1.z + r1.w + epsv);\n"
         "    r2 *= 1.0f / (r2.x + r2.y + r2.z + r2.w + epsv);\n"
         "    r3 *= 1.0f / (r3.x + r3.y + r3.z + r3.w + epsv);\n"
         "    col_inv = 1.0f / (r0 + r1 + r2 + r3 + epsv);\n"
         "    r0 *= col_inv; r1 *= col_inv; r2 *= col_inv; r3 *= col_inv;\n"
         "  }\n"
         "  *((device float4 *)(out +  8)) = r0;\n"
         "  *((device float4 *)(out + 12)) = r1;\n"
         "  *((device float4 *)(out + 16)) = r2;\n"
         "  *((device float4 *)(out + 20)) = r3;\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_hc_split_sinkhorn_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: hc_split_sinkhorn MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"hc_split_sinkhorn_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_hc_split_sinkhorn_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_hc_split_sinkhorn_mtl4_pipeline) {
        fprintf(stderr, "ds4: hc_split_sinkhorn MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: hc_split_sinkhorn MTL4 pipeline initialized\n");
    g_hc_split_sinkhorn_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_hc_split_sinkhorn_canary(uint32_t n_rows, uint32_t sinkhorn_iters) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_hc_split_sinkhorn_mtl4_pipeline_init()) return 0;
    if (n_rows == 0 || sinkhorn_iters == 0) {
        fprintf(stderr, "ds4: hc_split_sinkhorn canary requires n_rows>0 and sinkhorn_iters>0\n");
        return 0;
    }

    /* Canary: mix = 0, base = 0, scale = {1, 1, 1}, eps = 0.
     * Expected per row:
     *   pre[0..3]   = sigmoid(0) = 0.5
     *   post[4..7]  = 2*sigmoid(0) = 1.0
     *   comb[8..23] = 0.25 each (row+col Sinkhorn of zero matrix = 1/N uniform) */
    const uint32_t mix_hc = 24;  /* 8 + 4*4 */
    const uint64_t total = (uint64_t)n_rows * mix_hc;
    float *host_mix = (float *)calloc(total, sizeof(float));
    float *host_scale = (float *)calloc(3, sizeof(float));
    float *host_base = (float *)calloc(mix_hc, sizeof(float)); /* shared base, indexed without per-row offset */
    float *host_dst = (float *)calloc(total, sizeof(float));
    if (!host_mix || !host_scale || !host_base || !host_dst) {
        free(host_mix); free(host_scale); free(host_base); free(host_dst);
        return 0;
    }
    host_scale[0] = host_scale[1] = host_scale[2] = 1.0f;
    /* mix, base zero already */

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:48
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> mixBuf = [g_device newBufferWithBytes:host_mix
                                                     length:total * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> scaleBuf = [g_device newBufferWithBytes:host_scale
                                                       length:3 * sizeof(float)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> baseBuf = [g_device newBufferWithBytes:host_base
                                                      length:mix_hc * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int32_t n_hc_, sinkhorn_iters_;
            int64_t n_rows_, mix_hc_;
            uint64_t nb01_, nb1_;
            float eps_;
            uint32_t pad;
        } args = {
            .n_hc_ = 4, .sinkhorn_iters_ = (int32_t)sinkhorn_iters,
            .n_rows_ = (int64_t)n_rows, .mix_hc_ = mix_hc,
            .nb01_ = (uint64_t)mix_hc * sizeof(float),
            .nb1_  = (uint64_t)mix_hc * sizeof(float),
            .eps_ = 0.0f,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 6;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[5] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)mixBuf,
                (id<MTLAllocation>)scaleBuf,
                (id<MTLAllocation>)baseBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:5];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(6);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:mixBuf.gpuAddress atIndex:1];
                [argTable setAddress:scaleBuf.gpuAddress atIndex:2];
                [argTable setAddress:baseBuf.gpuAddress atIndex:3];
                [argTable setAddress:dstBuf.gpuAddress atIndex:4];

                /* Dispatch 1D: one thread per row, multiple TG's of 64 threads */
                NSUInteger nth = MIN((NSUInteger)64, MAX((NSUInteger)1, (NSUInteger)n_rows));
                NSUInteger n_tg = ((NSUInteger)n_rows + nth - 1u) / nth;

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_hc_split_sinkhorn_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(n_tg, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, total * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 6);
            }
        }
    }
    if (!rc) {
        free(host_mix); free(host_scale); free(host_base); free(host_dst);
        return 0;
    }

    /* Validate per-row layout: pre=0.5, post=1.0, comb=0.25 */
    double pre_dev = 0.0, post_dev = 0.0, comb_dev = 0.0;
    for (uint32_t r = 0; r < n_rows; r++) {
        const float *o = host_dst + (uint64_t)r * mix_hc;
        for (int i = 0; i < 4; i++) {
            double d = fabs((double)(o[i] - 0.5));
            if (d > pre_dev) pre_dev = d;
        }
        for (int i = 4; i < 8; i++) {
            double d = fabs((double)(o[i] - 1.0));
            if (d > post_dev) post_dev = d;
        }
        for (int i = 8; i < 24; i++) {
            double d = fabs((double)(o[i] - 0.25));
            if (d > comb_dev) comb_dev = d;
        }
    }
    fprintf(stderr,
        "ds4: hc_split_sinkhorn MTL4 canary n_rows=%u iters=%u "
        "pre[0]=%.4f (ref=0.5) post[4]=%.4f (ref=1.0) comb[8]=%.4f (ref=0.25) "
        "pre_dev=%.4e post_dev=%.4e comb_dev=%.4e\n",
        n_rows, sinkhorn_iters,
        (double)host_dst[0], (double)host_dst[4], (double)host_dst[8],
        pre_dev, post_dev, comb_dev);
    free(host_mix); free(host_scale); free(host_base); free(host_dst);
    return (pre_dev < 1.0e-6 && post_dev < 1.0e-6 && comb_dev < 1.0e-6) ? 1 : 0;
}

/* ============================================================ */
/* get_rows_f32 MTL4 port (silv 2026-05-27 task #691)             */
/* ============================================================ */
/* MTL4 port of kernel_get_rows_f<float, float> from metal/get_rows.metal.
 * Gathers embedding/table rows by integer ids. DS4 uses this for
 * token embeddings + router/hash lookup outputs.
 *
 * Dispatch: (n_rows*W, ne11, ne12) threadgroups × (ntg, 1, 1) threads.
 * Per-thread copies one element from src0[id*nb01 ...] to dst[...]
 * after reading the id from src1 (int32). */

static id<MTLComputePipelineState> g_get_rows_f32_mtl4_pipeline;
static int g_get_rows_f32_mtl4_init_attempted;
static int g_get_rows_f32_mtl4_init_ok;

static int ds4_get_rows_f32_mtl4_pipeline_init(void) {
    if (g_get_rows_f32_mtl4_init_attempted) return g_get_rows_f32_mtl4_init_ok;
    g_get_rows_f32_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct gr_args {\n"
         "  int32_t ne00t;     /* per-thread tile width */\n"
         "  int32_t ne00;      /* row width */\n"
         "  uint64_t nb01;\n"
         "  uint64_t nb02;\n"
         "  uint64_t nb03;\n"
         "  int32_t ne10;      /* ids width */\n"
         "  uint64_t nb10;\n"
         "  uint64_t nb11;\n"
         "  uint64_t nb12;\n"
         "  uint64_t nb1;\n"
         "  uint64_t nb2;\n"
         "  uint64_t nb3;\n"
         "};\n"
         "kernel void get_rows_f32_mtl4(\n"
         "    device const gr_args *args [[buffer(0)]],\n"
         "    device const char    *src0 [[buffer(1)]],   /* table */\n"
         "    device const char    *src1 [[buffer(2)]],   /* int32 ids */\n"
         "    device       char    *dst  [[buffer(3)]],\n"
         "    uint3   tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort  tiitg [[thread_index_in_threadgroup]],\n"
         "    ushort3 ntg   [[threads_per_threadgroup]]) {\n"
         "  const int32_t iw0 = tgpig.x / args->ne10;\n"
         "  const int32_t i10 = tgpig.x % args->ne10;\n"
         "  const int32_t i11 = tgpig.y;\n"
         "  const int32_t i12 = tgpig.z;\n"
         "  const int32_t r = ((const device int32_t *)(src1 + i12*args->nb12 + i11*args->nb11 + i10*args->nb10))[0];\n"
         "  const int32_t i02 = i11;\n"
         "  const int32_t i03 = i12;\n"
         "  device const float *psrc = (device const float *)(src0 + i03*args->nb03 + i02*args->nb02 + r*args->nb01);\n"
         "  device       float *pdst = (device       float *)(dst  + i12*args->nb3  + i11*args->nb2  + i10*args->nb1);\n"
         "  for (int ind = iw0*ntg.x + tiitg; ind < args->ne00t;) {\n"
         "    pdst[ind] = psrc[ind];\n"
         "    break;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_get_rows_f32_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: get_rows_f32 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"get_rows_f32_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_get_rows_f32_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_get_rows_f32_mtl4_pipeline) {
        fprintf(stderr, "ds4: get_rows_f32 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: get_rows_f32 MTL4 pipeline initialized\n");
    g_get_rows_f32_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_get_rows_f32_canary(uint32_t n_table_rows, uint32_t row_width, uint32_t n_ids) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_get_rows_f32_mtl4_pipeline_init()) return 0;
    if (n_table_rows == 0 || row_width == 0 || n_ids == 0) {
        fprintf(stderr, "ds4: get_rows_f32 canary needs n_table_rows>0, row_width>0, n_ids>0\n");
        return 0;
    }

    /* Canary: table[row, col] = row * 100 + col.
     * ids = [n_table_rows - 1, n_table_rows - 2, ..., n_table_rows - n_ids].
     * Expected: dst[i, col] = (n_table_rows - 1 - i) * 100 + col. */
    const uint64_t table_n = (uint64_t)n_table_rows * row_width;
    const uint64_t dst_n = (uint64_t)n_ids * row_width;
    float *host_tab = (float *)calloc(table_n, sizeof(float));
    int32_t *host_ids = (int32_t *)calloc(n_ids, sizeof(int32_t));
    float *host_dst = (float *)calloc(dst_n, sizeof(float));
    if (!host_tab || !host_ids || !host_dst) {
        free(host_tab); free(host_ids); free(host_dst); return 0;
    }
    for (uint32_t r = 0; r < n_table_rows; r++) {
        for (uint32_t c = 0; c < row_width; c++) {
            host_tab[(uint64_t)r * row_width + c] = (float)((int)r * 100 + (int)c);
        }
    }
    for (uint32_t i = 0; i < n_ids; i++) {
        host_ids[i] = (int32_t)(n_table_rows - 1 - i);
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:96
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> tabBuf = [g_device newBufferWithBytes:host_tab
                                                     length:table_n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> idsBuf = [g_device newBufferWithBytes:host_ids
                                                     length:n_ids * sizeof(int32_t)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int32_t ne00t; int32_t ne00;
            uint64_t nb01, nb02, nb03;
            int32_t ne10; uint32_t pad0;
            uint64_t nb10, nb11, nb12;
            uint64_t nb1, nb2, nb3;
        } args = {
            .ne00t = (int32_t)row_width,
            .ne00 = (int32_t)row_width,
            .nb01 = (uint64_t)row_width * sizeof(float),
            .nb02 = (uint64_t)n_table_rows * row_width * sizeof(float),
            .nb03 = (uint64_t)n_table_rows * row_width * sizeof(float),
            .ne10 = (int32_t)n_ids,
            .nb10 = sizeof(int32_t),
            .nb11 = (uint64_t)n_ids * sizeof(int32_t),
            .nb12 = (uint64_t)n_ids * sizeof(int32_t),
            .nb1 = (uint64_t)row_width * sizeof(float),
            .nb2 = (uint64_t)n_ids * row_width * sizeof(float),
            .nb3 = (uint64_t)n_ids * row_width * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 6;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[4] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)tabBuf,
                (id<MTLAllocation>)idsBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:4];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:tabBuf.gpuAddress atIndex:1];
                [argTable setAddress:idsBuf.gpuAddress atIndex:2];
                [argTable setAddress:dstBuf.gpuAddress atIndex:3];

                /* Dispatch shape per kernel: (n_ids * W, 1, 1) tg, where W
                 * = ceil(ne00t / ntg.x). For canary, use ntg = min(row_width, 256). */
                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)row_width));
                NSUInteger W = ((NSUInteger)row_width + nth - 1u) / nth;
                NSUInteger gx = (NSUInteger)n_ids * W;

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_get_rows_f32_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(gx, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, dst_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_tab); free(host_ids); free(host_dst); return 0; }

    /* Validate */
    double max_abs = 0.0;
    int mismatch_count = 0;
    for (uint32_t i = 0; i < n_ids; i++) {
        const int32_t id_val = (int32_t)(n_table_rows - 1 - i);
        for (uint32_t c = 0; c < row_width; c++) {
            const float v = host_dst[(uint64_t)i * row_width + c];
            const float ref = (float)(id_val * 100 + (int32_t)c);
            const double d = fabs((double)(v - ref));
            if (d > max_abs) max_abs = d;
            if (d > 1.0e-5) mismatch_count++;
        }
    }
    fprintf(stderr,
        "ds4: get_rows_f32 MTL4 canary n_table_rows=%u row_width=%u n_ids=%u "
        "dst[0,0]=%.1f (ref=%.1f) dst[0,end]=%.1f dst[end,0]=%.1f "
        "mismatch=%d max_abs=%.4e\n",
        n_table_rows, row_width, n_ids,
        (double)host_dst[0], (double)((n_table_rows - 1) * 100),
        (double)host_dst[row_width - 1],
        (double)host_dst[(uint64_t)(n_ids - 1) * row_width],
        mismatch_count, max_abs);
    free(host_tab); free(host_ids); free(host_dst);
    return (max_abs < 1.0e-5) ? 1 : 0;
}

/* ============================================================ */
/* argsort_f32_i32_desc MTL4 port (silv 2026-05-27 task #692)    */
/* ============================================================ */
/* MTL4 port of kernel_argsort_f32_i32<DS4_SORT_ORDER_DESC>.
 * Bitonic sort of indices keyed by float values. Returns the top_k
 * largest-value indices (descending) per row.
 *
 * Used by router top-K selection. Pairs with #588 sort_i32_rows_asc
 * (which sorts integer values directly); argsort is the value→index
 * version. ntg.x must be a power of 2.
 *
 * Canary: input row = [N-1, N-2, ..., 1, 0]; descending sort yields
 * indices [0, 1, 2, ..., N-1] (position of the largest = 0). */

static id<MTLComputePipelineState> g_argsort_f32_i32_desc_mtl4_pipeline;
static int g_argsort_f32_i32_desc_mtl4_init_attempted;
static int g_argsort_f32_i32_desc_mtl4_init_ok;

static int ds4_argsort_f32_i32_desc_mtl4_pipeline_init(void) {
    if (g_argsort_f32_i32_desc_mtl4_init_attempted) return g_argsort_f32_i32_desc_mtl4_init_ok;
    g_argsort_f32_i32_desc_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "#define SWAP(x, y) { int tmp = (x); (x) = (y); (y) = tmp; }\n"
         "struct as_args {\n"
         "  int32_t ne00; int32_t ne01; int32_t ne02; int32_t ne03;\n"
         "  uint64_t nb00; uint64_t nb01; uint64_t nb02; uint64_t nb03;\n"
         "  int32_t ne0; int32_t ne1; int32_t ne2; int32_t ne3;\n"
         "  int32_t top_k;\n"
         "};\n"
         "kernel void argsort_f32_i32_desc_mtl4(\n"
         "    device const as_args *args [[buffer(0)]],\n"
         "    device const char    *src0 [[buffer(1)]],\n"
         "    device       int32_t *dst  [[buffer(2)]],\n"
         "    threadgroup  int32_t *shmem_i32 [[threadgroup(0)]],\n"
         "    uint3   tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort3 tpitg [[thread_position_in_threadgroup]],\n"
         "    ushort3 ntg   [[threads_per_threadgroup]]) {\n"
         "  const int col = tpitg[0];\n"
         "  const int ib  = tgpig[0] / args->ne01;\n"
         "  const int i00 = ib * ntg.x;\n"
         "  const int i01 = tgpig[0] % args->ne01;\n"
         "  const int i02 = tgpig[1];\n"
         "  const int i03 = tgpig[2];\n"
         "  device const float *src0_row =\n"
         "    (device const float *)(src0 + args->nb01*i01 + args->nb02*i02 + args->nb03*i03);\n"
         "  /* initialize indices */\n"
         "  shmem_i32[col] = i00 + col;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  /* Bitonic sort, descending order */\n"
         "  for (int k = 2; k <= (int)ntg.x; k *= 2) {\n"
         "    for (int j = k / 2; j > 0; j /= 2) {\n"
         "      int ixj = col ^ j;\n"
         "      if (ixj > col) {\n"
         "        if ((col & k) == 0) {\n"
         "          /* descending: swap if col-element < ixj-element */\n"
         "          if (shmem_i32[col] >= args->ne00 ||\n"
         "             (shmem_i32[ixj] <  args->ne00 &&\n"
         "              src0_row[shmem_i32[col]] < src0_row[shmem_i32[ixj]]))\n"
         "          {\n"
         "            SWAP(shmem_i32[col], shmem_i32[ixj]);\n"
         "          }\n"
         "        } else {\n"
         "          if (shmem_i32[ixj] >= args->ne00 ||\n"
         "             (shmem_i32[col] <  args->ne00 &&\n"
         "              src0_row[shmem_i32[col]] > src0_row[shmem_i32[ixj]]))\n"
         "          {\n"
         "            SWAP(shmem_i32[col], shmem_i32[ixj]);\n"
         "          }\n"
         "        }\n"
         "      }\n"
         "      threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    }\n"
         "  }\n"
         "  const int64_t i0 = (int64_t)ib * args->top_k;\n"
         "  if (i0 + col < args->ne0 && col < args->top_k) {\n"
         "    dst[i03 * args->ne0 * args->ne1 * args->ne2 +\n"
         "        i02 * args->ne0 * args->ne1 +\n"
         "        i01 * args->ne0 + i0 + col] = shmem_i32[col];\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_argsort_f32_i32_desc_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: argsort_f32_i32_desc MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"argsort_f32_i32_desc_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 1024;
    g_argsort_f32_i32_desc_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_argsort_f32_i32_desc_mtl4_pipeline) {
        fprintf(stderr, "ds4: argsort_f32_i32_desc MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: argsort_f32_i32_desc MTL4 pipeline initialized\n");
    g_argsort_f32_i32_desc_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_argsort_f32_i32_desc_canary(uint32_t row_n, uint32_t top_k) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_argsort_f32_i32_desc_mtl4_pipeline_init()) return 0;
    if (row_n == 0 || top_k == 0 || top_k > row_n) {
        fprintf(stderr, "ds4: argsort canary needs row_n>0 and 0<top_k<=row_n\n");
        return 0;
    }
    /* row_n must be power of 2 for the bitonic sort */
    if ((row_n & (row_n - 1)) != 0) {
        fprintf(stderr, "ds4: argsort canary row_n must be power of 2\n");
        return 0;
    }

    /* Canary input: row = [row_n - 1, row_n - 2, ..., 1, 0] (descending values).
     * Descending argsort: position of largest (row_n - 1) is at index 0.
     * So output indices = [0, 1, 2, ..., top_k - 1]. */
    float *host_src = (float *)calloc(row_n, sizeof(float));
    int32_t *host_dst = (int32_t *)calloc(top_k, sizeof(int32_t));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    for (uint32_t i = 0; i < row_n; i++) {
        host_src[i] = (float)(row_n - 1 - i);
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:80
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:row_n * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:top_k * sizeof(int32_t)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int32_t ne00, ne01, ne02, ne03;
            uint64_t nb00, nb01, nb02, nb03;
            int32_t ne0, ne1, ne2, ne3;
            int32_t top_k_;
        } args = {
            .ne00 = (int32_t)row_n, .ne01 = 1, .ne02 = 1, .ne03 = 1,
            .nb00 = sizeof(float),
            .nb01 = (uint64_t)row_n * sizeof(float),
            .nb02 = (uint64_t)row_n * sizeof(float),
            .nb03 = (uint64_t)row_n * sizeof(float),
            .ne0 = (int32_t)top_k, .ne1 = 1, .ne2 = 1, .ne3 = 1,
            .top_k_ = (int32_t)top_k,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)srcBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_argsort_f32_i32_desc_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* shmem: row_n int32 slots */
                [enc setThreadgroupMemoryLength:row_n * sizeof(int32_t) atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(row_n, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, top_k * sizeof(int32_t));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    /* Validate: dst[i] should equal i (position of largest = 0, next = 1, ...) */
    int mismatch = 0;
    for (uint32_t i = 0; i < top_k; i++) {
        if (host_dst[i] != (int32_t)i) mismatch++;
    }
    fprintf(stderr,
        "ds4: argsort_f32_i32_desc MTL4 canary row_n=%u top_k=%u "
        "dst[0]=%d (ref=0) dst[1]=%d (ref=1) dst[end]=%d (ref=%u) mismatch=%d\n",
        row_n, top_k,
        host_dst[0], host_dst[1],
        host_dst[top_k - 1], top_k - 1,
        mismatch);
    free(host_src); free(host_dst);
    return (mismatch == 0) ? 1 : 0;
}

/* ============================================================ */
/* cpy_f32_f32 MTL4 port (silv 2026-05-27 task #693)              */
/* ============================================================ */
/* MTL4 port of kernel_cpy_t_t<float, float> from metal/cpy.metal.
 * Typed copy/conversion between graph tensors. DS4 uses this for
 * layout materialization + F32/F16 conversions at graph boundaries
 * (KV/cache packing, compressor pooling, FlashAttention staging).
 *
 * This port is the f32→f32 specialization; the templated MSL form
 * also supports f32↔f16 conversions which would be ported similarly
 * with the half/float buffer types swapped. */

static id<MTLComputePipelineState> g_cpy_f32_f32_mtl4_pipeline;
static int g_cpy_f32_f32_mtl4_init_attempted;
static int g_cpy_f32_f32_mtl4_init_ok;

static int ds4_cpy_f32_f32_mtl4_pipeline_init(void) {
    if (g_cpy_f32_f32_mtl4_init_attempted) return g_cpy_f32_f32_mtl4_init_ok;
    g_cpy_f32_f32_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct cpy_args {\n"
         "  int64_t nk0;\n"
         "  int64_t ne00; int64_t ne01; int64_t ne02; int64_t ne03;\n"
         "  uint64_t nb00; uint64_t nb01; uint64_t nb02; uint64_t nb03;\n"
         "  int64_t ne0; int64_t ne1; int64_t ne2; int64_t ne3;\n"
         "  uint64_t nb0; uint64_t nb1; uint64_t nb2; uint64_t nb3;\n"
         "};\n"
         "kernel void cpy_f32_f32_mtl4(\n"
         "    device const cpy_args *args [[buffer(0)]],\n"
         "    device const char     *src0 [[buffer(1)]],\n"
         "    device       char     *dst  [[buffer(2)]],\n"
         "    uint3   tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort  tiitg [[thread_index_in_threadgroup]],\n"
         "    ushort3 ntg   [[threads_per_threadgroup]]) {\n"
         "  const int i03 = tgpig[2];\n"
         "  const int i02 = tgpig[1];\n"
         "  const int i01 = ntg[1] == 1 ? tgpig[0] % args->ne01\n"
         "                              : tgpig[0] * ntg[1] + tiitg / ntg[0];\n"
         "  const int iw0 = ntg[1] == 1 ? tgpig[0] / args->ne01 : 0;\n"
         "  const int64_t n = i03*args->ne02*args->ne01*args->ne00\n"
         "                  + i02*args->ne01*args->ne00\n"
         "                  + i01*args->ne00;\n"
         "  const int64_t i3 = n / (args->ne2*args->ne1*args->ne0);\n"
         "  const int64_t i2 = (n - i3*args->ne2*args->ne1*args->ne0) / (args->ne1*args->ne0);\n"
         "  const int64_t i1 = (n - i3*args->ne2*args->ne1*args->ne0\n"
         "                        - i2*args->ne1*args->ne0) / args->ne0;\n"
         "  const int64_t i0 = (n - i3*args->ne2*args->ne1*args->ne0\n"
         "                        - i2*args->ne1*args->ne0\n"
         "                        - i1*args->ne0);\n"
         "  device float *dst_data = (device float *)\n"
         "    (dst + i3*args->nb3 + i2*args->nb2 + i1*args->nb1 + i0*args->nb0);\n"
         "  for (int64_t i00 = iw0*ntg[0] + tiitg % ntg[0]; i00 < args->ne00; ) {\n"
         "    device const float *src = (device const float *)\n"
         "      (src0 + i03*args->nb03 + i02*args->nb02 + i01*args->nb01 + i00*args->nb00);\n"
         "    dst_data[i00] = (float)src[0];\n"
         "    break;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_cpy_f32_f32_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: cpy_f32_f32 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"cpy_f32_f32_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_cpy_f32_f32_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_cpy_f32_f32_mtl4_pipeline) {
        fprintf(stderr, "ds4: cpy_f32_f32 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: cpy_f32_f32 MTL4 pipeline initialized\n");
    g_cpy_f32_f32_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_cpy_f32_f32_canary(uint32_t n_rows, uint32_t row_width) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_cpy_f32_f32_mtl4_pipeline_init()) return 0;
    if (n_rows == 0 || row_width == 0) {
        fprintf(stderr, "ds4: cpy_f32_f32 canary requires n_rows>0 and row_width>0\n");
        return 0;
    }

    /* Canary: src[r, c] = r*1000 + c. Expected: dst = src exactly.
     * Simple contiguous 2D tensor — ne00=row_width, ne01=n_rows. */
    const uint64_t total = (uint64_t)n_rows * row_width;
    float *host_src = (float *)calloc(total, sizeof(float));
    float *host_dst = (float *)calloc(total, sizeof(float));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    for (uint32_t r = 0; r < n_rows; r++) {
        for (uint32_t c = 0; c < row_width; c++) {
            host_src[(uint64_t)r * row_width + c] = (float)((int)r * 1000 + (int)c);
        }
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:144
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:total * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int64_t nk0;
            int64_t ne00, ne01, ne02, ne03;
            uint64_t nb00, nb01, nb02, nb03;
            int64_t ne0, ne1, ne2, ne3;
            uint64_t nb0, nb1, nb2, nb3;
        } args = {
            .nk0 = 1,
            .ne00 = row_width, .ne01 = n_rows, .ne02 = 1, .ne03 = 1,
            .nb00 = sizeof(float),
            .nb01 = (uint64_t)row_width * sizeof(float),
            .nb02 = (uint64_t)n_rows * row_width * sizeof(float),
            .nb03 = (uint64_t)n_rows * row_width * sizeof(float),
            .ne0 = row_width, .ne1 = n_rows, .ne2 = 1, .ne3 = 1,
            .nb0 = sizeof(float),
            .nb1 = (uint64_t)row_width * sizeof(float),
            .nb2 = (uint64_t)n_rows * row_width * sizeof(float),
            .nb3 = (uint64_t)n_rows * row_width * sizeof(float),
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[3] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)srcBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:3];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:dstBuf.gpuAddress atIndex:2];

                /* Dispatch: 1 thread per output element. Use ntg.y=1 path
                 * (the simpler indexing branch). One tg per row × ceil(row_width/ntg.x). */
                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)row_width));
                NSUInteger W = ((NSUInteger)row_width + nth - 1u) / nth;
                NSUInteger gx = (NSUInteger)n_rows * W;

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_cpy_f32_f32_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(gx, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, total * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    double max_abs = 0.0;
    int mismatch = 0;
    for (uint64_t i = 0; i < total; i++) {
        const double d = fabs((double)(host_dst[i] - host_src[i]));
        if (d > max_abs) max_abs = d;
        if (d > 1.0e-6) mismatch++;
    }
    fprintf(stderr,
        "ds4: cpy_f32_f32 MTL4 canary n_rows=%u row_width=%u "
        "dst[0,0]=%.1f (ref=0.0) dst[end]=%.1f mismatch=%d max_abs=%.4e\n",
        n_rows, row_width,
        (double)host_dst[0],
        (double)host_dst[total - 1],
        mismatch, max_abs);
    free(host_src); free(host_dst);
    return (mismatch == 0) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_hc_split_weighted_sum MTL4 port (silv 2026-05-27 task #694) */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_hc_split_weighted_sum from metal/dsv4_hc.metal.
 * Decode-side fusion of HC=4 split + HC-weighted reduction. One
 * threadgroup handles one token row:
 *   - tid 0 runs the entire #690 hc_split_sinkhorn split path, writes
 *     pre+post+comb into split[], and stashes pre[0..3] in shared mem
 *   - All threads then compute embedding[d] = sum_{h=0..3} x[d,h] × pre[h]
 *
 * Per-token dispatch with width-parallel reduction. */

static id<MTLComputePipelineState> g_hc_split_weighted_sum_mtl4_pipeline;
static int g_hc_split_weighted_sum_mtl4_init_attempted;
static int g_hc_split_weighted_sum_mtl4_init_ok;

static int ds4_hc_split_weighted_sum_mtl4_pipeline_init(void) {
    if (g_hc_split_weighted_sum_mtl4_init_attempted) return g_hc_split_weighted_sum_mtl4_init_ok;
    g_hc_split_weighted_sum_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct hcsw_args {\n"
         "  int64_t n_embd;\n"
         "  int32_t n_hc;\n"
         "  int32_t sinkhorn_iters;\n"
         "  int64_t n_rows;\n"
         "  int64_t mix_hc;\n"
         "  uint64_t nb_mix1;\n"
         "  uint64_t nb_split1;\n"
         "  uint64_t nb_x0;\n"
         "  uint64_t nb_x1;\n"
         "  uint64_t nb_x2;\n"
         "  uint64_t nb0;\n"
         "  uint64_t nb1;\n"
         "  float eps;\n"
         "};\n"
         "kernel void hc_split_weighted_sum_mtl4(\n"
         "    device const hcsw_args *args [[buffer(0)]],\n"
         "    device const char      *mixes [[buffer(1)]],\n"
         "    device const float     *scale [[buffer(2)]],\n"
         "    device const float     *base  [[buffer(3)]],\n"
         "    device const char      *x     [[buffer(4)]],\n"
         "    device       char      *split [[buffer(5)]],\n"
         "    device       char      *dst   [[buffer(6)]],\n"
         "    threadgroup  float     *pre_shmem [[threadgroup(0)]],\n"
         "    uint row [[threadgroup_position_in_grid]],\n"
         "    uint tid [[thread_position_in_threadgroup]],\n"
         "    uint ntg [[threads_per_threadgroup]]) {\n"
         "  if ((int64_t)row >= args->n_rows || args->n_hc != 4) return;\n"
         "  device const float *mix = (device const float *)(mixes + (uint64_t)row*args->nb_mix1);\n"
         "  device       float *out = (device       float *)(split + (uint64_t)row*args->nb_split1);\n"
         "  if (tid == 0) {\n"
         "    const float epsv = args->eps;\n"
         "    const float pre_s = scale[0];\n"
         "    const float post_s = scale[1];\n"
         "    const float comb_s = scale[2];\n"
         "    const float4 pre_z  = *((device const float4 *)mix)       * pre_s  + *((device const float4 *)base);\n"
         "    const float4 pre = 1.0f / (1.0f + exp(-pre_z)) + epsv;\n"
         "    *((device float4 *)out) = pre;\n"
         "    pre_shmem[0] = pre.x; pre_shmem[1] = pre.y;\n"
         "    pre_shmem[2] = pre.z; pre_shmem[3] = pre.w;\n"
         "    const float4 post_z = *((device const float4 *)(mix + 4)) * post_s + *((device const float4 *)(base + 4));\n"
         "    *((device float4 *)(out + 4)) = 2.0f / (1.0f + exp(-post_z));\n"
         "    /* Sinkhorn 4×4 with stable row-softmax */\n"
         "    float4 r0 = *((device const float4 *)(mix +  8)) * comb_s + *((device const float4 *)(base +  8));\n"
         "    float4 r1 = *((device const float4 *)(mix + 12)) * comb_s + *((device const float4 *)(base + 12));\n"
         "    float4 r2 = *((device const float4 *)(mix + 16)) * comb_s + *((device const float4 *)(base + 16));\n"
         "    float4 r3 = *((device const float4 *)(mix + 20)) * comb_s + *((device const float4 *)(base + 20));\n"
         "    const float m0 = max(max(r0.x, r0.y), max(r0.z, r0.w));\n"
         "    const float m1 = max(max(r1.x, r1.y), max(r1.z, r1.w));\n"
         "    const float m2 = max(max(r2.x, r2.y), max(r2.z, r2.w));\n"
         "    const float m3 = max(max(r3.x, r3.y), max(r3.z, r3.w));\n"
         "    r0 = exp(r0 - m0); r1 = exp(r1 - m1); r2 = exp(r2 - m2); r3 = exp(r3 - m3);\n"
         "    r0 = r0 * (1.0f / (r0.x + r0.y + r0.z + r0.w)) + epsv;\n"
         "    r1 = r1 * (1.0f / (r1.x + r1.y + r1.z + r1.w)) + epsv;\n"
         "    r2 = r2 * (1.0f / (r2.x + r2.y + r2.z + r2.w)) + epsv;\n"
         "    r3 = r3 * (1.0f / (r3.x + r3.y + r3.z + r3.w)) + epsv;\n"
         "    float4 col_inv = 1.0f / (r0 + r1 + r2 + r3 + epsv);\n"
         "    r0 *= col_inv; r1 *= col_inv; r2 *= col_inv; r3 *= col_inv;\n"
         "    for (int iter = 1; iter < args->sinkhorn_iters; ++iter) {\n"
         "      r0 *= 1.0f / (r0.x + r0.y + r0.z + r0.w + epsv);\n"
         "      r1 *= 1.0f / (r1.x + r1.y + r1.z + r1.w + epsv);\n"
         "      r2 *= 1.0f / (r2.x + r2.y + r2.z + r2.w + epsv);\n"
         "      r3 *= 1.0f / (r3.x + r3.y + r3.z + r3.w + epsv);\n"
         "      col_inv = 1.0f / (r0 + r1 + r2 + r3 + epsv);\n"
         "      r0 *= col_inv; r1 *= col_inv; r2 *= col_inv; r3 *= col_inv;\n"
         "    }\n"
         "    *((device float4 *)(out +  8)) = r0;\n"
         "    *((device float4 *)(out + 12)) = r1;\n"
         "    *((device float4 *)(out + 16)) = r2;\n"
         "    *((device float4 *)(out + 20)) = r3;\n"
         "  }\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  /* All threads: per-d HC-weighted sum into dst */\n"
         "  for (int64_t d = tid; d < args->n_embd; d += ntg) {\n"
         "    float acc = 0.0f;\n"
         "    acc += *((device const float *)(x + d*args->nb_x0 + 0*args->nb_x1 + (uint64_t)row*args->nb_x2)) * pre_shmem[0];\n"
         "    acc += *((device const float *)(x + d*args->nb_x0 + 1*args->nb_x1 + (uint64_t)row*args->nb_x2)) * pre_shmem[1];\n"
         "    acc += *((device const float *)(x + d*args->nb_x0 + 2*args->nb_x1 + (uint64_t)row*args->nb_x2)) * pre_shmem[2];\n"
         "    acc += *((device const float *)(x + d*args->nb_x0 + 3*args->nb_x1 + (uint64_t)row*args->nb_x2)) * pre_shmem[3];\n"
         "    *((device float *)(dst + d*args->nb0 + (uint64_t)row*args->nb1)) = acc;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_hc_split_weighted_sum_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: hc_split_weighted_sum MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"hc_split_weighted_sum_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_hc_split_weighted_sum_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_hc_split_weighted_sum_mtl4_pipeline) {
        fprintf(stderr, "ds4: hc_split_weighted_sum MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: hc_split_weighted_sum MTL4 pipeline initialized\n");
    g_hc_split_weighted_sum_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_hc_split_weighted_sum_canary(uint32_t n_rows, uint32_t n_embd) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_hc_split_weighted_sum_mtl4_pipeline_init()) return 0;
    if (n_rows == 0 || n_embd == 0) {
        fprintf(stderr, "ds4: hc_split_weighted_sum canary requires n_rows>0 and n_embd>0\n");
        return 0;
    }

    /* Canary: mix=0, base=0, scale=[1,1,1], eps=0, x[d,h,r] = 1.0.
     * Expected:
     *   pre[0..3] = sigmoid(0) = 0.5
     *   post[4..7] = 2*sigmoid(0) = 1.0
     *   comb[8..23] = 0.25 (uniform 4×4 doubly-stochastic)
     *   dst[d, r] = sum_{h=0..3} 1.0 × 0.5 = 2.0 */
    const uint32_t mix_hc = 24;
    const uint64_t mix_total = (uint64_t)n_rows * mix_hc;
    const uint64_t split_total = (uint64_t)n_rows * mix_hc;
    const uint64_t x_total = (uint64_t)n_embd * 4 * n_rows;
    const uint64_t dst_total = (uint64_t)n_embd * n_rows;

    float *host_mix = (float *)calloc(mix_total, sizeof(float));
    float *host_scale = (float *)calloc(3, sizeof(float));
    float *host_base = (float *)calloc(mix_hc, sizeof(float));
    float *host_x = (float *)calloc(x_total, sizeof(float));
    float *host_split = (float *)calloc(split_total, sizeof(float));
    float *host_dst = (float *)calloc(dst_total, sizeof(float));
    if (!host_mix || !host_scale || !host_base || !host_x || !host_split || !host_dst) {
        free(host_mix); free(host_scale); free(host_base);
        free(host_x); free(host_split); free(host_dst);
        return 0;
    }
    host_scale[0] = host_scale[1] = host_scale[2] = 1.0f;
    for (uint64_t i = 0; i < x_total; i++) host_x[i] = 1.0f;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:96
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> mixBuf = [g_device newBufferWithBytes:host_mix
                                                     length:mix_total * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> scaleBuf = [g_device newBufferWithBytes:host_scale
                                                       length:3 * sizeof(float)
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> baseBuf = [g_device newBufferWithBytes:host_base
                                                      length:mix_hc * sizeof(float)
                                                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> xBuf = [g_device newBufferWithBytes:host_x
                                                   length:x_total * sizeof(float)
                                                  options:MTLResourceStorageModeShared];
        id<MTLBuffer> splitBuf = [g_device newBufferWithLength:split_total * sizeof(float)
                                                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_total * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int64_t n_embd_;
            int32_t n_hc_, sinkhorn_iters_;
            int64_t n_rows_, mix_hc_;
            uint64_t nb_mix1_, nb_split1_;
            uint64_t nb_x0_, nb_x1_, nb_x2_;
            uint64_t nb0_, nb1_;
            float eps_;
            uint32_t pad;
        } args = {
            .n_embd_ = (int64_t)n_embd,
            .n_hc_ = 4, .sinkhorn_iters_ = 1,
            .n_rows_ = (int64_t)n_rows, .mix_hc_ = mix_hc,
            .nb_mix1_ = (uint64_t)mix_hc * sizeof(float),
            .nb_split1_ = (uint64_t)mix_hc * sizeof(float),
            .nb_x0_ = sizeof(float),
            .nb_x1_ = (uint64_t)n_embd * sizeof(float),
            .nb_x2_ = (uint64_t)n_embd * 4 * sizeof(float),
            .nb0_ = sizeof(float),
            .nb1_ = (uint64_t)n_embd * sizeof(float),
            .eps_ = 0.0f,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[7] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)mixBuf,
                (id<MTLAllocation>)scaleBuf,
                (id<MTLAllocation>)baseBuf,
                (id<MTLAllocation>)xBuf,
                (id<MTLAllocation>)splitBuf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:7];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(8);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:mixBuf.gpuAddress atIndex:1];
                [argTable setAddress:scaleBuf.gpuAddress atIndex:2];
                [argTable setAddress:baseBuf.gpuAddress atIndex:3];
                [argTable setAddress:xBuf.gpuAddress atIndex:4];
                [argTable setAddress:splitBuf.gpuAddress atIndex:5];
                [argTable setAddress:dstBuf.gpuAddress atIndex:6];

                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)n_embd));

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_hc_split_weighted_sum_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                /* shmem: pre_shmem[4] = 16 bytes */
                [enc setThreadgroupMemoryLength:16 atIndex:0];
                [enc dispatchThreadgroups:MTLSizeMake(n_rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_split, splitBuf.contents, split_total * sizeof(float));
                    memcpy(host_dst, dstBuf.contents, dst_total * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 8);
            }
        }
    }
    if (!rc) {
        free(host_mix); free(host_scale); free(host_base);
        free(host_x); free(host_split); free(host_dst);
        return 0;
    }

    /* Validate */
    double split_dev = 0.0, dst_dev = 0.0;
    for (uint32_t r = 0; r < n_rows; r++) {
        const float *s = host_split + (uint64_t)r * mix_hc;
        for (int i = 0; i < 4; i++) {
            double d = fabs((double)(s[i] - 0.5));
            if (d > split_dev) split_dev = d;
        }
        for (int i = 4; i < 8; i++) {
            double d = fabs((double)(s[i] - 1.0));
            if (d > split_dev) split_dev = d;
        }
        for (int i = 8; i < 24; i++) {
            double d = fabs((double)(s[i] - 0.25));
            if (d > split_dev) split_dev = d;
        }
        for (uint32_t d = 0; d < n_embd; d++) {
            double e = fabs((double)(host_dst[(uint64_t)r * n_embd + d] - 2.0));
            if (e > dst_dev) dst_dev = e;
        }
    }
    fprintf(stderr,
        "ds4: hc_split_weighted_sum MTL4 canary n_rows=%u n_embd=%u "
        "split[0]=%.4f (ref=0.5) split[4]=%.4f (ref=1.0) split[8]=%.4f (ref=0.25) "
        "dst[0,0]=%.4f (ref=2.0) split_dev=%.4e dst_dev=%.4e\n",
        n_rows, n_embd,
        (double)host_split[0], (double)host_split[4], (double)host_split[8],
        (double)host_dst[0],
        split_dev, dst_dev);
    free(host_mix); free(host_scale); free(host_base);
    free(host_x); free(host_split); free(host_dst);
    return (split_dev < 1.0e-6 && dst_dev < 1.0e-6) ? 1 : 0;
}

/* ============================================================ */
/* dsv4_rope_tail_f32 MTL4 port (silv 2026-05-27 task #695)       */
/* ============================================================ */
/* MTL4 port of kernel_dsv4_rope_tail_f32 from metal/dsv4_rope.metal.
 * DeepSeek V4's partial RoPE: the no-position prefix (first n_nope =
 * ne00 - n_dims elements) is copied unchanged, the rotated tail is
 * transformed via YaRN-scaled rotary embedding.
 *
 * NEW patterns:
 *   - YaRN helper functions inlined: ramp, corr_factor, corr_dims, yarn
 *   - Two RoPE variants: interleaved (mode != 2) + NeoX (mode == 2)
 *   - Optional src2 freq_factor table
 *   - Inverse rotation support (sin → -sin)
 *
 * Per-token dispatch: (n_seq, n_tokens, n_batches) tg × (ntg, 1, 1) threads.
 * Canary uses pos=0 (theta=0 → cos=1, sin=0) so rotation is identity. */

static id<MTLComputePipelineState> g_rope_tail_f32_mtl4_pipeline;
static int g_rope_tail_f32_mtl4_init_attempted;
static int g_rope_tail_f32_mtl4_init_ok;

static int ds4_rope_tail_f32_mtl4_pipeline_init(void) {
    if (g_rope_tail_f32_mtl4_init_attempted) return g_rope_tail_f32_mtl4_init_ok;
    g_rope_tail_f32_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "static float rope_yarn_ramp(const float low, const float high, const int i0) {\n"
         "  const float y = (i0 / 2 - low) / max(0.001f, high - low);\n"
         "  return 1.0f - min(1.0f, max(0.0f, y));\n"
         "}\n"
         "static void rope_yarn(\n"
         "    float theta_extrap, float freq_scale, float corr_dims[2], int i0,\n"
         "    float ext_factor, float mscale,\n"
         "    thread float *cos_theta, thread float *sin_theta) {\n"
         "  float theta_interp = freq_scale * theta_extrap;\n"
         "  float theta = theta_interp;\n"
         "  if (ext_factor != 0.0f) {\n"
         "    float ramp_mix = rope_yarn_ramp(corr_dims[0], corr_dims[1], i0) * ext_factor;\n"
         "    theta = theta_interp * (1 - ramp_mix) + theta_extrap * ramp_mix;\n"
         "    mscale *= 1.0f + 0.1f * log(1.0f / freq_scale);\n"
         "  }\n"
         "  *cos_theta = cos(theta) * mscale;\n"
         "  *sin_theta = sin(theta) * mscale;\n"
         "}\n"
         "static float rope_yarn_corr_factor(int n_dims, int n_ctx_orig, float n_rot, float base) {\n"
         "  return n_dims * log(n_ctx_orig / (n_rot * 2 * M_PI_F)) / (2 * log(base));\n"
         "}\n"
         "static void rope_yarn_corr_dims(\n"
         "    int n_dims, int n_ctx_orig, float freq_base, float beta_fast, float beta_slow,\n"
         "    thread float *dims) {\n"
         "  dims[0] = max(0.0f, floor(rope_yarn_corr_factor(n_dims, n_ctx_orig, beta_fast, freq_base)));\n"
         "  dims[1] = min(n_dims - 1.0f, ceil(rope_yarn_corr_factor(n_dims, n_ctx_orig, beta_slow, freq_base)));\n"
         "}\n"
         "struct rt_args {\n"
         "  int64_t  ne00; int64_t  ne01; int64_t  ne02; int64_t  ne03;\n"
         "  uint64_t nb00; uint64_t nb01; uint64_t nb02; uint64_t nb03;\n"
         "  uint64_t nb0;  uint64_t nb1;  uint64_t nb2;  uint64_t nb3;\n"
         "  int32_t  n_dims; int32_t mode; int32_t n_ctx_orig; int32_t inverse;\n"
         "  float    freq_base; float freq_scale; float ext_factor; float attn_factor;\n"
         "  float    beta_fast; float beta_slow;\n"
         "  uint32_t src2_flag;  /* 1 if src2 is used for freq_factor table */\n"
         "};\n"
         "kernel void rope_tail_f32_mtl4(\n"
         "    device const rt_args *args [[buffer(0)]],\n"
         "    device const char    *src0 [[buffer(1)]],\n"
         "    device const char    *src1 [[buffer(2)]],   /* int32 positions */\n"
         "    device const char    *src2 [[buffer(3)]],   /* float freq_factors (optional) */\n"
         "    device       char    *dst  [[buffer(4)]],\n"
         "    uint    tid   [[thread_index_in_threadgroup]],\n"
         "    ushort3 ntg   [[threads_per_threadgroup]],\n"
         "    uint3   tgpig [[threadgroup_position_in_grid]]) {\n"
         "  const int i1 = tgpig[0];\n"
         "  const int i2 = tgpig[1];\n"
         "  const int i3 = tgpig[2];\n"
         "  const int n_nope = (int)args->ne00 - args->n_dims;\n"
         "  if (n_nope < 0) return;\n"
         "  device const int32_t *pos = (device const int32_t *)src1;\n"
         "  float corr_dims[2];\n"
         "  rope_yarn_corr_dims(args->n_dims, args->n_ctx_orig, args->freq_base,\n"
         "                       args->beta_fast, args->beta_slow, corr_dims);\n"
         "  const float theta_base = (float)pos[i2];\n"
         "  const float inv_ndims = -1.f / (float)args->n_dims;\n"
         "  const bool is_neox = args->mode == 2;\n"
         "  for (int i0 = (int)tid; i0 < (int)args->ne00; i0 += (int)ntg.x) {\n"
         "    device const char *src_base = src0 + i3*args->nb03 + i2*args->nb02 + i1*args->nb01;\n"
         "    device       char *dst_base = dst  + i3*args->nb3  + i2*args->nb2  + i1*args->nb1;\n"
         "    if (i0 < n_nope) {\n"
         "      *((device float *)(dst_base + i0*args->nb0)) =\n"
         "        *((device const float *)(src_base + i0*args->nb00));\n"
         "      continue;\n"
         "    }\n"
         "    const int r = i0 - n_nope;\n"
         "    if (is_neox) {\n"
         "      const int n_half = args->n_dims / 2;\n"
         "      if (r >= n_half) continue;\n"
         "      const int ic = r;\n"
         "      const int rel_i0 = 2 * ic;\n"
         "      const float theta = theta_base * pow(args->freq_base, inv_ndims * (float)rel_i0);\n"
         "      const float freq_factor = args->src2_flag ? ((device const float *)src2)[ic] : 1.0f;\n"
         "      float cos_theta, sin_theta;\n"
         "      rope_yarn(theta / freq_factor, args->freq_scale, corr_dims, rel_i0,\n"
         "                args->ext_factor, args->attn_factor, &cos_theta, &sin_theta);\n"
         "      if (args->inverse) sin_theta = -sin_theta;\n"
         "      const int j0 = n_nope + ic;\n"
         "      const int j1 = n_nope + ic + n_half;\n"
         "      const float x0 = *((device const float *)(src_base + j0*args->nb00));\n"
         "      const float x1 = *((device const float *)(src_base + j1*args->nb00));\n"
         "      *((device float *)(dst_base + j0*args->nb0)) = x0*cos_theta - x1*sin_theta;\n"
         "      *((device float *)(dst_base + j1*args->nb0)) = x0*sin_theta + x1*cos_theta;\n"
         "    } else {\n"
         "      if ((r & 1) != 0) continue;\n"
         "      const int ic = r / 2;\n"
         "      const float theta = theta_base * pow(args->freq_base, inv_ndims * (float)r);\n"
         "      const float freq_factor = args->src2_flag ? ((device const float *)src2)[ic] : 1.0f;\n"
         "      float cos_theta, sin_theta;\n"
         "      rope_yarn(theta / freq_factor, args->freq_scale, corr_dims, r,\n"
         "                args->ext_factor, args->attn_factor, &cos_theta, &sin_theta);\n"
         "      if (args->inverse) sin_theta = -sin_theta;\n"
         "      const int j0 = n_nope + r;\n"
         "      const int j1 = j0 + 1;\n"
         "      const float x0 = *((device const float *)(src_base + j0*args->nb00));\n"
         "      const float x1 = *((device const float *)(src_base + j1*args->nb00));\n"
         "      *((device float *)(dst_base + j0*args->nb0)) = x0*cos_theta - x1*sin_theta;\n"
         "      *((device float *)(dst_base + j1*args->nb0)) = x0*sin_theta + x1*cos_theta;\n"
         "    }\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_rope_tail_f32_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: rope_tail_f32 MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"rope_tail_f32_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_rope_tail_f32_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_rope_tail_f32_mtl4_pipeline) {
        fprintf(stderr, "ds4: rope_tail_f32 MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: rope_tail_f32 MTL4 pipeline initialized\n");
    g_rope_tail_f32_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_rope_tail_f32_canary(uint32_t head_dim, uint32_t n_rot, uint32_t mode) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_rope_tail_f32_mtl4_pipeline_init()) return 0;
    if (head_dim == 0 || n_rot > head_dim) {
        fprintf(stderr, "ds4: rope_tail canary requires head_dim>0 and n_rot<=head_dim\n");
        return 0;
    }

    /* Canary: pos[0]=0 → theta_base=0 → cos(0)=1, sin(0)=0
     * → x0' = x0*1 - x1*0 = x0
     *   x1' = x0*0 + x1*1 = x1
     * Identity rotation → dst = src exactly across both prefix + tail.
     * src[i] = (float)i for verification. */
    const uint32_t n_nope = head_dim - n_rot;
    float *host_src = (float *)calloc(head_dim, sizeof(float));
    int32_t host_pos[1] = { 0 };
    float *host_dst = (float *)calloc(head_dim, sizeof(float));
    if (!host_src || !host_dst) { free(host_src); free(host_dst); return 0; }
    for (uint32_t i = 0; i < head_dim; i++) host_src[i] = (float)i;
    (void)n_nope;

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:160
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> srcBuf = [g_device newBufferWithBytes:host_src
                                                     length:head_dim * sizeof(float)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> posBuf = [g_device newBufferWithBytes:host_pos
                                                     length:sizeof(host_pos)
                                                    options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:head_dim * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int64_t ne00, ne01, ne02, ne03;
            uint64_t nb00, nb01, nb02, nb03;
            uint64_t nb0, nb1, nb2, nb3;
            int32_t n_dims, mode_, n_ctx_orig, inverse;
            float freq_base, freq_scale, ext_factor, attn_factor;
            float beta_fast, beta_slow;
            uint32_t src2_flag;
            uint32_t pad;
        } args = {
            .ne00 = head_dim, .ne01 = 1, .ne02 = 1, .ne03 = 1,
            .nb00 = sizeof(float),
            .nb01 = (uint64_t)head_dim * sizeof(float),
            .nb02 = (uint64_t)head_dim * sizeof(float),
            .nb03 = (uint64_t)head_dim * sizeof(float),
            .nb0 = sizeof(float),
            .nb1 = (uint64_t)head_dim * sizeof(float),
            .nb2 = (uint64_t)head_dim * sizeof(float),
            .nb3 = (uint64_t)head_dim * sizeof(float),
            .n_dims = (int32_t)n_rot,
            .mode_ = (int32_t)mode,
            .n_ctx_orig = 4096,
            .inverse = 0,
            .freq_base = 10000.0f,
            .freq_scale = 1.0f,
            .ext_factor = 0.0f,
            .attn_factor = 1.0f,
            .beta_fast = 32.0f, .beta_slow = 1.0f,
            .src2_flag = 0,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 6;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[5] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)srcBuf,
                (id<MTLAllocation>)posBuf,
                (id<MTLAllocation>)srcBuf,   /* src2 alias (src2_flag=0 so unused) */
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:5];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(6);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:srcBuf.gpuAddress atIndex:1];
                [argTable setAddress:posBuf.gpuAddress atIndex:2];
                [argTable setAddress:srcBuf.gpuAddress atIndex:3];   /* src2 unused */
                [argTable setAddress:dstBuf.gpuAddress atIndex:4];

                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)head_dim));

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_rope_tail_f32_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(1, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, head_dim * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 6);
            }
        }
    }
    if (!rc) { free(host_src); free(host_dst); return 0; }

    /* pos=0 → identity rotation → dst should equal src exactly */
    double max_abs = 0.0;
    int mismatch = 0;
    for (uint32_t i = 0; i < head_dim; i++) {
        double d = fabs((double)(host_dst[i] - host_src[i]));
        if (d > max_abs) max_abs = d;
        if (d > 1.0e-5) mismatch++;
    }
    fprintf(stderr,
        "ds4: rope_tail_f32 MTL4 canary head_dim=%u n_rot=%u mode=%u "
        "dst[0]=%.1f (ref=0.0) dst[%u]=%.1f (ref=%.1f) "
        "dst[end]=%.1f mismatch=%d max_abs=%.4e\n",
        head_dim, n_rot, mode,
        (double)host_dst[0],
        head_dim - 1, (double)host_dst[head_dim - 1], (double)(head_dim - 1),
        (double)host_dst[head_dim - 1],
        mismatch, max_abs);
    free(host_src); free(host_dst);
    return (mismatch == 0) ? 1 : 0;
}

/* ============================================================ */
/* concat MTL4 port (silv 2026-05-27 task #696)                   */
/* ============================================================ */
/* MTL4 port of kernel_concat from metal/concat.metal. Concatenates
 * two float tensors along a chosen dim. DS4 uses this as a graph
 * utility for assembling attention inputs with the same layout as
 * downstream kernels expect. */

static id<MTLComputePipelineState> g_concat_mtl4_pipeline;
static int g_concat_mtl4_init_attempted;
static int g_concat_mtl4_init_ok;

static int ds4_concat_mtl4_pipeline_init(void) {
    if (g_concat_mtl4_init_attempted) return g_concat_mtl4_init_ok;
    g_concat_mtl4_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0;

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "struct cc_args {\n"
         "  int32_t ne00; int32_t ne01; int32_t ne02; int32_t ne03;\n"
         "  uint64_t nb00; uint64_t nb01; uint64_t nb02; uint64_t nb03;\n"
         "  int32_t ne10; int32_t ne11; int32_t ne12; int32_t ne13;\n"
         "  uint64_t nb10; uint64_t nb11; uint64_t nb12; uint64_t nb13;\n"
         "  int32_t ne0; int32_t ne1; int32_t ne2; int32_t ne3;\n"
         "  uint64_t nb0; uint64_t nb1; uint64_t nb2; uint64_t nb3;\n"
         "  int32_t dim;\n"
         "};\n"
         "kernel void concat_mtl4(\n"
         "    device const cc_args *args [[buffer(0)]],\n"
         "    device const char    *src0 [[buffer(1)]],\n"
         "    device const char    *src1 [[buffer(2)]],\n"
         "    device       char    *dst  [[buffer(3)]],\n"
         "    uint3   tgpig [[threadgroup_position_in_grid]],\n"
         "    ushort3 tpitg [[thread_position_in_threadgroup]],\n"
         "    ushort3 ntg   [[threads_per_threadgroup]]) {\n"
         "  const int i3 = tgpig.z;\n"
         "  const int i2 = tgpig.y;\n"
         "  const int i1 = tgpig.x;\n"
         "  int o[4] = {0, 0, 0, 0};\n"
         "  o[args->dim] = args->dim == 0 ? args->ne00 :\n"
         "                  (args->dim == 1 ? args->ne01 :\n"
         "                   (args->dim == 2 ? args->ne02 : args->ne03));\n"
         "  device const float *x;\n"
         "  for (int i0 = tpitg.x; i0 < args->ne0; i0 += ntg.x) {\n"
         "    if (i0 < args->ne00 && i1 < args->ne01 && i2 < args->ne02 && i3 < args->ne03) {\n"
         "      x = (device const float *)(src0 + i3*args->nb03 + i2*args->nb02 + i1*args->nb01 + i0*args->nb00);\n"
         "    } else {\n"
         "      x = (device const float *)(src1 + (i3 - o[3])*args->nb13 + (i2 - o[2])*args->nb12 +\n"
         "                                  (i1 - o[1])*args->nb11 + (i0 - o[0])*args->nb10);\n"
         "    }\n"
         "    device float *y = (device float *)(dst + i3*args->nb3 + i2*args->nb2 + i1*args->nb1 + i0*args->nb0);\n"
         "    *y = *x;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_concat_mtl4";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: concat MTL4 library compile failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"concat_mtl4";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_concat_mtl4_pipeline =
        [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                           compilerTaskOptions:nil error:&err];
    if (!g_concat_mtl4_pipeline) {
        fprintf(stderr, "ds4: concat MTL4 pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    fprintf(stderr, "ds4: concat MTL4 pipeline initialized\n");
    g_concat_mtl4_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_concat_canary(uint32_t n0, uint32_t n1, uint32_t n_rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_concat_mtl4_pipeline_init()) return 0;
    if (n0 == 0 || n1 == 0 || n_rows == 0) {
        fprintf(stderr, "ds4: concat canary requires all sizes > 0\n");
        return 0;
    }

    /* Canary: concat two tensors along dim 0.
     *   src0[r, c] = (r * 10 + c),         for c in 0..n0
     *   src1[r, c] = (r * 10 + n0 + c),    for c in 0..n1
     *   dst[r, c]  = (r * 10 + c),         for c in 0..(n0+n1)
     * Each src row contributes its part to the dst row. */
    const uint32_t n_out = n0 + n1;
    const uint64_t s0_n = (uint64_t)n0 * n_rows;
    const uint64_t s1_n = (uint64_t)n1 * n_rows;
    const uint64_t dst_n = (uint64_t)n_out * n_rows;
    float *host_s0 = (float *)calloc(s0_n, sizeof(float));
    float *host_s1 = (float *)calloc(s1_n, sizeof(float));
    float *host_dst = (float *)calloc(dst_n, sizeof(float));
    if (!host_s0 || !host_s1 || !host_dst) {
        free(host_s0); free(host_s1); free(host_dst); return 0;
    }
    for (uint32_t r = 0; r < n_rows; r++) {
        for (uint32_t c = 0; c < n0; c++) host_s0[(uint64_t)r * n0 + c] = (float)((int)r * 10 + (int)c);
        for (uint32_t c = 0; c < n1; c++) host_s1[(uint64_t)r * n1 + c] = (float)((int)r * 10 + (int)n0 + (int)c);
    }

    int rc = 0;
    @autoreleasepool {
        NSError *err = nil;
        id<MTLBuffer> argsBuf = [g_device newBufferWithLength:160
                                                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> s0Buf = [g_device newBufferWithBytes:host_s0
                                                    length:s0_n * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> s1Buf = [g_device newBufferWithBytes:host_s1
                                                    length:s1_n * sizeof(float)
                                                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> dstBuf = [g_device newBufferWithLength:dst_n * sizeof(float)
                                                     options:MTLResourceStorageModeShared];

        struct {
            int32_t ne00, ne01, ne02, ne03;
            uint64_t nb00, nb01, nb02, nb03;
            int32_t ne10, ne11, ne12, ne13;
            uint64_t nb10, nb11, nb12, nb13;
            int32_t ne0, ne1, ne2, ne3;
            uint64_t nb0, nb1, nb2, nb3;
            int32_t dim_; uint32_t pad;
        } args = {
            .ne00 = (int32_t)n0, .ne01 = (int32_t)n_rows, .ne02 = 1, .ne03 = 1,
            .nb00 = sizeof(float),
            .nb01 = (uint64_t)n0 * sizeof(float),
            .nb02 = (uint64_t)n0 * n_rows * sizeof(float),
            .nb03 = (uint64_t)n0 * n_rows * sizeof(float),
            .ne10 = (int32_t)n1, .ne11 = (int32_t)n_rows, .ne12 = 1, .ne13 = 1,
            .nb10 = sizeof(float),
            .nb11 = (uint64_t)n1 * sizeof(float),
            .nb12 = (uint64_t)n1 * n_rows * sizeof(float),
            .nb13 = (uint64_t)n1 * n_rows * sizeof(float),
            .ne0 = (int32_t)n_out, .ne1 = (int32_t)n_rows, .ne2 = 1, .ne3 = 1,
            .nb0 = sizeof(float),
            .nb1 = (uint64_t)n_out * sizeof(float),
            .nb2 = (uint64_t)n_out * n_rows * sizeof(float),
            .nb3 = (uint64_t)n_out * n_rows * sizeof(float),
            .dim_ = 0,
        };
        memcpy(argsBuf.contents, &args, sizeof(args));

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 4;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (residency) {
            id<MTLAllocation> allocs[4] = {
                (id<MTLAllocation>)argsBuf,
                (id<MTLAllocation>)s0Buf,
                (id<MTLAllocation>)s1Buf,
                (id<MTLAllocation>)dstBuf,
            };
            [residency addAllocations:allocs count:4];
            [residency commit];
            [residency requestResidency];

            id<MTL4ArgumentTable> argTable = ds4_mtl4_pool_acquire(4);
            if (argTable) {
                [argTable setAddress:argsBuf.gpuAddress atIndex:0];
                [argTable setAddress:s0Buf.gpuAddress atIndex:1];
                [argTable setAddress:s1Buf.gpuAddress atIndex:2];
                [argTable setAddress:dstBuf.gpuAddress atIndex:3];

                NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)n_out));

                id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
                [cb beginCommandBufferWithAllocator:g_polar_allocator];
                [cb useResidencySet:residency];
                id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
                [enc setComputePipelineState:g_concat_mtl4_pipeline];
                [enc setArgumentTable:argTable];
                [enc dispatchThreadgroups:MTLSizeMake(n_rows, 1, 1)
                    threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
                [enc endEncoding];
                [cb endCommandBuffer];

                [g_polar_queue addResidencySet:residency];
                dispatch_semaphore_t sem = dispatch_semaphore_create(0);
                MTL4CommitOptions *opts = [MTL4CommitOptions new];
                [opts addFeedbackHandler:^(id<MTL4CommitFeedback> fb) {
                    (void)fb; dispatch_semaphore_signal(sem);
                }];
                id<MTL4CommandBuffer> bufs[1] = { cb };
                [g_polar_queue commit:bufs count:1 options:opts];
                long waitRes = dispatch_semaphore_wait(sem,
                    dispatch_time(DISPATCH_TIME_NOW, 5LL * NSEC_PER_SEC));
                [residency endResidency];
                if (waitRes == 0) {
                    memcpy(host_dst, dstBuf.contents, dst_n * sizeof(float));
                    rc = 1;
                }
                ds4_mtl4_pool_release(argTable, 4);
            }
        }
    }
    if (!rc) { free(host_s0); free(host_s1); free(host_dst); return 0; }

    /* Validate: dst[r, c] = r*10 + c for c in [0, n_out) */
    double max_abs = 0.0;
    int mismatch = 0;
    for (uint32_t r = 0; r < n_rows; r++) {
        for (uint32_t c = 0; c < n_out; c++) {
            const float v = host_dst[(uint64_t)r * n_out + c];
            const float ref = (float)((int)r * 10 + (int)c);
            const double d = fabs((double)(v - ref));
            if (d > max_abs) max_abs = d;
            if (d > 1.0e-6) mismatch++;
        }
    }
    fprintf(stderr,
        "ds4: concat MTL4 canary n0=%u n1=%u n_rows=%u "
        "dst[0,0]=%.1f (ref=0.0) dst[0,n0]=%.1f (ref=%.1f) "
        "dst[end]=%.1f mismatch=%d max_abs=%.4e\n",
        n0, n1, n_rows,
        (double)host_dst[0],
        (double)host_dst[n0], (double)n0,
        (double)host_dst[dst_n - 1],
        mismatch, max_abs);
    free(host_s0); free(host_s1); free(host_dst);
    return (mismatch == 0) ? 1 : 0;
}

/* ============================================================ */
/* H1729 tile×row×batch polar dot kernel                        */
/* ============================================================ */
/* Per codex H1729: real MoE execution unit = "resident expert-code tile +
 * streaming hidden states". Same MSL kernel shape as H1725 but the
 * dispatch is 3D (tile, row, batch) and the hidden vector is indexed by
 * (batch, tile) — SAME hidden vector reused across all rows of a tile.
 * That's the layout amortization: per-token hidden state fans out to all
 * the weight rows of one expert sub-block in a single dispatch.
 *
 * Measured (codex H1729 on M1 Max): b8 = 46.70 ns/output (1.45× over
 * per-packet H1725), b32 = 31.81× layout reduction. Best per-output at
 * b8; best layout amortization at b32.
 *
 * Self-test: ds4_gpu_mtl4_polar_tile_canary(tiles, rows, batches, pairs).
 * Synthetic deterministic input: mag=0, phase=4 (angle 0), level[0]=1,
 * hidden=1. Expected per output = pairs × 1.0.
 *
 * Codex artifact source:
 *   research/llm_fallacy_deconstruction/framework_deconstruction/
 *     h1729_mtl4_polar_tile32_batched_kernel_20260525.m
 */

static id<MTLComputePipelineState> g_polar_tile_pipeline;
static int g_polar_tile_init_attempted;
static int g_polar_tile_init_ok;

static int ds4_polar_tile_pipeline_init(void) {
    if (g_polar_tile_init_attempted) return g_polar_tile_init_ok;
    g_polar_tile_init_attempted = 1;

    if (!ds4_polar_pipeline_init()) return 0; /* reuse the compiler + queue + allocator */

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "kernel void polar_dot_tile(device const uchar* mag [[buffer(0)]],\n"
         "                            device const uchar* phase [[buffer(1)]],\n"
         "                            device const float* levels [[buffer(2)]],\n"
         "                            device const float* hidden [[buffer(3)]],\n"
         "                            device const float* cos_lut [[buffer(4)]],\n"
         "                            device const float* sin_lut [[buffer(5)]],\n"
         "                            device float* out [[buffer(6)]],\n"
         "                            device const uint* params [[buffer(7)]],\n"
         "                            uint3 tg [[threadgroup_position_in_grid]],\n"
         "                            uint tid [[thread_index_in_threadgroup]]) {\n"
         "  constexpr uint THREADS = 256;\n"
         "  threadgroup float partial[THREADS];\n"
         "  uint tile = tg.x;\n"
         "  uint row  = tg.y;\n"
         "  uint batch = tg.z;\n"
         "  uint pairs = params[0];\n"
         "  uint rows  = params[1];\n"
         "  uint tiles = params[2];\n"
         "  uint row_packet = tile * rows + row;\n"
         "  uint row_packets = tiles * rows;\n"
         "  uint code_base = row_packet * pairs;\n"
         "  uint hbase = (batch * tiles + tile) * pairs * 2;\n"
         "  float acc = 0.0f;\n"
         "  for (uint j = tid; j < pairs; j += THREADS) {\n"
         "    uint idx = code_base + j;\n"
         "    uchar mcode = mag[idx];\n"
         "    float qmag = levels[row_packet * 4 + uint(mcode)];\n"
         "    uint lut = uint(phase[idx]);\n"
         "    float x0 = qmag * cos_lut[lut];\n"
         "    float x1 = qmag * sin_lut[lut];\n"
         "    acc += x0 * hidden[hbase + 2*j] + x1 * hidden[hbase + 2*j + 1];\n"
         "  }\n"
         "  partial[tid] = acc;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  for (uint stride = THREADS >> 1; stride > 0; stride >>= 1) {\n"
         "    if (tid < stride) partial[tid] += partial[tid + stride];\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  if (tid == 0) out[batch * row_packets + row_packet] = partial[0];\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_polar_dot_tile";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: polar tile MTL4 library failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"polar_dot_tile";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_polar_tile_pipeline = [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                                                compilerTaskOptions:nil
                                                                              error:&err];
    if (!g_polar_tile_pipeline) {
        fprintf(stderr, "ds4: polar tile pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    g_polar_tile_init_ok = 1;
    return 1;
}

/* Same kernel as ds4_gpu_mtl4_polar_tile_canary, but loads buffers from
 * pre-encoded binary files produced by analyzers/polar_encode_safetensors.py.
 * Validates end-to-end against the Python reference in <prefix>.expected_polar.bin.
 *
 * Files read (sizes are tiles*rows*pairs for mag/phase, tiles*rows*4 for levels,
 * tiles*pairs*2 for hidden when batches=1):
 *   <prefix>.mag.bin        uint8
 *   <prefix>.phase.bin      uint8
 *   <prefix>.levels.bin     float32
 *   <prefix>.cos_lut.bin    9 float32
 *   <prefix>.sin_lut.bin    9 float32
 *   <prefix>.hidden.bin     float32 (size = batches * tiles * pairs * 2;
 *                                   encoder emits batches=n_tiles by default)
 *   <prefix>.expected_polar.bin  rows*tiles float32 (Python-computed reference)
 *
 * Returns 1 on success, 0 on failure. Reports max|GPU-Python_ref| difference. */
static long ds4_polar_read_file(const char *path, void *dst, size_t expected_bytes) {
    FILE *fp = fopen(path, "rb");
    if (!fp) { fprintf(stderr, "ds4: polar_tile_real: open %s failed\n", path); return -1; }
    long got = (long)fread(dst, 1, expected_bytes, fp);
    fclose(fp);
    if (got != (long)expected_bytes) {
        fprintf(stderr, "ds4: polar_tile_real: short read %s (%ld / %zu bytes)\n",
                path, got, expected_bytes);
        return -1;
    }
    return got;
}

int ds4_gpu_mtl4_polar_tile_real(const char *prefix,
                                  uint32_t tiles, uint32_t rows,
                                  uint32_t batches, uint32_t pairs) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_polar_tile_pipeline_init()) return 0;
    if (!prefix || tiles == 0 || rows == 0 || batches == 0 || pairs == 0) return 0;

    @autoreleasepool {
        NSError *err = nil;
        const NSUInteger row_packets = (NSUInteger)tiles * rows;
        const NSUInteger pair_count = row_packets * pairs;
        const NSUInteger hidden_count = (NSUInteger)batches * tiles * pairs * 2;
        const NSUInteger out_count = (NSUInteger)batches * row_packets;

        id<MTLBuffer> mag      = [g_device newBufferWithLength:pair_count                        options:MTLResourceStorageModeShared];
        id<MTLBuffer> phase    = [g_device newBufferWithLength:pair_count                        options:MTLResourceStorageModeShared];
        id<MTLBuffer> levels   = [g_device newBufferWithLength:row_packets * 4 * sizeof(float)   options:MTLResourceStorageModeShared];
        id<MTLBuffer> hidden   = [g_device newBufferWithLength:hidden_count * sizeof(float)      options:MTLResourceStorageModeShared];
        id<MTLBuffer> cosLut   = [g_device newBufferWithLength:9 * sizeof(float)                 options:MTLResourceStorageModeShared];
        id<MTLBuffer> sinLut   = [g_device newBufferWithLength:9 * sizeof(float)                 options:MTLResourceStorageModeShared];
        id<MTLBuffer> outBuf   = [g_device newBufferWithLength:out_count * sizeof(float)         options:MTLResourceStorageModeShared];
        id<MTLBuffer> paramsBuf= [g_device newBufferWithLength:3 * sizeof(uint32_t)              options:MTLResourceStorageModeShared];
        if (!mag || !phase || !levels || !hidden || !cosLut || !sinLut || !outBuf || !paramsBuf) return 0;

        char path[1024];
        snprintf(path, sizeof(path), "%s.mag.bin",   prefix); if (ds4_polar_read_file(path, mag.contents,    pair_count) < 0) return 0;
        snprintf(path, sizeof(path), "%s.phase.bin", prefix); if (ds4_polar_read_file(path, phase.contents,  pair_count) < 0) return 0;
        snprintf(path, sizeof(path), "%s.levels.bin",prefix); if (ds4_polar_read_file(path, levels.contents, row_packets * 4 * sizeof(float)) < 0) return 0;
        snprintf(path, sizeof(path), "%s.hidden.bin",prefix); if (ds4_polar_read_file(path, hidden.contents, hidden_count * sizeof(float)) < 0) return 0;
        snprintf(path, sizeof(path), "%s.cos_lut.bin", prefix); if (ds4_polar_read_file(path, cosLut.contents, 9 * sizeof(float)) < 0) return 0;
        snprintf(path, sizeof(path), "%s.sin_lut.bin", prefix); if (ds4_polar_read_file(path, sinLut.contents, 9 * sizeof(float)) < 0) return 0;

        uint32_t *params = (uint32_t *)paramsBuf.contents;
        params[0] = pairs; params[1] = rows; params[2] = tiles;

        /* Standard MTL4 dispatch — copied from the synthetic canary. */
        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) return 0;
        id<MTLAllocation> allocs[8] = {
            (id<MTLAllocation>)mag, (id<MTLAllocation>)phase,
            (id<MTLAllocation>)levels, (id<MTLAllocation>)hidden,
            (id<MTLAllocation>)cosLut, (id<MTLAllocation>)sinLut,
            (id<MTLAllocation>)outBuf, (id<MTLAllocation>)paramsBuf,
        };
        [residency addAllocations:allocs count:8];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 8;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) return 0;
        [argTable setAddress:mag.gpuAddress       atIndex:0];
        [argTable setAddress:phase.gpuAddress     atIndex:1];
        [argTable setAddress:levels.gpuAddress    atIndex:2];
        [argTable setAddress:hidden.gpuAddress    atIndex:3];
        [argTable setAddress:cosLut.gpuAddress    atIndex:4];
        [argTable setAddress:sinLut.gpuAddress    atIndex:5];
        [argTable setAddress:outBuf.gpuAddress    atIndex:6];
        [argTable setAddress:paramsBuf.gpuAddress atIndex:7];

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) return 0;
        [enc setComputePipelineState:g_polar_tile_pipeline];
        [enc setArgumentTable:argTable];
        [enc dispatchThreadgroups:MTLSizeMake(tiles, rows, batches)
            threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0, gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime; gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) { fprintf(stderr, "ds4: polar_tile_real timeout\n"); return 0; }
        if (fbErr) { fprintf(stderr, "ds4: polar_tile_real feedback err: %s\n", fbErr.localizedDescription.UTF8String); return 0; }

        /* Compare GPU output to Python reference. */
        float *expected_polar = malloc(out_count * sizeof(float));
        snprintf(path, sizeof(path), "%s.expected_polar.bin", prefix);
        if (ds4_polar_read_file(path, expected_polar, out_count * sizeof(float)) < 0) {
            free(expected_polar);
            return 0;
        }

        float *outPtr = (float *)outBuf.contents;
        float maxAbsErr = 0.0f;
        double sumAbsErr = 0.0;
        for (NSUInteger i = 0; i < out_count; i++) {
            float diff = fabsf(outPtr[i] - expected_polar[i]);
            sumAbsErr += diff;
            if (diff > maxAbsErr) maxAbsErr = diff;
        }
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        fprintf(stderr,
                "ds4: polar TILE REAL prefix=%s tiles=%u rows=%u batches=%u pairs=%u\n"
                "  GPU out[0]=%.4f  Python ref[0]=%.4f  max|diff|=%.3e  mean|diff|=%.3e\n"
                "  gpu_elapsed=%.6f ms  (%.0f ns/output, resident=%.1f MB)\n",
                prefix, tiles, rows, batches, pairs,
                (double)outPtr[0], (double)expected_polar[0],
                (double)maxAbsErr, sumAbsErr / out_count,
                gpuMs, gpuMs * 1e6 / (double)out_count,
                (double)(pair_count * 2 + row_packets * 4 * 4 + hidden_count * 4 + out_count * 4) / 1e6);
        free(expected_polar);
        return maxAbsErr < 1e-2f ? 1 : 0; /* fp32-vs-Python tolerance — codex H1729 hit 7e-9 */
    }
}

/* ============================================================ */
/* H1733 fused gate*silu*up*route_weight kernel                 */
/* ============================================================ */
/* Per codex H1733: the real DS4 MLP organ is the fused
 *   silu(gate(hidden)) * up(hidden) * route_weight
 * computed in ONE dispatch over the routed expert subset.
 *
 * b32 measured by codex: 21.28 ns/equiv row-dot (2.20× over single
 * row-dots at b32, 1.77× lower allocation), max_abs vs CPU = 7.55e-9.
 *
 * Architectural pieces:
 *   - mag/phase: ALL unique code tiles concatenated (H1731 dedup)
 *   - levels:    per-row 4-level quantile table
 *   - gate_code[route_pair]: which code tile is the gate for this route pair
 *   - up_code[route_pair]:   same, for up
 *   - route_weight[route_pair]: per-route scalar from top-k selection
 *   - hidden[batch, route_pair]: per-(batch, route_pair) input vector
 *
 * Dispatch: (route_pairs, rows, batches) × 256 threads. Each threadgroup
 * computes both gate_dot AND up_dot for one (route_pair, row, batch),
 * sharing hidden reads. The final write applies silu+mul+route_weight.
 *
 * Self-test: ds4_gpu_mtl4_polar_fused_canary(...) — synthetic input where
 * mag=0/phase=4(angle 0)/level[0]=1/hidden=1 → gate_dot = up_dot = pairs.
 * silu(pairs) ≈ pairs (for pairs > 5), so output ≈ pairs * pairs * route_weight.
 *
 * Codex source:
 *   research/llm_fallacy_deconstruction/framework_deconstruction/
 *     h1733_mtl4_gate_up_fused_packet_kernel_20260525.m
 */

static id<MTLComputePipelineState> g_polar_fused_pipeline;
static int g_polar_fused_init_attempted;
static int g_polar_fused_init_ok;

static int ds4_polar_fused_pipeline_init(void) {
    if (g_polar_fused_init_attempted) return g_polar_fused_init_ok;
    g_polar_fused_init_attempted = 1;

    if (!ds4_polar_pipeline_init()) return 0; /* shared compiler + alloc + queue */

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "kernel void gate_up_packet(device const uchar* mag [[buffer(0)]],\n"
         "                            device const uchar* phase [[buffer(1)]],\n"
         "                            device const float* levels [[buffer(2)]],\n"
         "                            device const uint* gate_code [[buffer(3)]],\n"
         "                            device const uint* up_code [[buffer(4)]],\n"
         "                            device const float* route_weight [[buffer(5)]],\n"
         "                            device const float* hidden [[buffer(6)]],\n"
         "                            device const float* cos_lut [[buffer(7)]],\n"
         "                            device const float* sin_lut [[buffer(8)]],\n"
         "                            device float* out [[buffer(9)]],\n"
         "                            device const uint* params [[buffer(10)]],\n"
         "                            uint3 tg [[threadgroup_position_in_grid]],\n"
         "                            uint tid [[thread_index_in_threadgroup]]) {\n"
         "  constexpr uint THREADS = 256;\n"
         "  threadgroup float gate_partial[THREADS];\n"
         "  threadgroup float up_partial[THREADS];\n"
         "  uint route_pair = tg.x;\n"
         "  uint row = tg.y;\n"
         "  uint batch = tg.z;\n"
         "  uint pairs = params[0];\n"
         "  uint rows = params[1];\n"
         "  uint route_pairs = params[2];\n"
         "  uint gate_row = gate_code[route_pair] * rows + row;\n"
         "  uint up_row = up_code[route_pair] * rows + row;\n"
         "  uint gate_base = gate_row * pairs;\n"
         "  uint up_base = up_row * pairs;\n"
         "  uint hbase = (batch * route_pairs + route_pair) * pairs * 2;\n"
         "  float gate_acc = 0.0f;\n"
         "  float up_acc = 0.0f;\n"
         "  for (uint j = tid; j < pairs; j += THREADS) {\n"
         "    float h0 = hidden[hbase + 2*j];\n"
         "    float h1 = hidden[hbase + 2*j + 1];\n"
         "    uchar gate_m = mag[gate_base + j];\n"
         "    uint gate_l = uint(phase[gate_base + j]);\n"
         "    float gate_q = levels[gate_row * 4 + uint(gate_m)];\n"
         "    gate_acc += gate_q * cos_lut[gate_l] * h0 + gate_q * sin_lut[gate_l] * h1;\n"
         "    uchar up_m = mag[up_base + j];\n"
         "    uint up_l = uint(phase[up_base + j]);\n"
         "    float up_q = levels[up_row * 4 + uint(up_m)];\n"
         "    up_acc += up_q * cos_lut[up_l] * h0 + up_q * sin_lut[up_l] * h1;\n"
         "  }\n"
         "  gate_partial[tid] = gate_acc;\n"
         "  up_partial[tid] = up_acc;\n"
         "  threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  for (uint stride = THREADS >> 1; stride > 0; stride >>= 1) {\n"
         "    if (tid < stride) {\n"
         "      gate_partial[tid] += gate_partial[tid + stride];\n"
         "      up_partial[tid] += up_partial[tid + stride];\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  if (tid == 0) {\n"
         "    float g = gate_partial[0];\n"
         "    float u = up_partial[0];\n"
         "    float silu = g / (1.0f + exp(-g));\n"
         "    out[(batch * route_pairs + route_pair) * rows + row] = silu * u * route_weight[route_pair];\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_polar_gate_up_fused";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: polar fused library failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"gate_up_packet";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_polar_fused_pipeline = [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                                                 compilerTaskOptions:nil
                                                                               error:&err];
    if (!g_polar_fused_pipeline) {
        fprintf(stderr, "ds4: polar fused pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    g_polar_fused_init_ok = 1;
    return 1;
}

/* Synthetic canary for the H1733 fused gate*silu*up*route_weight kernel.
 *
 * Layout: n_codes code tiles available, route_pairs pairs use them, each
 * pair picks one gate_code and one up_code, rows output rows per tile,
 * batches batches.
 *
 * Inputs are deterministic: mag=0 (code 0), phase=4 (angle 0 LUT entry),
 * level[0]=1.0, hidden=1.0, route_weight=1.0. With those:
 *   gate_dot = up_dot = pairs (since cos(0)=1, sum of pairs ones)
 *   silu(pairs) = pairs / (1 + exp(-pairs)) ≈ pairs (for pairs > 10)
 *   out = silu(pairs) * pairs * 1.0 ≈ pairs^2 - pairs*exp(-pairs)/(1+exp(-pairs))
 *
 * For pairs=2048, expected = 2048 * 2048 = 4194304 (exp(-2048) is sub-denormal).
 */
int ds4_gpu_mtl4_polar_fused_canary(uint32_t n_codes, uint32_t route_pairs,
                                     uint32_t rows, uint32_t batches, uint32_t pairs) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_polar_fused_pipeline_init()) return 0;
    if (n_codes == 0 || route_pairs == 0 || rows == 0 || batches == 0 || pairs == 0) return 0;

    @autoreleasepool {
        NSError *err = nil;
        const NSUInteger code_rows = (NSUInteger)n_codes * rows;
        const NSUInteger pair_count = code_rows * pairs;
        const NSUInteger hidden_count = (NSUInteger)batches * route_pairs * pairs * 2;
        const NSUInteger out_count = (NSUInteger)batches * route_pairs * rows;

        id<MTLBuffer> mag       = [g_device newBufferWithLength:pair_count                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> phase     = [g_device newBufferWithLength:pair_count                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> levels    = [g_device newBufferWithLength:code_rows * 4 * sizeof(float)    options:MTLResourceStorageModeShared];
        id<MTLBuffer> gateCode  = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)   options:MTLResourceStorageModeShared];
        id<MTLBuffer> upCode    = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)   options:MTLResourceStorageModeShared];
        id<MTLBuffer> routeW    = [g_device newBufferWithLength:route_pairs * sizeof(float)      options:MTLResourceStorageModeShared];
        id<MTLBuffer> hidden    = [g_device newBufferWithLength:hidden_count * sizeof(float)     options:MTLResourceStorageModeShared];
        id<MTLBuffer> cosLut    = [g_device newBufferWithLength:9 * sizeof(float)                options:MTLResourceStorageModeShared];
        id<MTLBuffer> sinLut    = [g_device newBufferWithLength:9 * sizeof(float)                options:MTLResourceStorageModeShared];
        id<MTLBuffer> outBuf    = [g_device newBufferWithLength:out_count * sizeof(float)        options:MTLResourceStorageModeShared];
        id<MTLBuffer> paramsBuf = [g_device newBufferWithLength:3 * sizeof(uint32_t)             options:MTLResourceStorageModeShared];
        if (!mag || !phase || !levels || !gateCode || !upCode || !routeW || !hidden || !cosLut || !sinLut || !outBuf || !paramsBuf) return 0;

        memset(mag.contents, 0, pair_count);
        memset(phase.contents, 4, pair_count);
        float *lvl = (float *)levels.contents;
        for (NSUInteger r = 0; r < code_rows; r++) {
            lvl[r * 4 + 0] = 1.0f; lvl[r * 4 + 1] = 0.5f;
            lvl[r * 4 + 2] = 0.25f; lvl[r * 4 + 3] = 0.125f;
        }
        uint32_t *gc = (uint32_t *)gateCode.contents;
        uint32_t *uc = (uint32_t *)upCode.contents;
        float *rw = (float *)routeW.contents;
        for (uint32_t r = 0; r < route_pairs; r++) {
            gc[r] = r % n_codes;
            uc[r] = (r + 1) % n_codes;
            rw[r] = 1.0f;
        }
        float *hid = (float *)hidden.contents;
        for (NSUInteger i = 0; i < hidden_count; i++) hid[i] = 1.0f;
        float *cosP = (float *)cosLut.contents;
        float *sinP = (float *)sinLut.contents;
        for (int code = -4; code <= 4; code++) {
            float angle = (float)code * 0.78539816339744830962f;
            cosP[code + 4] = cosf(angle);
            sinP[code + 4] = sinf(angle);
        }
        uint32_t *params = (uint32_t *)paramsBuf.contents;
        params[0] = pairs; params[1] = rows; params[2] = route_pairs;

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 11;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) return 0;
        id<MTLAllocation> allocs[11] = {
            (id<MTLAllocation>)mag, (id<MTLAllocation>)phase, (id<MTLAllocation>)levels,
            (id<MTLAllocation>)gateCode, (id<MTLAllocation>)upCode, (id<MTLAllocation>)routeW,
            (id<MTLAllocation>)hidden, (id<MTLAllocation>)cosLut, (id<MTLAllocation>)sinLut,
            (id<MTLAllocation>)outBuf, (id<MTLAllocation>)paramsBuf,
        };
        [residency addAllocations:allocs count:11];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 11;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) return 0;
        [argTable setAddress:mag.gpuAddress       atIndex:0];
        [argTable setAddress:phase.gpuAddress     atIndex:1];
        [argTable setAddress:levels.gpuAddress    atIndex:2];
        [argTable setAddress:gateCode.gpuAddress  atIndex:3];
        [argTable setAddress:upCode.gpuAddress    atIndex:4];
        [argTable setAddress:routeW.gpuAddress    atIndex:5];
        [argTable setAddress:hidden.gpuAddress    atIndex:6];
        [argTable setAddress:cosLut.gpuAddress    atIndex:7];
        [argTable setAddress:sinLut.gpuAddress    atIndex:8];
        [argTable setAddress:outBuf.gpuAddress    atIndex:9];
        [argTable setAddress:paramsBuf.gpuAddress atIndex:10];

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) return 0;
        [enc setComputePipelineState:g_polar_fused_pipeline];
        [enc setArgumentTable:argTable];
        [enc dispatchThreadgroups:MTLSizeMake(route_pairs, rows, batches)
            threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0, gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime; gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) { fprintf(stderr, "ds4: polar fused canary timeout\n"); return 0; }
        if (fbErr) { fprintf(stderr, "ds4: polar fused feedback err: %s\n", fbErr.localizedDescription.UTF8String); return 0; }

        /* Expected: gate=up=pairs, silu(pairs)≈pairs, out ≈ pairs*pairs.
         * For pairs=2048: 2048*2048 = 4194304. */
        float *outPtr = (float *)outBuf.contents;
        float expected = (float)pairs * (float)pairs; /* silu(pairs) ≈ pairs */
        /* tighter expected: silu(p) = p / (1 + exp(-p)); for p=2048 exp(-p) underflows */
        float gate = (float)pairs, silu = gate / (1.0f + expf(-gate));
        expected = silu * (float)pairs * 1.0f;
        float maxAbsErr = 0.0f;
        double sumAbsErr = 0.0;
        for (NSUInteger i = 0; i < out_count; i++) {
            float diff = fabsf(outPtr[i] - expected);
            sumAbsErr += diff;
            if (diff > maxAbsErr) maxAbsErr = diff;
        }
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        fprintf(stderr,
                "ds4: polar FUSED canary n_codes=%u route_pairs=%u rows=%u batches=%u pairs=%u\n"
                "  expected=%.3f out[0]=%.3f max_abs_err=%.3e mean_abs_err=%.3e\n"
                "  gpu_elapsed=%.6f ms (%.0f ns/output, %.0f ns/row-dot-equiv, resident=%.1f MB)\n",
                n_codes, route_pairs, rows, batches, pairs,
                (double)expected, (double)outPtr[0],
                (double)maxAbsErr, sumAbsErr / out_count,
                gpuMs,
                gpuMs * 1e6 / (double)out_count,
                gpuMs * 1e6 / (double)(out_count * 2), /* 2 dots per output */
                (double)(pair_count * 2 + code_rows * 4 * 4 + route_pairs * 4 * 2 + route_pairs * 4 + hidden_count * 4 + out_count * 4) / 1e6);
        /* Relative tolerance — output magnitudes can be huge (pairs^2) */
        float relErr = maxAbsErr / fabsf(expected);
        return relErr < 1e-3f ? 1 : 0;
    }
}

/* ============================================================ */
/* H1735 fused gate*silu*up*route_weight + down projection      */
/* ============================================================ */
/* Per codex H1735: adds down-projection on top of H1733's fused
 * gate/up packet. One threadgroup per (route_pair, batch) computes:
 *   1. For each act_row r ∈ [0, act_rows):
 *        gate_dot = polar_dot(gate_code[route_pair], r, hidden[batch,rp])
 *        up_dot   = polar_dot(up_code[route_pair],   r, hidden[batch,rp])
 *        act[r]   = silu(gate_dot) * up_dot * route_weight[route_pair]
 *   2. For tid < down_rows:
 *        out[batch, route_pair, tid] = sum_k act[k] * down[route_pair, tid, k]
 *
 * Codex measured at b8 16×8 (act_rows=16, down_rows=8): 22.31 ns/equiv
 * row-dot per H1736 tile sweep. b32 32×64 hits 21.03 ns. H1737 refuted
 * two-stage materialization; KEEP monolithic tiled fusion.
 *
 * Tile policy (from H1738 per-token measured table):
 *   b8  latency/memory  -> 8×8
 *   b8  gate-up throughput -> 16×8 (22.31 ns)
 *   b8  down/balanced -> 8×64
 *   b32 latency/memory -> 16×8
 *   b32 gate-up/down/balanced -> 32×64 (21.03 ns)
 *
 * Synthetic canary (this entry point): mag=0, phase=4, level[0]=1,
 * hidden=1, gate_code=r%n, up_code=(r+1)%n, route_weight=1,
 * down=1/act_rows. Then:
 *   gate_dot = up_dot = pairs   (cos(0)*1*pairs)
 *   silu(pairs) ≈ pairs         (pairs >> 1)
 *   act[r] = pairs² for all r
 *   out[i] = sum_r act[r] * (1/act_rows) = pairs² * act_rows/act_rows = pairs²
 *
 * So expected output is identical to the fused canary: pairs². Same
 * 1e-3 relative tolerance.
 *
 * Codex source:
 *   research/llm_fallacy_deconstruction/framework_deconstruction/
 *     h1735_mtl4_gate_up_down_partial_kernel_20260525.m  (kernel + dispatch)
 *     h1735_ds4_mtl4_gate_up_down_partial_harness_20260525.py (real data harness)
 */

static id<MTLComputePipelineState> g_polar_gud_pipeline;
static int g_polar_gud_init_attempted;
static int g_polar_gud_init_ok;

static int ds4_polar_gud_pipeline_init(void) {
    if (g_polar_gud_init_attempted) return g_polar_gud_init_ok;
    g_polar_gud_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0; /* shared compiler + allocator + queue */

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "kernel void gate_up_down_partial(device const uchar* mag [[buffer(0)]],\n"
         "                                  device const uchar* phase [[buffer(1)]],\n"
         "                                  device const float* levels [[buffer(2)]],\n"
         "                                  device const uint* gate_code [[buffer(3)]],\n"
         "                                  device const uint* up_code [[buffer(4)]],\n"
         "                                  device const float* route_weight [[buffer(5)]],\n"
         "                                  device const float* hidden [[buffer(6)]],\n"
         "                                  device const float* down [[buffer(7)]],\n"
         "                                  device const float* cos_lut [[buffer(8)]],\n"
         "                                  device const float* sin_lut [[buffer(9)]],\n"
         "                                  device float* out [[buffer(10)]],\n"
         "                                  device const uint* params [[buffer(11)]],\n"
         "                                  uint2 tg [[threadgroup_position_in_grid]],\n"
         "                                  uint tid [[thread_index_in_threadgroup]]) {\n"
         "  constexpr uint THREADS = 256;\n"
         "  constexpr uint MAX_ACT = 64;\n"
         "  threadgroup float gate_partial[THREADS];\n"
         "  threadgroup float up_partial[THREADS];\n"
         "  threadgroup float act[MAX_ACT];\n"
         "  uint route_pair = tg.x;\n"
         "  uint batch = tg.y;\n"
         "  uint pairs = params[0];\n"
         "  uint rows = params[1];\n"
         "  uint route_pairs = params[2];\n"
         "  uint down_rows = params[3];\n"
         "  uint act_rows = params[4];\n"
         "  uint mag_levels = params[5];\n"  /* H1735+m8: parameterized magnitude codebook size */
         "  uint hbase = (batch * route_pairs + route_pair) * pairs * 2;\n"
         "  for (uint row = 0; row < act_rows; row++) {\n"
         "    uint gate_row = gate_code[route_pair] * rows + row;\n"
         "    uint up_row = up_code[route_pair] * rows + row;\n"
         "    uint gate_base = gate_row * pairs;\n"
         "    uint up_base = up_row * pairs;\n"
         "    float gate_acc = 0.0f;\n"
         "    float up_acc = 0.0f;\n"
         "    for (uint j = tid; j < pairs; j += THREADS) {\n"
         "      float h0 = hidden[hbase + 2*j];\n"
         "      float h1 = hidden[hbase + 2*j + 1];\n"
         "      uchar gate_m = mag[gate_base + j];\n"
         "      uint gate_l = uint(phase[gate_base + j]);\n"
         "      float gate_q = levels[gate_row * mag_levels + uint(gate_m)];\n"
         "      gate_acc += gate_q * cos_lut[gate_l] * h0 + gate_q * sin_lut[gate_l] * h1;\n"
         "      uchar up_m = mag[up_base + j];\n"
         "      uint up_l = uint(phase[up_base + j]);\n"
         "      float up_q = levels[up_row * mag_levels + uint(up_m)];\n"
         "      up_acc += up_q * cos_lut[up_l] * h0 + up_q * sin_lut[up_l] * h1;\n"
         "    }\n"
         "    gate_partial[tid] = gate_acc;\n"
         "    up_partial[tid] = up_acc;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    for (uint stride = THREADS >> 1; stride > 0; stride >>= 1) {\n"
         "      if (tid < stride) {\n"
         "        gate_partial[tid] += gate_partial[tid + stride];\n"
         "        up_partial[tid] += up_partial[tid + stride];\n"
         "      }\n"
         "      threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    }\n"
         "    if (tid == 0) {\n"
         "      float g = gate_partial[0];\n"
         "      float u = up_partial[0];\n"
         "      act[row] = (g / (1.0f + exp(-g))) * u * route_weight[route_pair];\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  if (tid < down_rows) {\n"
         "    float acc = 0.0f;\n"
         "    uint down_base = (route_pair * down_rows + tid) * act_rows;\n"
         "    for (uint k = 0; k < act_rows; k++) acc += act[k] * down[down_base + k];\n"
         "    out[(batch * route_pairs + route_pair) * down_rows + tid] = acc;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_polar_gate_up_down";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: polar gud library failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"gate_up_down_partial";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_polar_gud_pipeline = [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                                                compilerTaskOptions:nil
                                                                              error:&err];
    if (!g_polar_gud_pipeline) {
        fprintf(stderr, "ds4: polar gud pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    g_polar_gud_init_ok = 1;
    return 1;
}

int ds4_gpu_mtl4_polar_gate_up_down_canary(uint32_t n_codes, uint32_t route_pairs,
                                            uint32_t rows, uint32_t batches, uint32_t pairs,
                                            uint32_t down_rows, uint32_t act_rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_polar_gud_pipeline_init()) return 0;
    if (n_codes == 0 || route_pairs == 0 || rows == 0 || batches == 0 ||
        pairs == 0 || down_rows == 0 || act_rows == 0) return 0;
    if (act_rows > 64) {
        fprintf(stderr, "ds4: polar gud canary act_rows=%u exceeds MAX_ACT=64\n", act_rows);
        return 0;
    }
    if (act_rows > rows) {
        fprintf(stderr, "ds4: polar gud canary act_rows=%u > rows=%u (must fit per-tile)\n", act_rows, rows);
        return 0;
    }
    if (down_rows > 256) {
        fprintf(stderr, "ds4: polar gud canary down_rows=%u exceeds THREADS=256\n", down_rows);
        return 0;
    }

    @autoreleasepool {
        NSError *err = nil;
        const NSUInteger code_rows = (NSUInteger)n_codes * rows;
        const NSUInteger pair_count = code_rows * pairs;
        const NSUInteger hidden_count = (NSUInteger)batches * route_pairs * pairs * 2;
        const NSUInteger down_count = (NSUInteger)route_pairs * down_rows * act_rows;
        const NSUInteger out_count = (NSUInteger)batches * route_pairs * down_rows;

        id<MTLBuffer> mag       = [g_device newBufferWithLength:pair_count                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> phase     = [g_device newBufferWithLength:pair_count                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> levels    = [g_device newBufferWithLength:code_rows * 4 * sizeof(float)    options:MTLResourceStorageModeShared];
        id<MTLBuffer> gateCode  = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)   options:MTLResourceStorageModeShared];
        id<MTLBuffer> upCode    = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)   options:MTLResourceStorageModeShared];
        id<MTLBuffer> routeW    = [g_device newBufferWithLength:route_pairs * sizeof(float)      options:MTLResourceStorageModeShared];
        id<MTLBuffer> hidden    = [g_device newBufferWithLength:hidden_count * sizeof(float)     options:MTLResourceStorageModeShared];
        id<MTLBuffer> downBuf   = [g_device newBufferWithLength:down_count * sizeof(float)       options:MTLResourceStorageModeShared];
        id<MTLBuffer> cosLut    = [g_device newBufferWithLength:9 * sizeof(float)                options:MTLResourceStorageModeShared];
        id<MTLBuffer> sinLut    = [g_device newBufferWithLength:9 * sizeof(float)                options:MTLResourceStorageModeShared];
        id<MTLBuffer> outBuf    = [g_device newBufferWithLength:out_count * sizeof(float)        options:MTLResourceStorageModeShared];
        id<MTLBuffer> paramsBuf = [g_device newBufferWithLength:6 * sizeof(uint32_t)             options:MTLResourceStorageModeShared];
        if (!mag || !phase || !levels || !gateCode || !upCode || !routeW || !hidden ||
            !downBuf || !cosLut || !sinLut || !outBuf || !paramsBuf) return 0;

        memset(mag.contents, 0, pair_count);
        memset(phase.contents, 4, pair_count);
        float *lvl = (float *)levels.contents;
        for (NSUInteger r = 0; r < code_rows; r++) {
            lvl[r * 4 + 0] = 1.0f; lvl[r * 4 + 1] = 0.5f;
            lvl[r * 4 + 2] = 0.25f; lvl[r * 4 + 3] = 0.125f;
        }
        uint32_t *gc = (uint32_t *)gateCode.contents;
        uint32_t *uc = (uint32_t *)upCode.contents;
        float *rw = (float *)routeW.contents;
        for (uint32_t r = 0; r < route_pairs; r++) {
            gc[r] = r % n_codes;
            uc[r] = (r + 1) % n_codes;
            rw[r] = 1.0f;
        }
        float *hid = (float *)hidden.contents;
        for (NSUInteger i = 0; i < hidden_count; i++) hid[i] = 1.0f;
        /* down = 1.0 / act_rows uniformly. Sum of act_rows terms × pairs² × (1/act_rows) = pairs². */
        float *dwn = (float *)downBuf.contents;
        const float down_val = 1.0f / (float)act_rows;
        for (NSUInteger i = 0; i < down_count; i++) dwn[i] = down_val;
        float *cosP = (float *)cosLut.contents;
        float *sinP = (float *)sinLut.contents;
        for (int code = -4; code <= 4; code++) {
            float angle = (float)code * 0.78539816339744830962f;
            cosP[code + 4] = cosf(angle);
            sinP[code + 4] = sinf(angle);
        }
        uint32_t *params = (uint32_t *)paramsBuf.contents;
        params[0] = pairs; params[1] = rows; params[2] = route_pairs;
        params[3] = down_rows; params[4] = act_rows;
        params[5] = 4;  /* synthetic canary uses m4 codebook */

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 12;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) return 0;
        id<MTLAllocation> allocs[12] = {
            (id<MTLAllocation>)mag, (id<MTLAllocation>)phase, (id<MTLAllocation>)levels,
            (id<MTLAllocation>)gateCode, (id<MTLAllocation>)upCode, (id<MTLAllocation>)routeW,
            (id<MTLAllocation>)hidden, (id<MTLAllocation>)downBuf,
            (id<MTLAllocation>)cosLut, (id<MTLAllocation>)sinLut,
            (id<MTLAllocation>)outBuf, (id<MTLAllocation>)paramsBuf,
        };
        [residency addAllocations:allocs count:12];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 12;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) return 0;
        [argTable setAddress:mag.gpuAddress       atIndex:0];
        [argTable setAddress:phase.gpuAddress     atIndex:1];
        [argTable setAddress:levels.gpuAddress    atIndex:2];
        [argTable setAddress:gateCode.gpuAddress  atIndex:3];
        [argTable setAddress:upCode.gpuAddress    atIndex:4];
        [argTable setAddress:routeW.gpuAddress    atIndex:5];
        [argTable setAddress:hidden.gpuAddress    atIndex:6];
        [argTable setAddress:downBuf.gpuAddress   atIndex:7];
        [argTable setAddress:cosLut.gpuAddress    atIndex:8];
        [argTable setAddress:sinLut.gpuAddress    atIndex:9];
        [argTable setAddress:outBuf.gpuAddress    atIndex:10];
        [argTable setAddress:paramsBuf.gpuAddress atIndex:11];

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) return 0;
        [enc setComputePipelineState:g_polar_gud_pipeline];
        [enc setArgumentTable:argTable];
        /* H1735 grid: 2D (route_pairs, batches) — NOT 3D like H1733. */
        [enc dispatchThreadgroups:MTLSizeMake(route_pairs, batches, 1)
            threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0, gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime; gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) { fprintf(stderr, "ds4: polar gud canary timeout\n"); return 0; }
        if (fbErr) { fprintf(stderr, "ds4: polar gud feedback err: %s\n", fbErr.localizedDescription.UTF8String); return 0; }

        /* Expected: gate=up=pairs, silu(pairs)≈pairs, act=pairs², down=1/act_rows uniform,
         * out = sum_k act × down = act_rows × pairs² × (1/act_rows) = pairs². */
        float *outPtr = (float *)outBuf.contents;
        const float gate = (float)pairs;
        const float silu = gate / (1.0f + expf(-gate));
        const float act = silu * (float)pairs * 1.0f;
        const float expected = act; /* sum_k act × (1/act_rows) × act_rows = act = pairs² */
        float maxAbsErr = 0.0f;
        double sumAbsErr = 0.0;
        for (NSUInteger i = 0; i < out_count; i++) {
            float diff = fabsf(outPtr[i] - expected);
            sumAbsErr += diff;
            if (diff > maxAbsErr) maxAbsErr = diff;
        }
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        /* gate-up equivalent row-dot count: 2 × act_rows per (batch, route_pair).
         * down equivalent: act_rows MACs per output, down_rows outputs per (batch, route_pair). */
        const NSUInteger gate_up_dots = (NSUInteger)batches * route_pairs * act_rows * 2;
        const double bytes = (double)(pair_count * 2 + code_rows * 4 * 4 +
                                       route_pairs * (4 * 2 + 4) +
                                       hidden_count * 4 + down_count * 4 +
                                       out_count * 4);
        fprintf(stderr,
                "ds4: polar GUD canary n_codes=%u route_pairs=%u rows=%u batches=%u pairs=%u down_rows=%u act_rows=%u\n"
                "  expected=%.3f out[0]=%.3f max_abs_err=%.3e mean_abs_err=%.3e\n"
                "  gpu_elapsed=%.6f ms (%.1f ns/output, %.1f ns/equiv-gate-up-row-dot, resident=%.1f MB)\n",
                n_codes, route_pairs, rows, batches, pairs, down_rows, act_rows,
                (double)expected, (double)outPtr[0],
                (double)maxAbsErr, sumAbsErr / out_count,
                gpuMs,
                gpuMs * 1e6 / (double)out_count,
                gpuMs * 1e6 / (double)gate_up_dots,
                bytes / 1e6);
        float relErr = maxAbsErr / fabsf(expected);
        return relErr < 1e-3f ? 1 : 0;
    }
}

/* ============================================================ */
/* #563 Phase B-2.2 real-data H1735 canary                       */
/* ============================================================ */
/* Bridges the PLR2 polar file format to the H1735 GPU kernel. Loads real
 * DS4 V4 expert weights from a directory of L{LL}_{kind}.polar files,
 * copies expert <expert>'s rows into MTL buffers, dispatches the kernel
 * with synthetic hidden=1, route_weight=1, down=1/act_rows, and compares
 * the GPU output to a CPU reference derived from ds4_polar_decode_pair_re/im.
 *
 * Verifies that the PLR2 byte format matches what the kernel reads. If byte
 * alignment, stride arithmetic, or LUT indexing diverged between encoder
 * (polar_encode_mlx.py) and decoder (H1735 MSL kernel), this canary catches
 * it BEFORE we touch the inference hot path in Phase B-2.3.
 *
 * Output cross-check: with hidden=h0=h1=1 the kernel's per-pair accumulator
 * is `qmag*cos*1 + qmag*sin*1 = re_decoded + im_decoded`. Summing over all
 * pairs of one row gives the dot product the kernel computes. We do this on
 * CPU for the FIRST `act_rows` of the FIRST expert in the pool's code slot,
 * apply silu, multiply, sum × (1/act_rows). Expected = act = silu(dot)*dot. */
int ds4_gpu_mtl4_polar_real_canary(const char *polar_dir,
                                    uint32_t layer, uint32_t expert,
                                    uint32_t down_rows, uint32_t act_rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_polar_gud_pipeline_init()) return 0;
    if (!polar_dir || !polar_dir[0]) return 0;
    if (down_rows == 0 || act_rows == 0 || down_rows > 256 || act_rows > 64) return 0;

    ds4_polar_pool pool;
    ds4_polar_pool_init(&pool);
    uint32_t opened = ds4_polar_pool_load_dir(&pool, polar_dir);
    if (opened == 0) {
        fprintf(stderr, "ds4: polar real canary — no PLR2 files in %s\n", polar_dir);
        ds4_polar_pool_close(&pool);
        return 0;
    }

    const ds4_polar_file *gate_file = ds4_polar_pool_get(&pool, layer, DS4_POLAR_KIND_GATE);
    const ds4_polar_file *up_file   = ds4_polar_pool_get(&pool, layer, DS4_POLAR_KIND_UP);
    if (!gate_file || !up_file) {
        fprintf(stderr, "ds4: polar real canary — layer %u missing gate/up in pool\n", layer);
        ds4_polar_pool_close(&pool);
        return 0;
    }
    if (expert >= gate_file->n_experts || expert >= up_file->n_experts) {
        fprintf(stderr, "ds4: polar real canary — expert %u OOR (gate/up have %u experts)\n",
                expert, gate_file->n_experts);
        ds4_polar_pool_close(&pool);
        return 0;
    }
    if (act_rows > gate_file->n_rows || act_rows > up_file->n_rows) {
        fprintf(stderr, "ds4: polar real canary — act_rows %u > available rows %u\n",
                act_rows, gate_file->n_rows);
        ds4_polar_pool_close(&pool);
        return 0;
    }

    /* Phase B-2.3a (D1 path): optionally validate polar-DOWN → fp32 → H1735
     * end-to-end on real DS4 V4 weights. Gated by env var DS4_POLAR_REAL_DOWN=1
     * so the original synthetic-uniform-down test path is preserved by default.
     *
     * Polar-down storage: row d ∈ [0, n_rows) carries n_pairs complex pairs
     * encoding (re_0, im_0, re_1, im_1, …, re_{n_pairs-1}, im_{n_pairs-1}) →
     * 2 × n_pairs real values per row. We need down_rows × act_rows reals
     * here, so require down_rows ≤ down_file->n_rows AND act_rows ≤ 2 × n_pairs. */
    const char *env_polar_real_down = getenv("DS4_POLAR_REAL_DOWN");
    const int use_polar_down = (env_polar_real_down && env_polar_real_down[0] == '1') ? 1 : 0;
    const ds4_polar_file *down_file = NULL;
    if (use_polar_down) {
        down_file = ds4_polar_pool_get(&pool, layer, DS4_POLAR_KIND_DOWN);
        if (!down_file) {
            fprintf(stderr, "ds4: polar real canary — DS4_POLAR_REAL_DOWN=1 but no down PLR2 for layer %u; falling back to synthetic\n",
                    layer);
        } else if (expert >= down_file->n_experts) {
            fprintf(stderr, "ds4: polar real canary — down expert %u OOR (down has %u experts); falling back to synthetic\n",
                    expert, down_file->n_experts);
            down_file = NULL;
        } else if (down_rows > down_file->n_rows) {
            fprintf(stderr, "ds4: polar real canary — down_rows %u > down n_rows %u; falling back to synthetic\n",
                    down_rows, down_file->n_rows);
            down_file = NULL;
        } else if (act_rows > down_file->n_pairs * 2u) {
            fprintf(stderr, "ds4: polar real canary — act_rows %u > down 2×n_pairs %u; falling back to synthetic\n",
                    act_rows, down_file->n_pairs * 2u);
            down_file = NULL;
        }
    }

    const uint32_t rows   = gate_file->n_rows;
    const uint32_t pairs  = gate_file->n_pairs;
    const uint32_t n_codes = 1;        /* single tile pool: just this expert */
    const uint32_t route_pairs = 1;    /* single route */
    const uint32_t batches = 1;

    @autoreleasepool {
        NSError *err = nil;
        const NSUInteger code_rows = (NSUInteger)n_codes * rows;
        const NSUInteger pair_count = code_rows * pairs;
        const NSUInteger hidden_count = (NSUInteger)batches * route_pairs * pairs * 2;
        const NSUInteger down_count = (NSUInteger)route_pairs * down_rows * act_rows;
        const NSUInteger out_count = (NSUInteger)batches * route_pairs * down_rows;

        /* LUT sizes depend on file's phase_levels (legacy=8 → 9 entries; new
         * p16 → 17 entries; ... up to p+1). H1735 kernel reads
         * cos_lut[phase_code] where phase_code ∈ [0, phase_levels], so
         * buffer must be at least (phase_levels + 1) floats. */
        const uint32_t phase_levels = gate_file->phase_levels;
        const uint32_t mag_levels   = gate_file->mag_levels;
        const NSUInteger lut_entries = (NSUInteger)phase_levels + 1u;
        const NSUInteger levels_bytes_per_expert = (NSUInteger)rows * mag_levels * sizeof(float);

        id<MTLBuffer> mag       = [g_device newBufferWithLength:pair_count                                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> phase     = [g_device newBufferWithLength:pair_count                                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> levels    = [g_device newBufferWithLength:code_rows * mag_levels * sizeof(float)           options:MTLResourceStorageModeShared];
        id<MTLBuffer> gateCode  = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> upCode    = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> routeW    = [g_device newBufferWithLength:route_pairs * sizeof(float)                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> hidden    = [g_device newBufferWithLength:hidden_count * sizeof(float)                     options:MTLResourceStorageModeShared];
        id<MTLBuffer> downBuf   = [g_device newBufferWithLength:down_count * sizeof(float)                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> cosLut    = [g_device newBufferWithLength:lut_entries * sizeof(float)                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> sinLut    = [g_device newBufferWithLength:lut_entries * sizeof(float)                      options:MTLResourceStorageModeShared];
        id<MTLBuffer> outBuf    = [g_device newBufferWithLength:out_count * sizeof(float)                        options:MTLResourceStorageModeShared];
        id<MTLBuffer> paramsBuf = [g_device newBufferWithLength:6 * sizeof(uint32_t)                             options:MTLResourceStorageModeShared];
        if (!mag || !phase || !levels || !gateCode || !upCode || !routeW || !hidden ||
            !downBuf || !cosLut || !sinLut || !outBuf || !paramsBuf) {
            ds4_polar_pool_close(&pool); return 0;
        }

        /* H1735+m8: levels buffer now sized from mag_levels (was hardcoded 4).
         * Any mag_levels ∈ {1..32} works; m4 = legacy, m8 = OOM-accuracy
         * candidate per codec_pareto_frontier.md. */

        /* Copy expert's real polar data from PLR2 (mmap-resident in pool).
         * For this canary, we use the SAME expert for gate AND up to keep
         * the CPU reference computation trivial. */
        const uint8_t *gate_mag_src = NULL;
        const uint8_t *gate_phase_src = NULL;
        const float   *gate_levels_src = NULL;
        ds4_polar_expert_view(gate_file, expert, &gate_mag_src, &gate_phase_src, &gate_levels_src);
        memcpy(mag.contents,    gate_mag_src,    (NSUInteger)rows * pairs);
        memcpy(phase.contents,  gate_phase_src,  (NSUInteger)rows * pairs);
        memcpy(levels.contents, gate_levels_src, levels_bytes_per_expert);

        /* Route metadata: single route_pair points at code tile 0 (our copied expert). */
        ((uint32_t *)gateCode.contents)[0] = 0;
        ((uint32_t *)upCode.contents)[0]   = 0;
        ((float    *)routeW.contents)[0]   = 1.0f;
        float *hid = (float *)hidden.contents;
        for (NSUInteger i = 0; i < hidden_count; i++) hid[i] = 1.0f;
        float *dwn = (float *)downBuf.contents;
        if (down_file) {
            /* Polar-down: decode first (down_rows × act_rows) reals into the
             * down buffer. Layout matches the H1735 kernel expectation
             * `down[route_pair, d, a]` flattened as
             * `dwn[((route_pair * down_rows) + d) * act_rows + a]`.
             * route_pairs == 1 here, so offset = d * act_rows + a.
             *
             * Polar storage: each pair at index k gives (re, im) → reals at
             * a = 2*k AND a = 2*k+1. For odd act_rows the last real comes
             * from re of pair k=act_rows/2. */
            for (uint32_t d = 0; d < down_rows; d++) {
                for (uint32_t a = 0; a < act_rows; a += 2) {
                    const uint32_t k = a >> 1;
                    const float re = ds4_polar_decode_pair_re(down_file, expert, d, k);
                    dwn[(NSUInteger)d * act_rows + a] = re;
                    if ((a + 1) < act_rows) {
                        const float im = ds4_polar_decode_pair_im(down_file, expert, d, k);
                        dwn[(NSUInteger)d * act_rows + a + 1] = im;
                    }
                }
            }
        } else {
            const float down_val = 1.0f / (float)act_rows;
            for (NSUInteger i = 0; i < down_count; i++) dwn[i] = down_val;
        }
        float *cosP = (float *)cosLut.contents;
        float *sinP = (float *)sinLut.contents;
        /* Populate LUT for phase_codes ∈ [0, phase_levels]:
         * decoded angle for code c is (c - phase_levels/2) × 2π/phase_levels. */
        const double phase_step_d = (2.0 * M_PI) / (double)phase_levels;
        const int half_P = (int)(phase_levels / 2u);
        for (NSUInteger c = 0; c < lut_entries; c++) {
            double angle = ((double)c - (double)half_P) * phase_step_d;
            cosP[c] = (float)cos(angle);
            sinP[c] = (float)sin(angle);
        }
        (void)0;  /* satisfy old loop tail; replaced by parameterized loop above */
        if (0) for (int code = -4; code <= 4; code++) {
            float angle = (float)code * 0.78539816339744830962f;
            cosP[code + 4] = cosf(angle);
            sinP[code + 4] = sinf(angle);
        }
        uint32_t *params = (uint32_t *)paramsBuf.contents;
        params[0] = pairs; params[1] = rows; params[2] = route_pairs;
        params[3] = down_rows; params[4] = act_rows;
        params[5] = mag_levels;  /* H1735+m8: dynamic magnitude codebook size */

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 12;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) { ds4_polar_pool_close(&pool); return 0; }
        id<MTLAllocation> allocs[12] = {
            (id<MTLAllocation>)mag, (id<MTLAllocation>)phase, (id<MTLAllocation>)levels,
            (id<MTLAllocation>)gateCode, (id<MTLAllocation>)upCode, (id<MTLAllocation>)routeW,
            (id<MTLAllocation>)hidden, (id<MTLAllocation>)downBuf,
            (id<MTLAllocation>)cosLut, (id<MTLAllocation>)sinLut,
            (id<MTLAllocation>)outBuf, (id<MTLAllocation>)paramsBuf,
        };
        [residency addAllocations:allocs count:12];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 12;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) { ds4_polar_pool_close(&pool); return 0; }
        [argTable setAddress:mag.gpuAddress       atIndex:0];
        [argTable setAddress:phase.gpuAddress     atIndex:1];
        [argTable setAddress:levels.gpuAddress    atIndex:2];
        [argTable setAddress:gateCode.gpuAddress  atIndex:3];
        [argTable setAddress:upCode.gpuAddress    atIndex:4];
        [argTable setAddress:routeW.gpuAddress    atIndex:5];
        [argTable setAddress:hidden.gpuAddress    atIndex:6];
        [argTable setAddress:downBuf.gpuAddress   atIndex:7];
        [argTable setAddress:cosLut.gpuAddress    atIndex:8];
        [argTable setAddress:sinLut.gpuAddress    atIndex:9];
        [argTable setAddress:outBuf.gpuAddress    atIndex:10];
        [argTable setAddress:paramsBuf.gpuAddress atIndex:11];

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) { ds4_polar_pool_close(&pool); return 0; }
        [enc setComputePipelineState:g_polar_gud_pipeline];
        [enc setArgumentTable:argTable];
        [enc dispatchThreadgroups:MTLSizeMake(route_pairs, batches, 1)
            threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0, gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime; gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) { fprintf(stderr, "ds4: polar real canary timeout\n"); ds4_polar_pool_close(&pool); return 0; }
        if (fbErr) { fprintf(stderr, "ds4: polar real canary feedback err: %s\n", fbErr.localizedDescription.UTF8String); ds4_polar_pool_close(&pool); return 0; }

        /* CPU reference computation. For each row r ∈ [0, act_rows):
         *   gate_dot[r] = sum over p ∈ [0, pairs): re_decoded(r,p) + im_decoded(r,p)
         * (same as up_dot since we copied gate into up's slot for this canary).
         * act[r] = silu(gate_dot) * up_dot * 1.0
         *
         * If down is synthetic-uniform (down_file==NULL):
         *   out[d] = sum_r act[r] * (1/act_rows)  → identical across d
         * If down is polar (down_file!=NULL):
         *   out[d] = sum_r act[r] * dwn[d * act_rows + r]  → per-d differentiated */
        float gate_dot_sum_rows[64] = {0};  /* MAX_ACT = 64 */
        for (uint32_t r = 0; r < act_rows; r++) {
            double sum_re_im = 0.0;
            for (uint32_t p = 0; p < pairs; p++) {
                sum_re_im += (double)ds4_polar_decode_pair_re(gate_file, expert, r, p);
                sum_re_im += (double)ds4_polar_decode_pair_im(gate_file, expert, r, p);
            }
            gate_dot_sum_rows[r] = (float)sum_re_im;
        }
        float act_per_row[64] = {0};  /* MAX_ACT = 64 */
        double act_sum = 0.0;
        for (uint32_t r = 0; r < act_rows; r++) {
            const float g = gate_dot_sum_rows[r];
            const float silu = g / (1.0f + expf(-g));
            const float a = silu * g * 1.0f;
            act_per_row[r] = a;
            act_sum += (double)a;
        }

        float *outPtr = (float *)outBuf.contents;
        float maxAbsErr = 0.0f;
        float refMagMax = 0.0f;  /* max |expected[d]| for rel-err denominator */
        float expected0 = 0.0f;
        if (down_file) {
            /* polar-down: per-d expected via real dwn values */
            for (uint32_t d = 0; d < down_rows; d++) {
                double od = 0.0;
                for (uint32_t r = 0; r < act_rows; r++) {
                    od += (double)act_per_row[r] * (double)dwn[(NSUInteger)d * act_rows + r];
                }
                const float exp_d = (float)od;
                if (d == 0) expected0 = exp_d;
                if (fabsf(exp_d) > refMagMax) refMagMax = fabsf(exp_d);
                const float diff = fabsf(outPtr[d] - exp_d);
                if (diff > maxAbsErr) maxAbsErr = diff;
            }
        } else {
            /* synthetic-uniform down: per-d expected is the same value act_sum/act_rows */
            expected0 = (float)(act_sum / (double)act_rows);
            refMagMax = fabsf(expected0);
            for (NSUInteger i = 0; i < out_count; i++) {
                float diff = fabsf(outPtr[i] - expected0);
                if (diff > maxAbsErr) maxAbsErr = diff;
            }
        }
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        const float relErr = refMagMax > 1e-6f ? maxAbsErr / refMagMax : maxAbsErr;
        fprintf(stderr,
                "ds4: polar REAL canary layer=%u expert=%u rows=%u pairs=%u down_rows=%u act_rows=%u\n"
                "  down_src=%s CPU expected[0]=%.4f GPU out[0]=%.4f max_abs_err=%.4e rel_err=%.4e\n"
                "  gpu_elapsed=%.4f ms  resident=%.1f MB\n",
                layer, expert, rows, pairs, down_rows, act_rows,
                down_file ? "polar" : "uniform",
                (double)expected0, (double)outPtr[0],
                (double)maxAbsErr, (double)relErr,
                gpuMs,
                (double)(pair_count * 2 + code_rows * 16 + hidden_count * 4 + down_count * 4) / 1e6);
        ds4_polar_pool_close(&pool);
        /* Threshold: synthetic-uniform tightly bit-equivalent (1e-3); polar-down
         * carries codec noise (rel_L2 ~0.20 expected per-row, ~0.05 per
         * output via the sum-projection averaging). Accept rel_err < 0.10 for
         * polar-down — well within codec quality envelope. */
        const float accept = down_file ? 0.10f : 1e-3f;
        return relErr < accept ? 1 : 0;
    }
}

/* ============================================================ */
/* VQ-2D: fused gate*silu*up*route_weight + down projection     */
/* ============================================================ */
/* Per the VQ-2D codec exploration (commit cf39af8 + breakthrough memo):
 * VQ K=256 with per-(layer, kind) codebook gives rel_L2 0.022 / cos_sim
 * 0.9998 — 6.15× lower codec error than polar p32_m8 at half storage.
 *
 * Kernel structure mirrors H1735 polar gate_up_down kernel but:
 *   - Single uint8 code per pair (no separate mag/phase bytes)
 *   - K-entry codebook lookup → (re, im) directly (no trig LUT, no
 *     levels indirection)
 *   - Same threadgroup / partial-sum / down-projection structure
 *
 * Canary uses single shared codebook for gate AND up (canary
 * simplification matching polar real_canary's gate==up convention).
 * Real deployment uses separate codebooks per (layer, kind) tile.
 *
 * Input layout (VQB1 file mmap'd by ds4_vqb1_reader):
 *   gate_codes: [n_experts][n_rows][n_pairs] uint8
 *   codebook:   [K][2] fp32 (re, im pairs)
 */
#include "ds4_vqb1_reader.h"

static id<MTLComputePipelineState> g_vq_gud_pipeline;
static int g_vq_gud_init_attempted;
static int g_vq_gud_init_ok;

static int ds4_vq_gud_pipeline_init(void) {
    if (g_vq_gud_init_attempted) return g_vq_gud_init_ok;
    g_vq_gud_init_attempted = 1;
    if (!ds4_polar_pipeline_init()) return 0; /* shared compiler + queue */

    NSError *err = nil;
    NSString *source =
        @"#include <metal_stdlib>\n"
         "using namespace metal;\n"
         "kernel void vq_gate_up_down(device const uchar* gate_codes [[buffer(0)]],\n"
         "                            device const uchar* up_codes [[buffer(1)]],\n"
         "                            device const float* codebook [[buffer(2)]],\n"
         "                            device const uint* gate_code [[buffer(3)]],\n"
         "                            device const uint* up_code [[buffer(4)]],\n"
         "                            device const float* route_weight [[buffer(5)]],\n"
         "                            device const float* hidden [[buffer(6)]],\n"
         "                            device const float* down [[buffer(7)]],\n"
         "                            device float* out [[buffer(8)]],\n"
         "                            device const uint* params [[buffer(9)]],\n"
         "                            uint2 tg [[threadgroup_position_in_grid]],\n"
         "                            uint tid [[thread_index_in_threadgroup]]) {\n"
         "  constexpr uint THREADS = 256;\n"
         "  constexpr uint MAX_ACT = 64;\n"
         "  threadgroup float gate_partial[THREADS];\n"
         "  threadgroup float up_partial[THREADS];\n"
         "  threadgroup float act[MAX_ACT];\n"
         "  uint route_pair = tg.x;\n"
         "  uint batch = tg.y;\n"
         "  uint pairs = params[0];\n"
         "  uint rows = params[1];\n"
         "  uint route_pairs = params[2];\n"
         "  uint down_rows = params[3];\n"
         "  uint act_rows = params[4];\n"
         "  uint hbase = (batch * route_pairs + route_pair) * pairs * 2;\n"
         "  for (uint row = 0; row < act_rows; row++) {\n"
         "    uint gate_row = gate_code[route_pair] * rows + row;\n"
         "    uint up_row = up_code[route_pair] * rows + row;\n"
         "    uint gate_base = gate_row * pairs;\n"
         "    uint up_base = up_row * pairs;\n"
         "    float gate_acc = 0.0f;\n"
         "    float up_acc = 0.0f;\n"
         "    for (uint j = tid; j < pairs; j += THREADS) {\n"
         "      float h0 = hidden[hbase + 2*j];\n"
         "      float h1 = hidden[hbase + 2*j + 1];\n"
         "      uchar gate_c = gate_codes[gate_base + j];\n"
         "      float gate_re = codebook[gate_c * 2];\n"
         "      float gate_im = codebook[gate_c * 2 + 1];\n"
         "      gate_acc += gate_re * h0 + gate_im * h1;\n"
         "      uchar up_c = up_codes[up_base + j];\n"
         "      float up_re = codebook[up_c * 2];\n"
         "      float up_im = codebook[up_c * 2 + 1];\n"
         "      up_acc += up_re * h0 + up_im * h1;\n"
         "    }\n"
         "    gate_partial[tid] = gate_acc;\n"
         "    up_partial[tid] = up_acc;\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    for (uint stride = THREADS >> 1; stride > 0; stride >>= 1) {\n"
         "      if (tid < stride) {\n"
         "        gate_partial[tid] += gate_partial[tid + stride];\n"
         "        up_partial[tid] += up_partial[tid + stride];\n"
         "      }\n"
         "      threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "    }\n"
         "    if (tid == 0) {\n"
         "      float g = gate_partial[0];\n"
         "      float u = up_partial[0];\n"
         "      act[row] = (g / (1.0f + exp(-g))) * u * route_weight[route_pair];\n"
         "    }\n"
         "    threadgroup_barrier(mem_flags::mem_threadgroup);\n"
         "  }\n"
         "  if (tid < down_rows) {\n"
         "    float acc = 0.0f;\n"
         "    uint down_base = (route_pair * down_rows + tid) * act_rows;\n"
         "    for (uint k = 0; k < act_rows; k++) acc += act[k] * down[down_base + k];\n"
         "    out[(batch * route_pairs + route_pair) * down_rows + tid] = acc;\n"
         "  }\n"
         "}\n";

    MTL4LibraryDescriptor *libDesc = [MTL4LibraryDescriptor new];
    libDesc.source = source;
    libDesc.name = @"ds4_vq_gate_up_down";
    id<MTLLibrary> lib = [g_polar_compiler newLibraryWithDescriptor:libDesc error:&err];
    if (!lib) {
        fprintf(stderr, "ds4: vq gud library failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    MTL4LibraryFunctionDescriptor *fnDesc = [MTL4LibraryFunctionDescriptor new];
    fnDesc.library = lib;
    fnDesc.name = @"vq_gate_up_down";
    MTL4ComputePipelineDescriptor *pipeDesc = [MTL4ComputePipelineDescriptor new];
    pipeDesc.computeFunctionDescriptor = fnDesc;
    pipeDesc.threadGroupSizeIsMultipleOfThreadExecutionWidth = YES;
    pipeDesc.maxTotalThreadsPerThreadgroup = 256;
    g_vq_gud_pipeline = [g_polar_compiler newComputePipelineStateWithDescriptor:pipeDesc
                                                          compilerTaskOptions:nil
                                                                        error:&err];
    if (!g_vq_gud_pipeline) {
        fprintf(stderr, "ds4: vq gud pipeline failed: %s\n",
                err ? err.localizedDescription.UTF8String : "(no error)");
        return 0;
    }
    g_vq_gud_init_ok = 1;
    return 1;
}

/* CLI: ds4 --vq-real-canary <vqb1_dir> <layer> <expert> [down_rows [act_rows]]
 *
 * Loads gate/up/down VQB1 files for <layer> from <vqb1_dir>. For canary
 * simplicity, uses GATE codebook for both gate and up paths (mirrors
 * polar real_canary's gate==up convention). Real inference would pass
 * separate codebooks per kind.
 *
 * Validates VQB1 → MTL4 GPU pipeline at fp32 noise floor on real DS4
 * V4 weights. Mirror of ds4_gpu_mtl4_polar_real_canary structure.
 */
int ds4_gpu_mtl4_vq_real_canary(const char *vqb1_dir,
                                  uint32_t layer, uint32_t expert,
                                  uint32_t down_rows, uint32_t act_rows) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_vq_gud_pipeline_init()) return 0;
    if (!vqb1_dir || !vqb1_dir[0]) return 0;
    if (down_rows == 0 || act_rows == 0 || down_rows > 256 || act_rows > 64) return 0;

    char gate_path[1024], up_path[1024], down_path[1024];
    snprintf(gate_path, sizeof(gate_path), "%s/L%02u_gate.vqb1", vqb1_dir, layer);
    snprintf(up_path,   sizeof(up_path),   "%s/L%02u_up.vqb1",   vqb1_dir, layer);
    snprintf(down_path, sizeof(down_path), "%s/L%02u_down.vqb1", vqb1_dir, layer);

    ds4_vqb1_file gate_file, up_file, down_file;
    if (!ds4_vqb1_open(gate_path, &gate_file)) {
        fprintf(stderr, "ds4: vq real canary — failed to open %s\n", gate_path);
        return 0;
    }
    if (!ds4_vqb1_open(up_path, &up_file)) {
        fprintf(stderr, "ds4: vq real canary — failed to open %s\n", up_path);
        ds4_vqb1_close(&gate_file);
        return 0;
    }
    if (!ds4_vqb1_open(down_path, &down_file)) {
        fprintf(stderr, "ds4: vq real canary — failed to open %s\n", down_path);
        ds4_vqb1_close(&gate_file);
        ds4_vqb1_close(&up_file);
        return 0;
    }
    if (expert >= gate_file.n_experts) {
        fprintf(stderr, "ds4: vq real canary — expert %u OOR (gate has %u)\n",
                expert, gate_file.n_experts);
        ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
        return 0;
    }
    if (act_rows > gate_file.n_rows) {
        fprintf(stderr, "ds4: vq real canary — act_rows %u > gate n_rows %u\n",
                act_rows, gate_file.n_rows);
        ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
        return 0;
    }
    if (down_rows > down_file.n_rows) {
        fprintf(stderr, "ds4: vq real canary — down_rows %u > down n_rows %u\n",
                down_rows, down_file.n_rows);
        ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
        return 0;
    }
    if (act_rows > down_file.n_pairs * 2u) {
        fprintf(stderr, "ds4: vq real canary — act_rows %u > down 2×n_pairs %u\n",
                act_rows, down_file.n_pairs * 2u);
        ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
        return 0;
    }
    /* Soundness: kernel reads codebook[code * 2] with code being uint8.
     * If K < 256 and any code value >= K, this is OOB on the codebook
     * buffer. Validate K matches kernel's uint8 code domain. */
    if (gate_file.k != 256 || up_file.k != 256 || down_file.k != 256) {
        fprintf(stderr, "ds4: vq real canary — only K=256 supported by kernel "
                        "(gate.k=%u up.k=%u down.k=%u)\n",
                gate_file.k, up_file.k, down_file.k);
        ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
        return 0;
    }
    /* NOTE: canary uses gate_file's codes AND codebook for BOTH gate
     * and up paths (gate==up convention). up_file is loaded only to
     * validate it exists; its data is not consumed in this canary.
     * Real-inference dispatcher will use separate codebooks per kind. */

    const uint32_t rows   = gate_file.n_rows;
    const uint32_t pairs  = gate_file.n_pairs;
    const uint32_t n_codes = 1;
    const uint32_t route_pairs = 1;
    const uint32_t batches = 1;
    const uint32_t k_size = gate_file.k;

    @autoreleasepool {
        NSError *err = nil;
        const NSUInteger pair_count = (NSUInteger)n_codes * rows * pairs;
        const NSUInteger hidden_count = (NSUInteger)batches * route_pairs * pairs * 2;
        const NSUInteger down_count = (NSUInteger)route_pairs * down_rows * act_rows;
        const NSUInteger out_count = (NSUInteger)batches * route_pairs * down_rows;
        const NSUInteger codebook_bytes = (NSUInteger)k_size * 2u * sizeof(float);

        id<MTLBuffer> gateCodes = [g_device newBufferWithLength:pair_count                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> upCodes   = [g_device newBufferWithLength:pair_count                       options:MTLResourceStorageModeShared];
        id<MTLBuffer> codebook  = [g_device newBufferWithLength:codebook_bytes                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> gateCode  = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)   options:MTLResourceStorageModeShared];
        id<MTLBuffer> upCode    = [g_device newBufferWithLength:route_pairs * sizeof(uint32_t)   options:MTLResourceStorageModeShared];
        id<MTLBuffer> routeW    = [g_device newBufferWithLength:route_pairs * sizeof(float)      options:MTLResourceStorageModeShared];
        id<MTLBuffer> hidden    = [g_device newBufferWithLength:hidden_count * sizeof(float)     options:MTLResourceStorageModeShared];
        id<MTLBuffer> downBuf   = [g_device newBufferWithLength:down_count * sizeof(float)       options:MTLResourceStorageModeShared];
        id<MTLBuffer> outBuf    = [g_device newBufferWithLength:out_count * sizeof(float)        options:MTLResourceStorageModeShared];
        id<MTLBuffer> paramsBuf = [g_device newBufferWithLength:5 * sizeof(uint32_t)             options:MTLResourceStorageModeShared];

        if (!gateCodes || !upCodes || !codebook || !gateCode || !upCode || !routeW ||
            !hidden || !downBuf || !outBuf || !paramsBuf) {
            ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
            return 0;
        }

        /* Copy expert's codes from VQB1 file (mmap-resident) to MTL buffer.
         * Canary uses GATE expert codes for BOTH gate AND up (gate==up
         * convention matching polar canary). */
        const uint8_t *gate_src = ds4_vqb1_expert_codes(&gate_file, expert);
        memcpy(gateCodes.contents, gate_src, (NSUInteger)rows * pairs);
        memcpy(upCodes.contents,   gate_src, (NSUInteger)rows * pairs);
        /* Codebook: use gate's codebook (since gate==up in canary). */
        memcpy(codebook.contents, gate_file.codebook, codebook_bytes);

        ((uint32_t *)gateCode.contents)[0] = 0;
        ((uint32_t *)upCode.contents)[0]   = 0;
        ((float    *)routeW.contents)[0]   = 1.0f;
        float *hid = (float *)hidden.contents;
        for (NSUInteger i = 0; i < hidden_count; i++) hid[i] = 1.0f;

        /* down values: decode polar-style from VQB1 down file.
         * dwn[d * act_rows + a] for d in [0, down_rows), a in [0, act_rows).
         * Each act_rows pair k → reals at a=2k, a=2k+1. */
        float *dwn = (float *)downBuf.contents;
        for (uint32_t d = 0; d < down_rows; d++) {
            for (uint32_t a = 0; a < act_rows; a += 2) {
                const uint32_t k = a >> 1;
                float re = 0.0f, im = 0.0f;
                ds4_vqb1_decode_pair(&down_file, expert, d, k, &re, &im);
                dwn[(NSUInteger)d * act_rows + a] = re;
                if ((a + 1) < act_rows) {
                    dwn[(NSUInteger)d * act_rows + a + 1] = im;
                }
            }
        }

        uint32_t *params = (uint32_t *)paramsBuf.contents;
        params[0] = pairs; params[1] = rows; params[2] = route_pairs;
        params[3] = down_rows; params[4] = act_rows;

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 10;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) {
            ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
            return 0;
        }
        id<MTLAllocation> allocs[10] = {
            (id<MTLAllocation>)gateCodes, (id<MTLAllocation>)upCodes, (id<MTLAllocation>)codebook,
            (id<MTLAllocation>)gateCode, (id<MTLAllocation>)upCode, (id<MTLAllocation>)routeW,
            (id<MTLAllocation>)hidden, (id<MTLAllocation>)downBuf,
            (id<MTLAllocation>)outBuf, (id<MTLAllocation>)paramsBuf,
        };
        [residency addAllocations:allocs count:10];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 10;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) {
            ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
            return 0;
        }
        [argTable setAddress:gateCodes.gpuAddress atIndex:0];
        [argTable setAddress:upCodes.gpuAddress   atIndex:1];
        [argTable setAddress:codebook.gpuAddress  atIndex:2];
        [argTable setAddress:gateCode.gpuAddress  atIndex:3];
        [argTable setAddress:upCode.gpuAddress    atIndex:4];
        [argTable setAddress:routeW.gpuAddress    atIndex:5];
        [argTable setAddress:hidden.gpuAddress    atIndex:6];
        [argTable setAddress:downBuf.gpuAddress   atIndex:7];
        [argTable setAddress:outBuf.gpuAddress    atIndex:8];
        [argTable setAddress:paramsBuf.gpuAddress atIndex:9];

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) {
            ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
            return 0;
        }
        [enc setComputePipelineState:g_vq_gud_pipeline];
        [enc setArgumentTable:argTable];
        [enc dispatchThreadgroups:MTLSizeMake(route_pairs, batches, 1)
            threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0, gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime; gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) {
            fprintf(stderr, "ds4: vq real canary timeout\n");
            ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
            return 0;
        }
        if (fbErr) {
            fprintf(stderr, "ds4: vq real canary feedback err: %s\n",
                    fbErr.localizedDescription.UTF8String);
            ds4_vqb1_close(&gate_file); ds4_vqb1_close(&up_file); ds4_vqb1_close(&down_file);
            return 0;
        }

        /* CPU reference: same structure as polar real_canary but with VQ
         * decode (codebook[code] lookup instead of mag/phase + trig). */
        float gate_dot_sum_rows[64] = {0};
        for (uint32_t r = 0; r < act_rows; r++) {
            double sum_re_im = 0.0;
            const uint8_t *exp_codes = ds4_vqb1_expert_codes(&gate_file, expert);
            for (uint32_t p = 0; p < pairs; p++) {
                const uint8_t c = exp_codes[(size_t)r * pairs + p];
                if (c >= gate_file.k) continue;
                sum_re_im += (double)gate_file.codebook[(size_t)c * 2u];
                sum_re_im += (double)gate_file.codebook[(size_t)c * 2u + 1u];
            }
            gate_dot_sum_rows[r] = (float)sum_re_im;
        }
        float act_per_row[64] = {0};
        for (uint32_t r = 0; r < act_rows; r++) {
            const float g = gate_dot_sum_rows[r];
            const float silu = g / (1.0f + expf(-g));
            act_per_row[r] = silu * g * 1.0f;
        }

        float *outPtr = (float *)outBuf.contents;
        float maxAbsErr = 0.0f;
        float refMagMax = 0.0f;
        float expected0 = 0.0f;
        for (uint32_t d = 0; d < down_rows; d++) {
            double od = 0.0;
            for (uint32_t r = 0; r < act_rows; r++) {
                od += (double)act_per_row[r] * (double)dwn[(NSUInteger)d * act_rows + r];
            }
            const float exp_d = (float)od;
            if (d == 0) expected0 = exp_d;
            if (fabsf(exp_d) > refMagMax) refMagMax = fabsf(exp_d);
            const float diff = fabsf(outPtr[d] - exp_d);
            if (diff > maxAbsErr) maxAbsErr = diff;
        }
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        const float relErr = refMagMax > 1e-6f ? maxAbsErr / refMagMax : maxAbsErr;
        fprintf(stderr,
                "ds4: vq REAL canary layer=%u expert=%u rows=%u pairs=%u down_rows=%u act_rows=%u K=%u\n"
                "  CPU expected[0]=%.4f GPU out[0]=%.4f max_abs_err=%.4e rel_err=%.4e\n"
                "  gpu_elapsed=%.4f ms  resident=%.1f MB\n",
                layer, expert, rows, pairs, down_rows, act_rows, k_size,
                (double)expected0, (double)outPtr[0],
                (double)maxAbsErr, (double)relErr,
                gpuMs,
                (double)(pair_count * 2 + codebook_bytes + hidden_count * 4 + down_count * 4) / 1e6);

        ds4_vqb1_close(&gate_file);
        ds4_vqb1_close(&up_file);
        ds4_vqb1_close(&down_file);
        /* VQ canary uses real polar-decoded down, so codec noise dominates
         * (rel_L2 ~0.02 weight-level). Accept rel_err < 0.05 — fp32-noise
         * floor at GPU level, codec-floor at CPU-vs-GPU comparison level. */
        return relErr < 1e-3f ? 1 : 0;
    }
}

/* ============================================================ */
/* Phase B-2.3c: polar hot-path dispatcher (stub)                */
/* ============================================================ */
/* silv chose Branch A (polar hot-path + runtime). Per BRANCH_A_PREFLIGHT.md
 * memo (commit b5e84f1), the row-coverage prerequisite forks into A.1
 * (full-row corpus, needs disk approval), A.2 (full-row VQ corpus), or
 * A.3 (hybrid polar+FP4). silv decision pending.
 *
 * This stub ships the hot-path GATE wiring without yet performing actual
 * polar substitution. Validates:
 *   - Pool reference reaches the hot path correctly
 *   - Per-layer enable check works
 *   - Diagnostic emits when polar would dispatch
 *   - Graceful fallback to FP4 (returns 0)
 *
 * silv can runtime-test the gate logic without risking incorrect inference:
 *   DS4_POLAR_DIR=tmp/polar_full_p32m8 DS4_POLAR_LAYERS=0,1,2,3 ./ds4 ...
 * Expected: stderr emits "polar pool has GUD for layer=N" lines on FFN
 * boundaries; FP4 path runs normally; AIME hold-rate unchanged.
 *
 * Body fills in once silv resolves A.1/A.2/A.3 sub-decision.
 */
int ds4_gpu_mtl4_polar_routed_moe_batch_stub(const void *pool_opaque,
                                              uint32_t layer,
                                              uint32_t n_tokens) {
    const ds4_polar_pool *pool = (const ds4_polar_pool *)pool_opaque;
    if (!pool) return 0;
    const ds4_polar_file *gate = ds4_polar_pool_get(pool, layer, DS4_POLAR_KIND_GATE);
    const ds4_polar_file *up   = ds4_polar_pool_get(pool, layer, DS4_POLAR_KIND_UP);
    const ds4_polar_file *down = ds4_polar_pool_get(pool, layer, DS4_POLAR_KIND_DOWN);
    if (!gate || !up || !down) {
        /* Layer not in polar pool — silent fallback (some layers may be
         * intentionally polar-disabled per DS4_POLAR_LAYERS mask). */
        return 0;
    }
    /* Diagnostic: confirm pool has all GUD files; stub returns 0 to fall
     * through to FP4 path. Once row-coverage decision resolves and body
     * lands, this returns 1 on successful polar dispatch instead. */
    static int diag_emitted[DS4_POLAR_MAX_LAYERS] = {0};
    if (layer < DS4_POLAR_MAX_LAYERS && !diag_emitted[layer]) {
        fprintf(stderr,
                "ds4: polar B-2.3c gate engaged layer=%u "
                "(gate=%ux%u up=%ux%u down=%ux%u K_or_M=p%u_m%u  n_tokens=%u) "
                "— STUB returns 0 → FP4 fallback. Body pending A.1/A.2/A.3 decision.\n",
                layer,
                gate->n_rows, gate->n_pairs,
                up->n_rows, up->n_pairs,
                down->n_rows, down->n_pairs,
                gate->phase_levels, gate->mag_levels,
                n_tokens);
        diag_emitted[layer] = 1;
    }
    return 0;  /* Stub: always fall back to FP4 (no actual polar substitution yet) */
}

int ds4_gpu_mtl4_polar_tile_canary(uint32_t tiles, uint32_t rows, uint32_t batches, uint32_t pairs) {
    if (!g_initialized && !ds4_gpu_init()) return 0;
    if (!ds4_polar_tile_pipeline_init()) return 0;
    if (tiles == 0 || rows == 0 || batches == 0 || pairs == 0) return 0;

    @autoreleasepool {
        NSError *err = nil;
        const NSUInteger row_packets = (NSUInteger)tiles * rows;
        const NSUInteger pair_count = row_packets * pairs;
        const NSUInteger hidden_count = (NSUInteger)batches * tiles * pairs * 2;
        const NSUInteger out_count = (NSUInteger)batches * row_packets;

        id<MTLBuffer> mag      = [g_device newBufferWithLength:pair_count                          options:MTLResourceStorageModeShared];
        id<MTLBuffer> phase    = [g_device newBufferWithLength:pair_count                          options:MTLResourceStorageModeShared];
        id<MTLBuffer> levels   = [g_device newBufferWithLength:row_packets * 4 * sizeof(float)     options:MTLResourceStorageModeShared];
        id<MTLBuffer> hidden   = [g_device newBufferWithLength:hidden_count * sizeof(float)        options:MTLResourceStorageModeShared];
        id<MTLBuffer> cosLut   = [g_device newBufferWithLength:9 * sizeof(float)                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> sinLut   = [g_device newBufferWithLength:9 * sizeof(float)                   options:MTLResourceStorageModeShared];
        id<MTLBuffer> outBuf   = [g_device newBufferWithLength:out_count * sizeof(float)           options:MTLResourceStorageModeShared];
        id<MTLBuffer> paramsBuf= [g_device newBufferWithLength:3 * sizeof(uint32_t)                options:MTLResourceStorageModeShared];
        if (!mag || !phase || !levels || !hidden || !cosLut || !sinLut || !outBuf || !paramsBuf) return 0;

        memset(mag.contents, 0, pair_count);
        memset(phase.contents, 4, pair_count);
        float *lvl = (float *)levels.contents;
        for (NSUInteger p = 0; p < row_packets; p++) {
            lvl[p * 4 + 0] = 1.0f; lvl[p * 4 + 1] = 0.5f;
            lvl[p * 4 + 2] = 0.25f; lvl[p * 4 + 3] = 0.125f;
        }
        float *hid = (float *)hidden.contents;
        for (NSUInteger i = 0; i < hidden_count; i++) hid[i] = 1.0f;
        float *cosP = (float *)cosLut.contents;
        float *sinP = (float *)sinLut.contents;
        for (int code = -4; code <= 4; code++) {
            float angle = (float)code * 0.78539816339744830962f;
            cosP[code + 4] = cosf(angle);
            sinP[code + 4] = sinf(angle);
        }
        uint32_t *params = (uint32_t *)paramsBuf.contents;
        params[0] = pairs; params[1] = rows; params[2] = tiles;

        MTLResidencySetDescriptor *rsDesc = [MTLResidencySetDescriptor new];
        rsDesc.initialCapacity = 8;
        id<MTLResidencySet> residency = [g_device newResidencySetWithDescriptor:rsDesc error:&err];
        if (!residency) return 0;
        id<MTLAllocation> allocs[8] = {
            (id<MTLAllocation>)mag, (id<MTLAllocation>)phase,
            (id<MTLAllocation>)levels, (id<MTLAllocation>)hidden,
            (id<MTLAllocation>)cosLut, (id<MTLAllocation>)sinLut,
            (id<MTLAllocation>)outBuf, (id<MTLAllocation>)paramsBuf,
        };
        [residency addAllocations:allocs count:8];
        [residency commit];
        [residency requestResidency];

        MTL4ArgumentTableDescriptor *atDesc = [MTL4ArgumentTableDescriptor new];
        atDesc.maxBufferBindCount = 8;
        atDesc.initializeBindings = YES;
        id<MTL4ArgumentTable> argTable = [g_device newArgumentTableWithDescriptor:atDesc error:&err];
        if (!argTable) return 0;
        [argTable setAddress:mag.gpuAddress       atIndex:0];
        [argTable setAddress:phase.gpuAddress     atIndex:1];
        [argTable setAddress:levels.gpuAddress    atIndex:2];
        [argTable setAddress:hidden.gpuAddress    atIndex:3];
        [argTable setAddress:cosLut.gpuAddress    atIndex:4];
        [argTable setAddress:sinLut.gpuAddress    atIndex:5];
        [argTable setAddress:outBuf.gpuAddress    atIndex:6];
        [argTable setAddress:paramsBuf.gpuAddress atIndex:7];

        id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
        [cb beginCommandBufferWithAllocator:g_polar_allocator];
        [cb useResidencySet:residency];
        id<MTL4ComputeCommandEncoder> enc = [cb computeCommandEncoder];
        if (!enc) return 0;
        [enc setComputePipelineState:g_polar_tile_pipeline];
        [enc setArgumentTable:argTable];
        [enc dispatchThreadgroups:MTLSizeMake(tiles, rows, batches)
            threadsPerThreadgroup:MTLSizeMake(256, 1, 1)];
        [enc endEncoding];
        [cb endCommandBuffer];

        [g_polar_queue addResidencySet:residency];
        dispatch_semaphore_t sem = dispatch_semaphore_create(0);
        __block CFTimeInterval gpuStart = 0.0;
        __block CFTimeInterval gpuEnd = 0.0;
        __block NSError *fbErr = nil;
        MTL4CommitOptions *opts = [MTL4CommitOptions new];
        [opts addFeedbackHandler:^(id<MTL4CommitFeedback> feedback) {
            fbErr = feedback.error;
            gpuStart = feedback.GPUStartTime;
            gpuEnd = feedback.GPUEndTime;
            dispatch_semaphore_signal(sem);
        }];
        id<MTL4CommandBuffer> bufs[1] = { cb };
        [g_polar_queue commit:bufs count:1 options:opts];
        long waitRes = dispatch_semaphore_wait(sem, dispatch_time(DISPATCH_TIME_NOW, 30LL * NSEC_PER_SEC));
        [residency endResidency];
        if (waitRes != 0) { fprintf(stderr, "ds4: polar tile canary timeout\n"); return 0; }
        if (fbErr) { fprintf(stderr, "ds4: polar tile feedback err: %s\n", fbErr.localizedDescription.UTF8String); return 0; }

        float *outPtr = (float *)outBuf.contents;
        float expected = (float)pairs * 1.0f;
        float maxAbsErr = 0.0f;
        for (NSUInteger i = 0; i < out_count; i++) {
            float diff = fabsf(outPtr[i] - expected);
            if (diff > maxAbsErr) maxAbsErr = diff;
        }
        const double gpuMs = (gpuEnd - gpuStart) * 1000.0;
        fprintf(stderr,
                "ds4: polar TILE canary tiles=%u rows=%u batches=%u pairs=%u "
                "expected=%.3f out[0]=%.3f max_abs_err=%.3e gpu=%.6f ms "
                "(%.0f ns/output, %.0f ns/packet, resident=%.1f MB)\n",
                tiles, rows, batches, pairs,
                (double)expected, (double)outPtr[0], (double)maxAbsErr, gpuMs,
                gpuMs * 1e6 / (double)out_count,
                gpuMs * 1e6 / (double)(out_count),
                (double)(pair_count * 2 + row_packets * 4 * 4 + hidden_count * 4 + out_count * 4) / 1e6);
        return maxAbsErr < 1e-3f ? 1 : 0;
    }
}

static int ds4_mtl4_moe_env_enabled(void) {
 static int cached = -1;
 if (cached < 0) {
 const char *v = getenv("DS4_MTL4_MOE_ENABLE");
 cached = (v && v[0] && v[0] != '0') ? 1 : 0;
 }
 return cached;
}

enum { DS4_MTL4_MOE_MAX_T = 16 };

/* IQ2_XXS dequant tables: defined non-static in ds4.c (dedup). */
extern const uint8_t kmask_iq2xs[8];
extern const uint8_t ksigns_iq2xs[128];
extern const uint64_t iq2xxs_grid[256];

/* Convert one block_iq2_xxs (66 bytes) → 256 float32 values.
 *
 * silv 2026-05-27 codex H2086 fix: align with CPU/hot-store IQ2_XXS
 * dequant path in ds4.c:2112-2113:
 *   ls = 2 * (aux32[1] >> 28) + 1
 *   bscale = d * (float)ls * 0.125f
 *
 * Previous formula `d * 0.125 * (0.5 + h)` = `d * (2h+1)/16` was
 * SYSTEMATICALLY 2× SMALLER than the reference `d * (2h+1)/8`. This
 * affected every IQ2_XXS expert dequant in the MTL4 path → all expert
 * weights were half-magnitude → routed-MoE outputs scaled wrong.
 *
 * Math verification: NEON path at ds4.c:2049-2056 uses `(0.5+h)` and
 * multiplies by 0.25 at the end → `(0.5+h)/4 = (1+2h)/8` ✓ matches
 * non-NEON `(2h+1) * 0.125 = (1+2h)/8` ✓. MTL4 OLD was using
 * `(0.5+h) * 0.125 = (1+2h)/16` ✗ — half of reference.
 */
static void ds4_mtl4_dequant_iq2_xxs_block(const uint8_t *src66, float *dst256) {
 const uint16_t d_f16 = ((const uint16_t *)src66)[0];
 /* Inline F16 → F32 (ARM half-precision intrinsic if available). */
 union { uint16_t u; _Float16 h; } cvt = { .u = d_f16 };
 const float d = (float)cvt.h;
 const uint16_t *qs_u16 = (const uint16_t *)(src66 + 2);
 uint32_t aux32[2];
 const uint8_t *aux8 = (const uint8_t *)aux32;
 for (int ib32 = 0; ib32 < 8; ib32++) {
 memcpy(aux32, qs_u16 + 4 * ib32, 8);
 const uint32_t scale_nibble = aux32[1] >> 28;
 const float db = d * 0.125f * (float)(2u * scale_nibble + 1u);
 for (int l = 0; l < 4; l++) {
 const uint8_t *grid = (const uint8_t *)(iq2xxs_grid + aux8[l]);
 const uint8_t signs = ksigns_iq2xs[(aux32[1] >> (7 * l)) & 127];
 for (int j = 0; j < 8; j++) {
 dst256[j] = db * (float)grid[j] * ((signs & kmask_iq2xs[j]) ? -1.0f : 1.0f);
 }
 dst256 += 8;
 }
 }
}

/* Dequant a single routed-expert weight tensor (n_in × n_out F32 row-major).
 * The IQ2_XXS layout stores 256 elements per 66-byte block, n_in*n_out total
 * elements per expert. Returns true on success. */
static bool ds4_mtl4_dequant_iq2_xxs_expert(const uint8_t *src_bytes,
 uint64_t n_in, uint64_t n_out,
 float *dst) {
 const uint64_t n_elem = n_in * n_out;
 if ((n_elem % 256) != 0) {
 fprintf(stderr, "ds4_mtl4: IQ2_XXS dequant: n_elem=%llu not divisible by 256\n",
 (unsigned long long)n_elem);
 return false;
 }
 const uint64_t n_blocks = n_elem / 256;
 for (uint64_t b = 0; b < n_blocks; b++) {
 ds4_mtl4_dequant_iq2_xxs_block(src_bytes + b * 66, dst + b * 256);
 }
 return true;
}

/* ---- MTL4 ML pipeline cache + Apple package loader ----
 * Shared MTL4 ML compiler/queue/event/allocator. Pipeline states cached per
 * shape (gate/up: rows×4096@4096×24576; down: rows×2048@2048×24576).
 * The Apple sample matmul package accepts arbitrary input dimensions via
 * MTL4MachineLearningPipelineDescriptor.setInputDimensions:atBufferIndex:.
 *
 * Package path: configurable via DS4_MTL4_PACKAGE_PATH env (default points
 * to the codex sample directory). */
static id<MTLLibrary> g_mtl4_ml_library = nil;
static id<MTL4Compiler> g_mtl4_ml_compiler = nil;
static id<MTL4CommandQueue> g_mtl4_ml_queue = nil;
static id<MTL4CommandAllocator> g_mtl4_ml_allocator = nil;
static id<MTLSharedEvent> g_mtl4_ml_event = nil;
static int g_mtl4_ml_setup_state = 0; /* 0=unchecked, 1=ready, -1=failed */

typedef struct {
 int T, H, O;
 id<MTL4MachineLearningPipelineState> state;
 id<MTLTensor> A_tensor;
 id<MTLTensor> B_tensor;
 id<MTLTensor> out_tensor;
 id<MTL4ArgumentTable> arg_table;
 id<MTLHeap> heap;
} ds4_mtl4_cache_entry;

#define DS4_MTL4_CACHE_MAX 4
static ds4_mtl4_cache_entry g_mtl4_cache[DS4_MTL4_CACHE_MAX];
static int g_mtl4_cache_count = 0;
static pthread_mutex_t g_mtl4_setup_mu = PTHREAD_MUTEX_INITIALIZER;

static MTLTensorExtents *ds4_mtl4_extents2(NSInteger inner, NSInteger outer) {
 NSInteger v[2] = {inner, outer};
 return [[MTLTensorExtents alloc] initWithRank:2 values:v];
}

static int ds4_mtl4_setup_apple_package(void) {
 pthread_mutex_lock(&g_mtl4_setup_mu);
 if (g_mtl4_ml_setup_state != 0) {
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return g_mtl4_ml_setup_state;
 }
 const char *pkg_env = getenv("DS4_MTL4_PACKAGE_PATH");
 NSString *pkg_path = pkg_env && pkg_env[0]
 ? [NSString stringWithUTF8String:pkg_env]
 : @"/tmp/mtl4_sample/Packages/matrix-multiplication.mtlpackage";

 if (![[NSFileManager defaultManager] fileExistsAtPath:pkg_path]) {
 fprintf(stderr, "ds4_mtl4: package not found at %s\n", pkg_path.UTF8String);
 g_mtl4_ml_setup_state = -1;
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return -1;
 }

 /* Ensure device + Metal4 are available. g_device is the existing global. */
 extern id<MTLDevice> g_device;
 if (!g_device) {
 g_mtl4_ml_setup_state = -1;
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return -1;
 }

 NSError *err = nil;
 g_mtl4_ml_library = [g_device newLibraryWithURL:[NSURL fileURLWithPath:pkg_path] error:&err];
 if (!g_mtl4_ml_library) {
 fprintf(stderr, "ds4_mtl4: newLibraryWithURL failed: %s\n",
 err ? err.localizedDescription.UTF8String : "(null)");
 g_mtl4_ml_setup_state = -1;
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return -1;
 }
 err = nil;
 g_mtl4_ml_compiler = [g_device newCompilerWithDescriptor:[MTL4CompilerDescriptor new] error:&err];
 if (!g_mtl4_ml_compiler) {
 g_mtl4_ml_setup_state = -1;
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return -1;
 }
 g_mtl4_ml_queue = [g_device newMTL4CommandQueue];
 g_mtl4_ml_allocator = [g_device newCommandAllocator];
 g_mtl4_ml_event = [g_device newSharedEvent];
 if (!g_mtl4_ml_queue || !g_mtl4_ml_allocator || !g_mtl4_ml_event) {
 g_mtl4_ml_setup_state = -1;
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return -1;
 }
 g_mtl4_ml_setup_state = 1;
 fprintf(stderr, "ds4_mtl4: Apple package loaded from %s\n", pkg_path.UTF8String);
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return 1;
}

/* Build (or cache-hit) a pipeline + tensors for one shape (T × H @ H × O).
 * Returns NULL on failure. */
static ds4_mtl4_cache_entry *ds4_mtl4_get_or_build_pipeline(int T, int H, int O) {
 extern id<MTLDevice> g_device;
 pthread_mutex_lock(&g_mtl4_setup_mu);
 for (int i = 0; i < g_mtl4_cache_count; i++) {
 if (g_mtl4_cache[i].T == T && g_mtl4_cache[i].H == H && g_mtl4_cache[i].O == O) {
 ds4_mtl4_cache_entry *e = &g_mtl4_cache[i];
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return e;
 }
 }
 if (g_mtl4_cache_count >= DS4_MTL4_CACHE_MAX) {
 fprintf(stderr, "ds4_mtl4: pipeline cache full (max %d)\n", DS4_MTL4_CACHE_MAX);
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return NULL;
 }
 ds4_mtl4_cache_entry *e = &g_mtl4_cache[g_mtl4_cache_count];
 e->T = T; e->H = H; e->O = O;

 MTLFunctionReflection *refl = [g_mtl4_ml_library reflectionForFunctionWithName:@"main"];
 if (!refl) { pthread_mutex_unlock(&g_mtl4_setup_mu); return NULL; }
 MTL4LibraryFunctionDescriptor *fd = [MTL4LibraryFunctionDescriptor new];
 fd.name = @"main"; fd.library = g_mtl4_ml_library;
 MTL4MachineLearningPipelineDescriptor *pd = [MTL4MachineLearningPipelineDescriptor new];
 pd.machineLearningFunctionDescriptor = fd;
 MTL4PipelineOptions *opts = [MTL4PipelineOptions new];
 opts.shaderReflection = MTL4ShaderReflectionBindingInfo;
 pd.options = opts;
 for (id<MTLBinding> b in refl.bindings) {
 if (b.type != MTLBindingTypeTensor) continue;
 id<MTLTensorBinding> tb = (id<MTLTensorBinding>)b;
 NSString *name = tb.name.lowercaseString;
 if ([name containsString:@"inputa"]) [pd setInputDimensions:ds4_mtl4_extents2(H, T) atBufferIndex:tb.index];
 if ([name containsString:@"inputb"]) [pd setInputDimensions:ds4_mtl4_extents2(O, H) atBufferIndex:tb.index];
 }
 NSError *err = nil;
 e->state = [g_mtl4_ml_compiler newMachineLearningPipelineStateWithDescriptor:pd error:&err];
 if (!e->state) {
 fprintf(stderr, "ds4_mtl4: pipeline build failed for T=%d H=%d O=%d: %s\n",
 T, H, O, err ? err.localizedDescription.UTF8String : "(null)");
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return NULL;
 }

 /* Build A, B, output tensors + heap + argument table from the pipeline reflection. */
 NSMutableDictionary<NSString*, id<MTLTensor>> *tdict = [NSMutableDictionary new];
 for (id<MTLBinding> b in e->state.reflection.bindings) {
 if (b.type != MTLBindingTypeTensor) continue;
 id<MTLTensorBinding> tb = (id<MTLTensorBinding>)b;
 MTLTensorDescriptor *desc = [MTLTensorDescriptor new];
 desc.usage = MTLTensorUsageMachineLearning;
 desc.dimensions = tb.dimensions;
 desc.dataType = tb.tensorDataType;
 err = nil;
 id<MTLTensor> tns = [g_device newTensorWithDescriptor:desc error:&err];
 if (!tns) {
 fprintf(stderr, "ds4_mtl4: tensor alloc failed: %s\n",
 err ? err.localizedDescription.UTF8String : "(null)");
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return NULL;
 }
 tdict[tb.name] = tns;
 NSString *lower = tb.name.lowercaseString;
 if ([lower containsString:@"inputa"]) e->A_tensor = tns;
 else if ([lower containsString:@"inputb"]) e->B_tensor = tns;
 else if ([lower containsString:@"output"]) e->out_tensor = tns;
 }
 if (!e->A_tensor || !e->B_tensor || !e->out_tensor) {
 fprintf(stderr, "ds4_mtl4: A/B/output binding lookup failed\n");
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return NULL;
 }

 MTL4ArgumentTableDescriptor *atd = [MTL4ArgumentTableDescriptor new];
 atd.maxBufferBindCount = 31;
 atd.initializeBindings = YES;
 err = nil;
 e->arg_table = [g_device newArgumentTableWithDescriptor:atd error:&err];
 if (!e->arg_table) {
 fprintf(stderr, "ds4_mtl4: arg table failed\n");
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return NULL;
 }
 for (id<MTLBinding> b in e->state.reflection.bindings) {
 if (b.type != MTLBindingTypeTensor) continue;
 id<MTLTensorBinding> tb = (id<MTLTensorBinding>)b;
 [e->arg_table setResource:tdict[tb.name].gpuResourceID atBufferIndex:tb.index];
 }
 MTLHeapDescriptor *hd = [MTLHeapDescriptor new];
 hd.type = MTLHeapTypePlacement;
 hd.size = e->state.intermediatesHeapSize;
 e->heap = [g_device newHeapWithDescriptor:hd];
 if (!e->heap) {
 fprintf(stderr, "ds4_mtl4: heap alloc failed\n");
 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return NULL;
 }
 g_mtl4_cache_count++;
 fprintf(stderr, "ds4_mtl4: built pipeline T=%d H=%d O=%d (cache %d/%d)\n",
 T, H, O, g_mtl4_cache_count, DS4_MTL4_CACHE_MAX);

 /* Warmup pass. First dispatch on a fresh MTL4 ML pipeline produces
 * undefined output (observed: NaN). The codex h1672 pattern also
 * does a discard warm dispatch before measurement. */
 id<MTL4CommandBuffer> wcb = [g_device newCommandBuffer];
 [wcb beginCommandBufferWithAllocator:g_mtl4_ml_allocator];
 id<MTL4MachineLearningCommandEncoder> wenc = [wcb machineLearningCommandEncoder];
 [wenc setArgumentTable:e->arg_table];
 [wenc setPipelineState:e->state];
 [wenc dispatchNetworkWithIntermediatesHeap:e->heap];
 [wenc endEncoding];
 [wcb endCommandBuffer];
 id<MTL4CommandBuffer> wbufs[] = {wcb};
 [g_mtl4_ml_queue commit:wbufs count:1];
 uint64_t wsv = g_mtl4_ml_event.signaledValue + 1;
 [g_mtl4_ml_queue signalEvent:g_mtl4_ml_event value:wsv];
 [g_mtl4_ml_event waitUntilSignaledValue:wsv timeoutMS:30000];

 pthread_mutex_unlock(&g_mtl4_setup_mu);
 return e;
}

/* Run one matmul dispatch via the cached pipeline; reads/writes via tensor APIs. */
static bool ds4_mtl4_dispatch_matmul(ds4_mtl4_cache_entry *e,
 const float *A_data, const float *B_data,
 float *out_data) {
 extern id<MTLDevice> g_device;
 MTLTensorExtents *origin = ds4_mtl4_extents2(0, 0);
 [e->A_tensor replaceSliceOrigin:origin sliceDimensions:ds4_mtl4_extents2(e->H, e->T)
 withBytes:A_data strides:ds4_mtl4_extents2(1, e->H)];
 [e->B_tensor replaceSliceOrigin:origin sliceDimensions:ds4_mtl4_extents2(e->O, e->H)
 withBytes:B_data strides:ds4_mtl4_extents2(1, e->O)];
 id<MTL4CommandBuffer> cb = [g_device newCommandBuffer];
 [cb beginCommandBufferWithAllocator:g_mtl4_ml_allocator];
 id<MTL4MachineLearningCommandEncoder> enc = [cb machineLearningCommandEncoder];
 [enc setArgumentTable:e->arg_table];
 [enc setPipelineState:e->state];
 [enc dispatchNetworkWithIntermediatesHeap:e->heap];
 [enc endEncoding];
 [cb endCommandBuffer];
 id<MTL4CommandBuffer> bufs[] = {cb};
 [g_mtl4_ml_queue commit:bufs count:1];
 uint64_t sv = g_mtl4_ml_event.signaledValue + 1;
 [g_mtl4_ml_queue signalEvent:g_mtl4_ml_event value:sv];
 if (![g_mtl4_ml_event waitUntilSignaledValue:sv timeoutMS:30000]) {
 fprintf(stderr, "ds4_mtl4: dispatch timeout\n");
 return false;
 }
 [e->out_tensor getBytes:out_data strides:ds4_mtl4_extents2(1, e->O)
 fromSliceOrigin:origin sliceDimensions:ds4_mtl4_extents2(e->O, e->T)];
 return true;
}

int ds4_gpu_routed_moe_batch_tensor_mtl4(
 ds4_gpu_tensor *out,
 ds4_gpu_tensor *gate,
 ds4_gpu_tensor *up,
 ds4_gpu_tensor *mid,
 ds4_gpu_tensor *experts,
 const void *model_map,
 uint64_t model_size,
 uint64_t gate_offset,
 uint64_t up_offset,
 uint64_t down_offset,
 uint32_t gate_type,
 uint32_t down_type,
 uint64_t gate_expert_bytes,
 uint64_t gate_row_bytes,
 uint64_t down_expert_bytes,
 uint64_t down_row_bytes,
 uint32_t expert_in_dim,
 uint32_t expert_mid_dim,
 uint32_t out_dim,
 const ds4_gpu_tensor *selected,
 const ds4_gpu_tensor *weights,
 uint32_t n_total_expert,
 uint32_t n_expert,
 float clamp,
 const ds4_gpu_tensor *x,
 uint32_t layer_index,
 uint32_t n_tokens,
 bool *mid_is_f16,
 bool *mtl4_path_taken) {
 (void)n_total_expert;
 /* Preflight: all conditions must hold or fall back to legacy. */
 const int env_ok = ds4_mtl4_moe_env_enabled();
 const int shape_ok = (n_expert == 6 && n_tokens <= DS4_MTL4_MOE_MAX_T);
 if (mtl4_path_taken) *mtl4_path_taken = false;

 if (!env_ok || !shape_ok) {
 /* Legacy fallback — drop in. */
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }

 /* IQ2_XXS gate/up + Q8_0 down is the IQ2_XXS-w2Q2K-AProjQ8-SExpQ8-OutQ8
 * recipe shipped. We only support IQ2_XXS gate path here for the
 * canary; up + down still go through legacy if anything fails. */
 enum { DS4Q_TYPE_IQ2_XXS = 16, DS4Q_TYPE_Q8_0 = 8 };
 if (gate_type != DS4Q_TYPE_IQ2_XXS) {
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }

 /* Setup Apple matmul package on first use. */
 if (ds4_mtl4_setup_apple_package() != 1) {
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }

 /* Host-side dequant + packed dispatch.
 * COST WARNING: per call this allocates:
 * - 6 × (expert_in_dim × expert_mid_dim × 4) bytes dequant tmp ≈ 192 MB
 * - 2 × (expert_in_dim × 6·expert_mid_dim × 4) packed B ≈ 400 MB (gate+up)
 * - 1 × (expert_mid_dim × 6·out_dim × 4) packed down B ≈ 200 MB
 * The legacy SIMD path does dequant inline at register level and avoids
 * these allocations. THIS PATH IS A FUNCTIONAL CORRECTNESS PROBE, NOT A
 * SPEED WIN until/unless replaces host dequant with a Metal compute
 * shader that does dequant+matmul in one pass. */

 int32_t selected_ids[16] = {0};
 const size_t sel_bytes = (size_t)n_expert * sizeof(int32_t);
 if (ds4_gpu_tensor_read(selected, 0, selected_ids, sel_bytes) == 0) {
 fprintf(stderr, "ds4_mtl4: failed to read selected expert IDs\n");
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }

 /* For the first iteration we just measure: dequant gate weights for the
 * 6 selected experts, pack them, dispatch a matmul, compare checksum.
 * This validates that:
 * (a) the dequant tables are correct
 * (b) Apple's package loads + dispatches our shapes
 * (c) end-to-end time vs legacy
 * Then fall back to legacy for the actual output (correctness preserved). */

 const size_t per_expert_floats = (size_t)expert_in_dim * (size_t)expert_mid_dim;
 const size_t packed_floats = (size_t)expert_in_dim * 6ull * (size_t)expert_mid_dim;
 float *tmp_dequant = (float *)malloc(per_expert_floats * sizeof(float));
 float *packed_gate_B = (float *)malloc(packed_floats * sizeof(float));
 float *x_data = (float *)malloc((size_t)n_tokens * (size_t)expert_in_dim * sizeof(float));
 float *gate_out = (float *)malloc((size_t)n_tokens * 6ull * (size_t)expert_mid_dim * sizeof(float));
 if (!tmp_dequant || !packed_gate_B || !x_data || !gate_out) {
 free(tmp_dequant); free(packed_gate_B); free(x_data); free(gate_out);
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }

 /* Bounds check: under trim50, router can output IDs in original 0..255
 * space but the on-disk gate_exps tensor only stores N_kept < 256
 * experts. Reading at expert_id × gate_expert_bytes for an out-of-range
 * id reads past the tensor's allocated bytes → garbage F16 d scales
 * → IQ2_XXS dequant produces NaN. The proper fix is to plumb the
 * expert_remap translation through inference (pending integration. Until then: detect + fall back. */
 extern uint32_t ds4_get_layer_expert_count(uint32_t layer);
 const uint32_t layer_expert_count = ds4_get_layer_expert_count(layer_index);
 int out_of_bounds = 0;
 for (uint32_t e = 0; e < n_expert; e++) {
 if (selected_ids[e] < 0 || (uint32_t)selected_ids[e] >= layer_expert_count) {
 out_of_bounds++;
 }
 }
 if (out_of_bounds > 0) {
 static int warned[64] = {0}; /* DS4_N_LAYER = 43 but use a const here */
 if (layer_index < 64 && !warned[layer_index]) {
 warned[layer_index] = 1;
 fprintf(stderr,
 "ds4_mtl4: L%u — %d/%d selected_ids out of trim_count=%u, "
 "falling back to legacy. Need expert_remap plumbing.\n",
 layer_index, out_of_bounds, n_expert, layer_expert_count);
 }
 free(tmp_dequant); free(packed_gate_B); free(x_data); free(gate_out);
 if (mtl4_path_taken) *mtl4_path_taken = false;
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }

 fprintf(stderr, "ds4_mtl4: L%u selected_ids: [%d %d %d %d %d %d] (trim=%u)\n",
 layer_index,
 selected_ids[0], selected_ids[1], selected_ids[2],
 selected_ids[3], selected_ids[4], selected_ids[5], layer_expert_count);

 uint64_t t_dequant_ns_total = 0;
 for (int e = 0; e < (int)n_expert && e < 6; e++) {
 const int32_t expert_id = selected_ids[e];
 if (expert_id < 0 || (uint64_t)expert_id >= (model_size / gate_expert_bytes)) {
 fprintf(stderr, "ds4_mtl4: invalid expert_id=%d\n", expert_id);
 free(tmp_dequant); free(packed_gate_B); free(x_data); free(gate_out);
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }
 const uint8_t *expert_bytes = (const uint8_t *)model_map + gate_offset + (uint64_t)expert_id * gate_expert_bytes;
 uint64_t t0 = clock_gettime_nsec_np(CLOCK_UPTIME_RAW);
 ds4_mtl4_dequant_iq2_xxs_expert(expert_bytes, expert_in_dim, expert_mid_dim, tmp_dequant);
 t_dequant_ns_total += clock_gettime_nsec_np(CLOCK_UPTIME_RAW) - t0;
 /* GGUF quantized expert layout: stored as [output_col][input_row]
 * row-major (output_col outer, input_row inner — natural quant
 * blocking along the matmul inner-product axis). The dequant walks
 * blocks sequentially, so tmp_dequant has the same [out_col][in_row]
 * layout. Pack into packed_gate_B which is [input_row][packed_out]
 * row-major where packed_out = e * expert_mid_dim + c. TRANSPOSE. */
 for (uint64_t c = 0; c < expert_mid_dim; c++) {
 for (uint64_t r = 0; r < expert_in_dim; r++) {
 packed_gate_B[r * 6 * expert_mid_dim + e * expert_mid_dim + c] =
 tmp_dequant[c * expert_in_dim + r];
 }
 }
 }

 /* Read x activation from GPU tensor. Force command buffer flush first
 * so prior in-flight Metal work (layer pre-MoE compute) is committed
 * before host read. Without this, layers immediately after cpu_moe
 * layers can race-read uninitialized batch_ffn_norm tensor data
 * (observed: NaN gate_abs_sum on first 2 Metal MoE layers after a
 * cpu_moe sequence; the 3rd layer succeeds because by then the
 * tensor has been populated by the prior Metal MoE dispatch). */
 (void)ds4_gpu_end_commands();
 (void)ds4_gpu_begin_commands();

 const size_t x_bytes = (size_t)n_tokens * (size_t)expert_in_dim * sizeof(float);
 if (ds4_gpu_tensor_read(x, 0, x_data, x_bytes) == 0) {
 fprintf(stderr, "ds4_mtl4: failed to read x activation\n");
 free(tmp_dequant); free(packed_gate_B); free(x_data); free(gate_out);
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
 }

 /* Pipeline cache build + dispatch. */
 uint64_t t_dispatch0 = clock_gettime_nsec_np(CLOCK_UPTIME_RAW);
 ds4_mtl4_cache_entry *gate_pipe = ds4_mtl4_get_or_build_pipeline(
 (int)n_tokens, (int)expert_in_dim, 6 * (int)expert_mid_dim);
 bool dispatch_ok = false;
 if (gate_pipe) {
 dispatch_ok = ds4_mtl4_dispatch_matmul(gate_pipe, x_data, packed_gate_B, gate_out);
 }
 uint64_t t_dispatch_ns = clock_gettime_nsec_np(CLOCK_UPTIME_RAW) - t_dispatch0;

 /* Compute checksums to localize NaN source. */
 double x_abs_sum = 0.0, B_abs_sum = 0.0, gate_abs_sum = 0.0;
 int x_nan = 0, B_nan = 0, gate_nan = 0;
 const size_t x_n = (size_t)n_tokens * (size_t)expert_in_dim;
 for (size_t i = 0; i < x_n; i++) {
 const float v = x_data[i];
 if (isnan(v) || isinf(v)) x_nan++;
 else x_abs_sum += fabs((double)v);
 }
 const size_t B_n = (size_t)expert_in_dim * 6 * (size_t)expert_mid_dim;
 for (size_t i = 0; i < B_n; i++) {
 const float v = packed_gate_B[i];
 if (isnan(v) || isinf(v)) B_nan++;
 else B_abs_sum += fabs((double)v);
 }
 const size_t gate_out_n = (size_t)n_tokens * 6 * (size_t)expert_mid_dim;
 for (size_t i = 0; i < gate_out_n; i++) {
 const float v = gate_out[i];
 if (isnan(v) || isinf(v)) gate_nan++;
 else gate_abs_sum += fabs((double)v);
 }
 fprintf(stderr,
 "ds4_mtl4: L%u T=%u dequant=%.1fms disp=%.1fms "
 "| x: |sum|=%.3e nan=%d/%zu | B: |sum|=%.3e nan=%d/%zu "
 "| gate: |sum|=%.3e nan=%d/%zu | ok=%d\n",
 layer_index, n_tokens,
 (double)t_dequant_ns_total / 1e6, (double)t_dispatch_ns / 1e6,
 x_abs_sum, x_nan, x_n,
 B_abs_sum, B_nan, B_n,
 gate_abs_sum, gate_nan, gate_out_n,
 dispatch_ok ? 1 : 0);

 free(tmp_dequant); free(packed_gate_B); free(x_data); free(gate_out);

 if (mtl4_path_taken) *mtl4_path_taken = true;

 /* CANARY MODE: measured + logged the path, now fall back to legacy for
 * the actual output. When reviewed we extend to up + SwiGLU + down. */
 return ds4_gpu_routed_moe_batch_tensor(
 out, gate, up, mid, experts, model_map, model_size,
 gate_offset, up_offset, down_offset, gate_type, down_type,
 gate_expert_bytes, gate_row_bytes, down_expert_bytes, down_row_bytes,
 expert_in_dim, expert_mid_dim, out_dim,
 selected, weights, n_total_expert, n_expert, clamp, x,
 layer_index, n_tokens, mid_is_f16);
}

int ds4_gpu_hc_split_sinkhorn_tensor(
 ds4_gpu_tensor *out,
 const ds4_gpu_tensor *mix,
 const void *model_map,
 uint64_t model_size,
 uint64_t scale_offset,
 uint64_t base_offset,
 uint32_t n_hc,
 uint32_t sinkhorn_iters,
 float eps) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (n_hc == 0 || n_hc > 16) return 0;
 const uint64_t mix_hc = 2ull * n_hc + (uint64_t)n_hc * n_hc;
 const uint64_t mix_bytes = mix_hc * sizeof(float);
 const uint64_t scale_bytes = 3ull * sizeof(float);

 @autoreleasepool {
 id<MTLBuffer> mixbuf = ds4_gpu_tensor_buffer(mix);
 id<MTLBuffer> outbuf = ds4_gpu_tensor_buffer(out);
 const uint64_t mix_tensor_bytes = ds4_gpu_tensor_bytes(mix);
 const uint64_t out_tensor_bytes = ds4_gpu_tensor_bytes(out);
 if (!mixbuf || !outbuf ||
 mix_tensor_bytes < mix_bytes ||
 out_tensor_bytes < mix_bytes) {
 fprintf(stderr, "ds4: Metal HC split received undersized activation buffers\n");
 return 0;
 }
 if (scale_offset > model_size || scale_bytes > model_size - scale_offset ||
 base_offset > model_size || mix_bytes > model_size - base_offset) {
 fprintf(stderr, "ds4: Metal HC split parameter range is outside the mapped model\n");
 return 0;
 }

 uint64_t scale_inner = 0;
 uint64_t base_inner = 0;
 id<MTLBuffer> scalebuf = ds4_gpu_wrap_model_range(model_map, model_size, scale_offset, scale_bytes, &scale_inner);
 id<MTLBuffer> basebuf = ds4_gpu_wrap_model_range(model_map, model_size, base_offset, mix_bytes, &base_inner);
 if (!scalebuf || !basebuf) return 0;

 uint64_t n_rows64 = mix_tensor_bytes / mix_bytes;
 const uint64_t out_rows64 = out_tensor_bytes / mix_bytes;
 if (out_rows64 < n_rows64) n_rows64 = out_rows64;
 if (n_rows64 == 0 || n_rows64 > UINT32_MAX) {
 fprintf(stderr, "ds4: Metal HC split row count is outside supported range\n");
 return 0;
 }

 ds4_gpu_hc_split_args args = {
 .n_hc = (int32_t)n_hc,
 .sinkhorn_iters = (int32_t)sinkhorn_iters,
 .n_rows = (int64_t)n_rows64,
 .mix_hc = (int64_t)mix_hc,
 .nb01 = mix_bytes,
 .nb1 = mix_bytes,
 .eps = eps,
 };
 const NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)n_rows64));
 const NSUInteger n_tg = ((NSUInteger)n_rows64 + nth - 1u) / nth;

 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_hc_split_sinkhorn_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:mixbuf offset:ds4_gpu_tensor_offset(mix) atIndex:1];
 [enc setBuffer:scalebuf offset:(NSUInteger)scale_inner atIndex:2];
 [enc setBuffer:basebuf offset:(NSUInteger)base_inner atIndex:3];
 [enc setBuffer:outbuf offset:ds4_gpu_tensor_offset(out) atIndex:4];
 [enc dispatchThreadgroups:MTLSizeMake(n_tg, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);

 if (!ds4_gpu_finish_command_buffer(cb, owned, "HC split/sinkhorn")) return 0;
 }

 return 1;
}

static int ds4_gpu_hc_weighted_sum_strided(
 ds4_gpu_tensor *out,
 const ds4_gpu_tensor *residual_hc,
 const ds4_gpu_tensor *weights,
 uint64_t weight_offset,
 uint64_t weight_row_stride,
 uint32_t n_embd,
 uint32_t n_hc,
 const char *label) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!out || !residual_hc || !weights || n_embd == 0 || n_hc == 0 ||
 weight_row_stride < (uint64_t)n_hc * sizeof(float)) {
 return 0;
 }

 @autoreleasepool {
 id<MTLBuffer> xbuf = ds4_gpu_tensor_buffer(residual_hc);
 id<MTLBuffer> wbuf = ds4_gpu_tensor_buffer(weights);
 id<MTLBuffer> outbuf = ds4_gpu_tensor_buffer(out);
 const uint64_t out_row_bytes = (uint64_t)n_embd * sizeof(float);
 const uint64_t out_tensor_bytes = ds4_gpu_tensor_bytes(out);
 if (out_row_bytes == 0 || out_tensor_bytes < out_row_bytes || out_tensor_bytes % out_row_bytes != 0) {
 fprintf(stderr, "ds4: Metal HC weighted sum output size is not a whole token row\n");
 return 0;
 }

 const uint64_t n_tokens64 = out_tensor_bytes / out_row_bytes;
 if (n_tokens64 == 0 || n_tokens64 > UINT32_MAX) {
 fprintf(stderr, "ds4: Metal HC weighted sum token count is outside supported range\n");
 return 0;
 }

 const uint64_t x_row_values = (uint64_t)n_hc * n_embd;
 if (x_row_values == 0 ||
 x_row_values > UINT64_MAX / sizeof(float) ||
 n_tokens64 > UINT64_MAX / (x_row_values * sizeof(float)) ||
 n_tokens64 > UINT64_MAX / ((uint64_t)n_hc * sizeof(float))) {
 fprintf(stderr, "ds4: Metal HC weighted sum activation size overflow\n");
 return 0;
 }

 const uint64_t x_bytes = n_tokens64 * x_row_values * sizeof(float);
 const uint64_t w_last = weight_offset +
 (n_tokens64 - 1u) * weight_row_stride +
 (uint64_t)n_hc * sizeof(float);
 if (!xbuf || !wbuf || !outbuf ||
 ds4_gpu_tensor_bytes(residual_hc) < x_bytes ||
 ds4_gpu_tensor_bytes(weights) < w_last) {
 fprintf(stderr, "ds4: Metal HC weighted sum received undersized activation buffers\n");
 return 0;
 }

 ds4_gpu_hc_weighted_sum_args args = {
 .n_embd = n_embd,
 .n_hc = n_hc,
 .n_tokens = (int64_t)n_tokens64,
 .nb_x0 = sizeof(float),
 .nb_x1 = (uint64_t)n_embd * sizeof(float),
 .nb_x2 = (uint64_t)n_hc * n_embd * sizeof(float),
 .nb_w0 = sizeof(float),
 .nb_w1 = weight_row_stride,
 .nb0 = sizeof(float),
 .nb1 = (uint64_t)n_embd * sizeof(float),
 };
 const uint64_t n_elem = (uint64_t)n_embd * n_tokens64;
 const NSUInteger nth = MIN((NSUInteger)256, MAX((NSUInteger)1, (NSUInteger)n_elem));
 const NSUInteger n_tg = ((NSUInteger)n_elem + nth - 1u) / nth;
 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_hc_weighted_sum_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:xbuf offset:ds4_gpu_tensor_offset(residual_hc) atIndex:1];
 [enc setBuffer:wbuf offset:ds4_gpu_tensor_offset(weights) + (NSUInteger)weight_offset atIndex:2];
 [enc setBuffer:outbuf offset:ds4_gpu_tensor_offset(out) atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake(n_tg, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);

 if (!ds4_gpu_finish_command_buffer(cb, owned, label)) return 0;
 }

 return 1;
}

int ds4_gpu_hc_weighted_sum_tensor(
 ds4_gpu_tensor *out,
 const ds4_gpu_tensor *residual_hc,
 const ds4_gpu_tensor *weights,
 uint32_t n_embd,
 uint32_t n_hc) {
 return ds4_gpu_hc_weighted_sum_strided(out,
 residual_hc,
 weights,
 0,
 (uint64_t)n_hc * sizeof(float),
 n_embd,
 n_hc,
 "HC weighted sum");
}

int ds4_gpu_hc_weighted_sum_split_tensor(
 ds4_gpu_tensor *out,
 const ds4_gpu_tensor *residual_hc,
 const ds4_gpu_tensor *split,
 uint32_t n_embd,
 uint32_t n_hc) {
 const uint64_t mix_hc = 2ull * n_hc + (uint64_t)n_hc * n_hc;
 return ds4_gpu_hc_weighted_sum_strided(out,
 residual_hc,
 split,
 0,
 mix_hc * sizeof(float),
 n_embd,
 n_hc,
 "HC weighted sum split");
}

/* Release decode fused HC pre-sublayer operation. The graph driver owns the
 * optional reference fallback so this function stays a direct fused dispatch. */
int ds4_gpu_hc_split_weighted_sum_tensor(
 ds4_gpu_tensor *out,
 ds4_gpu_tensor *split,
 const ds4_gpu_tensor *mix,
 const ds4_gpu_tensor *residual_hc,
 const void *model_map,
 uint64_t model_size,
 uint64_t scale_offset,
 uint64_t base_offset,
 uint32_t n_embd,
 uint32_t n_hc,
 uint32_t sinkhorn_iters,
 float eps) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!out || !split || !mix || !residual_hc || !model_map ||
 n_embd == 0 || n_hc == 0) {
 return 0;
 }
 if (n_hc != 4) {
 fprintf(stderr, "ds4: Metal fused HC split/sum is specialized for HC=4\n");
 return 0;
 }

 const uint64_t mix_hc = 2ull * n_hc + (uint64_t)n_hc * n_hc;
 const uint64_t mix_bytes = mix_hc * sizeof(float);
 const uint64_t out_row_bytes = (uint64_t)n_embd * sizeof(float);
 const uint64_t residual_row_bytes = (uint64_t)n_hc * n_embd * sizeof(float);
 const uint64_t scale_bytes = 3ull * sizeof(float);

 @autoreleasepool {
 id<MTLBuffer> mixbuf = ds4_gpu_tensor_buffer(mix);
 id<MTLBuffer> splitbuf = ds4_gpu_tensor_buffer(split);
 id<MTLBuffer> xbuf = ds4_gpu_tensor_buffer(residual_hc);
 id<MTLBuffer> outbuf = ds4_gpu_tensor_buffer(out);
 const uint64_t out_tensor_bytes = ds4_gpu_tensor_bytes(out);
 if (out_row_bytes == 0 || out_tensor_bytes < out_row_bytes ||
 out_tensor_bytes % out_row_bytes != 0) {
 fprintf(stderr, "ds4: Metal fused HC split/sum output size is not a whole token row\n");
 return 0;
 }

 const uint64_t n_rows64 = out_tensor_bytes / out_row_bytes;
 if (n_rows64 == 0 || n_rows64 > UINT32_MAX ||
 n_rows64 > UINT64_MAX / mix_bytes ||
 n_rows64 > UINT64_MAX / residual_row_bytes) {
 fprintf(stderr, "ds4: Metal fused HC split/sum row count is outside supported range\n");
 return 0;
 }

 const uint64_t mix_total_bytes = n_rows64 * mix_bytes;
 const uint64_t residual_total_bytes = n_rows64 * residual_row_bytes;
 if (!mixbuf || !splitbuf || !xbuf || !outbuf ||
 ds4_gpu_tensor_bytes(mix) < mix_total_bytes ||
 ds4_gpu_tensor_bytes(split) < mix_total_bytes ||
 ds4_gpu_tensor_bytes(residual_hc) < residual_total_bytes) {
 fprintf(stderr, "ds4: Metal fused HC split/sum received undersized activation buffers\n");
 return 0;
 }

 if (scale_offset > model_size || scale_bytes > model_size - scale_offset ||
 base_offset > model_size || mix_bytes > model_size - base_offset) {
 fprintf(stderr, "ds4: Metal fused HC split/sum parameter range is outside the mapped model\n");
 return 0;
 }

 uint64_t scale_inner = 0;
 uint64_t base_inner = 0;
 id<MTLBuffer> scalebuf = ds4_gpu_wrap_model_range(model_map, model_size, scale_offset, scale_bytes, &scale_inner);
 id<MTLBuffer> basebuf = ds4_gpu_wrap_model_range(model_map, model_size, base_offset, mix_bytes, &base_inner);
 if (!scalebuf || !basebuf) return 0;

 ds4_gpu_hc_split_weighted_sum_args args = {
 .n_embd = (int64_t)n_embd,
 .n_hc = (int32_t)n_hc,
 .sinkhorn_iters = (int32_t)sinkhorn_iters,
 .n_rows = (int64_t)n_rows64,
 .mix_hc = (int64_t)mix_hc,
 .nb_mix1 = mix_bytes,
 .nb_split1 = mix_bytes,
 .nb_x0 = sizeof(float),
 .nb_x1 = (uint64_t)n_embd * sizeof(float),
 .nb_x2 = residual_row_bytes,
 .nb0 = sizeof(float),
 .nb1 = out_row_bytes,
 .eps = eps,
 };

 NSUInteger nth = g_hc_split_weighted_sum_pipeline.maxTotalThreadsPerThreadgroup;
 if (nth > 256u) nth = 256u;
 if (nth > (NSUInteger)n_embd) nth = (NSUInteger)n_embd;
 if (nth == 0) nth = 1u;

 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:g_hc_split_weighted_sum_pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:mixbuf offset:ds4_gpu_tensor_offset(mix) atIndex:1];
 [enc setBuffer:scalebuf offset:(NSUInteger)scale_inner atIndex:2];
 [enc setBuffer:basebuf offset:(NSUInteger)base_inner atIndex:3];
 [enc setBuffer:xbuf offset:ds4_gpu_tensor_offset(residual_hc) atIndex:4];
 [enc setBuffer:splitbuf offset:ds4_gpu_tensor_offset(split) atIndex:5];
 [enc setBuffer:outbuf offset:ds4_gpu_tensor_offset(out) atIndex:6];
 [enc setThreadgroupMemoryLength:(NSUInteger)n_hc * sizeof(float) atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_rows64, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);

 if (!ds4_gpu_finish_command_buffer(cb, owned, "HC split/sum fused")) return 0;
 }

 return 1;
}

/* Decode-only HC-pre plus the immediately following weighted RMSNorm. This is
 * intentionally specialized for DS4's fixed HC=4, embd=4096 shape; larger
 * batched prefill keeps using the existing two-stage path. */
int ds4_gpu_hc_split_weighted_sum_norm_tensor(
 ds4_gpu_tensor *out,
 ds4_gpu_tensor *norm_out,
 ds4_gpu_tensor *split,
 const ds4_gpu_tensor *mix,
 const ds4_gpu_tensor *residual_hc,
 const void *model_map,
 uint64_t model_size,
 uint64_t scale_offset,
 uint64_t base_offset,
 uint64_t norm_weight_offset,
 uint32_t n_embd,
 uint32_t n_hc,
 uint32_t sinkhorn_iters,
 float eps,
 float norm_eps) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!out || !norm_out || !split || !mix || !residual_hc || !model_map ||
 n_embd != 4096 || n_hc != 4) {
 return 0;
 }

 const uint64_t mix_hc = 2ull * n_hc + (uint64_t)n_hc * n_hc;
 const uint64_t mix_bytes = mix_hc * sizeof(float);
 const uint64_t out_row_bytes = (uint64_t)n_embd * sizeof(float);
 const uint64_t residual_row_bytes = (uint64_t)n_hc * n_embd * sizeof(float);
 const uint64_t scale_bytes = 3ull * sizeof(float);

 @autoreleasepool {
 id<MTLBuffer> mixbuf = ds4_gpu_tensor_buffer(mix);
 id<MTLBuffer> splitbuf = ds4_gpu_tensor_buffer(split);
 id<MTLBuffer> xbuf = ds4_gpu_tensor_buffer(residual_hc);
 id<MTLBuffer> outbuf = ds4_gpu_tensor_buffer(out);
 id<MTLBuffer> normbuf = ds4_gpu_tensor_buffer(norm_out);
 const uint64_t out_tensor_bytes = ds4_gpu_tensor_bytes(out);
 if (out_row_bytes == 0 || out_tensor_bytes < out_row_bytes ||
 out_tensor_bytes % out_row_bytes != 0) {
 fprintf(stderr, "ds4: Metal fused HC split/sum/norm output size is not a whole token row\n");
 return 0;
 }

 const uint64_t n_rows64 = out_tensor_bytes / out_row_bytes;
 if (n_rows64 == 0 || n_rows64 > UINT32_MAX ||
 n_rows64 > UINT64_MAX / mix_bytes ||
 n_rows64 > UINT64_MAX / residual_row_bytes) {
 fprintf(stderr, "ds4: Metal fused HC split/sum/norm row count is outside supported range\n");
 return 0;
 }

 const uint64_t mix_total_bytes = n_rows64 * mix_bytes;
 const uint64_t residual_total_bytes = n_rows64 * residual_row_bytes;
 const uint64_t out_total_bytes = n_rows64 * out_row_bytes;
 if (!mixbuf || !splitbuf || !xbuf || !outbuf || !normbuf ||
 ds4_gpu_tensor_bytes(mix) < mix_total_bytes ||
 ds4_gpu_tensor_bytes(split) < mix_total_bytes ||
 ds4_gpu_tensor_bytes(residual_hc) < residual_total_bytes ||
 ds4_gpu_tensor_bytes(norm_out) < out_total_bytes) {
 fprintf(stderr, "ds4: Metal fused HC split/sum/norm received undersized activation buffers\n");
 return 0;
 }

 if (scale_offset > model_size || scale_bytes > model_size - scale_offset ||
 base_offset > model_size || mix_bytes > model_size - base_offset ||
 norm_weight_offset > model_size || out_row_bytes > model_size - norm_weight_offset) {
 fprintf(stderr, "ds4: Metal fused HC split/sum/norm parameter range is outside the mapped model\n");
 return 0;
 }

 uint64_t scale_inner = 0;
 uint64_t base_inner = 0;
 uint64_t norm_inner = 0;
 id<MTLBuffer> scalebuf = ds4_gpu_wrap_model_range(model_map, model_size, scale_offset, scale_bytes, &scale_inner);
 id<MTLBuffer> basebuf = ds4_gpu_wrap_model_range(model_map, model_size, base_offset, mix_bytes, &base_inner);
 id<MTLBuffer> normwbuf = ds4_gpu_wrap_model_range(model_map, model_size, norm_weight_offset, out_row_bytes, &norm_inner);
 if (!scalebuf || !basebuf || !normwbuf) return 0;

 id<MTLComputePipelineState> pipeline =
 ds4_gpu_hot_pipeline(g_hc_split_weighted_sum_norm_pipeline,
 "kernel_dsv4_hc_split_weighted_sum_norm4");
 if (!pipeline) return 0;

 ds4_gpu_hc_split_weighted_sum_norm_args args = {
 .n_embd = (int64_t)n_embd,
 .n_hc = (int32_t)n_hc,
 .sinkhorn_iters = (int32_t)sinkhorn_iters,
 .n_rows = (int64_t)n_rows64,
 .mix_hc = (int64_t)mix_hc,
 .nb_mix1 = mix_bytes,
 .nb_split1 = mix_bytes,
 .nb_x0 = sizeof(float),
 .nb_x1 = (uint64_t)n_embd * sizeof(float),
 .nb_x2 = residual_row_bytes,
 .nb0 = sizeof(float),
 .nb1 = out_row_bytes,
 .nb_norm1 = out_row_bytes,
 .eps = eps,
 .norm_eps = norm_eps,
 };

 NSUInteger nth = ds4_gpu_rms_norm_threads(n_embd);
 if (nth > pipeline.maxTotalThreadsPerThreadgroup) {
 fprintf(stderr, "ds4: Metal fused HC split/sum/norm requires %lu threads but pipeline supports %lu\n",
 (unsigned long)nth,
 (unsigned long)pipeline.maxTotalThreadsPerThreadgroup);
 return 0;
 }

 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);
 [enc setComputePipelineState:pipeline];
 [enc setBytes:&args length:sizeof(args) atIndex:0];
 [enc setBuffer:mixbuf offset:ds4_gpu_tensor_offset(mix) atIndex:1];
 [enc setBuffer:scalebuf offset:(NSUInteger)scale_inner atIndex:2];
 [enc setBuffer:basebuf offset:(NSUInteger)base_inner atIndex:3];
 [enc setBuffer:xbuf offset:ds4_gpu_tensor_offset(residual_hc) atIndex:4];
 [enc setBuffer:splitbuf offset:ds4_gpu_tensor_offset(split) atIndex:5];
 [enc setBuffer:outbuf offset:ds4_gpu_tensor_offset(out) atIndex:6];
 [enc setBuffer:normwbuf offset:(NSUInteger)norm_inner atIndex:7];
 [enc setBuffer:normbuf offset:ds4_gpu_tensor_offset(norm_out) atIndex:8];
 [enc setThreadgroupMemoryLength:((NSUInteger)n_embd + 4u + 32u) * sizeof(float)
 atIndex:0];
 [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_rows64, 1, 1)
 threadsPerThreadgroup:MTLSizeMake(nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);

 if (!ds4_gpu_finish_command_buffer(cb, owned, "HC split/sum/norm fused")) return 0;
 }

 return 1;
}

int ds4_gpu_output_hc_weights_tensor(
 ds4_gpu_tensor *out,
 const ds4_gpu_tensor *pre,
 const void *model_map,
 uint64_t model_size,
 uint64_t scale_offset,
 uint64_t base_offset,
 uint32_t n_hc,
 float eps) {
 if (!g_initialized && !ds4_gpu_init()) return 0;
 if (!out || !pre || !model_map || n_hc == 0) return 0;

 @autoreleasepool {
 if ((n_hc % 4u) != 0) {
 fprintf(stderr, "ds4: Metal output HC weights requires a multiple-of-4 HC width\n");
 return 0;
 }

 id<MTLBuffer> prebuf = ds4_gpu_tensor_buffer(pre);
 id<MTLBuffer> outbuf = ds4_gpu_tensor_buffer(out);
 const uint64_t row_bytes = (uint64_t)n_hc * sizeof(float);
 const uint64_t out_tensor_bytes = ds4_gpu_tensor_bytes(out);
 if (row_bytes == 0 || out_tensor_bytes < row_bytes || out_tensor_bytes % row_bytes != 0) {
 fprintf(stderr, "ds4: Metal output HC weights size is not a whole token row\n");
 return 0;
 }

 const uint64_t n_tokens64 = out_tensor_bytes / row_bytes;
 if (n_tokens64 == 0 || n_tokens64 > UINT32_MAX ||
 n_tokens64 > UINT64_MAX / row_bytes) {
 fprintf(stderr, "ds4: Metal output HC weights token count is outside supported range\n");
 return 0;
 }

 const uint64_t bytes = n_tokens64 * row_bytes;
 if (!prebuf || !outbuf ||
 ds4_gpu_tensor_bytes(pre) < bytes ||
 ds4_gpu_tensor_bytes(out) < bytes) {
 fprintf(stderr, "ds4: Metal output HC weights received undersized buffers\n");
 return 0;
 }

 uint64_t scale_inner = 0;
 uint64_t base_inner = 0;
 id<MTLBuffer> scalebuf = ds4_gpu_wrap_model_range(model_map, model_size,
 scale_offset, sizeof(float),
 &scale_inner);
 id<MTLBuffer> basebuf = ds4_gpu_wrap_model_range(model_map, model_size,
 base_offset, row_bytes,
 &base_inner);
 if (!scalebuf || !basebuf) return 0;

 const uint32_t n_tokens = (uint32_t)n_tokens64;
 ds4_gpu_bin_args mul_args = ds4_gpu_make_bin_rows_args(n_hc, n_tokens, 1);
 ds4_gpu_bin_args add_args = ds4_gpu_make_bin_rows_args(n_hc, n_tokens, n_hc);
 ds4_gpu_unary_args sigmoid_args = ds4_gpu_make_unary_rows_args(n_hc, n_tokens, 1, 0.0f, 0.0f);
 ds4_gpu_unary_args scale_args = ds4_gpu_make_unary_rows_args(n_hc, n_tokens, 1, 1.0f, eps);

 NSUInteger mul_nth_max = g_bin_mul_scalar_pipeline.maxTotalThreadsPerThreadgroup;
 if (mul_nth_max > 256u) mul_nth_max = 256u;
 NSUInteger mul_nth = 1u;
 while (2u * mul_nth < (NSUInteger)mul_args.ne0 && mul_nth < mul_nth_max) {
 mul_nth *= 2u;
 }

 NSUInteger add_nth_max = g_add_pipeline.maxTotalThreadsPerThreadgroup;
 if (add_nth_max > 256u) add_nth_max = 256u;
 NSUInteger add_nth = 1u;
 while (2u * add_nth < (NSUInteger)add_args.ne0 && add_nth < add_nth_max) {
 add_nth *= 2u;
 }

 NSUInteger unary_nth_max = g_unary_sigmoid_pipeline.maxTotalThreadsPerThreadgroup;
 if (unary_nth_max > 256u) unary_nth_max = 256u;
 NSUInteger unary_nth = (NSUInteger)sigmoid_args.ne00;
 if (unary_nth > unary_nth_max) unary_nth = unary_nth_max;
 if (unary_nth == 0) unary_nth = 1u;
 const NSUInteger unary_nk0 = ((NSUInteger)sigmoid_args.ne00 + unary_nth - 1u) / unary_nth;
 const NSUInteger out_offset = ds4_gpu_tensor_offset(out);

 int owned = 0;
 id<MTLCommandBuffer> cb = ds4_gpu_command_buffer(&owned);
 if (!cb) return 0;

 id<MTLComputeCommandEncoder> enc = ds4_gpu_compute_encoder(cb);

 [enc setComputePipelineState:g_bin_mul_scalar_pipeline];
 [enc setBytes:&mul_args length:sizeof(mul_args) atIndex:0];
 [enc setBuffer:prebuf offset:ds4_gpu_tensor_offset(pre) atIndex:1];
 [enc setBuffer:scalebuf offset:(NSUInteger)scale_inner atIndex:2];
 [enc setBuffer:outbuf offset:out_offset atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)mul_args.ne01,
 (NSUInteger)mul_args.ne02,
 (NSUInteger)mul_args.ne03)
 threadsPerThreadgroup:MTLSizeMake(mul_nth, 1, 1)];

 [enc setComputePipelineState:g_add_pipeline];
 [enc setBytes:&add_args length:sizeof(add_args) atIndex:0];
 [enc setBuffer:outbuf offset:out_offset atIndex:1];
 [enc setBuffer:basebuf offset:(NSUInteger)base_inner atIndex:2];
 [enc setBuffer:outbuf offset:out_offset atIndex:3];
 [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)add_args.ne01,
 (NSUInteger)add_args.ne02,
 (NSUInteger)add_args.ne03)
 threadsPerThreadgroup:MTLSizeMake(add_nth, 1, 1)];

 [enc setComputePipelineState:g_unary_sigmoid_pipeline];
 [enc setBytes:&sigmoid_args length:sizeof(sigmoid_args) atIndex:0];
 [enc setBuffer:outbuf offset:out_offset atIndex:1];
 [enc setBuffer:outbuf offset:out_offset atIndex:2];
 [enc dispatchThreadgroups:MTLSizeMake(unary_nk0 * (NSUInteger)sigmoid_args.ne01,
 (NSUInteger)sigmoid_args.ne02,
 (NSUInteger)sigmoid_args.ne03)
 threadsPerThreadgroup:MTLSizeMake(unary_nth, 1, 1)];

 [enc setComputePipelineState:g_unary_scale_pipeline];
 [enc setBytes:&scale_args length:sizeof(scale_args) atIndex:0];
 [enc setBuffer:outbuf offset:out_offset atIndex:1];
 [enc setBuffer:outbuf offset:out_offset atIndex:2];
 [enc dispatchThreadgroups:MTLSizeMake(unary_nk0 * (NSUInteger)scale_args.ne01,
 (NSUInteger)scale_args.ne02,
 (NSUInteger)scale_args.ne03)
 threadsPerThreadgroup:MTLSizeMake(unary_nth, 1, 1)];
 ds4_gpu_end_compute_encoder(cb, enc);

 if (!ds4_gpu_finish_command_buffer(cb, owned, "output HC weights")) return 0;
 }

 return 1;
}

